(function(root,factory){var data=factory();if(typeof module==='object'&&module.exports)module.exports=data;root.GateTikTokSourceData=data;})(typeof globalThis!=='undefined'?globalThis:this,function(){return {"sourceCounts":{"definitions":66,"study":287,"cheatSheets":54,"traps":31,"practice":37,"inlineQuizzes":9,"gateQuestions":21},"cards":[{"id":"la-vectors-001","topicId":"vectors","order":1,"type":"basic-definition","hook":"Vector","body":"an ordered list of numbers, e.g. $v=(3,1)$. Each number is a component (the amount of movement along one axis).","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"definition-1","sourceLabel":"Basic definitions","detail":"Vector: an ordered list of numbers, e.g. $v=(3,1)$. Each number is a component (the amount of movement along one axis).","detailHtml":"<p><strong>Vector:</strong> an ordered list of numbers, e.g. $v=(3,1)$. Each number is a <strong>component</strong> (the amount of movement along one axis).</p>","question":null},{"id":"la-vectors-002","topicId":"vectors","order":2,"type":"basic-definition","hook":"$\\mathbb{R}^n$","body":"the space of all vectors with $n$ real components — $(1,2)\\in\\mathbb{R}^2$, $(3,4,5)\\in\\mathbb{R}^3$. The symbol $\\in$ means \"belongs to\".","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"definition-2","sourceLabel":"Basic definitions","detail":"$\\mathbb{R}^n$: the space of all vectors with $n$ real components — $(1,2)\\in\\mathbb{R}^2$, $(3,4,5)\\in\\mathbb{R}^3$. The symbol $\\in$ means &quot;belongs to&quot;.","detailHtml":"<p><strong>$\\mathbb{R}^n$:</strong> the space of all vectors with $n$ real components — $(1,2)\\in\\mathbb{R}^2$, $(3,4,5)\\in\\mathbb{R}^3$. The symbol $\\in$ means &quot;belongs to&quot;.</p>","question":null},{"id":"la-vectors-003","topicId":"vectors","order":3,"type":"basic-definition","hook":"Zero vector ($0$)","body":"all components zero, e.g. $(0,0)$ — \"no movement\", the origin.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"definition-3","sourceLabel":"Basic definitions","detail":"Zero vector ($0$): all components zero, e.g. $(0,0)$ — &quot;no movement&quot;, the origin.","detailHtml":"<p><strong>Zero vector ($0$):</strong> all components zero, e.g. $(0,0)$ — &quot;no movement&quot;, the origin.</p>","question":null},{"id":"la-vectors-004","topicId":"vectors","order":4,"type":"basic-definition","hook":"Vector space","body":"a set of vectors that is closed — add any two, or scale any one, and the result is still inside the set. ($\\mathbb{R}^2$ is the flat plane; $\\mathbb{R}^3$ is 3-D space.)","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"definition-4","sourceLabel":"Basic definitions","detail":"Vector space: a set of vectors that is closed — add any two, or scale any one, and the result is still inside the set. ($\\mathbb{R}^2$ is the flat plane; $\\mathbb{R}^3$ is 3-D space.)","detailHtml":"<p><strong>Vector space:</strong> a set of vectors that is <em>closed</em> — add any two, or scale any one, and the result is still inside the set. ($\\mathbb{R}^2$ is the flat plane; $\\mathbb{R}^3$ is 3-D space.)</p>","question":null},{"id":"la-vectors-005","topicId":"vectors","order":5,"type":"basic-definition","hook":"Subspace","body":"a smaller vector space sitting inside a bigger one — for example a line through the origin inside $\\mathbb{R}^2$.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"definition-5","sourceLabel":"Basic definitions","detail":"Subspace: a smaller vector space sitting inside a bigger one — for example a line through the origin inside $\\mathbb{R}^2$.","detailHtml":"<p><strong>Subspace:</strong> a smaller vector space sitting inside a bigger one — for example a line through the origin inside $\\mathbb{R}^2$.</p>","question":null},{"id":"la-vectors-006","topicId":"vectors","order":6,"type":"basic-definition","hook":"Span","body":"all vectors you can build from a given set by scaling and adding.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"definition-6","sourceLabel":"Basic definitions","detail":"Span: all vectors you can build from a given set by scaling and adding.","detailHtml":"<p><strong>Span:</strong> all vectors you can build from a given set by scaling and adding.</p>","question":null},{"id":"la-vectors-007","topicId":"vectors","order":7,"type":"basic-definition","hook":"Linear combination","body":"one such built vector, $c_1v_1+c_2v_2+\\dots$.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"definition-7","sourceLabel":"Basic definitions","detail":"Linear combination: one such built vector, $c_1v_1+c_2v_2+\\dots$.","detailHtml":"<p><strong>Linear combination:</strong> one such built vector, $c_1v_1+c_2v_2+\\dots$.</p>","question":null},{"id":"la-vectors-008","topicId":"vectors","order":8,"type":"basic-definition","hook":"Linearly independent","body":"no vector in the set can be built from the others (no waste). Dependent: at least one is redundant.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"definition-8","sourceLabel":"Basic definitions","detail":"Linearly independent: no vector in the set can be built from the others (no waste). Dependent: at least one is redundant.","detailHtml":"<p><strong>Linearly independent:</strong> no vector in the set can be built from the others (no waste). <strong>Dependent:</strong> at least one is redundant.</p>","question":null},{"id":"la-vectors-009","topicId":"vectors","order":9,"type":"basic-definition","hook":"Basis","body":"a set that is independent and spans the space — the minimum team that reaches everywhere.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"definition-9","sourceLabel":"Basic definitions","detail":"Basis: a set that is independent and spans the space — the minimum team that reaches everywhere.","detailHtml":"<p><strong>Basis:</strong> a set that is independent <em>and</em> spans the space — the minimum team that reaches everywhere.</p>","question":null},{"id":"la-vectors-010","topicId":"vectors","order":10,"type":"basic-definition","hook":"Dimension","body":"how many vectors are in a basis.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"definition-10","sourceLabel":"Basic definitions","detail":"Dimension: how many vectors are in a basis.","detailHtml":"<p><strong>Dimension:</strong> how many vectors are in a basis.</p>","question":null},{"id":"la-vectors-011","topicId":"vectors","order":11,"type":"deep-dive","hook":"What is a vector?","body":"A vector is a list of numbers.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"study-item-1","sourceLabel":"Study in Depth","detail":"A vector is a list of numbers. Example: v = [1, 2] This means: move 1 step in the x direction move 2 steps in the y direction So in a 2D game map, [1, 2] means: from origin (0, 0) go right 1 go up 2 Visually: y ↑ 2 | ● [1, 2] 1 | 0 |__ __ __→ x 0 1 2 So [1, 2] is not just two numbers — it is an arrow from (0, 0) to (1, 2) .","detailHtml":"\n          \n          <p>A <strong>vector</strong> is a list of numbers.</p>\n          <p class=\"lead\">Example:</p>\n          <pre>v = [1, 2]</pre>\n          <p class=\"lead\">This means:</p>\n          <pre>move 1 step in the x direction\nmove 2 steps in the y direction</pre>\n          <p class=\"lead\">So in a 2D game map, <code>[1, 2]</code> means:</p>\n          <pre>from origin (0, 0)\ngo right 1\ngo up 2</pre>\n          <p class=\"lead\">Visually:</p>\n          <pre class=\"ascii\">y\n↑\n2 |        ● [1, 2]\n1 |\n0 |__ __ __→ x\n   0  1  2</pre>\n          <p>So <code>[1, 2]</code> is not just two numbers — it is an <strong>arrow</strong> from <code>(0, 0)</code> to <code>(1, 2)</code>.</p>\n        ","question":null},{"id":"la-vectors-012","topicId":"vectors","order":12,"type":"deep-dive","hook":"What do x and y mean?","body":"In 2D, [x, y] means:","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"study-item-2","sourceLabel":"Study in Depth","detail":"In 2D, [x, y] means: x = left / right movement y = up / down movement Usually: positive x = right negative x = left positive y = up negative y = down Examples: [3, 0] = move 3 right [-2, 0] = move 2 left [0, 4] = move 4 up [0, -5] = move 5 down [2, 3] = move 2 right and 3 up 🎮 Game imagination: the player starts at the origin [0, 0] . The input vector [2, 3] means: right 2 tiles, up 3 tiles.","detailHtml":"\n          \n          <p>In 2D, <code>[x, y]</code> means:</p>\n          <pre>x = left / right movement\ny = up / down movement</pre>\n          <p class=\"lead\">Usually:</p>\n          <pre>positive x = right\nnegative x = left\npositive y = up\nnegative y = down</pre>\n          <p class=\"lead\">Examples:</p>\n          <pre>[3, 0]   = move 3 right\n[-2, 0]  = move 2 left\n[0, 4]   = move 4 up\n[0, -5]  = move 5 down\n[2, 3]   = move 2 right and 3 up</pre>\n          <p><span style=\"color:var(--coral-text)\">🎮 Game imagination:</span> the player starts at the origin <code>[0, 0]</code>. The input vector <code>[2, 3]</code> means: right 2 tiles, up 3 tiles.</p>\n        ","question":null},{"id":"la-vectors-013","topicId":"vectors","order":13,"type":"deep-dive","hook":"What is a component?","body":"In v = [1, 2], the numbers 1 and 2 are called components.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"study-item-3","sourceLabel":"Study in Depth","detail":"In v = [1, 2] , the numbers 1 and 2 are called components . 1 = first component = x component 2 = second component = y component For a 3D vector: v = [v₁, v₂, v₃] v₁ = first component v₂ = second component v₃ = third component The small numbers are called subscripts : v₁ means &quot;v one&quot;, v₂ means &quot;v two&quot;. They are not powers — they are labels.","detailHtml":"\n          \n          <p>In <code>v = [1, 2]</code>, the numbers 1 and 2 are called <strong>components</strong>.</p>\n          <pre>1 = first component  = x component\n2 = second component = y component</pre>\n          <p class=\"lead\">For a 3D vector:</p>\n          <pre>v = [v₁, v₂, v₃]\n\nv₁ = first component\nv₂ = second component\nv₃ = third component</pre>\n          <p>The small numbers are called <strong>subscripts</strong>: <code>v₁</code> means &quot;v one&quot;, <code>v₂</code> means &quot;v two&quot;. They are <strong>not powers</strong> — they are labels.</p>\n        ","question":null},{"id":"la-vectors-014","topicId":"vectors","order":14,"type":"deep-dive","hook":"Row vector vs column vector","body":"You may see a row vector:","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"study-item-4","sourceLabel":"Study in Depth","detail":"You may see a row vector : v = [1, 2] Or a column vector : v = [1 2] In books, vectors are often written as columns: v = [v₁ v₂ ... vₙ] When they write v = [v₁, v₂, ..., vₙ]ᵀ , the T means transpose — turn a row into a column: [v₁, v₂, v₃]ᵀ = [v₁ v₂ v₃] For GATE, just remember: ᵀ = transpose = flip row / column.","detailHtml":"\n          \n          <p class=\"lead\">You may see a <strong>row vector</strong>:</p>\n          <pre>v = [1, 2]</pre>\n          <p class=\"lead\">Or a <strong>column vector</strong>:</p>\n          <pre>v = [1\n     2]</pre>\n          <p>In books, vectors are often written as columns:</p>\n          <pre>v = [v₁\n     v₂\n     ...\n     vₙ]</pre>\n          <p>When they write <code>v = [v₁, v₂, ..., vₙ]ᵀ</code>, the <strong>T</strong> means <strong>transpose</strong> — turn a row into a column:</p>\n          <pre>[v₁, v₂, v₃]ᵀ  =  [v₁\n                   v₂\n                   v₃]</pre>\n          <p>For GATE, just remember: <code>ᵀ</code> = transpose = flip row / column.</p>\n        ","question":null},{"id":"la-vectors-015","topicId":"vectors","order":15,"type":"deep-dive","hook":"What is ℝⁿ?","body":"This symbol is very important:","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"study-item-5","sourceLabel":"Study in Depth","detail":"This symbol is very important: ℝⁿ Read it as: R n It means: the space of all vectors with n real-number components ℝ means real numbers — normal numbers like: 1, 2, -3, 0, 4.5, 1/2, √2 So: ℝ² = all 2D vectors ℝ³ = all 3D vectors ℝⁿ = all n-dimensional vectors Examples: [1, 2] belongs to ℝ² [3, 4, 5] belongs to ℝ³ [1, 0, 2, 7] belongs to ℝ⁴ The symbol ∈ means belongs to . So [1, 2] ∈ ℝ² means &quot; [1, 2] belongs to…","detailHtml":"\n          \n          <p>This symbol is very important:</p>\n          <pre>ℝⁿ</pre>\n          <p class=\"lead\">Read it as:</p>\n          <pre>R n</pre>\n          <p class=\"lead\">It means:</p>\n          <pre>the space of all vectors with n real-number components</pre>\n          <p><code>ℝ</code> means <strong>real numbers</strong> — normal numbers like:</p>\n          <pre>1,  2,  -3,  0,  4.5,  1/2,  √2</pre>\n          <p class=\"lead\">So:</p>\n          <pre>ℝ² = all 2D vectors\nℝ³ = all 3D vectors\nℝⁿ = all n-dimensional vectors</pre>\n          <p class=\"lead\">Examples:</p>\n          <pre>[1, 2]       belongs to ℝ²\n[3, 4, 5]    belongs to ℝ³\n[1, 0, 2, 7] belongs to ℝ⁴</pre>\n          <p>The symbol <code>∈</code> means <strong>belongs to</strong>. So <code>[1, 2] ∈ ℝ²</code> means &quot;<code>[1, 2]</code> belongs to 2D real vector space&quot;.</p>\n        ","question":null},{"id":"la-vectors-016","topicId":"vectors","order":16,"type":"deep-dive","hook":"Vector addition","body":"Suppose:","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"study-item-6","sourceLabel":"Study in Depth","detail":"Suppose: u = [1, 2] v = [3, 1] Then add component by component: u + v = [1+3, 2+1] = [4, 3] 🎮 Game imagination: u = right 1, up 2 v = right 3, up 1 total = right 4, up 3 Visually: first follow arrow u , then from its tip follow arrow v . The final arrow is u + v . This is called tip-to-tail addition.","detailHtml":"\n          \n          <p class=\"lead\">Suppose:</p>\n          <pre>u = [1, 2]\nv = [3, 1]</pre>\n          <p class=\"lead\">Then add component by component:</p>\n          <pre>u + v = [1+3, 2+1] = [4, 3]</pre>\n          <p><span style=\"color:var(--coral-text)\">🎮 Game imagination:</span></p>\n          <pre>u = right 1, up 2\nv = right 3, up 1\ntotal = right 4, up 3</pre>\n          <p>Visually: first follow arrow <code>u</code>, then from its tip follow arrow <code>v</code>. The final arrow is <code>u + v</code>. This is called <strong>tip-to-tail</strong> addition.</p>\n        ","question":null},{"id":"la-vectors-017","topicId":"vectors","order":17,"type":"deep-dive","hook":"Scalar multiplication","body":"A scalar is just a normal number.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"study-item-7","sourceLabel":"Study in Depth","detail":"A scalar is just a normal number. Example: c = 3 v = [2, 1] c · v = 3 · [2, 1] = [6, 3] It means stretch the vector 3 times. More examples: 2 · [1, 2] = [2, 4] bigger, same direction 0.5 · [2, 4] = [1, 2] smaller, same direction -1 · [1, 2] = [-1, -2] flipped, opposite direction 0 · [1, 2] = [0, 0] becomes the zero vector 🎮 Imagine: vector = movement direction, scalar = speed multiplier. 5 · [1, 0] = [5, 0] means…","detailHtml":"\n          \n          <p>A <strong>scalar</strong> is just a normal number.</p>\n          <p class=\"lead\">Example:</p>\n          <pre>c = 3\nv = [2, 1]\n\nc · v = 3 · [2, 1] = [6, 3]</pre>\n          <p>It means <strong>stretch</strong> the vector 3 times.</p>\n          <p class=\"lead\">More examples:</p>\n          <pre>2 · [1, 2]    = [2, 4]      bigger, same direction\n0.5 · [2, 4]  = [1, 2]      smaller, same direction\n-1 · [1, 2]   = [-1, -2]    flipped, opposite direction\n0 · [1, 2]    = [0, 0]      becomes the zero vector</pre>\n          <p><span style=\"color:var(--coral-text)\">🎮 Imagine:</span> vector = movement direction, scalar = speed multiplier. <code>5 · [1, 0] = [5, 0]</code> means move faster to the right.</p>\n        ","question":null},{"id":"la-vectors-018","topicId":"vectors","order":18,"type":"deep-dive","hook":"Zero vector","body":"The zero vector means no movement.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"study-item-8","sourceLabel":"Study in Depth","detail":"The zero vector means no movement. 2D: 0 = [0, 0] 3D: 0 = [0, 0, 0] It is the origin point. For GATE, remember: every vector space and every subspace must contain the zero vector. If the zero vector is missing, it is not a subspace.","detailHtml":"\n          \n          <p>The <strong>zero vector</strong> means no movement.</p>\n          <pre>2D:  0 = [0, 0]\n3D:  0 = [0, 0, 0]</pre>\n          <p>It is the origin point.</p>\n          <p><strong>For GATE, remember:</strong> every vector space and every subspace <strong>must</strong> contain the zero vector. If the zero vector is missing, it is not a subspace.</p>\n        ","question":null},{"id":"la-vectors-019","topicId":"vectors","order":19,"type":"deep-dive","hook":"Vector space","body":"A vector space is a collection of vectors where two operations are safe:","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"study-item-9","sourceLabel":"Study in Depth","detail":"A vector space is a collection of vectors where two operations are safe: 1. add two vectors 2. multiply a vector by a scalar ...and after doing them, the answer still stays inside the same space. This property is called closure . Example — ℝ² is a vector space: u = [1, 2] v = [3, 4] u + v = [4, 6] still in ℝ² 5 · u = [5, 10] still in ℝ² So ℝ² is closed under addition and scaling.","detailHtml":"\n          \n          <p>A <strong>vector space</strong> is a collection of vectors where two operations are safe:</p>\n          <pre>1. add two vectors\n2. multiply a vector by a scalar</pre>\n          <p>...and after doing them, the answer still stays inside the same space. This property is called <strong>closure</strong>.</p>\n          <p class=\"lead\">Example — ℝ² is a vector space:</p>\n          <pre>u = [1, 2]   v = [3, 4]\n\nu + v = [4, 6]   still in ℝ²\n5 · u = [5, 10]  still in ℝ²</pre>\n          <p>So ℝ² is closed under addition and scaling.</p>\n        ","question":null},{"id":"la-vectors-020","topicId":"vectors","order":20,"type":"deep-dive","hook":"What is closure?","body":"Closure means: you do something inside the world, and the result stays inside the same world.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"study-item-10","sourceLabel":"Study in Depth","detail":"Closure means: you do something inside the world, and the result stays inside the same world. 🎮 Game imagination: imagine a game map. If your character moves and still stays inside the map, the map is &quot;closed&quot; for that movement. For vector spaces: add vectors → still inside scale vector → still inside That is closure.","detailHtml":"\n          \n          <p><strong>Closure</strong> means: you do something inside the world, and the result stays inside the same world.</p>\n          <p><span style=\"color:var(--coral-text)\">🎮 Game imagination:</span> imagine a game map. If your character moves and still stays inside the map, the map is &quot;closed&quot; for that movement.</p>\n          <p class=\"lead\">For vector spaces:</p>\n          <pre>add vectors   → still inside\nscale vector  → still inside</pre>\n          <p>That is closure.</p>\n        ","question":null},{"id":"la-vectors-021","topicId":"vectors","order":21,"type":"deep-dive","hook":"Subspace","body":"A subspace is a smaller vector space inside a bigger vector space. Example: a line through the origin inside ℝ².","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"study-item-11","sourceLabel":"Study in Depth","detail":"A subspace is a smaller vector space inside a bigger vector space. Example: a line through the origin inside ℝ². Think of ℝ² as the whole flat game map. One subspace is a line through the origin: W = { (x, y) : x + y = 0 } This means all points where x + y = 0. Some examples: (1, -1) because 1 + (-1) = 0 (2, -2) because 2 + (-2) = 0 (0, 0) because 0 + 0 = 0 This is the line y = -x , and it passes through the origin…","detailHtml":"\n          \n          <p>A <strong>subspace</strong> is a smaller vector space inside a bigger vector space. Example: a line through the origin inside ℝ².</p>\n          <p class=\"lead\">Think of ℝ² as the whole flat game map. One subspace is a line through the origin:</p>\n          <pre>W = { (x, y) : x + y = 0 }</pre>\n          <p>This means all points where x + y = 0. Some examples:</p>\n          <pre>(1, -1)   because  1 + (-1) = 0\n(2, -2)   because  2 + (-2) = 0\n(0, 0)    because  0 + 0    = 0</pre>\n          <p>This is the line <code>y = -x</code>, and it passes through the origin — so it is a subspace.</p>\n        ","question":null},{"id":"la-vectors-022","topicId":"vectors","order":22,"type":"deep-dive","hook":"Subspace test","body":"To check if something is a subspace, test only these 3 things:","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"study-item-12","sourceLabel":"Study in Depth","detail":"To check if something is a subspace, test only these 3 things: Does it contain the zero vector ? Is it closed under addition ? Is it closed under scalar multiplication ? Most important shortcut: if the zero vector is not present, it is NOT a subspace — stop immediately. Example: W = { (x, y) : x + y = 1 } check zero: (0, 0) → 0 + 0 = 0 but the condition says x + y = 1 so (0, 0) is NOT inside W → W is NOT a subspace…","detailHtml":"\n          \n          <p class=\"lead\">To check if something is a subspace, test only these 3 things:</p>\n          <ol class=\"steps\">\n            <li>Does it contain the <strong>zero vector</strong>?</li>\n            <li>Is it <strong>closed under addition</strong>?</li>\n            <li>Is it <strong>closed under scalar multiplication</strong>?</li>\n          </ol>\n          <p><strong>Most important shortcut:</strong> if the zero vector is not present, it is <strong>NOT</strong> a subspace — stop immediately.</p>\n          <p class=\"lead\">Example:</p>\n          <pre>W = { (x, y) : x + y = 1 }\n\ncheck zero:  (0, 0) → 0 + 0 = 0\nbut the condition says x + y = 1\nso (0, 0) is NOT inside W\n\n→ W is NOT a subspace   (no need to check anything else)</pre>\n        ","question":null},{"id":"la-vectors-023","topicId":"vectors","order":23,"type":"deep-dive","hook":"Span","body":"Span means: all possible vectors you can create using the given vectors.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"study-item-13","sourceLabel":"Study in Depth","detail":"Span means: all possible vectors you can create using the given vectors. Formula: span{v₁, v₂, ..., vₖ} = { c₁v₁ + c₂v₂ + ... + cₖvₖ } Do not fear the formula. It just says: scale each vector by any number, add them, and see all the places you can reach. 🎮 Game imagination: v₁ = [1, 0] move right v₂ = [0, 1] move up 2v₁ + 3v₂ = [2, 0] + [0, 3] = [2, 3] You can reach any point in 2D, so span{[1,0], [0,1]} = ℝ² —…","detailHtml":"\n          \n          <p><strong>Span</strong> means: all possible vectors you can create using the given vectors.</p>\n          <p class=\"lead\">Formula:</p>\n          <pre>span{v₁, v₂, ..., vₖ} = { c₁v₁ + c₂v₂ + ... + cₖvₖ }</pre>\n          <p>Do not fear the formula. It just says: scale each vector by any number, add them, and see all the places you can reach.</p>\n          <p><span style=\"color:var(--coral-text)\">🎮 Game imagination:</span></p>\n          <pre>v₁ = [1, 0]   move right\nv₂ = [0, 1]   move up\n\n2v₁ + 3v₂ = [2, 0] + [0, 3] = [2, 3]</pre>\n          <p>You can reach any point in 2D, so <code>span{[1,0], [0,1]} = ℝ²</code> — these two vectors span the whole plane.</p>\n        ","question":null},{"id":"la-vectors-024","topicId":"vectors","order":24,"type":"deep-dive","hook":"Linear combination","body":"This expression is called a linear combination:","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"study-item-14","sourceLabel":"Study in Depth","detail":"This expression is called a linear combination : c₁v₁ + c₂v₂ + ... + cₖvₖ Meaning: scale the vectors, then add them. Example: v₁ = [1, 0] v₂ = [0, 1] 3v₁ + 4v₂ = [3, 0] + [0, 4] = [3, 4] So [3, 4] is a linear combination of [1, 0] and [0, 1] .","detailHtml":"\n          \n          <p>This expression is called a <strong>linear combination</strong>:</p>\n          <pre>c₁v₁ + c₂v₂ + ... + cₖvₖ</pre>\n          <p>Meaning: scale the vectors, then add them.</p>\n          <p class=\"lead\">Example:</p>\n          <pre>v₁ = [1, 0]   v₂ = [0, 1]\n\n3v₁ + 4v₂ = [3, 0] + [0, 4] = [3, 4]</pre>\n          <p>So <code>[3, 4]</code> is a linear combination of <code>[1, 0]</code> and <code>[0, 1]</code>.</p>\n        ","question":null},{"id":"la-vectors-025","topicId":"vectors","order":25,"type":"deep-dive","hook":"Linear independence","body":"This is extremely important for GATE. Vectors are linearly independent if no vector is useless or a duplicate.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"study-item-15","sourceLabel":"Study in Depth","detail":"This is extremely important for GATE. Vectors are linearly independent if no vector is useless or a duplicate. Formal rule: c₁v₁ + c₂v₂ + ... + cₖvₖ = 0 has only one solution: c₁ = c₂ = ... = cₖ = 0 This is called the trivial solution — the only way to make zero is to use nothing. 🎮 Game imagination: v₁ = [1, 0] right v₂ = [0, 1] up Can one be made from the other? No. Right cannot create up. Up cannot create right.…","detailHtml":"\n          \n          <p>This is extremely important for GATE. Vectors are <strong>linearly independent</strong> if no vector is useless or a duplicate.</p>\n          <p class=\"lead\">Formal rule:</p>\n          <pre>c₁v₁ + c₂v₂ + ... + cₖvₖ = 0\n\nhas only one solution:\nc₁ = c₂ = ... = cₖ = 0</pre>\n          <p>This is called the <strong>trivial solution</strong> — the only way to make zero is to use nothing.</p>\n          <p><span style=\"color:var(--coral-text)\">🎮 Game imagination:</span></p>\n          <pre>v₁ = [1, 0]   right\nv₂ = [0, 1]   up\n\nCan one be made from the other?  No.\nRight cannot create up. Up cannot create right.\n→ they are independent.</pre>\n        ","question":null},{"id":"la-vectors-026","topicId":"vectors","order":26,"type":"deep-dive","hook":"Linear dependence","body":"Vectors are dependent if one vector can be built from the others.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"study-item-16","sourceLabel":"Study in Depth","detail":"Vectors are dependent if one vector can be built from the others. Example: v₁ = [1, 0] v₂ = [0, 1] v₃ = [2, 3] v₃ = 2v₁ + 3v₂ = [2, 0] + [0, 3] = [2, 3] So v₃ gives no new direction — it is already built from v₁ and v₂ . Therefore v₁, v₂, v₃ are linearly dependent. Memory trick: independent = no vector is redundant dependent = at least one vector is redundant","detailHtml":"\n          \n          <p>Vectors are <strong>dependent</strong> if one vector can be built from the others.</p>\n          <p class=\"lead\">Example:</p>\n          <pre>v₁ = [1, 0]   v₂ = [0, 1]   v₃ = [2, 3]\n\nv₃ = 2v₁ + 3v₂ = [2, 0] + [0, 3] = [2, 3]</pre>\n          <p>So <code>v₃</code> gives no new direction — it is already built from <code>v₁</code> and <code>v₂</code>. Therefore <code>v₁, v₂, v₃</code> are linearly dependent.</p>\n          <p class=\"lead\">Memory trick:</p>\n          <pre>independent = no vector is redundant\ndependent   = at least one vector is redundant</pre>\n        ","question":null},{"id":"la-vectors-027","topicId":"vectors","order":27,"type":"deep-dive","hook":"Basis","body":"A basis is the perfect team of vectors. A set is a basis if:","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"study-item-17","sourceLabel":"Study in Depth","detail":"A basis is the perfect team of vectors. A set is a basis if: 1. it spans the space 2. it is linearly independent So a basis has enough vectors to cover the whole space, but no extra useless vector. For ℝ², the standard basis is: e₁ = [1, 0] gives the x direction e₂ = [0, 1] gives the y direction Any vector can be built from them: [x, y] = x[1,0] + y[0,1] [5, 7] = 5[1,0] + 7[0,1] They span ℝ² and are independent, so…","detailHtml":"\n          \n          <p>A <strong>basis</strong> is the perfect team of vectors. A set is a basis if:</p>\n          <pre>1. it spans the space\n2. it is linearly independent</pre>\n          <p>So a basis has enough vectors to cover the whole space, but no extra useless vector.</p>\n          <p class=\"lead\">For ℝ², the standard basis is:</p>\n          <pre>e₁ = [1, 0]    gives the x direction\ne₂ = [0, 1]    gives the y direction</pre>\n          <p class=\"lead\">Any vector can be built from them:</p>\n          <pre>[x, y] = x[1,0] + y[0,1]\n\n[5, 7] = 5[1,0] + 7[0,1]</pre>\n          <p>They span ℝ² and are independent, so <code>{[1,0], [0,1]}</code> is a basis of ℝ².</p>\n        ","question":null},{"id":"la-vectors-028","topicId":"vectors","order":28,"type":"deep-dive","hook":"Dimension","body":"Dimension means the number of vectors in a basis.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"study-item-18","sourceLabel":"Study in Depth","detail":"Dimension means the number of vectors in a basis. ℝ² → basis has 2 vectors → dim(ℝ²) = 2 ℝ³ → basis has 3 vectors → dim(ℝ³) = 3 General: dim(ℝⁿ) = n","detailHtml":"\n          \n          <p><strong>Dimension</strong> means the number of vectors in a basis.</p>\n          <pre>ℝ² → basis has 2 vectors → dim(ℝ²) = 2\nℝ³ → basis has 3 vectors → dim(ℝ³) = 3</pre>\n          <p class=\"lead\">General:</p>\n          <pre>dim(ℝⁿ) = n</pre>\n        ","question":null},{"id":"la-vectors-029","topicId":"vectors","order":29,"type":"cheat-sheet","hook":"more than $n$ vectors are always dependent","body":"re always dependent. (3 in $\\mathbb{R}^2$, 4 in $\\mathbb{R}^3$ → dependent.)","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"cheat-1","sourceLabel":"GATE cheat sheet","detail":"In $\\mathbb{R}^n$, more than $n$ vectors are always dependent . (3 in $\\mathbb{R}^2$, 4 in $\\mathbb{R}^3$ → dependent.)","detailHtml":"<p>In $\\mathbb{R}^n$, <strong>more than $n$ vectors are always dependent</strong>. (3 in $\\mathbb{R}^2$, 4 in $\\mathbb{R}^3$ → dependent.)</p>","question":null},{"id":"la-vectors-030","topicId":"vectors","order":30,"type":"cheat-sheet","hook":"must","body":"bspace must contain $0$. If $0\\notin W$, stop — not a subspace.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"cheat-2","sourceLabel":"GATE cheat sheet","detail":"A subspace must contain $0$. If $0\\notin W$, stop — not a subspace.","detailHtml":"<p>A subspace <strong>must</strong> contain $0$. If $0\\notin W$, stop — not a subspace.</p>","question":null},{"id":"la-vectors-031","topicId":"vectors","order":31,"type":"cheat-sheet","hook":"$\\dim(\\mathbb{R}^n)=n$; every basis of a space has the same number of vectors.","body":"$\\dim(\\mathbb{R}^n)=n$; every basis of a space has the same number of vectors.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"cheat-3","sourceLabel":"GATE cheat sheet","detail":"$\\dim(\\mathbb{R}^n)=n$; every basis of a space has the same number of vectors.","detailHtml":"<p>$\\dim(\\mathbb{R}^n)=n$; every basis of a space has the same number of vectors.</p>","question":null},{"id":"la-vectors-032","topicId":"vectors","order":32,"type":"cheat-sheet","hook":"Two vectors are dependent iff one is a scalar multiple of the other (they're parallel).","body":"Two vectors are dependent iff one is a scalar multiple of the other (they're parallel).","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"cheat-4","sourceLabel":"GATE cheat sheet","detail":"Two vectors are dependent iff one is a scalar multiple of the other (they&#x27;re parallel).","detailHtml":"<p>Two vectors are dependent iff one is a scalar multiple of the other (they&#x27;re parallel).</p>","question":null},{"id":"la-vectors-033","topicId":"vectors","order":33,"type":"cheat-sheet","hook":"The span of $k$ vectors has dimension = number of independent ones among them.","body":"The span of $k$ vectors has dimension = number of independent ones among them.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"cheat-5","sourceLabel":"GATE cheat sheet","detail":"The span of $k$ vectors has dimension = number of independent ones among them.","detailHtml":"<p>The span of $k$ vectors has dimension = number of <em>independent</em> ones among them.</p>","question":null},{"id":"la-vectors-034","topicId":"vectors","order":34,"type":"cheat-sheet","hook":"any 3 vectors in $\\mathbb{R}^2$ are always dependent","body":"vectors is $2$ — so any 3 vectors in $\\mathbb{R}^2$ are always dependent.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"cheat-6","sourceLabel":"GATE cheat sheet","detail":"In $\\mathbb{R}^2$ the maximum number of independent vectors is $2$ — so any 3 vectors in $\\mathbb{R}^2$ are always dependent .","detailHtml":"<p>In $\\mathbb{R}^2$ the maximum number of independent vectors is $2$ — so <strong>any 3 vectors in $\\mathbb{R}^2$ are always dependent</strong>.</p>","question":null},{"id":"la-vectors-035","topicId":"vectors","order":35,"type":"cheat-sheet","hook":"any 4 vectors in $\\mathbb{R}^3$ are always dependent","body":"ors in $\\mathbb{R}^3$ are always dependent.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"cheat-7","sourceLabel":"GATE cheat sheet","detail":"In $\\mathbb{R}^3$ the maximum is $3$ — so any 4 vectors in $\\mathbb{R}^3$ are always dependent .","detailHtml":"<p>In $\\mathbb{R}^3$ the maximum is $3$ — so <strong>any 4 vectors in $\\mathbb{R}^3$ are always dependent</strong>.</p>","question":null},{"id":"la-vectors-036","topicId":"vectors","order":36,"type":"cheat-sheet","hook":"more than $n$ vectors are always dependent","body":"$n$ vectors are always dependent.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"cheat-8","sourceLabel":"GATE cheat sheet","detail":"General rule: in $\\mathbb{R}^n$, more than $n$ vectors are always dependent .","detailHtml":"<p>General rule: in $\\mathbb{R}^n$, <strong>more than $n$ vectors are always dependent</strong>.</p>","question":null},{"id":"la-vectors-037","topicId":"vectors","order":37,"type":"cheat-sheet","hook":"Vector","body":"= ordered list of numbers.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"cheat-9","sourceLabel":"GATE cheat sheet","detail":"Vector = ordered list of numbers.","detailHtml":"<p><strong>Vector</strong> = ordered list of numbers.</p>","question":null},{"id":"la-vectors-038","topicId":"vectors","order":38,"type":"cheat-sheet","hook":"$\\mathbb{R}^n$","body":"= all vectors with $n$ real components.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"cheat-10","sourceLabel":"GATE cheat sheet","detail":"$\\mathbb{R}^n$ = all vectors with $n$ real components.","detailHtml":"<p><strong>$\\mathbb{R}^n$</strong> = all vectors with $n$ real components.</p>","question":null},{"id":"la-vectors-039","topicId":"vectors","order":39,"type":"cheat-sheet","hook":"Subspace","body":"= a smaller vector space inside a bigger one; it must contain the zero vector.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"cheat-11","sourceLabel":"GATE cheat sheet","detail":"Subspace = a smaller vector space inside a bigger one; it must contain the zero vector .","detailHtml":"<p><strong>Subspace</strong> = a smaller vector space inside a bigger one; it <strong>must contain the zero vector</strong>.</p>","question":null},{"id":"la-vectors-040","topicId":"vectors","order":40,"type":"cheat-sheet","hook":"Span","body":"= all vectors you can create; a linear combination is scaled vectors added together.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"cheat-12","sourceLabel":"GATE cheat sheet","detail":"Span = all vectors you can create; a linear combination is scaled vectors added together.","detailHtml":"<p><strong>Span</strong> = all vectors you can create; a <strong>linear combination</strong> is scaled vectors added together.</p>","question":null},{"id":"la-vectors-041","topicId":"vectors","order":41,"type":"cheat-sheet","hook":"Independent","body":"= no vector can be built from the others; dependent = at least one is redundant.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"cheat-13","sourceLabel":"GATE cheat sheet","detail":"Independent = no vector can be built from the others; dependent = at least one is redundant.","detailHtml":"<p><strong>Independent</strong> = no vector can be built from the others; <strong>dependent</strong> = at least one is redundant.</p>","question":null},{"id":"la-vectors-042","topicId":"vectors","order":42,"type":"cheat-sheet","hook":"Basis","body":"= independent + spans; dimension = number of vectors in a basis, with $\\dim(\\mathbb{R}^n)=n$.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"cheat-14","sourceLabel":"GATE cheat sheet","detail":"Basis = independent + spans; dimension = number of vectors in a basis, with $\\dim(\\mathbb{R}^n)=n$.","detailHtml":"<p><strong>Basis</strong> = independent + spans; <strong>dimension</strong> = number of vectors in a basis, with $\\dim(\\mathbb{R}^n)=n$.</p>","question":null},{"id":"la-vectors-043","topicId":"vectors","order":43,"type":"cheat-sheet","hook":"more than $n$ vectors are always dependent","body":"re always dependent.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"cheat-15","sourceLabel":"GATE cheat sheet","detail":"In $\\mathbb{R}^n$, more than $n$ vectors are always dependent .","detailHtml":"<p>In $\\mathbb{R}^n$, <strong>more than $n$ vectors are always dependent</strong>.</p>","question":null},{"id":"la-vectors-044","topicId":"vectors","order":44,"type":"trap","hook":"Trap","body":"\"A line is always a subspace.\" Reality: only if it passes through the origin. $x+y=1$ is not a subspace.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"trap-1","sourceLabel":"Common traps","detail":"Trap: &quot;A line is always a subspace.&quot; Reality: only if it passes through the origin. $x+y=1$ is not a subspace.","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;A line is always a subspace.&quot;\n        <span class=\"right\">Reality:</span> only if it passes through the origin. $x+y=1$ is not a subspace.</p>","question":null},{"id":"la-vectors-045","topicId":"vectors","order":45,"type":"trap","hook":"Trap","body":"\"The zero vector can be an eigenvector / a basis vector.\" Reality: the zero vector is never independent and never in a basis.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"trap-2","sourceLabel":"Common traps","detail":"Trap: &quot;The zero vector can be an eigenvector / a basis vector.&quot; Reality: the zero vector is never independent and never in a basis.","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;The zero vector can be an eigenvector / a basis vector.&quot;\n        <span class=\"right\">Reality:</span> the zero vector is never independent and never in a basis.</p>","question":null},{"id":"la-vectors-046","topicId":"vectors","order":46,"type":"trap","hook":"Trap","body":"\"More vectors means a bigger span / dimension.\" Reality: extra dependent vectors add nothing; dimension counts independent directions only.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"trap-3","sourceLabel":"Common traps","detail":"Trap: &quot;More vectors means a bigger span / dimension.&quot; Reality: extra dependent vectors add nothing; dimension counts independent directions only.","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;More vectors means a bigger span / dimension.&quot;\n        <span class=\"right\">Reality:</span> extra dependent vectors add nothing; dimension counts independent directions only.</p>","question":null},{"id":"la-vectors-047","topicId":"vectors","order":47,"type":"practice","hook":"Q1. Is $(2,3,4)$ in $\\mathbb{R}^2$?","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"practice-1","sourceLabel":"Practice problems","detail":"No — it has 3 components, so it lives in $\\mathbb{R}^3$.","detailHtml":"No — it has 3 components, so it lives in $\\mathbb{R}^3$.","question":{"type":"REVEAL","prompt":"Q1. Is $(2,3,4)$ in $\\mathbb{R}^2$?","options":[],"answer":true,"explanation":"No — it has 3 components, so it lives in $\\mathbb{R}^3$.","explanationHtml":"No — it has 3 components, so it lives in $\\mathbb{R}^3$."}},{"id":"la-vectors-048","topicId":"vectors","order":48,"type":"practice","hook":"Q2. Is $W=\\{(x,y): x+y=5\\}$ a subspace of $\\mathbb{R}^2$?","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"practice-2","sourceLabel":"Practice problems","detail":"No — $(0,0)$ gives $0\\neq5$, so $W$ doesn&#x27;t contain the zero vector. Stop there.","detailHtml":"No — $(0,0)$ gives $0\\neq5$, so $W$ doesn&#x27;t contain the zero vector. Stop there.","question":{"type":"REVEAL","prompt":"Q2. Is $W=\\{(x,y): x+y=5\\}$ a subspace of $\\mathbb{R}^2$?","options":[],"answer":true,"explanation":"No — $(0,0)$ gives $0\\neq5$, so $W$ doesn't contain the zero vector. Stop there.","explanationHtml":"No — $(0,0)$ gives $0\\neq5$, so $W$ doesn&#x27;t contain the zero vector. Stop there."}},{"id":"la-vectors-049","topicId":"vectors","order":49,"type":"practice","hook":"Q3. Are $(1,0),(0,1),(4,5)$ independent?","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"practice-3","sourceLabel":"Practice problems","detail":"Dependent — 3 vectors in $\\mathbb{R}^2$ ($&gt;n$) are always dependent.","detailHtml":"Dependent — 3 vectors in $\\mathbb{R}^2$ ($&gt;n$) are always dependent.","question":{"type":"REVEAL","prompt":"Q3. Are $(1,0),(0,1),(4,5)$ independent?","options":[],"answer":true,"explanation":"Dependent — 3 vectors in $\\mathbb{R}^2$ ($>n$) are always dependent.","explanationHtml":"Dependent — 3 vectors in $\\mathbb{R}^2$ ($&gt;n$) are always dependent."}},{"id":"la-vectors-050","topicId":"vectors","order":50,"type":"practice","hook":"Q4. What is $\\dim(\\operatorname{span}\\{(1,2,3),(2,4,6)\\})$?","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"practice-4","sourceLabel":"Practice problems","detail":"$1$ — the second vector is $2\\times$ the first, so they&#x27;re parallel; the span is a line.","detailHtml":"$1$ — the second vector is $2\\times$ the first, so they&#x27;re parallel; the span is a line.","question":{"type":"REVEAL","prompt":"Q4. What is $\\dim(\\operatorname{span}\\{(1,2,3),(2,4,6)\\})$?","options":[],"answer":true,"explanation":"$1$ — the second vector is $2\\times$ the first, so they're parallel; the span is a line.","explanationHtml":"$1$ — the second vector is $2\\times$ the first, so they&#x27;re parallel; the span is a line."}},{"id":"la-vectors-051","topicId":"vectors","order":51,"type":"practice","hook":"Q5. Write $(5,7)$ as a combination of $(1,0)$ and $(0,1)$.","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"practice-5","sourceLabel":"Practice problems","detail":"$(5,7)=5(1,0)+7(0,1)$.","detailHtml":"$(5,7)=5(1,0)+7(0,1)$.","question":{"type":"REVEAL","prompt":"Q5. Write $(5,7)$ as a combination of $(1,0)$ and $(0,1)$.","options":[],"answer":true,"explanation":"$(5,7)=5(1,0)+7(0,1)$.","explanationHtml":"$(5,7)=5(1,0)+7(0,1)$."}},{"id":"la-vectors-052","topicId":"vectors","order":52,"type":"practice","hook":"Which of the following is not a subspace of $\\mathbb{R}^2$?","body":"Choose an answer, then check the explanation.","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"01-vectors.html","sourceAnchor":"practice-quiz-1","sourceLabel":"Practice quiz","detail":"✅ Correct — $x+y=1$ excludes $(0,0)$, so not a subspace.","detailHtml":"✅ Correct — $x+y=1$ excludes $(0,0)$, so not a subspace.","question":{"type":"MCQ","prompt":"Which of the following is not a subspace of $\\mathbb{R}^2$?","options":["A: $\\{(x,y): 2x-y=0\\}$","B: $\\{(0,0)\\}$","C: $\\mathbb{R}^2$","D: $\\{(x,y): x+y=1\\}$"],"answer":"D","explanation":"✅ Correct — $x+y=1$ excludes $(0,0)$, so not a subspace.","explanationHtml":"✅ Correct — $x+y=1$ excludes $(0,0)$, so not a subspace."}},{"id":"la-matrices-001","topicId":"matrices","order":1,"type":"basic-definition","hook":"Matrix","body":"a rectangular table of numbers; an $m\\times n$ matrix has $m$ rows and $n$ columns (rows first — \"RC cola\"). Entry $a_{ij}$ sits in row $i$, column $j$.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"definition-1","sourceLabel":"Basic definitions","detail":"Matrix: a rectangular table of numbers; an $m\\times n$ matrix has $m$ rows and $n$ columns (rows first — &quot;RC cola&quot;). Entry $a_{ij}$ sits in row $i$, column $j$.","detailHtml":"<p><strong>Matrix:</strong> a rectangular table of numbers; an <strong>$m\\times n$</strong> matrix has $m$ rows and $n$ columns (rows first — &quot;RC cola&quot;). Entry $a_{ij}$ sits in row $i$, column $j$.</p>","question":null},{"id":"la-matrices-002","topicId":"matrices","order":2,"type":"basic-definition","hook":"Square matrix","body":"equal rows and columns ($n\\times n$). Column vector: $n\\times1$; row vector: $1\\times n$.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"definition-2","sourceLabel":"Basic definitions","detail":"Square matrix: equal rows and columns ($n\\times n$). Column vector: $n\\times1$; row vector: $1\\times n$.","detailHtml":"<p><strong>Square matrix:</strong> equal rows and columns ($n\\times n$). <strong>Column vector:</strong> $n\\times1$; <strong>row vector:</strong> $1\\times n$.</p>","question":null},{"id":"la-matrices-003","topicId":"matrices","order":3,"type":"basic-definition","hook":"Diagonal matrix","body":"non-zero entries only on the main diagonal (top-left to bottom-right).","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"definition-3","sourceLabel":"Basic definitions","detail":"Diagonal matrix: non-zero entries only on the main diagonal (top-left to bottom-right).","detailHtml":"<p><strong>Diagonal matrix:</strong> non-zero entries only on the main diagonal (top-left to bottom-right).</p>","question":null},{"id":"la-matrices-004","topicId":"matrices","order":4,"type":"basic-definition","hook":"Identity $I$","body":"a diagonal of $1$s; multiplying by it changes nothing ($AI=A$) — the \"1\" of matrices.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"definition-4","sourceLabel":"Basic definitions","detail":"Identity $I$: a diagonal of $1$s; multiplying by it changes nothing ($AI=A$) — the &quot;1&quot; of matrices.","detailHtml":"<p><strong>Identity $I$:</strong> a diagonal of $1$s; multiplying by it changes nothing ($AI=A$) — the &quot;1&quot; of matrices.</p>","question":null},{"id":"la-matrices-005","topicId":"matrices","order":5,"type":"basic-definition","hook":"Transpose $A^{\\mathsf T}$","body":"flip rows into columns, so $a_{ij}$ becomes $a_{ji}$.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"definition-5","sourceLabel":"Basic definitions","detail":"Transpose $A^{\\mathsf T}$: flip rows into columns, so $a_{ij}$ becomes $a_{ji}$.","detailHtml":"<p><strong>Transpose $A^{\\mathsf T}$:</strong> flip rows into columns, so $a_{ij}$ becomes $a_{ji}$.</p>","question":null},{"id":"la-matrices-006","topicId":"matrices","order":6,"type":"basic-definition","hook":"Symmetric","body":"$A=A^{\\mathsf T}$ — a mirror image across the main diagonal.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"definition-6","sourceLabel":"Basic definitions","detail":"Symmetric: $A=A^{\\mathsf T}$ — a mirror image across the main diagonal.","detailHtml":"<p><strong>Symmetric:</strong> $A=A^{\\mathsf T}$ — a mirror image across the main diagonal.</p>","question":null},{"id":"la-matrices-007","topicId":"matrices","order":7,"type":"basic-definition","hook":"Inverse $A^{-1}$","body":"the matrix that undoes $A$ ($AA^{-1}=I$); exists only for square, non-singular matrices.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"definition-7","sourceLabel":"Basic definitions","detail":"Inverse $A^{-1}$: the matrix that undoes $A$ ($AA^{-1}=I$); exists only for square, non-singular matrices.","detailHtml":"<p><strong>Inverse $A^{-1}$:</strong> the matrix that undoes $A$ ($AA^{-1}=I$); exists only for square, non-singular matrices.</p>","question":null},{"id":"la-matrices-008","topicId":"matrices","order":8,"type":"basic-definition","hook":"Trace","body":"the sum of the diagonal entries, $\\operatorname{tr}(A)=\\sum_i a_{ii}$.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"definition-8","sourceLabel":"Basic definitions","detail":"Trace: the sum of the diagonal entries, $\\operatorname{tr}(A)=\\sum_i a_{ii}$.","detailHtml":"<p><strong>Trace:</strong> the sum of the diagonal entries, $\\operatorname{tr}(A)=\\sum_i a_{ii}$.</p>","question":null},{"id":"la-matrices-009","topicId":"matrices","order":9,"type":"deep-dive","hook":"What is a matrix?","body":"A matrix is a rectangular table of numbers.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"study-item-1","sourceLabel":"Study in Depth","detail":"A matrix is a rectangular table of numbers. A = [1 2 3 4] This has 2 rows and 2 columns, so its size is 2 × 2 (&quot;two by two&quot;). B = [1 2 3 4 5 6] → B is a 2 × 3 matrix An m × n matrix has m rows and n columns — rows first, columns second. Memory trick: RC cola — Rows first, Columns second.","detailHtml":"\n          \n          <p>A <strong>matrix</strong> is a rectangular table of numbers.</p>\n          <pre>A = [1  2\n     3  4]</pre>\n          <p>This has 2 rows and 2 columns, so its size is <code>2 × 2</code> (&quot;two by two&quot;).</p>\n          <pre>B = [1  2  3\n     4  5  6]      →  B is a 2 × 3 matrix</pre>\n          <p>An <code>m × n</code> matrix has <strong>m rows and n columns</strong> — rows first, columns second.</p>\n          <p><span style=\"color:var(--coral-text)\">Memory trick:</span> <strong>RC cola</strong> — Rows first, Columns second.</p>\n        ","question":null},{"id":"la-matrices-010","topicId":"matrices","order":10,"type":"deep-dive","hook":"Matrix entry: what aᵢⱼ means","body":"Every number has a position, written aᵢⱼ (\"a i j\") = the entry in row i, column j.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"study-item-2","sourceLabel":"Study in Depth","detail":"Every number has a position, written aᵢⱼ (&quot;a i j&quot;) = the entry in row i, column j . A = [1 2 3 4] a₁₁ = row 1, col 1 = 1 a₁₂ = row 1, col 2 = 2 a₂₁ = row 2, col 1 = 3 a₂₂ = row 2, col 2 = 4 Always row first, column second : A = [5 8 2 7 1 9] a₂₃ = 9, a₁₂ = 8","detailHtml":"\n          \n          <p>Every number has a position, written <code>aᵢⱼ</code> (&quot;a i j&quot;) = the entry in <strong>row i, column j</strong>.</p>\n          <pre>A = [1  2\n     3  4]\n\na₁₁ = row 1, col 1 = 1\na₁₂ = row 1, col 2 = 2\na₂₁ = row 2, col 1 = 3\na₂₂ = row 2, col 2 = 4</pre>\n          <p>Always <strong>row first, column second</strong>:</p>\n          <pre>A = [5  8  2\n     7  1  9]      a₂₃ = 9,   a₁₂ = 8</pre>\n        ","question":null},{"id":"la-matrices-011","topicId":"matrices","order":11,"type":"deep-dive","hook":"Matrix as a data table","body":"At the simplest level a matrix is just a table — e.g. student marks:","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"study-item-3","sourceLabel":"Study in Depth","detail":"At the simplest level a matrix is just a table — e.g. student marks: Math CS Stats Amit 80 90 70 Ravi 60 85 75 Sita 95 88 91 M = [80 90 70 60 85 75 95 88 91] But in linear algebra the more powerful meaning is: matrix = transformation machine .","detailHtml":"\n          \n          <p>At the simplest level a matrix is just a table — e.g. student marks:</p>\n          <pre>          Math  CS  Stats\nAmit       80   90   70\nRavi       60   85   75\nSita       95   88   91\n\nM = [80  90  70\n     60  85  75\n     95  88  91]</pre>\n          <p>But in linear algebra the more powerful meaning is: <strong>matrix = transformation machine</strong>.</p>\n        ","question":null},{"id":"la-matrices-012","topicId":"matrices","order":12,"type":"deep-dive","hook":"Matrix as a transformation machine","body":"A matrix acts on a vector to produce a new vector.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"study-item-4","sourceLabel":"Study in Depth","detail":"A matrix acts on a vector to produce a new vector. A = [2 0 v = [1 0 2] 3] Av = [2×1 + 0×3 = [2 0×1 + 2×3] 6] So [1, 3] becomes [2, 6] — stretched by 2. 🎮 Imagine: the vector is the player&#x27;s position and the matrix is a transformation portal — walk through and your coordinates change.","detailHtml":"\n          \n          <p>A matrix <em>acts</em> on a vector to produce a new vector.</p>\n          <pre>A = [2  0      v = [1\n     0  2]          3]\n\nAv = [2×1 + 0×3     = [2\n      0×1 + 2×3]       6]</pre>\n          <p>So <code>[1, 3]</code> becomes <code>[2, 6]</code> — stretched by 2.</p>\n          <p><span style=\"color:var(--coral-text)\">🎮 Imagine:</span> the vector is the player&#x27;s position and the matrix is a transformation portal — walk through and your coordinates change.</p>\n        ","question":null},{"id":"la-matrices-013","topicId":"matrices","order":13,"type":"deep-dive","hook":"Matrix size (row / column vectors)","body":"A column vector is an n × 1 matrix; a row vector is a 1 × n matrix.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"study-item-5","sourceLabel":"Study in Depth","detail":"A = [1 2 3 4 5 6] → 2 × 3 B = [1 2 3] → 3 × 1 (a column vector) C = [1 2 3] → 1 × 3 (a row vector) A column vector is an n × 1 matrix; a row vector is a 1 × n matrix.","detailHtml":"\n          \n          <pre>A = [1  2  3\n     4  5  6]      →  2 × 3\n\nB = [1\n     2\n     3]            →  3 × 1   (a column vector)\n\nC = [1  2  3]      →  1 × 3   (a row vector)</pre>\n          <p>A <strong>column vector</strong> is an <code>n × 1</code> matrix; a <strong>row vector</strong> is a <code>1 × n</code> matrix.</p>\n        ","question":null},{"id":"la-matrices-014","topicId":"matrices","order":14,"type":"deep-dive","hook":"Why matrix size matters","body":"Multiplication is allowed only when the inner dimensions match.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"study-item-6","sourceLabel":"Study in Depth","detail":"Multiplication is allowed only when the inner dimensions match . A is m × n B is n × p → AB is possible, and AB is m × p (m × n)(n × p) = m × p ↑ ↑ these must match A = 2 × 3, B = 3 × 4 → AB = 2 × 4 ✓ A = 2 × 3, B = 2 × 4 → not possible (3 ≠ 2) Memory: outside numbers become the answer size; inside numbers must match.","detailHtml":"\n          \n          <p>Multiplication is allowed only when the <strong>inner dimensions match</strong>.</p>\n          <pre>A is m × n\nB is n × p\n→ AB is possible, and AB is m × p\n\n(m × n)(n × p) = m × p\n        ↑    ↑  these must match</pre>\n          <pre>A = 2 × 3,  B = 3 × 4   → AB = 2 × 4   ✓\nA = 2 × 3,  B = 2 × 4   → not possible (3 ≠ 2)</pre>\n          <p><span style=\"color:var(--coral-text)\">Memory:</span> outside numbers become the answer size; inside numbers must match.</p>\n        ","question":null},{"id":"la-matrices-015","topicId":"matrices","order":15,"type":"worked-example","hook":"Matrix multiplication (worked)","body":"Each entry of C = AB is a row of A dotted with a column of B.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"study-item-7","sourceLabel":"Study in Depth","detail":"A = [1 2 B = [5 6 3 4] 7 8] Each entry of C = AB is a row of A dotted with a column of B . C₁₁ = $\\begin{bmatrix}1&amp;2\\end{bmatrix}\\begin{bmatrix}5\\\\7\\end{bmatrix}$ = 1×5 + 2×7 = 19 C₁₂ = $\\begin{bmatrix}1&amp;2\\end{bmatrix}\\begin{bmatrix}6\\\\8\\end{bmatrix}$ = 1×6 + 2×8 = 22 C₂₁ = $\\begin{bmatrix}3&amp;4\\end{bmatrix}\\begin{bmatrix}5\\\\7\\end{bmatrix}$ = 3×5 + 4×7 = 43 C₂₂ =…","detailHtml":"\n          \n          <pre>A = [1  2      B = [5  6\n     3  4]          7  8]</pre>\n          <p>Each entry of <code>C = AB</code> is a <strong>row of A dotted with a column of B</strong>.</p>\n          <div class=\"math-steps\"><div class=\"ms-line\">C₁₁ = $\\begin{bmatrix}1&amp;2\\end{bmatrix}\\begin{bmatrix}5\\\\7\\end{bmatrix}$ = 1×5 + 2×7 = 19</div><div class=\"ms-line\">C₁₂ = $\\begin{bmatrix}1&amp;2\\end{bmatrix}\\begin{bmatrix}6\\\\8\\end{bmatrix}$ = 1×6 + 2×8 = 22</div><div class=\"ms-line\">C₂₁ = $\\begin{bmatrix}3&amp;4\\end{bmatrix}\\begin{bmatrix}5\\\\7\\end{bmatrix}$ = 3×5 + 4×7 = 43</div><div class=\"ms-line\">C₂₂ = $\\begin{bmatrix}3&amp;4\\end{bmatrix}\\begin{bmatrix}6\\\\8\\end{bmatrix}$ = 3×6 + 4×8 = 50</div><div class=\"ms-line\"></div><div class=\"ms-line\">AB = $\\begin{bmatrix}19&amp;22\\\\43&amp;50\\end{bmatrix}$</div></div>\n        ","question":null},{"id":"la-matrices-016","topicId":"matrices","order":16,"type":"deep-dive","hook":"Why multiplication looks strange","body":"Matrix multiplication is not just number multiplication — it means applying one transformation after another.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"study-item-8","sourceLabel":"Study in Depth","detail":"Matrix multiplication is not just number multiplication — it means applying one transformation after another . A = rotate, B = stretch AB means: first apply B, then apply A Order matters: &quot;rotate then stretch&quot; ≠ &quot;stretch then rotate&quot;. That is why AB ≠ BA in general.","detailHtml":"\n          \n          <p>Matrix multiplication is not just number multiplication — it means <strong>applying one transformation after another</strong>.</p>\n          <pre>A = rotate,  B = stretch\nAB means: first apply B, then apply A</pre>\n          <p>Order matters: &quot;rotate then stretch&quot; ≠ &quot;stretch then rotate&quot;. That is why <code>AB ≠ BA</code> in general.</p>\n        ","question":null},{"id":"la-matrices-017","topicId":"matrices","order":17,"type":"deep-dive","hook":"AB ≠ BA","body":"GATE memory: matrix multiplication is associative — A(BC) = (AB)C — but not commutative.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"study-item-9","sourceLabel":"Study in Depth","detail":"A = [1 2 B = [1 0 0 1] 3 1] AB = [7 2 BA = [1 2 3 1] 3 7] → AB ≠ BA GATE memory: matrix multiplication is associative — A(BC) = (AB)C — but not commutative .","detailHtml":"\n          \n          <pre>A = [1  2      B = [1  0\n     0  1]          3  1]\n\nAB = [7  2          BA = [1  2\n      3  1]                3  7]\n\n→ AB ≠ BA</pre>\n          <p><span style=\"color:var(--coral-text)\">GATE memory:</span> matrix multiplication is <strong>associative</strong> — <code>A(BC) = (AB)C</code> — but <strong>not commutative</strong>.</p>\n        ","question":null},{"id":"la-matrices-018","topicId":"matrices","order":18,"type":"deep-dive","hook":"Matrix addition","body":"Add matrices only if same size; addition is component-wise.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"study-item-10","sourceLabel":"Study in Depth","detail":"Add matrices only if same size ; addition is component-wise. A = [1 2 B = [5 6 3 4] 7 8] A + B = [6 8 10 12] allowed: 2×2 + 2×2 not allowed: 2×3 + 3×2","detailHtml":"\n          \n          <p>Add matrices <strong>only if same size</strong>; addition is component-wise.</p>\n          <pre>A = [1  2      B = [5  6\n     3  4]          7  8]\n\nA + B = [6   8\n         10  12]</pre>\n          <pre>allowed:    2×2 + 2×2\nnot allowed: 2×3 + 3×2</pre>\n        ","question":null},{"id":"la-matrices-019","topicId":"matrices","order":19,"type":"deep-dive","hook":"Scalar multiplication","body":"A scalar multiplies every entry.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"study-item-11","sourceLabel":"Study in Depth","detail":"A scalar multiplies every entry. A = [1 2 3A = [3 6 3 4] 9 12]","detailHtml":"\n          \n          <p>A scalar multiplies <strong>every</strong> entry.</p>\n          <pre>A = [1  2          3A = [3   6\n     3  4]                9   12]</pre>\n        ","question":null},{"id":"la-matrices-020","topicId":"matrices","order":20,"type":"deep-dive","hook":"Identity matrix","body":"The identity I is the matrix version of 1: AI = IA = A.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"study-item-12","sourceLabel":"Study in Depth","detail":"The identity I is the matrix version of 1: AI = IA = A . I₂ = [1 0 I₃ = [1 0 0 0 1] 0 1 0 0 0 1] 1 on the diagonal, 0 elsewhere; a vector passes through unchanged. 🎮 Imagine: the &quot;no-effect&quot; portal.","detailHtml":"\n          \n          <p>The identity <code>I</code> is the matrix version of 1: <code>AI = IA = A</code>.</p>\n          <pre>I₂ = [1  0       I₃ = [1  0  0\n      0  1]            0  1  0\n                       0  0  1]</pre>\n          <p>1 on the diagonal, 0 elsewhere; a vector passes through unchanged. <span style=\"color:var(--coral-text)\">🎮 Imagine:</span> the &quot;no-effect&quot; portal.</p>\n        ","question":null},{"id":"la-matrices-021","topicId":"matrices","order":21,"type":"deep-dive","hook":"Diagonal matrix","body":"Non-zero values only on the diagonal — scales each axis independently.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"study-item-13","sourceLabel":"Study in Depth","detail":"Non-zero values only on the diagonal — scales each axis independently. D = [2 0 Dv = [2x 0 3] 3y] x stretched by 2, y by 3. 🎮 Imagine: a stretch machine.","detailHtml":"\n          \n          <p>Non-zero values only on the diagonal — scales each axis independently.</p>\n          <pre>D = [2  0          Dv = [2x\n     0  3]                3y]</pre>\n          <p>x stretched by 2, y by 3. <span style=\"color:var(--coral-text)\">🎮 Imagine:</span> a stretch machine.</p>\n        ","question":null},{"id":"la-matrices-022","topicId":"matrices","order":22,"type":"deep-dive","hook":"Square matrix","body":"A matrix is square when rows = columns (2×2, 3×3, …). Only square matrices can have a determinant, inverse, eigenvalues and trace.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"study-item-14","sourceLabel":"Study in Depth","detail":"A matrix is square when rows = columns (2×2, 3×3, …). Only square matrices can have a determinant, inverse, eigenvalues and trace .","detailHtml":"\n          \n          <p>A matrix is <strong>square</strong> when rows = columns (2×2, 3×3, …). Only square matrices can have a <strong>determinant, inverse, eigenvalues</strong> and <strong>trace</strong>.</p>\n        ","question":null},{"id":"la-matrices-023","topicId":"matrices","order":23,"type":"deep-dive","hook":"Zero matrix","body":"All entries 0; sends every vector to the origin: Ov = 0.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"study-item-15","sourceLabel":"Study in Depth","detail":"All entries 0; sends every vector to the origin: Ov = 0 . O = [0 0 0 0] 🎮 Imagine: a black-hole portal — everything collapses to the origin.","detailHtml":"\n          \n          <p>All entries 0; sends every vector to the origin: <code>Ov = 0</code>.</p>\n          <pre>O = [0  0\n     0  0]</pre>\n          <p><span style=\"color:var(--coral-text)\">🎮 Imagine:</span> a black-hole portal — everything collapses to the origin.</p>\n        ","question":null},{"id":"la-matrices-024","topicId":"matrices","order":24,"type":"deep-dive","hook":"Transpose (Aᵀ)","body":"Transpose flips rows into columns. If A is m × n, then Aᵀ is n × m.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"study-item-16","sourceLabel":"Study in Depth","detail":"Transpose flips rows into columns. If A is m × n , then Aᵀ is n × m . A = [1 2 3 Aᵀ = [1 4 4 5 6] 2 5 3 6] Properties: (Aᵀ)ᵀ = A (A + B)ᵀ = Aᵀ + Bᵀ (cA)ᵀ = cAᵀ (AB)ᵀ = BᵀAᵀ — the order reverses (classic GATE trap).","detailHtml":"\n          \n          <p><strong>Transpose</strong> flips rows into columns. If A is <code>m × n</code>, then <code>Aᵀ</code> is <code>n × m</code>.</p>\n          <pre>A = [1  2  3        Aᵀ = [1  4\n     4  5  6]              2  5\n                           3  6]</pre>\n          <p class=\"lead\">Properties:</p>\n          <ul class=\"styled\">\n            <li><code>(Aᵀ)ᵀ = A</code></li>\n            <li><code>(A + B)ᵀ = Aᵀ + Bᵀ</code></li>\n            <li><code>(cA)ᵀ = cAᵀ</code></li>\n            <li><strong><code>(AB)ᵀ = BᵀAᵀ</code> — the order reverses</strong> (classic GATE trap).</li>\n          </ul>\n        ","question":null},{"id":"la-matrices-025","topicId":"matrices","order":25,"type":"deep-dive","hook":"Symmetric matrix","body":"Symmetric if A = Aᵀ — a mirror image across the diagonal (must be square).","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"study-item-17","sourceLabel":"Study in Depth","detail":"Symmetric if A = Aᵀ — a mirror image across the diagonal (must be square). A = [1 2 3 2 5 6 aᵢⱼ = aⱼᵢ 3 6 9] GATE facts: Real symmetric matrices have real eigenvalues . Eigenvectors for distinct eigenvalues are orthogonal .","detailHtml":"\n          \n          <p>Symmetric if <code>A = Aᵀ</code> — a mirror image across the diagonal (must be square).</p>\n          <pre>A = [1  2  3\n     2  5  6        aᵢⱼ = aⱼᵢ\n     3  6  9]</pre>\n          <p class=\"lead\">GATE facts:</p>\n          <ul class=\"styled\">\n            <li>Real symmetric matrices have <strong>real eigenvalues</strong>.</li>\n            <li>Eigenvectors for distinct eigenvalues are <strong>orthogonal</strong>.</li>\n          </ul>\n        ","question":null},{"id":"la-matrices-026","topicId":"matrices","order":26,"type":"deep-dive","hook":"Upper triangular matrix","body":"Everything below the diagonal is zero.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"study-item-18","sourceLabel":"Study in Depth","detail":"Everything below the diagonal is zero. U = [2 5 7 0 3 9 0 0 4] det(U) = 2×3×4 = 24 GATE fact: determinant = product of the diagonal entries.","detailHtml":"\n          \n          <p>Everything <strong>below</strong> the diagonal is zero.</p>\n          <pre>U = [2  5  7\n     0  3  9\n     0  0  4]      det(U) = 2×3×4 = 24</pre>\n          <p><span style=\"color:var(--coral-text)\">GATE fact:</span> determinant = product of the diagonal entries.</p>\n        ","question":null},{"id":"la-matrices-027","topicId":"matrices","order":27,"type":"deep-dive","hook":"Lower triangular matrix","body":"Everything above the diagonal is zero.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"study-item-19","sourceLabel":"Study in Depth","detail":"Everything above the diagonal is zero. L = [2 0 0 5 3 0 7 9 4] det(L) = 2×3×4 = 24 Same rule: determinant = product of the diagonal.","detailHtml":"\n          \n          <p>Everything <strong>above</strong> the diagonal is zero.</p>\n          <pre>L = [2  0  0\n     5  3  0\n     7  9  4]      det(L) = 2×3×4 = 24</pre>\n          <p>Same rule: determinant = product of the diagonal.</p>\n        ","question":null},{"id":"la-matrices-028","topicId":"matrices","order":28,"type":"deep-dive","hook":"Trace","body":"Trace = sum of the diagonal entries, written tr(A).","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"study-item-20","sourceLabel":"Study in Depth","detail":"Trace = sum of the diagonal entries, written tr(A) . A = [1 2 3 4 5 6 tr(A) = 1 + 5 + 9 = 15 7 8 9] tr(A + B) = tr(A) + tr(B) , tr(cA) = c·tr(A) , tr(Aᵀ) = tr(A) tr(AB) = tr(BA) even though AB ≠ BA . Trace = sum of eigenvalues.","detailHtml":"\n          \n          <p><strong>Trace</strong> = sum of the diagonal entries, written <code>tr(A)</code>.</p>\n          <pre>A = [1  2  3\n     4  5  6        tr(A) = 1 + 5 + 9 = 15\n     7  8  9]</pre>\n          <ul class=\"styled\">\n            <li><code>tr(A + B) = tr(A) + tr(B)</code>,   <code>tr(cA) = c·tr(A)</code>,   <code>tr(Aᵀ) = tr(A)</code></li>\n            <li><strong><code>tr(AB) = tr(BA)</code></strong> even though <code>AB ≠ BA</code>.</li>\n            <li><strong>Trace = sum of eigenvalues.</strong></li>\n          </ul>\n        ","question":null},{"id":"la-matrices-029","topicId":"matrices","order":29,"type":"deep-dive","hook":"Idempotent matrix","body":"Idempotent means A² = A — applying it twice is the same as once.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"study-item-21","sourceLabel":"Study in Depth","detail":"Idempotent means A² = A — applying it twice is the same as once. P = [1 0 P[x [x P² = P 0 0] y] = 0] (projection onto the x-axis) 🎮 Imagine: a projection / snap-to-ground machine. GATE fact: its eigenvalues are only 0 or 1 .","detailHtml":"\n          \n          <p><strong>Idempotent</strong> means <code>A² = A</code> — applying it twice is the same as once.</p>\n          <pre>P = [1  0       P[x      [x        P² = P\n     0  0]         y]  =   0]   (projection onto the x-axis)</pre>\n          <p><span style=\"color:var(--coral-text)\">🎮 Imagine:</span> a projection / snap-to-ground machine. <span style=\"color:var(--coral-text)\">GATE fact:</span> its eigenvalues are only <strong>0 or 1</strong>.</p>\n        ","question":null},{"id":"la-matrices-030","topicId":"matrices","order":30,"type":"deep-dive","hook":"Matrix–vector multiplication is the heart","body":"So a matrix is not just a table — it is an action on space.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"study-item-22","sourceLabel":"Study in Depth","detail":"A = [2 0 Av = [2x (stretch x×2, y×3) 0 3] 3y] A = [0 -1 A[1 [0 (90° rotation: 1 0] 0] = 1] [1,0] → [0,1]) So a matrix is not just a table — it is an action on space .","detailHtml":"\n          \n          <pre>A = [2  0        Av = [2x      (stretch x×2, y×3)\n     0  3]              3y]\n\nA = [0  -1       A[1     [0       (90° rotation:\n     1   0]        0] =   1]       [1,0] → [0,1])</pre>\n          <p>So a matrix is not just a table — it is an <strong>action on space</strong>.</p>\n        ","question":null},{"id":"la-matrices-031","topicId":"matrices","order":31,"type":"deep-dive","hook":"How the columns explain a transformation","body":"The columns of A tell you where the basis vectors go.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"study-item-23","sourceLabel":"Study in Depth","detail":"The columns of A tell you where the basis vectors go . e₁ = [1 e₂ = [0 0] 1] Ae₁ = first column of A Ae₂ = second column of A A = [2 1 Ae₁ = [2 Ae₂ = [1 0 3] 0] 3] The x-axis moves to [2,0] and the y-axis to [1,3] — the matrix transforms the whole grid. The best way to see a matrix.","detailHtml":"\n          \n          <p>The columns of <code>A</code> tell you <strong>where the basis vectors go</strong>.</p>\n          <pre>e₁ = [1      e₂ = [0\n      0]            1]\n\nAe₁ = first column of A\nAe₂ = second column of A</pre>\n          <pre>A = [2  1       Ae₁ = [2      Ae₂ = [1\n     0  3]             0]            3]</pre>\n          <p>The x-axis moves to <code>[2,0]</code> and the y-axis to <code>[1,3]</code> — the matrix transforms the whole grid. The best way to <em>see</em> a matrix.</p>\n        ","question":null},{"id":"la-matrices-032","topicId":"matrices","order":32,"type":"deep-dive","hook":"Common GATE traps (matrix algebra)","body":"AB = BA? Usually false — AB ≠ BA in general. (AB)ᵀ = AᵀBᵀ? False — it is BᵀAᵀ. A skew-symmetric ⇒ diagonal entries are 0. True. A triangular ⇒ det = product of the diagonal. True. tr(AB) = tr(BA) even though AB ≠ BA. True.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"study-item-24","sourceLabel":"Study in Depth","detail":"AB = BA ? Usually false — AB ≠ BA in general. (AB)ᵀ = AᵀBᵀ ? False — it is BᵀAᵀ . A skew-symmetric ⇒ diagonal entries are 0. True. A triangular ⇒ det = product of the diagonal. True. tr(AB) = tr(BA) even though AB ≠ BA . True.","detailHtml":"\n          \n          <ul class=\"styled\">\n            <li><code>AB = BA</code>? <strong>Usually false</strong> — <code>AB ≠ BA</code> in general.</li>\n            <li><code>(AB)ᵀ = AᵀBᵀ</code>? <strong>False</strong> — it is <code>BᵀAᵀ</code>.</li>\n            <li>A skew-symmetric ⇒ diagonal entries are 0. <strong>True.</strong></li>\n            <li>A triangular ⇒ <code>det =</code> product of the diagonal. <strong>True.</strong></li>\n            <li><code>tr(AB) = tr(BA)</code> even though <code>AB ≠ BA</code>. <strong>True.</strong></li>\n          </ul>\n        ","question":null},{"id":"la-matrices-033","topicId":"matrices","order":33,"type":"deep-dive","hook":"Special matrices — quick table","body":"Type / opMeaningKey fact A + Badd entriessame size required ABrow × columninner dims must match AB ≠ BAorder matterscommon trap Aᵀtranspose(AB)ᵀ = BᵀAᵀ IidentityAI = IA = A tr(A)sum of diagonal= sum of eigenvalues symmetricA = Aᵀreal eigenvalues…","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"study-item-25","sourceLabel":"Study in Depth","detail":"Type / op Meaning Key fact A + B add entries same size required AB row × column inner dims must match AB ≠ BA order matters common trap Aᵀ transpose (AB)ᵀ = BᵀAᵀ I identity AI = IA = A tr(A) sum of diagonal = sum of eigenvalues symmetric A = Aᵀ real eigenvalues skew-symmetric A = −Aᵀ diagonal zero idempotent A² = A eigenvalues 0 or 1 nilpotent Aᵏ = 0 eigenvalues all 0","detailHtml":"\n          \n          <div class=\"tbl-wrap\"><table>\n            <tr><th>Type / op</th><th>Meaning</th><th>Key fact</th></tr>\n            <tr><td><code>A + B</code></td><td>add entries</td><td>same size required</td></tr>\n            <tr><td><code>AB</code></td><td>row × column</td><td>inner dims must match</td></tr>\n            <tr><td><code>AB ≠ BA</code></td><td>order matters</td><td>common trap</td></tr>\n            <tr><td><code>Aᵀ</code></td><td>transpose</td><td><code>(AB)ᵀ = BᵀAᵀ</code></td></tr>\n            <tr><td><code>I</code></td><td>identity</td><td><code>AI = IA = A</code></td></tr>\n            <tr><td><code>tr(A)</code></td><td>sum of diagonal</td><td>= sum of eigenvalues</td></tr>\n            <tr><td>symmetric</td><td><code>A = Aᵀ</code></td><td>real eigenvalues</td></tr>\n            <tr><td>skew-symmetric</td><td><code>A = −Aᵀ</code></td><td>diagonal zero</td></tr>\n            <tr><td>idempotent</td><td><code>A² = A</code></td><td>eigenvalues 0 or 1</td></tr>\n            <tr><td>nilpotent</td><td><code>Aᵏ = 0</code></td><td>eigenvalues all 0</td></tr>\n          </table></div>\n        ","question":null},{"id":"la-matrices-034","topicId":"matrices","order":34,"type":"deep-dive","hook":"Quick self-check","body":"Q1. Size of [[1,2,3],[4,5,6]]?","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"study-item-26","sourceLabel":"Study in Depth","detail":"Q1. Size of [[1,2,3],[4,5,6]]? 2 rows, 3 columns → 2 × 3 Q2. A = 2×3, B = 3×4 — is AB possible? Yes — inner 3 = 3. AB is 2 × 4. Q3. A = 2×3, B = 2×4 — is AB possible? No — inner 3 ≠ 2. Q4. Is [[1,4],[4,9]] symmetric? Aᵀ = [[1,4],[4,9]] = A → yes. Q5. Is [[0,5],[−5,0]] skew-symmetric? −Aᵀ = [[0,5],[−5,0]] = A → yes.","detailHtml":"\n          \n          <p class=\"lead\">Q1. Size of [[1,2,3],[4,5,6]]?</p>\n          <pre>2 rows, 3 columns  →  2 × 3</pre>\n          <p class=\"lead\">Q2. A = 2×3, B = 3×4 — is AB possible?</p>\n          <pre>Yes — inner 3 = 3.  AB is 2 × 4.</pre>\n          <p class=\"lead\">Q3. A = 2×3, B = 2×4 — is AB possible?</p>\n          <pre>No — inner 3 ≠ 2.</pre>\n          <p class=\"lead\">Q4. Is [[1,4],[4,9]] symmetric?</p>\n          <pre>Aᵀ = [[1,4],[4,9]] = A  → yes.</pre>\n          <p class=\"lead\">Q5. Is [[0,5],[−5,0]] skew-symmetric?</p>\n          <pre>−Aᵀ = [[0,5],[−5,0]] = A  → yes.</pre>\n        ","question":null},{"id":"la-matrices-035","topicId":"matrices","order":35,"type":"deep-dive","hook":"Final mental model","body":"Vector = arrow; matrix = machine that transforms arrows. Multiplication = applying machines one after another (order matters). Identity = no-change machine; diagonal = stretch; zero = collapse to origin. Transpose = flip rows/columns; trace = sum of…","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"study-item-27","sourceLabel":"Study in Depth","detail":"Vector = arrow; matrix = machine that transforms arrows. Multiplication = applying machines one after another (order matters). Identity = no-change machine; diagonal = stretch; zero = collapse to origin. Transpose = flip rows/columns; trace = sum of diagonal = sum of eigenvalues. Idempotent = projection; nilpotent = eventually-zero.","detailHtml":"\n          \n          <ul class=\"styled\">\n            <li><strong>Vector</strong> = arrow; <strong>matrix</strong> = machine that transforms arrows.</li>\n            <li><strong>Multiplication</strong> = applying machines one after another (order matters).</li>\n            <li><strong>Identity</strong> = no-change machine; <strong>diagonal</strong> = stretch; <strong>zero</strong> = collapse to origin.</li>\n            <li><strong>Transpose</strong> = flip rows/columns; <strong>trace</strong> = sum of diagonal = sum of eigenvalues.</li>\n            <li><strong>Idempotent</strong> = projection; <strong>nilpotent</strong> = eventually-zero.</li>\n          </ul>\n        ","question":null},{"id":"la-matrices-036","topicId":"matrices","order":36,"type":"cheat-sheet","hook":"associative","body":"ion is associative $A(BC)=(AB)C$ but not commutative $AB\\neq BA$.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"cheat-1","sourceLabel":"GATE cheat sheet","detail":"Multiplication is associative $A(BC)=(AB)C$ but not commutative $AB\\neq BA$.","detailHtml":"<p>Multiplication is <strong>associative</strong> $A(BC)=(AB)C$ but <strong>not commutative</strong> $AB\\neq BA$.</p>","question":null},{"id":"la-matrices-037","topicId":"matrices","order":37,"type":"cheat-sheet","hook":"reverse order","body":"inverse reverse order: $(AB)^{\\mathsf T}=B^{\\mathsf T}A^{\\mathsf T}$, $(AB)^{-1}=B^{-1}A^{-1}$.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"cheat-2","sourceLabel":"GATE cheat sheet","detail":"Transpose and inverse reverse order : $(AB)^{\\mathsf T}=B^{\\mathsf T}A^{\\mathsf T}$, $(AB)^{-1}=B^{-1}A^{-1}$.","detailHtml":"<p>Transpose and inverse <strong>reverse order</strong>: $(AB)^{\\mathsf T}=B^{\\mathsf T}A^{\\mathsf T}$, $(AB)^{-1}=B^{-1}A^{-1}$.</p>","question":null},{"id":"la-matrices-038","topicId":"matrices","order":38,"type":"cheat-sheet","hook":"$\\operatorname{tr}(AB)=\\operatorname{tr}(BA)$ even though $AB\\neq BA$.","body":"Also $\\operatorname{tr}(A)=\\sum\\lambda_i$.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"cheat-3","sourceLabel":"GATE cheat sheet","detail":"$\\operatorname{tr}(AB)=\\operatorname{tr}(BA)$ even though $AB\\neq BA$. Also $\\operatorname{tr}(A)=\\sum\\lambda_i$.","detailHtml":"<p>$\\operatorname{tr}(AB)=\\operatorname{tr}(BA)$ even though $AB\\neq BA$. Also $\\operatorname{tr}(A)=\\sum\\lambda_i$.</p>","question":null},{"id":"la-matrices-039","topicId":"matrices","order":39,"type":"cheat-sheet","hook":"Diagonal / triangular matrix","body":"$\\det=$ product of diagonal entries.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"cheat-4","sourceLabel":"GATE cheat sheet","detail":"Diagonal / triangular matrix: $\\det=$ product of diagonal entries.","detailHtml":"<p>Diagonal / triangular matrix: $\\det=$ product of diagonal entries.</p>","question":null},{"id":"la-matrices-040","topicId":"matrices","order":40,"type":"cheat-sheet","hook":"$A^{-1}$ exists $\\iff \\det(A)\\neq0$.","body":"$A^{-1}$ exists $\\iff \\det(A)\\neq0$.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"cheat-5","sourceLabel":"GATE cheat sheet","detail":"$A^{-1}$ exists $\\iff \\det(A)\\neq0$.","detailHtml":"<p>$A^{-1}$ exists $\\iff \\det(A)\\neq0$.</p>","question":null},{"id":"la-matrices-041","topicId":"matrices","order":41,"type":"trap","hook":"Trap","body":"\"$AB=BA$ always.\" Reality: almost never — order matters.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"trap-1","sourceLabel":"Common traps","detail":"Trap: &quot;$AB=BA$ always.&quot; Reality: almost never — order matters.","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;$AB=BA$ always.&quot; <span class=\"right\">Reality:</span> almost never — order matters.</p>","question":null},{"id":"la-matrices-042","topicId":"matrices","order":42,"type":"trap","hook":"Trap","body":"\"$(AB)^{\\mathsf T}=A^{\\mathsf T}B^{\\mathsf T}$.\" Reality: the order reverses: $B^{\\mathsf T}A^{\\mathsf T}$.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"trap-2","sourceLabel":"Common traps","detail":"Trap: &quot;$(AB)^{\\mathsf T}=A^{\\mathsf T}B^{\\mathsf T}$.&quot; Reality: the order reverses: $B^{\\mathsf T}A^{\\mathsf T}$.","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;$(AB)^{\\mathsf T}=A^{\\mathsf T}B^{\\mathsf T}$.&quot; <span class=\"right\">Reality:</span> the order reverses: $B^{\\mathsf T}A^{\\mathsf T}$.</p>","question":null},{"id":"la-matrices-043","topicId":"matrices","order":43,"type":"trap","hook":"Trap","body":"\"$A^2=A$ means $A=I$.\" Reality: any projection (idempotent) works; eigenvalues are just $0$ or $1$.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"trap-3","sourceLabel":"Common traps","detail":"Trap: &quot;$A^2=A$ means $A=I$.&quot; Reality: any projection (idempotent) works; eigenvalues are just $0$ or $1$.","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;$A^2=A$ means $A=I$.&quot; <span class=\"right\">Reality:</span> any projection (idempotent) works; eigenvalues are just $0$ or $1$.</p>","question":null},{"id":"la-matrices-044","topicId":"matrices","order":44,"type":"trap","hook":"Trap","body":"\"Any two matrices can be multiplied.\" Reality: only if inner dimensions match.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"trap-4","sourceLabel":"Common traps","detail":"Trap: &quot;Any two matrices can be multiplied.&quot; Reality: only if inner dimensions match.","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;Any two matrices can be multiplied.&quot; <span class=\"right\">Reality:</span> only if inner dimensions match.</p>","question":null},{"id":"la-matrices-045","topicId":"matrices","order":45,"type":"practice","hook":"Q1. Can a $2\\times3$ matrix multiply a $2\\times2$ matrix (in that order)?","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"practice-1","sourceLabel":"Practice problems","detail":"No — inner dimensions $3$ and $2$ don&#x27;t match. $(2\\times3)(2\\times2)$ is undefined.","detailHtml":"No — inner dimensions $3$ and $2$ don&#x27;t match. $(2\\times3)(2\\times2)$ is undefined.","question":{"type":"REVEAL","prompt":"Q1. Can a $2\\times3$ matrix multiply a $2\\times2$ matrix (in that order)?","options":[],"answer":true,"explanation":"No — inner dimensions $3$ and $2$ don't match. $(2\\times3)(2\\times2)$ is undefined.","explanationHtml":"No — inner dimensions $3$ and $2$ don&#x27;t match. $(2\\times3)(2\\times2)$ is undefined."}},{"id":"la-matrices-046","topicId":"matrices","order":46,"type":"practice","hook":"Q2. If $A$ is $4\\times3$ and $B$ is $3\\times5$, what size is $AB$?","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"practice-2","sourceLabel":"Practice problems","detail":"$4\\times5$ (outer numbers).","detailHtml":"$4\\times5$ (outer numbers).","question":{"type":"REVEAL","prompt":"Q2. If $A$ is $4\\times3$ and $B$ is $3\\times5$, what size is $AB$?","options":[],"answer":true,"explanation":"$4\\times5$ (outer numbers).","explanationHtml":"$4\\times5$ (outer numbers)."}},{"id":"la-matrices-047","topicId":"matrices","order":47,"type":"practice","hook":"Q3. $\\operatorname{tr}\\begin{bmatrix}1&2&3\\\\4&5&6\\\\7&8&9\\end{bmatrix}=?$","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"practice-3","sourceLabel":"Practice problems","detail":"$1+5+9=15$.","detailHtml":"$1+5+9=15$.","question":{"type":"REVEAL","prompt":"Q3. $\\operatorname{tr}\\begin{bmatrix}1&2&3\\\\4&5&6\\\\7&8&9\\end{bmatrix}=?$","options":[],"answer":true,"explanation":"$1+5+9=15$.","explanationHtml":"$1+5+9=15$."}},{"id":"la-matrices-048","topicId":"matrices","order":48,"type":"practice","hook":"Q4. For an orthogonal matrix $Q$, what is $Q^{-1}$?","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"practice-4","sourceLabel":"Practice problems","detail":"$Q^{-1}=Q^{\\mathsf T}$ (its transpose), since $Q^{\\mathsf T}Q=I$.","detailHtml":"$Q^{-1}=Q^{\\mathsf T}$ (its transpose), since $Q^{\\mathsf T}Q=I$.","question":{"type":"REVEAL","prompt":"Q4. For an orthogonal matrix $Q$, what is $Q^{-1}$?","options":[],"answer":true,"explanation":"$Q^{-1}=Q^{\\mathsf T}$ (its transpose), since $Q^{\\mathsf T}Q=I$.","explanationHtml":"$Q^{-1}=Q^{\\mathsf T}$ (its transpose), since $Q^{\\mathsf T}Q=I$."}},{"id":"la-matrices-049","topicId":"matrices","order":49,"type":"practice","hook":"Q5. Is $\\begin{bmatrix}1&4\\\\4&9\\end{bmatrix}$ symmetric? Is $\\begin{bmatrix}0&5\\\\-5&0\\end{bmatrix}$ skew-symmetric?","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"practice-5","sourceLabel":"Practice problems","detail":"First: $A=A^{\\mathsf T}$ → yes, symmetric. Second: $A^{\\mathsf T}=\\begin{bmatrix}0&amp;-5\\\\5&amp;0\\end{bmatrix}=-A$ → yes, skew-symmetric (note the zero diagonal).","detailHtml":"First: $A=A^{\\mathsf T}$ → yes, symmetric. Second: $A^{\\mathsf T}=\\begin{bmatrix}0&amp;-5\\\\5&amp;0\\end{bmatrix}=-A$ → yes, skew-symmetric (note the zero diagonal).","question":{"type":"REVEAL","prompt":"Q5. Is $\\begin{bmatrix}1&4\\\\4&9\\end{bmatrix}$ symmetric? Is $\\begin{bmatrix}0&5\\\\-5&0\\end{bmatrix}$ skew-symmetric?","options":[],"answer":true,"explanation":"First: $A=A^{\\mathsf T}$ → yes, symmetric. Second: $A^{\\mathsf T}=\\begin{bmatrix}0&-5\\\\5&0\\end{bmatrix}=-A$ → yes, skew-symmetric (note the zero diagonal).","explanationHtml":"First: $A=A^{\\mathsf T}$ → yes, symmetric. Second: $A^{\\mathsf T}=\\begin{bmatrix}0&amp;-5\\\\5&amp;0\\end{bmatrix}=-A$ → yes, skew-symmetric (note the zero diagonal)."}},{"id":"la-matrices-050","topicId":"matrices","order":50,"type":"practice","hook":"Q6. $\\operatorname{tr}(AB)$ vs $\\operatorname{tr}(BA)$ — equal or not?","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"practice-6","sourceLabel":"Practice problems","detail":"Always equal (cyclic property), even though $AB\\neq BA$ in general.","detailHtml":"Always equal (cyclic property), even though $AB\\neq BA$ in general.","question":{"type":"REVEAL","prompt":"Q6. $\\operatorname{tr}(AB)$ vs $\\operatorname{tr}(BA)$ — equal or not?","options":[],"answer":true,"explanation":"Always equal (cyclic property), even though $AB\\neq BA$ in general.","explanationHtml":"Always equal (cyclic property), even though $AB\\neq BA$ in general."}},{"id":"la-matrices-051","topicId":"matrices","order":51,"type":"practice","hook":"If $A$ is $3\\times3$ with $A^2=A$, which must be true?","body":"Choose an answer, then check the explanation.","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"02-matrices.html","sourceAnchor":"practice-quiz-1","sourceLabel":"Practice quiz","detail":"✅ Correct — $A^2=A\\Rightarrow\\lambda^2=\\lambda\\Rightarrow\\lambda\\in\\{0,1\\}$.","detailHtml":"✅ Correct — $A^2=A\\Rightarrow\\lambda^2=\\lambda\\Rightarrow\\lambda\\in\\{0,1\\}$.","question":{"type":"MCQ","prompt":"If $A$ is $3\\times3$ with $A^2=A$, which must be true?","options":["A: $A=I$","B: $A=0$","C: Every eigenvalue is $0$ or $1$","D: $\\det(A)=1$"],"answer":"C","explanation":"✅ Correct — $A^2=A\\Rightarrow\\lambda^2=\\lambda\\Rightarrow\\lambda\\in\\{0,1\\}$.","explanationHtml":"✅ Correct — $A^2=A\\Rightarrow\\lambda^2=\\lambda\\Rightarrow\\lambda\\in\\{0,1\\}$."}},{"id":"la-determinants-001","topicId":"determinants","order":1,"type":"basic-definition","hook":"Determinant $\\det(A)$ (also $|A|$)","body":"a single number showing how much a square matrix scales area/volume; defined only for square matrices.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"definition-1","sourceLabel":"Basic definitions","detail":"Determinant $\\det(A)$ (also $|A|$): a single number showing how much a square matrix scales area/volume; defined only for square matrices.","detailHtml":"<p><strong>Determinant $\\det(A)$ (also $|A|$):</strong> a single number showing how much a square matrix scales area/volume; defined only for square matrices.</p>","question":null},{"id":"la-determinants-002","topicId":"determinants","order":2,"type":"basic-definition","hook":"Singular","body":"$\\det=0$ — not invertible, dependent columns, space collapses. Non-singular: $\\det\\neq0$ — invertible, independent columns.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"definition-2","sourceLabel":"Basic definitions","detail":"Singular: $\\det=0$ — not invertible, dependent columns, space collapses. Non-singular: $\\det\\neq0$ — invertible, independent columns.","detailHtml":"<p><strong>Singular:</strong> $\\det=0$ — not invertible, dependent columns, space collapses. <strong>Non-singular:</strong> $\\det\\neq0$ — invertible, independent columns.</p>","question":null},{"id":"la-determinants-003","topicId":"determinants","order":3,"type":"basic-definition","hook":"Minor $M_{ij}$","body":"the determinant left after deleting entry $a_{ij}$'s row and column.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"definition-3","sourceLabel":"Basic definitions","detail":"Minor $M_{ij}$: the determinant left after deleting entry $a_{ij}$&#x27;s row and column.","detailHtml":"<p><strong>Minor $M_{ij}$:</strong> the determinant left after deleting entry $a_{ij}$&#x27;s row and column.</p>","question":null},{"id":"la-determinants-004","topicId":"determinants","order":4,"type":"basic-definition","hook":"Cofactor $C_{ij}$","body":"a minor with a $+/-$ sign from the checkerboard, $C_{ij}=(-1)^{i+j}M_{ij}$.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"definition-4","sourceLabel":"Basic definitions","detail":"Cofactor $C_{ij}$: a minor with a $+/-$ sign from the checkerboard, $C_{ij}=(-1)^{i+j}M_{ij}$.","detailHtml":"<p><strong>Cofactor $C_{ij}$:</strong> a minor with a $+/-$ sign from the checkerboard, $C_{ij}=(-1)^{i+j}M_{ij}$.</p>","question":null},{"id":"la-determinants-005","topicId":"determinants","order":5,"type":"basic-definition","hook":"Cofactor expansion","body":"computing $\\det$ by expanding along any row or column using cofactors.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"definition-5","sourceLabel":"Basic definitions","detail":"Cofactor expansion: computing $\\det$ by expanding along any row or column using cofactors.","detailHtml":"<p><strong>Cofactor expansion:</strong> computing $\\det$ by expanding along any row or column using cofactors.</p>","question":null},{"id":"la-determinants-006","topicId":"determinants","order":6,"type":"basic-definition","hook":"Adjugate (adjoint)","body":"the transpose of the cofactor matrix; appears in the inverse formula.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"definition-6","sourceLabel":"Basic definitions","detail":"Adjugate (adjoint): the transpose of the cofactor matrix; appears in the inverse formula.","detailHtml":"<p><strong>Adjugate (adjoint):</strong> the transpose of the cofactor matrix; appears in the inverse formula.</p>","question":null},{"id":"la-determinants-007","topicId":"determinants","order":7,"type":"deep-dive","hook":"What is a determinant?","body":"A determinant is a single number computed from a square matrix, written det(A) or |A| (same thing).","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-1","sourceLabel":"Study in Depth","detail":"A determinant is a single number computed from a square matrix, written det(A) or |A| (same thing). A = [1 2 det(A) or |A| 3 4] Important: only square matrices (2×2, 3×3, n×n) have a determinant — a 2×3 has none.","detailHtml":"\n          \n          <p>A <strong>determinant</strong> is a single number computed from a <strong>square</strong> matrix, written <code>det(A)</code> or <code>|A|</code> (same thing).</p>\n          <pre>A = [1  2        det(A) or |A|\n     3  4]</pre>\n          <p><span style=\"color:var(--coral-text)\">Important:</span> only square matrices (2×2, 3×3, n×n) have a determinant — a 2×3 has none.</p>\n        ","question":null},{"id":"la-determinants-008","topicId":"determinants","order":8,"type":"deep-dive","hook":"What the determinant tells you","body":"For a square matrix, det(A) answers three things at once:","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-2","sourceLabel":"Study in Depth","detail":"For a square matrix, det(A) answers three things at once: Is the matrix invertible ? How much does area / volume change? Does orientation flip? Most important rule: det(A) = 0 → singular → inverse does NOT exist det(A) ≠ 0 → non-singular → inverse exists","detailHtml":"\n          \n          <p>For a square matrix, <code>det(A)</code> answers three things at once:</p>\n          <ul class=\"styled\">\n            <li>Is the matrix <strong>invertible</strong>?</li>\n            <li>How much does <strong>area / volume</strong> change?</li>\n            <li>Does <strong>orientation</strong> flip?</li>\n          </ul>\n          <p><span style=\"color:var(--coral-text)\">Most important rule:</span></p>\n          <pre>det(A) = 0   →  singular     →  inverse does NOT exist\ndet(A) ≠ 0   →  non-singular →  inverse exists</pre>\n        ","question":null},{"id":"la-determinants-009","topicId":"determinants","order":9,"type":"deep-dive","hook":"Game imagination: the rubber tile","body":"Picture a unit square rubber tile (area 1). A matrix stretches, squashes, rotates, flips or collapses it. The determinant says what happened to the area:","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-3","sourceLabel":"Study in Depth","detail":"Picture a unit square rubber tile (area 1). A matrix stretches, squashes, rotates, flips or collapses it. The determinant says what happened to the area: det = 2 area becomes 2× bigger det = 0.5 area becomes half det = -3 area 3× bigger AND orientation flipped det = 0 area becomes zero — space collapsed to a line/point","detailHtml":"\n          \n          <p>Picture a unit square rubber tile (area 1). A matrix stretches, squashes, rotates, flips or collapses it. The determinant says what happened to the area:</p>\n          <pre>det = 2     area becomes 2× bigger\ndet = 0.5   area becomes half\ndet = -3    area 3× bigger AND orientation flipped\ndet = 0     area becomes zero — space collapsed to a line/point</pre>\n        ","question":null},{"id":"la-determinants-010","topicId":"determinants","order":10,"type":"deep-dive","hook":"Determinant = area scaling (2D)","body":"In 2D, |det(A)| is the area scaling factor.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-4","sourceLabel":"Study in Depth","detail":"In 2D, |det(A)| is the area scaling factor . |det(A)| = 5 any area becomes 5× bigger |det(A)| = 1 area unchanged |det(A)| = 0 area collapses to zero det = 0 means the 2D map became a 1D road or a point — you cannot recover the plane, so there is no inverse.","detailHtml":"\n          \n          <p>In 2D, <code>|det(A)|</code> is the <strong>area scaling factor</strong>.</p>\n          <pre>|det(A)| = 5   any area becomes 5× bigger\n|det(A)| = 1   area unchanged\n|det(A)| = 0   area collapses to zero</pre>\n          <p><code>det = 0</code> means the 2D map became a 1D road or a point — you cannot recover the plane, so there is no inverse.</p>\n        ","question":null},{"id":"la-determinants-011","topicId":"determinants","order":11,"type":"deep-dive","hook":"Determinant = volume scaling (3D)","body":"In 3D, |det(A)| is the volume scaling factor.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-5","sourceLabel":"Study in Depth","detail":"In 3D, |det(A)| is the volume scaling factor . det = 8 volume 8× bigger det = -2 volume 2× bigger, orientation flipped det = 0 3D space collapsed into a plane, line, or point","detailHtml":"\n          \n          <p>In 3D, <code>|det(A)|</code> is the <strong>volume scaling factor</strong>.</p>\n          <pre>det = 8    volume 8× bigger\ndet = -2   volume 2× bigger, orientation flipped\ndet = 0    3D space collapsed into a plane, line, or point</pre>\n        ","question":null},{"id":"la-determinants-012","topicId":"determinants","order":12,"type":"deep-dive","hook":"Positive, negative, zero determinant","body":"The sign is the orientation; the size is the scaling.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-6","sourceLabel":"Study in Depth","detail":"det &gt; 0 orientation preserved (e.g. rotation + stretch) det &lt; 0 orientation flipped (a reflection / mirror) det = 0 space collapsed: singular, dependent columns, rank &lt; n The sign is the orientation; the size is the scaling.","detailHtml":"\n          \n          <pre>det &gt; 0   orientation preserved   (e.g. rotation + stretch)\ndet &lt; 0   orientation flipped     (a reflection / mirror)\ndet = 0   space collapsed: singular, dependent columns, rank &lt; n</pre>\n          <p>The sign is the orientation; the size is the scaling.</p>\n        ","question":null},{"id":"la-determinants-013","topicId":"determinants","order":13,"type":"deep-dive","hook":"The 2×2 formula: ad − bc","body":"So area becomes 2×, orientation flips, and (det ≠ 0) the matrix is invertible.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-7","sourceLabel":"Study in Depth","detail":"A = [a b det(A) = ad − bc c d] (main diagonal − other diagonal) A = [1 2 det = 1×4 − 2×3 = −2 3 4] So area becomes 2×, orientation flips, and (det ≠ 0) the matrix is invertible.","detailHtml":"\n          \n          <pre>A = [a  b        det(A) = ad − bc\n     c  d]        (main diagonal − other diagonal)</pre>\n          <pre>A = [1  2        det = 1×4 − 2×3 = −2\n     3  4]</pre>\n          <p>So area becomes 2×, orientation flips, and (det ≠ 0) the matrix is invertible.</p>\n        ","question":null},{"id":"la-determinants-014","topicId":"determinants","order":14,"type":"deep-dive","hook":"The 2×2 visual: signed area","body":"The two columns of A form a parallelogram; det is its signed area.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-8","sourceLabel":"Study in Depth","detail":"The two columns of A form a parallelogram; det is its signed area . A = [1 0 columns [1,0] and [0,1] → unit square 0 1] det = 1 A = [2 0 stretch x×2, y×3 0 3] det = 6 → area 6×","detailHtml":"\n          \n          <p>The two columns of A form a parallelogram; <code>det</code> is its <strong>signed area</strong>.</p>\n          <pre>A = [1  0     columns [1,0] and [0,1] → unit square\n     0  1]    det = 1\n\nA = [2  0     stretch x×2, y×3\n     0  3]    det = 6  → area 6×</pre>\n        ","question":null},{"id":"la-determinants-015","topicId":"determinants","order":15,"type":"deep-dive","hook":"Why det = 0 means collapse","body":"Both columns point the same way, so they span only a line, not an area — area 0. Hence det = 0 ⇔ dependent columns, rank < n, no inverse.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-9","sourceLabel":"Study in Depth","detail":"A = [1 2 det = 1×4 − 2×2 = 0 2 4] columns: [1,2] and [2,4] = 2·[1,2] (same direction!) Both columns point the same way, so they span only a line , not an area — area 0. Hence det = 0 ⇔ dependent columns, rank &lt; n, no inverse.","detailHtml":"\n          \n          <pre>A = [1  2        det = 1×4 − 2×2 = 0\n     2  4]\n\ncolumns: [1,2] and [2,4] = 2·[1,2]  (same direction!)</pre>\n          <p>Both columns point the same way, so they span only a <strong>line</strong>, not an area — area 0. Hence <code>det = 0 ⇔</code> dependent columns, rank &lt; n, no inverse.</p>\n        ","question":null},{"id":"la-determinants-016","topicId":"determinants","order":16,"type":"deep-dive","hook":"The 3×3 determinant (cofactor expansion)","body":"This is cofactor expansion along the first row; the signs alternate + − +.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-10","sourceLabel":"Study in Depth","detail":"A = [a b c d e f g h i] det = a(ei−fh) − b(di−fg) + c(dh−eg) This is cofactor expansion along the first row; the signs alternate + − + .","detailHtml":"\n          \n          <pre>A = [a  b  c\n     d  e  f\n     g  h  i]\n\ndet = a(ei−fh) − b(di−fg) + c(dh−eg)</pre>\n          <p>This is cofactor expansion along the first row; the signs alternate <code>+ − +</code>.</p>\n        ","question":null},{"id":"la-determinants-017","topicId":"determinants","order":17,"type":"worked-example","hook":"Worked 3×3 example","body":"Volume scales by 30, orientation preserved, matrix invertible.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-11","sourceLabel":"Study in Depth","detail":"A = [2 1 3 0 4 2 1 0 5] det = 2·|4 2; 0 5| − 1·|0 2; 1 5| + 3·|0 4; 1 0| = 2(20) − 1(−2) + 3(−4) = 40 + 2 − 12 = 30 Volume scales by 30, orientation preserved, matrix invertible.","detailHtml":"\n          \n          <pre>A = [2  1  3\n     0  4  2\n     1  0  5]\n\ndet = 2·|4 2; 0 5| − 1·|0 2; 1 5| + 3·|0 4; 1 0|\n    = 2(20) − 1(−2) + 3(−4)\n    = 40 + 2 − 12\n    = 30</pre>\n          <p>Volume scales by 30, orientation preserved, matrix invertible.</p>\n        ","question":null},{"id":"la-determinants-018","topicId":"determinants","order":18,"type":"deep-dive","hook":"Expand along any row or column","body":"You may expand along any row or column — pick the one with the most zeros to save work.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-12","sourceLabel":"Study in Depth","detail":"You may expand along any row or column — pick the one with the most zeros to save work. A = [2 1 3 0 4 2 ← row 2 / column 1 each have a zero 1 0 5] GATE shortcut: more zeros = faster expansion.","detailHtml":"\n          \n          <p>You may expand along <strong>any</strong> row or column — pick the one with the <strong>most zeros</strong> to save work.</p>\n          <pre>A = [2  1  3\n     0  4  2     ← row 2 / column 1 each have a zero\n     1  0  5]</pre>\n          <p><span style=\"color:var(--coral-text)\">GATE shortcut:</span> more zeros = faster expansion.</p>\n        ","question":null},{"id":"la-determinants-019","topicId":"determinants","order":19,"type":"deep-dive","hook":"Determinant of a diagonal matrix","body":"Diagonal determinant = product of the diagonal — no expansion needed.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-13","sourceLabel":"Study in Depth","detail":"D = [2 0 0 0 3 0 det(D) = 2 × 3 × 5 = 30 0 0 5] Diagonal determinant = product of the diagonal — no expansion needed.","detailHtml":"\n          \n          <pre>D = [2  0  0\n     0  3  0      det(D) = 2 × 3 × 5 = 30\n     0  0  5]</pre>\n          <p>Diagonal determinant = <strong>product of the diagonal</strong> — no expansion needed.</p>\n        ","question":null},{"id":"la-determinants-020","topicId":"determinants","order":20,"type":"deep-dive","hook":"Determinant of a triangular matrix","body":"Upper or lower triangular — same rule:","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-14","sourceLabel":"Study in Depth","detail":"Upper or lower triangular — same rule: U = [2 7 8 L = [2 0 0 0 3 4 7 3 0 0 0 5] 8 4 5] det(U) = det(L) = 2 × 3 × 5 = 30 A huge GATE time-saver.","detailHtml":"\n          \n          <p>Upper or lower triangular — same rule:</p>\n          <pre>U = [2  7  8        L = [2  0  0\n     0  3  4             7  3  0\n     0  0  5]            8  4  5]\n\ndet(U) = det(L) = 2 × 3 × 5 = 30</pre>\n          <p>A huge GATE time-saver.</p>\n        ","question":null},{"id":"la-determinants-021","topicId":"determinants","order":21,"type":"deep-dive","hook":"Determinant of the identity","body":"The identity changes nothing, so it scales area/volume by 1.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-15","sourceLabel":"Study in Depth","detail":"det(Iₙ) = 1 The identity changes nothing, so it scales area/volume by 1.","detailHtml":"\n          \n          <pre>det(Iₙ) = 1</pre>\n          <p>The identity changes nothing, so it scales area/volume by 1.</p>\n        ","question":null},{"id":"la-determinants-022","topicId":"determinants","order":22,"type":"deep-dive","hook":"Determinant of the zero matrix","body":"It collapses everything to the origin, so it is never invertible.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-16","sourceLabel":"Study in Depth","detail":"det(O) = 0 It collapses everything to the origin, so it is never invertible.","detailHtml":"\n          \n          <pre>det(O) = 0</pre>\n          <p>It collapses everything to the origin, so it is never invertible.</p>\n        ","question":null},{"id":"la-determinants-023","topicId":"determinants","order":23,"type":"deep-dive","hook":"Property: det(AB) = det(A)·det(B)","body":"Scalings multiply: if A scales by 4 and B by 5, then AB scales by 20.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-17","sourceLabel":"Study in Depth","detail":"det(AB) = det(A) × det(B) Scalings multiply: if A scales by 4 and B by 5, then AB scales by 20. det(A²) = det(A)², det(Aᵏ) = det(A)ᵏ Note det(AB) = det(BA) even though AB ≠ BA — both equal det(A)det(B) .","detailHtml":"\n          \n          <pre>det(AB) = det(A) × det(B)</pre>\n          <p>Scalings multiply: if A scales by 4 and B by 5, then AB scales by 20.</p>\n          <pre>det(A²) = det(A)²,   det(Aᵏ) = det(A)ᵏ</pre>\n          <p>Note <code>det(AB) = det(BA)</code> even though <code>AB ≠ BA</code> — both equal <code>det(A)det(B)</code>.</p>\n        ","question":null},{"id":"la-determinants-024","topicId":"determinants","order":24,"type":"deep-dive","hook":"Property: det(Aᵀ) = det(A)","body":"Transpose does not change the determinant.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-18","sourceLabel":"Study in Depth","detail":"Transpose does not change the determinant. A = [1 2 det(A) = 1×4 − 2×3 = −2 3 4] Aᵀ = [1 3 det(Aᵀ) = 1×4 − 3×2 = −2","detailHtml":"\n          \n          <p>Transpose does not change the determinant.</p>\n          <pre>A = [1  2        det(A)  = 1×4 − 2×3 = −2\n     3  4]\n\nAᵀ = [1  3       det(Aᵀ) = 1×4 − 3×2 = −2</pre>\n        ","question":null},{"id":"la-determinants-025","topicId":"determinants","order":25,"type":"deep-dive","hook":"Property: det(A⁻¹) = 1 / det(A)","body":"Why? A A⁻¹ = I ⇒ det(A)·det(A⁻¹) = 1. So if det(A) = 5, then det(A⁻¹) = 1/5.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-19","sourceLabel":"Study in Depth","detail":"det(A⁻¹) = 1 / det(A) (when A is invertible) Why? A A⁻¹ = I ⇒ det(A)·det(A⁻¹) = 1 . So if det(A) = 5 , then det(A⁻¹) = 1/5 .","detailHtml":"\n          \n          <pre>det(A⁻¹) = 1 / det(A)      (when A is invertible)</pre>\n          <p>Why? <code>A A⁻¹ = I ⇒ det(A)·det(A⁻¹) = 1</code>. So if <code>det(A) = 5</code>, then <code>det(A⁻¹) = 1/5</code>.</p>\n        ","question":null},{"id":"la-determinants-026","topicId":"determinants","order":26,"type":"deep-dive","hook":"Property: det(cA) = cⁿ·det(A) (trap!)","body":"For an n × n matrix, multiplying the whole matrix by c multiplies every one of the n rows by c:","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-20","sourceLabel":"Study in Depth","detail":"For an n × n matrix, multiplying the whole matrix by c multiplies every one of the n rows by c: det(cA) = cⁿ · det(A) (NOT c · det(A)) A is 3×3, det(A) = 4 det(2A) = 2³ × 4 = 8 × 4 = 32 GATE trap: the power is the matrix size n.","detailHtml":"\n          \n          <p>For an <code>n × n</code> matrix, multiplying the whole matrix by c multiplies <strong>every one of the n rows</strong> by c:</p>\n          <pre>det(cA) = cⁿ · det(A)      (NOT c · det(A))</pre>\n          <pre>A is 3×3, det(A) = 4\ndet(2A) = 2³ × 4 = 8 × 4 = 32</pre>\n          <p><span style=\"color:var(--coral-text)\">GATE trap:</span> the power is the matrix size n.</p>\n        ","question":null},{"id":"la-determinants-027","topicId":"determinants","order":27,"type":"deep-dive","hook":"Row operations and the determinant","body":"The same three rules hold for columns.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-21","sourceLabel":"Study in Depth","detail":"Swap two rows → determinant changes sign . Multiply a row by k → determinant × k . Add a multiple of one row to another → determinant unchanged . R₂ → R₂ − 3R₁ on $\\begin{bmatrix}1&amp;2\\\\3&amp;4\\end{bmatrix}$ gives $\\begin{bmatrix}1&amp;2\\\\0&amp;-2\\end{bmatrix}$ det stays −2. (used in Gaussian elimination) The same three rules hold for columns.","detailHtml":"\n          \n          <ul class=\"styled\">\n            <li><strong>Swap two rows</strong> → determinant <strong>changes sign</strong>.</li>\n            <li><strong>Multiply a row by k</strong> → determinant <strong>× k</strong>.</li>\n            <li><strong>Add a multiple of one row to another</strong> → determinant <strong>unchanged</strong>.</li>\n          </ul>\n          <div class=\"math-steps\"><div class=\"ms-line\">R₂ → R₂ − 3R₁ on $\\begin{bmatrix}1&amp;2\\\\3&amp;4\\end{bmatrix}$  gives  $\\begin{bmatrix}1&amp;2\\\\0&amp;-2\\end{bmatrix}$</div><div class=\"ms-line\">det stays −2.   (used in Gaussian elimination)</div></div>\n          <p>The same three rules hold for columns.</p>\n        ","question":null},{"id":"la-determinants-028","topicId":"determinants","order":28,"type":"deep-dive","hook":"When the determinant is automatically 0","body":"Two identical rows (or columns) → det = 0. A completely zero row (or column) → det = 0. One row/column is a multiple of another (dependent) → det = 0. $\\begin{bmatrix}1&2\\\\2&4\\end{bmatrix}$ → row2 = 2·row1 → det = 0","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-22","sourceLabel":"Study in Depth","detail":"Two identical rows (or columns) → det = 0 . A completely zero row (or column) → det = 0 . One row/column is a multiple of another (dependent) → det = 0 . $\\begin{bmatrix}1&amp;2\\\\2&amp;4\\end{bmatrix}$ → row2 = 2·row1 → det = 0","detailHtml":"\n          \n          <ul class=\"styled\">\n            <li>Two <strong>identical</strong> rows (or columns) → <code>det = 0</code>.</li>\n            <li>A completely <strong>zero</strong> row (or column) → <code>det = 0</code>.</li>\n            <li>One row/column is a <strong>multiple</strong> of another (dependent) → <code>det = 0</code>.</li>\n          </ul>\n          <div class=\"math-steps\"><div class=\"ms-line\">$\\begin{bmatrix}1&amp;2\\\\2&amp;4\\end{bmatrix}$  → row2 = 2·row1 → det = 0</div></div>\n        ","question":null},{"id":"la-determinants-029","topicId":"determinants","order":29,"type":"deep-dive","hook":"Determinant and rank","body":"For a 3×3 with det = 0, the rank is 0, 1, or 2 — never 3.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-23","sourceLabel":"Study in Depth","detail":"det(A) ≠ 0 ⇔ rank(A) = n (full rank) det(A) = 0 ⇔ rank(A) &lt; n For a 3×3 with det = 0 , the rank is 0, 1, or 2 — never 3.","detailHtml":"\n          \n          <pre>det(A) ≠ 0   ⇔   rank(A) = n   (full rank)\ndet(A) = 0   ⇔   rank(A) &lt; n</pre>\n          <p>For a 3×3 with <code>det = 0</code>, the rank is 0, 1, or 2 — never 3.</p>\n        ","question":null},{"id":"la-determinants-030","topicId":"determinants","order":30,"type":"deep-dive","hook":"Determinant, inverse & the 2×2 formula","body":"The denominator ad − bc is det(A). If det(A) = 0 the denominator is 0 — so the inverse cannot exist. That is exactly why det = 0 ⇒ no inverse.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-24","sourceLabel":"Study in Depth","detail":"A = [a b A⁻¹ = 1/(ad−bc) · [ d −b c d] −c a] The denominator ad − bc is det(A) . If det(A) = 0 the denominator is 0 — so the inverse cannot exist. That is exactly why det = 0 ⇒ no inverse.","detailHtml":"\n          \n          <pre>A = [a  b        A⁻¹ = 1/(ad−bc) · [ d  −b\n     c  d]                            −c   a]</pre>\n          <p>The denominator <code>ad − bc</code> <em>is</em> <code>det(A)</code>. If <code>det(A) = 0</code> the denominator is 0 — so the inverse cannot exist. That is exactly why <code>det = 0 ⇒</code> no inverse.</p>\n        ","question":null},{"id":"la-determinants-031","topicId":"determinants","order":31,"type":"deep-dive","hook":"Determinant of an orthogonal matrix","body":"If AᵀA = I then det(A)² = 1, so:","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-25","sourceLabel":"Study in Depth","detail":"If AᵀA = I then det(A)² = 1 , so: det(A) = ±1 +1 = rotation (orientation preserved); −1 = reflection (flipped). Orthogonal maps preserve area/volume.","detailHtml":"\n          \n          <p>If <code>AᵀA = I</code> then <code>det(A)² = 1</code>, so:</p>\n          <pre>det(A) = ±1</pre>\n          <p><code>+1</code> = rotation (orientation preserved); <code>−1</code> = reflection (flipped). Orthogonal maps preserve area/volume.</p>\n        ","question":null},{"id":"la-determinants-032","topicId":"determinants","order":32,"type":"deep-dive","hook":"Determinant of a scalar matrix","body":"A = cIₙ det(cIₙ) = cⁿ 5·I₃ = diag(5,5,5) det = 5³ = 125","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-26","sourceLabel":"Study in Depth","detail":"A = cIₙ det(cIₙ) = cⁿ 5·I₃ = diag(5,5,5) det = 5³ = 125","detailHtml":"\n          \n          <pre>A = cIₙ        det(cIₙ) = cⁿ</pre>\n          <pre>5·I₃ = diag(5,5,5)   det = 5³ = 125</pre>\n        ","question":null},{"id":"la-determinants-033","topicId":"determinants","order":33,"type":"deep-dive","hook":"Determinant by row reduction","body":"Reduce to triangular form with row ops (the \"add a multiple\" op keeps det unchanged), then multiply the diagonal.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-27","sourceLabel":"Study in Depth","detail":"Reduce to triangular form with row ops (the &quot;add a multiple&quot; op keeps det unchanged), then multiply the diagonal. $\\begin{bmatrix}1&amp;2&amp;3\\\\2&amp;5&amp;6\\\\3&amp;8&amp;10\\end{bmatrix}$ → R₂−2R₁, R₃−3R₁ → $\\begin{bmatrix}1&amp;2&amp;3\\\\0&amp;1&amp;0\\\\0&amp;2&amp;1\\end{bmatrix}$ → R₃−2R₂ → $\\begin{bmatrix}1&amp;2&amp;3\\\\0&amp;1&amp;0\\\\0&amp;0&amp;1\\end{bmatrix}$ det = 1 × 1 × 1 = 1","detailHtml":"\n          \n          <p>Reduce to triangular form with row ops (the &quot;add a multiple&quot; op keeps det unchanged), then multiply the diagonal.</p>\n          <div class=\"math-steps\"><div class=\"ms-line\">$\\begin{bmatrix}1&amp;2&amp;3\\\\2&amp;5&amp;6\\\\3&amp;8&amp;10\\end{bmatrix}$</div><div class=\"ms-line\"> → R₂−2R₁, R₃−3R₁ → $\\begin{bmatrix}1&amp;2&amp;3\\\\0&amp;1&amp;0\\\\0&amp;2&amp;1\\end{bmatrix}$</div><div class=\"ms-line\"> → R₃−2R₂          → $\\begin{bmatrix}1&amp;2&amp;3\\\\0&amp;1&amp;0\\\\0&amp;0&amp;1\\end{bmatrix}$</div><div class=\"ms-line\"></div><div class=\"ms-line\">det = 1 × 1 × 1 = 1</div></div>\n        ","question":null},{"id":"la-determinants-034","topicId":"determinants","order":34,"type":"deep-dive","hook":"Determinant as an independence test","body":"Put n vectors of ℝⁿ as columns; det ≠ 0 ⇔ they are independent.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-28","sourceLabel":"Study in Depth","detail":"Put n vectors of ℝⁿ as columns; det ≠ 0 ⇔ they are independent . v₁=[1,2], v₂=[3,4] → A = $\\begin{bmatrix}1&amp;3\\\\2&amp;4\\end{bmatrix}$ det = 1×4 − 3×2 = −2 ≠ 0 → independent","detailHtml":"\n          \n          <p>Put n vectors of ℝⁿ as columns; <code>det ≠ 0 ⇔</code> they are <strong>independent</strong>.</p>\n          <div class=\"math-steps\"><div class=\"ms-line\">v₁=[1,2], v₂=[3,4] → A = $\\begin{bmatrix}1&amp;3\\\\2&amp;4\\end{bmatrix}$</div><div class=\"ms-line\">det = 1×4 − 3×2 = −2 ≠ 0  → independent</div></div>\n        ","question":null},{"id":"la-determinants-035","topicId":"determinants","order":35,"type":"deep-dive","hook":"det(A) = product of eigenvalues","body":"(The characteristic equation that produces these λ lives in the Eigenvalues topic.)","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-29","sourceLabel":"Study in Depth","detail":"det(A) = λ₁ · λ₂ · … · λₙ (product of eigenvalues) tr(A) = λ₁ + λ₂ + … + λₙ (sum — that is the trace) eigenvalues 2, 3, 5 → det = 30, trace = 10 (The characteristic equation that produces these λ lives in the Eigenvalues topic.)","detailHtml":"\n          \n          <pre>det(A) = λ₁ · λ₂ · … · λₙ          (product of eigenvalues)\ntr(A)  = λ₁ + λ₂ + … + λₙ          (sum — that is the trace)</pre>\n          <pre>eigenvalues 2, 3, 5  →  det = 30,  trace = 10</pre>\n          <p>(The characteristic equation that produces these λ lives in the Eigenvalues topic.)</p>\n        ","question":null},{"id":"la-determinants-036","topicId":"determinants","order":36,"type":"deep-dive","hook":"Determinant vs trace — don't confuse them","body":"trace(A) = sum of diagonal = sum of eigenvalues determinant(A) = area/volume scale = product of eigenvalues A = $\\begin{bmatrix}2&0\\\\0&3\\end{bmatrix}$ trace = 5, det = 6","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-30","sourceLabel":"Study in Depth","detail":"trace(A) = sum of diagonal = sum of eigenvalues determinant(A) = area/volume scale = product of eigenvalues A = $\\begin{bmatrix}2&amp;0\\\\0&amp;3\\end{bmatrix}$ trace = 5, det = 6","detailHtml":"\n          \n          <pre>trace(A)       = sum of diagonal     = sum of eigenvalues\ndeterminant(A) = area/volume scale  = product of eigenvalues</pre>\n          <div class=\"math-steps\"><div class=\"ms-line\">A = $\\begin{bmatrix}2&amp;0\\\\0&amp;3\\end{bmatrix}$   trace = 5,   det = 6</div></div>\n        ","question":null},{"id":"la-determinants-037","topicId":"determinants","order":37,"type":"deep-dive","hook":"Common GATE shortcuts","body":"Triangular / diagonal → det = product of diagonal. Any zero row/column, or repeated/proportional rows → det = 0. det = 0 ⇒ singular, rank-deficient, dependent, no unique solution. det ≠ 0 ⇒ invertible, full rank, independent, unique Ax=b solution.…","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-31","sourceLabel":"Study in Depth","detail":"Triangular / diagonal → det = product of diagonal. Any zero row/column, or repeated/proportional rows → det = 0. det = 0 ⇒ singular, rank-deficient, dependent, no unique solution. det ≠ 0 ⇒ invertible, full rank, independent, unique Ax=b solution. det(cA) = cⁿ det(A) · det(AB) = det(A)det(B) .","detailHtml":"\n          \n          <ul class=\"styled\">\n            <li>Triangular / diagonal → det = product of diagonal.</li>\n            <li>Any zero row/column, or repeated/proportional rows → det = 0.</li>\n            <li><code>det = 0</code> ⇒ singular, rank-deficient, dependent, no unique solution.</li>\n            <li><code>det ≠ 0</code> ⇒ invertible, full rank, independent, unique <code>Ax=b</code> solution.</li>\n            <li><code>det(cA) = cⁿ det(A)</code>  ·  <code>det(AB) = det(A)det(B)</code>.</li>\n          </ul>\n        ","question":null},{"id":"la-determinants-038","topicId":"determinants","order":38,"type":"deep-dive","hook":"Important true / false","body":"det(A) = 0 ⇒ A invertible? False — it is NOT invertible. det(A+B) = det(A) + det(B)? False — det is multiplicative, not additive (e.g. det(I+I)=4 ≠ 2). det(kA) = k·det(A)? False — it is kⁿ·det(A). Triangular det = sum of diagonal? False — it is the…","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-32","sourceLabel":"Study in Depth","detail":"det(A) = 0 ⇒ A invertible ? False — it is NOT invertible. det(A+B) = det(A) + det(B) ? False — det is multiplicative, not additive (e.g. det(I+I)=4 ≠ 2 ). det(kA) = k·det(A) ? False — it is kⁿ·det(A) . Triangular det = sum of diagonal? False — it is the product (sum is the trace). det(Aᵀ)=det(A) , orthogonal ⇒ det=±1 , det=∏λ ? All true.","detailHtml":"\n          \n          <ul class=\"styled\">\n            <li><code>det(A) = 0 ⇒ A invertible</code>? <strong>False</strong> — it is NOT invertible.</li>\n            <li><code>det(A+B) = det(A) + det(B)</code>? <strong>False</strong> — det is multiplicative, not additive (e.g. <code>det(I+I)=4 ≠ 2</code>).</li>\n            <li><code>det(kA) = k·det(A)</code>? <strong>False</strong> — it is <code>kⁿ·det(A)</code>.</li>\n            <li>Triangular det = <em>sum</em> of diagonal? <strong>False</strong> — it is the <em>product</em> (sum is the trace).</li>\n            <li><code>det(Aᵀ)=det(A)</code>, orthogonal ⇒ <code>det=±1</code>, <code>det=∏λ</code>? <strong>All true.</strong></li>\n          </ul>\n        ","question":null},{"id":"la-determinants-039","topicId":"determinants","order":39,"type":"deep-dive","hook":"Determinant decision tree","body":"1. Square? no → not defined 2. Triangular/diag? yes → product of diagonal 3. Zero row/col? yes → 0 4. Repeated/proportional row/col? yes → 0 5. 2×2? ad − bc 6. 3×3? cofactor expansion / row-reduce 7. Eigenvalues given? product of eigenvalues 8.…","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-33","sourceLabel":"Study in Depth","detail":"1. Square? no → not defined 2. Triangular/diag? yes → product of diagonal 3. Zero row/col? yes → 0 4. Repeated/proportional row/col? yes → 0 5. 2×2? ad − bc 6. 3×3? cofactor expansion / row-reduce 7. Eigenvalues given? product of eigenvalues 8. Product/inverse/transpose/scalar? use properties","detailHtml":"\n          \n          <pre>1. Square?            no → not defined\n2. Triangular/diag?   yes → product of diagonal\n3. Zero row/col?      yes → 0\n4. Repeated/proportional row/col? yes → 0\n5. 2×2?               ad − bc\n6. 3×3?               cofactor expansion / row-reduce\n7. Eigenvalues given? product of eigenvalues\n8. Product/inverse/transpose/scalar? use properties</pre>\n        ","question":null},{"id":"la-determinants-040","topicId":"determinants","order":40,"type":"deep-dive","hook":"Quick practice","body":"Q1. det of [[3,4],[2,5]]?","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-34","sourceLabel":"Study in Depth","detail":"Q1. det of [[3,4],[2,5]]? 3×5 − 4×2 = 7 (invertible) Q2. Is [[2,6],[1,3]] invertible? det = 2×3 − 6×1 = 0 → no. Q3. det of upper-triangular [[2,4,7],[0,3,8],[0,0,5]]? 2 × 3 × 5 = 30 Q4. det(A)=4, A is 3×3 — det(2A)? 2³ × 4 = 32 Q5. det(A)=5, det(B)=3 — det(AB)? 5 × 3 = 15 Q6. det(A)=5 — det(A⁻¹)? 1/5 Q7. eigenvalues 2, −1, 4 — det(A)? 2 × (−1) × 4 = −8 Q8. A orthogonal — det(A)? ±1","detailHtml":"\n          \n          <p class=\"lead\">Q1. det of [[3,4],[2,5]]?</p>\n          <pre>3×5 − 4×2 = 7   (invertible)</pre>\n          <p class=\"lead\">Q2. Is [[2,6],[1,3]] invertible?</p>\n          <pre>det = 2×3 − 6×1 = 0  → no.</pre>\n          <p class=\"lead\">Q3. det of upper-triangular [[2,4,7],[0,3,8],[0,0,5]]?</p>\n          <pre>2 × 3 × 5 = 30</pre>\n          <p class=\"lead\">Q4. det(A)=4, A is 3×3 — det(2A)?</p>\n          <pre>2³ × 4 = 32</pre>\n          <p class=\"lead\">Q5. det(A)=5, det(B)=3 — det(AB)?</p>\n          <pre>5 × 3 = 15</pre>\n          <p class=\"lead\">Q6. det(A)=5 — det(A⁻¹)?</p>\n          <pre>1/5</pre>\n          <p class=\"lead\">Q7. eigenvalues 2, −1, 4 — det(A)?</p>\n          <pre>2 × (−1) × 4 = −8</pre>\n          <p class=\"lead\">Q8. A orthogonal — det(A)?</p>\n          <pre>±1</pre>\n        ","question":null},{"id":"la-determinants-041","topicId":"determinants","order":41,"type":"deep-dive","hook":"Best mental model","body":"Determinant = how the matrix-machine changes space. det = 0 → space crushed, no reverse possible. det > 0 → scales, orientation kept. det < 0 → scales and mirror-flips. |det| → the area/volume multiplier.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"study-item-35","sourceLabel":"Study in Depth","detail":"Determinant = how the matrix-machine changes space. det = 0 → space crushed, no reverse possible. det &gt; 0 → scales, orientation kept. det &lt; 0 → scales and mirror-flips. |det| → the area/volume multiplier.","detailHtml":"\n          \n          <ul class=\"styled\">\n            <li><strong>Determinant = how the matrix-machine changes space.</strong></li>\n            <li><code>det = 0</code> → space crushed, no reverse possible.</li>\n            <li><code>det &gt; 0</code> → scales, orientation kept.</li>\n            <li><code>det &lt; 0</code> → scales and mirror-flips.</li>\n            <li><code>|det|</code> → the area/volume multiplier.</li>\n          </ul>\n        ","question":null},{"id":"la-determinants-042","topicId":"determinants","order":42,"type":"cheat-sheet","hook":"$\\det(AB)=\\det A\\det B$ ⇒ $\\det(A^k)=(\\det A)^k$, and $\\det(AB)=\\det(BA)$.","body":"$\\det(AB)=\\det A\\det B$ ⇒ $\\det(A^k)=(\\det A)^k$, and $\\det(AB)=\\det(BA)$.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"cheat-1","sourceLabel":"GATE cheat sheet","detail":"$\\det(AB)=\\det A\\det B$ ⇒ $\\det(A^k)=(\\det A)^k$, and $\\det(AB)=\\det(BA)$.","detailHtml":"<p>$\\det(AB)=\\det A\\det B$  ⇒  $\\det(A^k)=(\\det A)^k$, and $\\det(AB)=\\det(BA)$.</p>","question":null},{"id":"la-determinants-043","topicId":"determinants","order":43,"type":"cheat-sheet","hook":"$\\det(A^{\\mathsf T})=\\det A$; $\\det(A^{-1})=1/\\det A$.","body":"$\\det(A^{\\mathsf T})=\\det A$; $\\det(A^{-1})=1/\\det A$.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"cheat-2","sourceLabel":"GATE cheat sheet","detail":"$\\det(A^{\\mathsf T})=\\det A$; $\\det(A^{-1})=1/\\det A$.","detailHtml":"<p>$\\det(A^{\\mathsf T})=\\det A$;   $\\det(A^{-1})=1/\\det A$.</p>","question":null},{"id":"la-determinants-044","topicId":"determinants","order":44,"type":"cheat-sheet","hook":"$\\det(cA)=c^{\\,n}\\det A$ for an $n\\times n$ matrix (size is the exponent!).","body":"$\\det(cA)=c^{\\,n}\\det A$ for an $n\\times n$ matrix (size is the exponent!).","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"cheat-3","sourceLabel":"GATE cheat sheet","detail":"$\\det(cA)=c^{\\,n}\\det A$ for an $n\\times n$ matrix (size is the exponent!).","detailHtml":"<p>$\\det(cA)=c^{\\,n}\\det A$ for an $n\\times n$ matrix (size is the exponent!).</p>","question":null},{"id":"la-determinants-045","topicId":"determinants","order":45,"type":"cheat-sheet","hook":"$\\det(cI_n)=c^n$; block-triangular $\\det\\begin{bmatrix}A&B\\\\0&D\\end{bmatrix}=\\det A\\,\\det D$.","body":"$\\det(cI_n)=c^n$; block-triangular $\\det\\begin{bmatrix}A&B\\\\0&D\\end{bmatrix}=\\det A\\,\\det D$.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"cheat-4","sourceLabel":"GATE cheat sheet","detail":"$\\det(cI_n)=c^n$; block-triangular $\\det\\begin{bmatrix}A&amp;B\\\\0&amp;D\\end{bmatrix}=\\det A\\,\\det D$.","detailHtml":"<p>$\\det(cI_n)=c^n$;   block-triangular $\\det\\begin{bmatrix}A&amp;B\\\\0&amp;D\\end{bmatrix}=\\det A\\,\\det D$.</p>","question":null},{"id":"la-determinants-046","topicId":"determinants","order":46,"type":"cheat-sheet","hook":"Triangular / diagonal → $\\det=$ product of the diagonal; $\\det=\\prod\\lambda_i$.","body":"Triangular / diagonal → $\\det=$ product of the diagonal; $\\det=\\prod\\lambda_i$.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"cheat-5","sourceLabel":"GATE cheat sheet","detail":"Triangular / diagonal → $\\det=$ product of the diagonal; $\\det=\\prod\\lambda_i$.","detailHtml":"<p>Triangular / diagonal → $\\det=$ product of the diagonal; $\\det=\\prod\\lambda_i$.</p>","question":null},{"id":"la-determinants-047","topicId":"determinants","order":47,"type":"cheat-sheet","hook":"Orthogonal matrix → $\\det=\\pm1$.","body":"Idempotent → $\\det\\in\\{0,1\\}$. Nilpotent → $\\det=0$.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"cheat-6","sourceLabel":"GATE cheat sheet","detail":"Orthogonal matrix → $\\det=\\pm1$. Idempotent → $\\det\\in\\{0,1\\}$. Nilpotent → $\\det=0$.","detailHtml":"<p>Orthogonal matrix → $\\det=\\pm1$. Idempotent → $\\det\\in\\{0,1\\}$. Nilpotent → $\\det=0$.</p>","question":null},{"id":"la-determinants-048","topicId":"determinants","order":48,"type":"trap","hook":"Trap","body":"\"$\\det(A+B)=\\det A+\\det B$.\" Reality: false — det is multiplicative, not additive. (E.g. $A=B=I_2$: LHS $=4$, RHS $=2$.)","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"trap-1","sourceLabel":"Common traps","detail":"Trap: &quot;$\\det(A+B)=\\det A+\\det B$.&quot; Reality: false — det is multiplicative, not additive. (E.g. $A=B=I_2$: LHS $=4$, RHS $=2$.)","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;$\\det(A+B)=\\det A+\\det B$.&quot; <span class=\"right\">Reality:</span> false — det is multiplicative, not additive. (E.g. $A=B=I_2$: LHS $=4$, RHS $=2$.)</p>","question":null},{"id":"la-determinants-049","topicId":"determinants","order":49,"type":"trap","hook":"Trap","body":"\"$\\det(2A)=2\\det A$.\" Reality: $\\det(2A)=2^n\\det A$ — e.g. $2^3$ for a $3\\times3$.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"trap-2","sourceLabel":"Common traps","detail":"Trap: &quot;$\\det(2A)=2\\det A$.&quot; Reality: $\\det(2A)=2^n\\det A$ — e.g. $2^3$ for a $3\\times3$.","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;$\\det(2A)=2\\det A$.&quot; <span class=\"right\">Reality:</span> $\\det(2A)=2^n\\det A$ — e.g. $2^3$ for a $3\\times3$.</p>","question":null},{"id":"la-determinants-050","topicId":"determinants","order":50,"type":"trap","hook":"Trap","body":"\"Triangular determinant is the sum of the diagonal.\" Reality: it's the product (the sum is the trace).","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"trap-3","sourceLabel":"Common traps","detail":"Trap: &quot;Triangular determinant is the sum of the diagonal.&quot; Reality: it&#x27;s the product (the sum is the trace).","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;Triangular determinant is the <em>sum</em> of the diagonal.&quot; <span class=\"right\">Reality:</span> it&#x27;s the <em>product</em> (the sum is the trace).</p>","question":null},{"id":"la-determinants-051","topicId":"determinants","order":51,"type":"trap","hook":"Trap","body":"\"Non-square matrices have determinants.\" Reality: only square matrices do.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"trap-4","sourceLabel":"Common traps","detail":"Trap: &quot;Non-square matrices have determinants.&quot; Reality: only square matrices do.","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;Non-square matrices have determinants.&quot; <span class=\"right\">Reality:</span> only square matrices do.</p>","question":null},{"id":"la-determinants-052","topicId":"determinants","order":52,"type":"practice","hook":"Q1. $\\det(A)=5$ for a $3\\times3$ matrix. Find $\\det(2A)$.","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"practice-1","sourceLabel":"Practice problems","detail":"$2^3\\cdot5=40$.","detailHtml":"$2^3\\cdot5=40$.","question":{"type":"REVEAL","prompt":"Q1. $\\det(A)=5$ for a $3\\times3$ matrix. Find $\\det(2A)$.","options":[],"answer":true,"explanation":"$2^3\\cdot5=40$.","explanationHtml":"$2^3\\cdot5=40$."}},{"id":"la-determinants-053","topicId":"determinants","order":53,"type":"practice","hook":"Q2. $\\det\\begin{bmatrix}2&4&7\\\\0&3&8\\\\0&0&5\\end{bmatrix}=?$","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"practice-2","sourceLabel":"Practice problems","detail":"Upper-triangular → $2\\cdot3\\cdot5=30$.","detailHtml":"Upper-triangular → $2\\cdot3\\cdot5=30$.","question":{"type":"REVEAL","prompt":"Q2. $\\det\\begin{bmatrix}2&4&7\\\\0&3&8\\\\0&0&5\\end{bmatrix}=?$","options":[],"answer":true,"explanation":"Upper-triangular → $2\\cdot3\\cdot5=30$.","explanationHtml":"Upper-triangular → $2\\cdot3\\cdot5=30$."}},{"id":"la-determinants-054","topicId":"determinants","order":54,"type":"practice","hook":"Q3. $\\det A=5,\\ \\det B=3$. Find $\\det(AB)$ and $\\det(A^{-1})$.","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"practice-3","sourceLabel":"Practice problems","detail":"$\\det(AB)=15$; $\\det(A^{-1})=1/5$.","detailHtml":"$\\det(AB)=15$; $\\det(A^{-1})=1/5$.","question":{"type":"REVEAL","prompt":"Q3. $\\det A=5,\\ \\det B=3$. Find $\\det(AB)$ and $\\det(A^{-1})$.","options":[],"answer":true,"explanation":"$\\det(AB)=15$; $\\det(A^{-1})=1/5$.","explanationHtml":"$\\det(AB)=15$; $\\det(A^{-1})=1/5$."}},{"id":"la-determinants-055","topicId":"determinants","order":55,"type":"practice","hook":"Q4. Eigenvalues of $A$ are $2,-1,4$. Find $\\det A$.","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"practice-4","sourceLabel":"Practice problems","detail":"$\\det A=2\\cdot(-1)\\cdot4=-8$ (negative ⇒ orientation flips).","detailHtml":"$\\det A=2\\cdot(-1)\\cdot4=-8$ (negative ⇒ orientation flips).","question":{"type":"REVEAL","prompt":"Q4. Eigenvalues of $A$ are $2,-1,4$. Find $\\det A$.","options":[],"answer":true,"explanation":"$\\det A=2\\cdot(-1)\\cdot4=-8$ (negative ⇒ orientation flips).","explanationHtml":"$\\det A=2\\cdot(-1)\\cdot4=-8$ (negative ⇒ orientation flips)."}},{"id":"la-determinants-056","topicId":"determinants","order":56,"type":"practice","hook":"Q5. Is $A=\\begin{bmatrix}2&6\\\\1&3\\end{bmatrix}$ invertible?","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"practice-5","sourceLabel":"Practice problems","detail":"$\\det=2\\cdot3-6\\cdot1=0$ → singular, not invertible (column 2 $=3\\times$ column 1).","detailHtml":"$\\det=2\\cdot3-6\\cdot1=0$ → singular, <strong>not</strong> invertible (column 2 $=3\\times$ column 1).","question":{"type":"REVEAL","prompt":"Q5. Is $A=\\begin{bmatrix}2&6\\\\1&3\\end{bmatrix}$ invertible?","options":[],"answer":true,"explanation":"$\\det=2\\cdot3-6\\cdot1=0$ → singular, not invertible (column 2 $=3\\times$ column 1).","explanationHtml":"$\\det=2\\cdot3-6\\cdot1=0$ → singular, <strong>not</strong> invertible (column 2 $=3\\times$ column 1)."}},{"id":"la-determinants-057","topicId":"determinants","order":57,"type":"practice","hook":"Q6. If $A$ is orthogonal, what values can $\\det A$ take?","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"practice-6","sourceLabel":"Practice problems","detail":"$\\pm1$ (from $\\det(A^{\\mathsf T}A)=\\det I=1$ ⇒ $(\\det A)^2=1$).","detailHtml":"$\\pm1$ (from $\\det(A^{\\mathsf T}A)=\\det I=1$ ⇒ $(\\det A)^2=1$).","question":{"type":"REVEAL","prompt":"Q6. If $A$ is orthogonal, what values can $\\det A$ take?","options":[],"answer":true,"explanation":"$\\pm1$ (from $\\det(A^{\\mathsf T}A)=\\det I=1$ ⇒ $(\\det A)^2=1$).","explanationHtml":"$\\pm1$ (from $\\det(A^{\\mathsf T}A)=\\det I=1$ ⇒ $(\\det A)^2=1$)."}},{"id":"la-determinants-058","topicId":"determinants","order":58,"type":"practice","hook":"Which statement is true?","body":"Choose an answer, then check the explanation.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"03-determinants.html","sourceAnchor":"practice-quiz-1","sourceLabel":"Practice quiz","detail":"✅ Correct — both equal $\\det A\\,\\det B$.","detailHtml":"✅ Correct — both equal $\\det A\\,\\det B$.","question":{"type":"MCQ","prompt":"Which statement is true?","options":["A: $\\det(A+B)=\\det A+\\det B$","B: $\\det(kA)=k\\det A$","C: $\\det(AB)=\\det(BA)$","D: Triangular $\\det$ = sum of diagonal"],"answer":"C","explanation":"✅ Correct — both equal $\\det A\\,\\det B$.","explanationHtml":"✅ Correct — both equal $\\det A\\,\\det B$."}},{"id":"la-rank-nullity-001","topicId":"rank-nullity","order":1,"type":"basic-definition","hook":"Rank","body":"the number of linearly independent rows (= independent columns); equivalently the number of non-zero rows after row-reduction.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"definition-1","sourceLabel":"Basic definitions","detail":"Rank: the number of linearly independent rows (= independent columns); equivalently the number of non-zero rows after row-reduction.","detailHtml":"<p><strong>Rank:</strong> the number of linearly independent rows (= independent columns); equivalently the number of non-zero rows after row-reduction.</p>","question":null},{"id":"la-rank-nullity-002","topicId":"rank-nullity","order":2,"type":"basic-definition","hook":"Null space (kernel)","body":"all vectors $x$ with $Ax=0$. Nullity: its dimension.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"definition-2","sourceLabel":"Basic definitions","detail":"Null space (kernel): all vectors $x$ with $Ax=0$. Nullity: its dimension.","detailHtml":"<p><strong>Null space (kernel):</strong> all vectors $x$ with $Ax=0$. <strong>Nullity:</strong> its dimension.</p>","question":null},{"id":"la-rank-nullity-003","topicId":"rank-nullity","order":3,"type":"basic-definition","hook":"Column space","body":"all outputs $Ax$ (span of the columns). Row space: span of the rows.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"definition-3","sourceLabel":"Basic definitions","detail":"Column space: all outputs $Ax$ (span of the columns). Row space: span of the rows.","detailHtml":"<p><strong>Column space:</strong> all outputs $Ax$ (span of the columns). <strong>Row space:</strong> span of the rows.</p>","question":null},{"id":"la-rank-nullity-004","topicId":"rank-nullity","order":4,"type":"basic-definition","hook":"Pivot","body":"the first non-zero entry of a row after row-reduction — rank = number of pivots.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"definition-4","sourceLabel":"Basic definitions","detail":"Pivot: the first non-zero entry of a row after row-reduction — rank = number of pivots .","detailHtml":"<p><strong>Pivot:</strong> the first non-zero entry of a row after row-reduction — <strong>rank = number of pivots</strong>.</p>","question":null},{"id":"la-rank-nullity-005","topicId":"rank-nullity","order":5,"type":"basic-definition","hook":"Row-echelon form","body":"zero rows sit at the bottom; each leading entry is further right than the one above.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"definition-5","sourceLabel":"Basic definitions","detail":"Row-echelon form: zero rows sit at the bottom; each leading entry is further right than the one above.","detailHtml":"<p><strong>Row-echelon form:</strong> zero rows sit at the bottom; each leading entry is further right than the one above.</p>","question":null},{"id":"la-rank-nullity-006","topicId":"rank-nullity","order":6,"type":"basic-definition","hook":"Full rank","body":"rank $=\\min(m,n)$ (nothing collapses). Rank-deficient: rank $\\lt\\min(m,n)$.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"definition-6","sourceLabel":"Basic definitions","detail":"Full rank: rank $=\\min(m,n)$ (nothing collapses). Rank-deficient: rank $\\lt\\min(m,n)$.","detailHtml":"<p><strong>Full rank:</strong> rank $=\\min(m,n)$ (nothing collapses). <strong>Rank-deficient:</strong> rank $\\lt\\min(m,n)$.</p>","question":null},{"id":"la-rank-nullity-007","topicId":"rank-nullity","order":7,"type":"basic-definition","hook":"Free variable","body":"an unknown not pinned by a pivot — each adds a dimension of solutions (nullity counts them).","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"definition-7","sourceLabel":"Basic definitions","detail":"Free variable: an unknown not pinned by a pivot — each adds a dimension of solutions (nullity counts them).","detailHtml":"<p><strong>Free variable:</strong> an unknown not pinned by a pivot — each adds a dimension of solutions (nullity counts them).</p>","question":null},{"id":"la-rank-nullity-008","topicId":"rank-nullity","order":8,"type":"deep-dive","hook":"What is rank? (intuition)","body":"Picture a 3D game world with full movement (x, y, z = 3 independent directions). A matrix transforms it; rank = how many independent directions survive.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-1","sourceLabel":"Study in Depth","detail":"Picture a 3D game world with full movement (x, y, z = 3 independent directions). A matrix transforms it; rank = how many independent directions survive . 3D stays 3D → rank 3 3D crushed to a plane → rank 2 3D crushed to a line → rank 1 everything → a point → rank 0 So rank = dimension of the output space after the transformation.","detailHtml":"\n          \n          <p>Picture a 3D game world with full movement (x, y, z = 3 independent directions). A matrix transforms it; <strong>rank = how many independent directions survive</strong>.</p>\n          <pre>3D stays 3D            → rank 3\n3D crushed to a plane  → rank 2\n3D crushed to a line   → rank 1\neverything → a point   → rank 0</pre>\n          <p>So <strong>rank = dimension of the output space</strong> after the transformation.</p>\n        ","question":null},{"id":"la-rank-nullity-009","topicId":"rank-nullity","order":9,"type":"deep-dive","hook":"Matrix as an information carrier","body":"A matrix maps input x to output Ax. Keeping more independent directions = preserving more information.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-2","sourceLabel":"Study in Depth","detail":"A matrix maps input x to output Ax . Keeping more independent directions = preserving more information. $\\begin{bmatrix}1&amp;0\\\\0&amp;1\\end{bmatrix}$ keeps everything → rank 2 $\\begin{bmatrix}1&amp;0\\\\0&amp;0\\end{bmatrix}$ destroys the y-direction → rank 1 $\\begin{bmatrix}0&amp;0\\\\0&amp;0\\end{bmatrix}$ destroys everything → rank 0 High rank = more information preserved; low rank = more lost.","detailHtml":"\n          \n          <p>A matrix maps input <code>x</code> to output <code>Ax</code>. Keeping more independent directions = preserving more information.</p>\n          <div class=\"math-steps\"><div class=\"ms-line\">$\\begin{bmatrix}1&amp;0\\\\0&amp;1\\end{bmatrix}$ keeps everything       → rank 2</div><div class=\"ms-line\">$\\begin{bmatrix}1&amp;0\\\\0&amp;0\\end{bmatrix}$ destroys the y-direction → rank 1</div><div class=\"ms-line\">$\\begin{bmatrix}0&amp;0\\\\0&amp;0\\end{bmatrix}$ destroys everything      → rank 0</div></div>\n          <p>High rank = more information preserved; low rank = more lost.</p>\n        ","question":null},{"id":"la-rank-nullity-010","topicId":"rank-nullity","order":10,"type":"deep-dive","hook":"Formal definition","body":"The rank is the maximum number of linearly independent rows — or columns.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-3","sourceLabel":"Study in Depth","detail":"The rank is the maximum number of linearly independent rows — or columns. Beautiful fact: row rank = column rank . That common number is rank(A) .","detailHtml":"\n          \n          <p>The <strong>rank</strong> is the maximum number of linearly independent rows — or columns.</p>\n          <p><span style=\"color:var(--coral-text)\">Beautiful fact:</span> <strong>row rank = column rank</strong>. That common number is <code>rank(A)</code>.</p>\n        ","question":null},{"id":"la-rank-nullity-011","topicId":"rank-nullity","order":11,"type":"worked-example","hook":"Independent rows — example","body":"Useful independent rows are R1 and R3, so rank(A) = 2.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-4","sourceLabel":"Study in Depth","detail":"A = [1 2 3 2 4 6 R2 = 2·R1 (dependent, no new info) 1 1 1] R3 is not a multiple of R1 Useful independent rows are R1 and R3, so rank(A) = 2 .","detailHtml":"\n          \n          <pre>A = [1  2  3\n     2  4  6        R2 = 2·R1  (dependent, no new info)\n     1  1  1]       R3 is not a multiple of R1</pre>\n          <p>Useful independent rows are R1 and R3, so <code>rank(A) = 2</code>.</p>\n        ","question":null},{"id":"la-rank-nullity-012","topicId":"rank-nullity","order":12,"type":"deep-dive","hook":"Rank via row echelon form (the practical method)","body":"Allowed row ops (swap, scale by non-zero, add a multiple of a row) do not change rank.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-5","sourceLabel":"Study in Depth","detail":"Row-reduce A to echelon form. Count the non-zero rows . That count is the rank. Allowed row ops (swap, scale by non-zero, add a multiple of a row) do not change rank .","detailHtml":"\n          \n          <ol class=\"steps\">\n            <li>Row-reduce A to echelon form.</li>\n            <li>Count the <strong>non-zero rows</strong>.</li>\n            <li>That count is the rank.</li>\n          </ol>\n          <p>Allowed row ops (swap, scale by non-zero, add a multiple of a row) <strong>do not change rank</strong>.</p>\n        ","question":null},{"id":"la-rank-nullity-013","topicId":"rank-nullity","order":13,"type":"deep-dive","hook":"What is row echelon form?","body":"Echelon form: zero rows at the bottom; each row's first non-zero entry sits to the right of the one above; entries below each pivot are zero.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-6","sourceLabel":"Study in Depth","detail":"Echelon form: zero rows at the bottom; each row&#x27;s first non-zero entry sits to the right of the one above; entries below each pivot are zero. $\\begin{bmatrix}1&amp;2&amp;3\\\\0&amp;1&amp;4\\\\0&amp;0&amp;5\\end{bmatrix}$ → 3 non-zero rows → rank 3 $\\begin{bmatrix}1&amp;2&amp;3\\\\0&amp;1&amp;4\\\\0&amp;0&amp;0\\end{bmatrix}$ → 2 non-zero rows → rank 2","detailHtml":"\n          \n          <p>Echelon form: zero rows at the bottom; each row&#x27;s first non-zero entry sits to the right of the one above; entries below each pivot are zero.</p>\n          <div class=\"math-steps\"><div class=\"ms-line\">$\\begin{bmatrix}1&amp;2&amp;3\\\\0&amp;1&amp;4\\\\0&amp;0&amp;5\\end{bmatrix}$  → 3 non-zero rows → rank 3</div><div class=\"ms-line\">$\\begin{bmatrix}1&amp;2&amp;3\\\\0&amp;1&amp;4\\\\0&amp;0&amp;0\\end{bmatrix}$  → 2 non-zero rows → rank 2</div></div>\n        ","question":null},{"id":"la-rank-nullity-014","topicId":"rank-nullity","order":14,"type":"deep-dive","hook":"Pivots — rank = number of pivots","body":"A pivot is the first non-zero entry of a row after reduction.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-7","sourceLabel":"Study in Depth","detail":"A pivot is the first non-zero entry of a row after reduction. $\\begin{bmatrix}1&amp;2&amp;3\\\\0&amp;5&amp;6\\\\0&amp;0&amp;0\\end{bmatrix}$ → pivots: 1, 5 → rank = 2","detailHtml":"\n          \n          <p>A <strong>pivot</strong> is the first non-zero entry of a row after reduction.</p>\n          <div class=\"math-steps\"><div class=\"ms-line\">$\\begin{bmatrix}1&amp;2&amp;3\\\\0&amp;5&amp;6\\\\0&amp;0&amp;0\\end{bmatrix}$  → pivots: 1, 5 → rank = 2</div></div>\n        ","question":null},{"id":"la-rank-nullity-015","topicId":"rank-nullity","order":15,"type":"worked-example","hook":"Worked rank example","body":"A = $\\begin{bmatrix}1&2&3\\\\2&4&6\\\\1&1&1\\end{bmatrix}$R₂ → R₂ − 2R₁ → $\\begin{bmatrix}0&0&0\\end{bmatrix}$R₃ → R₃ − R₁ → $\\begin{bmatrix}0&-1&-2\\end{bmatrix}$$\\begin{bmatrix}1&2&3\\\\0&-1&-2\\\\0&0&0\\end{bmatrix}$ → 2 non-zero rows, so rank(A) = 2","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-8","sourceLabel":"Study in Depth","detail":"A = $\\begin{bmatrix}1&amp;2&amp;3\\\\2&amp;4&amp;6\\\\1&amp;1&amp;1\\end{bmatrix}$ R₂ → R₂ − 2R₁ → $\\begin{bmatrix}0&amp;0&amp;0\\end{bmatrix}$ R₃ → R₃ − R₁ → $\\begin{bmatrix}0&amp;-1&amp;-2\\end{bmatrix}$ $\\begin{bmatrix}1&amp;2&amp;3\\\\0&amp;-1&amp;-2\\\\0&amp;0&amp;0\\end{bmatrix}$ → 2 non-zero rows, so rank(A) = 2","detailHtml":"\n          \n          <div class=\"math-steps\"><div class=\"ms-line\">A = $\\begin{bmatrix}1&amp;2&amp;3\\\\2&amp;4&amp;6\\\\1&amp;1&amp;1\\end{bmatrix}$</div><div class=\"ms-line\">R₂ → R₂ − 2R₁  →  $\\begin{bmatrix}0&amp;0&amp;0\\end{bmatrix}$</div><div class=\"ms-line\">R₃ → R₃ − R₁  →  $\\begin{bmatrix}0&amp;-1&amp;-2\\end{bmatrix}$</div><div class=\"ms-line\"></div><div class=\"ms-line\">$\\begin{bmatrix}1&amp;2&amp;3\\\\0&amp;-1&amp;-2\\\\0&amp;0&amp;0\\end{bmatrix}$  →  2 non-zero rows, so rank(A) = 2</div></div>\n        ","question":null},{"id":"la-rank-nullity-016","topicId":"rank-nullity","order":16,"type":"deep-dive","hook":"Rank limit: ≤ min(m, n)","body":"You cannot have more independent rows than rows, nor more independent columns than columns.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-9","sourceLabel":"Study in Depth","detail":"rank(A) ≤ min(m, n) (A is m×n) 3×5 → rank ≤ 3 5×3 → rank ≤ 3 4×4 → rank ≤ 4 You cannot have more independent rows than rows, nor more independent columns than columns.","detailHtml":"\n          \n          <pre>rank(A) ≤ min(m, n)        (A is m×n)\n\n3×5 → rank ≤ 3\n5×3 → rank ≤ 3\n4×4 → rank ≤ 4</pre>\n          <p>You cannot have more independent rows than rows, nor more independent columns than columns.</p>\n        ","question":null},{"id":"la-rank-nullity-017","topicId":"rank-nullity","order":17,"type":"deep-dive","hook":"Full rank","body":"Full rank means rank = min(m, n). For a square n×n matrix, full rank = n, and:","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-10","sourceLabel":"Study in Depth","detail":"Full rank means rank = min(m, n) . For a square n×n matrix, full rank = n, and: rank(A) = n ⇔ det(A) ≠ 0 ⇔ A is invertible ⇔ columns independent ⇔ rows independent","detailHtml":"\n          \n          <p><strong>Full rank</strong> means <code>rank = min(m, n)</code>. For a square n×n matrix, full rank = n, and:</p>\n          <pre>rank(A) = n\n⇔ det(A) ≠ 0\n⇔ A is invertible\n⇔ columns independent\n⇔ rows independent</pre>\n        ","question":null},{"id":"la-rank-nullity-018","topicId":"rank-nullity","order":18,"type":"deep-dive","hook":"Rank and determinant","body":"Memory: det ≠ 0 = full-power matrix; det = 0 = collapsed matrix.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-11","sourceLabel":"Study in Depth","detail":"det(A) ≠ 0 → rank = n (full): invertible, independent, unique solution det(A) = 0 → rank &lt; n: singular, dependent, Ax=0 has non-zero solutions Memory: det ≠ 0 = full-power matrix; det = 0 = collapsed matrix.","detailHtml":"\n          \n          <pre>det(A) ≠ 0   →  rank = n  (full): invertible, independent, unique solution\ndet(A) = 0   →  rank &lt; n: singular, dependent, Ax=0 has non-zero solutions</pre>\n          <p><span style=\"color:var(--coral-text)\">Memory:</span> det ≠ 0 = full-power matrix; det = 0 = collapsed matrix.</p>\n        ","question":null},{"id":"la-rank-nullity-019","topicId":"rank-nullity","order":19,"type":"deep-dive","hook":"Rank by eigenvalues (careful)","body":"For diagonal / triangular / symmetric / diagonalizable matrices, rank = number of non-zero eigenvalues.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-12","sourceLabel":"Study in Depth","detail":"For diagonal / triangular / symmetric / diagonalizable matrices, rank = number of non-zero eigenvalues . D = diag(3, 0, 5) → non-zero: 3, 5 → rank 2 Caution: for defective (non-diagonalizable) matrices this can fail — algebraic multiplicity matters. GATE usually gives the friendly cases.","detailHtml":"\n          \n          <p>For <strong>diagonal / triangular / symmetric / diagonalizable</strong> matrices, <code>rank = number of non-zero eigenvalues</code>.</p>\n          <pre>D = diag(3, 0, 5)  → non-zero: 3, 5 → rank 2</pre>\n          <p><span style=\"color:var(--coral-text)\">Caution:</span> for defective (non-diagonalizable) matrices this can fail — algebraic multiplicity matters. GATE usually gives the friendly cases.</p>\n        ","question":null},{"id":"la-rank-nullity-020","topicId":"rank-nullity","order":20,"type":"deep-dive","hook":"Null space","body":"The null space is every input that the matrix sends to zero:","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-13","sourceLabel":"Study in Depth","detail":"The null space is every input that the matrix sends to zero: Null(A) = { x ∈ ℝⁿ : Ax = 0 } 🎮 Imagine: the portal&#x27;s &quot;disappearing directions&quot; — non-zero vectors that come out as 0 are destroyed directions.","detailHtml":"\n          \n          <p>The <strong>null space</strong> is every input that the matrix sends to zero:</p>\n          <pre>Null(A) = { x ∈ ℝⁿ : Ax = 0 }</pre>\n          <p><span style=\"color:var(--coral-text)\">🎮 Imagine:</span> the portal&#x27;s &quot;disappearing directions&quot; — non-zero vectors that come out as 0 are destroyed directions.</p>\n        ","question":null},{"id":"la-rank-nullity-021","topicId":"rank-nullity","order":21,"type":"deep-dive","hook":"Nullity","body":"Nullity = dimension of the null space = number of independent directions the matrix destroys.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-14","sourceLabel":"Study in Depth","detail":"Nullity = dimension of the null space = number of independent directions the matrix destroys. nullity 0 → destroys no non-zero direction nullity 1 → destroys one independent direction nullity 2 → destroys two","detailHtml":"\n          \n          <p><strong>Nullity</strong> = dimension of the null space = number of independent directions the matrix destroys.</p>\n          <pre>nullity 0  → destroys no non-zero direction\nnullity 1  → destroys one independent direction\nnullity 2  → destroys two</pre>\n        ","question":null},{"id":"la-rank-nullity-022","topicId":"rank-nullity","order":22,"type":"deep-dive","hook":"The Rank–Nullity Theorem","body":"The input x has n components, and the input space splits into surviving directions (rank) + destroyed directions (nullity).","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-15","sourceLabel":"Study in Depth","detail":"rank(A) + nullity(A) = n (n = number of COLUMNS) The input x has n components, and the input space splits into surviving directions (rank) + destroyed directions (nullity). Memory: columns = input variables, so rank + nullity = columns (not rows!).","detailHtml":"\n          \n          <pre>rank(A) + nullity(A) = n        (n = number of COLUMNS)</pre>\n          <p>The input <code>x</code> has n components, and the input space splits into surviving directions (rank) + destroyed directions (nullity).</p>\n          <p><span style=\"color:var(--coral-text)\">Memory:</span> columns = input variables, so rank + nullity = columns (not rows!).</p>\n        ","question":null},{"id":"la-rank-nullity-023","topicId":"rank-nullity","order":23,"type":"deep-dive","hook":"Rank–nullity — game imagination","body":"3D input (n = 3): rank 2 → nullity 1 (2 survive, 1 crushed) rank 1 → nullity 2 (1 survives, 2 crushed)","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-16","sourceLabel":"Study in Depth","detail":"3D input (n = 3): rank 2 → nullity 1 (2 survive, 1 crushed) rank 1 → nullity 2 (1 survives, 2 crushed)","detailHtml":"\n          \n          <pre>3D input (n = 3):\nrank 2 → nullity 1   (2 survive, 1 crushed)\nrank 1 → nullity 2   (1 survives, 2 crushed)</pre>\n        ","question":null},{"id":"la-rank-nullity-024","topicId":"rank-nullity","order":24,"type":"worked-example","hook":"Example: rank and nullity","body":"A = $\\begin{bmatrix}1&0\\\\0&0\\end{bmatrix}$ maps [x,y] → [x,0]x survives → rank = 1n = 2 columns → nullity = 2 − 1 = 1destroyed direction: [0,1] (since A[0,1]ᵀ = 0)Null(A) = span{[0,1]}","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-17","sourceLabel":"Study in Depth","detail":"A = $\\begin{bmatrix}1&amp;0\\\\0&amp;0\\end{bmatrix}$ maps [x,y] → [x,0] x survives → rank = 1 n = 2 columns → nullity = 2 − 1 = 1 destroyed direction: [0,1] (since A[0,1]ᵀ = 0) Null(A) = span{[0,1]}","detailHtml":"\n          \n          <div class=\"math-steps\"><div class=\"ms-line\">A = $\\begin{bmatrix}1&amp;0\\\\0&amp;0\\end{bmatrix}$  maps [x,y] → [x,0]</div><div class=\"ms-line\"></div><div class=\"ms-line\">x survives → rank = 1</div><div class=\"ms-line\">n = 2 columns → nullity = 2 − 1 = 1</div><div class=\"ms-line\">destroyed direction: [0,1]  (since A[0,1]ᵀ = 0)</div><div class=\"ms-line\">Null(A) = span{[0,1]}</div></div>\n        ","question":null},{"id":"la-rank-nullity-025","topicId":"rank-nullity","order":25,"type":"deep-dive","hook":"Solving for a null space","body":"A = [1 2] (1×2) Ax = 0 ⇒ x₁ + 2x₂ = 0 ⇒ x₁ = −2x₂ let x₂ = t: x = t·[−2, 1] Null(A) = span{[−2, 1]}, nullity = 1 rank = 1 ✓ (rank + nullity = 1 + 1 = 2 = columns)","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-18","sourceLabel":"Study in Depth","detail":"A = [1 2] (1×2) Ax = 0 ⇒ x₁ + 2x₂ = 0 ⇒ x₁ = −2x₂ let x₂ = t: x = t·[−2, 1] Null(A) = span{[−2, 1]}, nullity = 1 rank = 1 ✓ (rank + nullity = 1 + 1 = 2 = columns)","detailHtml":"\n          \n          <pre>A = [1  2]   (1×2)\nAx = 0  ⇒  x₁ + 2x₂ = 0  ⇒  x₁ = −2x₂\n\nlet x₂ = t:  x = t·[−2, 1]\nNull(A) = span{[−2, 1]},  nullity = 1\nrank = 1  ✓  (rank + nullity = 1 + 1 = 2 = columns)</pre>\n        ","question":null},{"id":"la-rank-nullity-026","topicId":"rank-nullity","order":26,"type":"deep-dive","hook":"Free variables = nullity","body":"When solving Ax = 0, the number of free variables = nullity, and the number of pivot variables = rank.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-19","sourceLabel":"Study in Depth","detail":"When solving Ax = 0 , the number of free variables = nullity , and the number of pivot variables = rank . pivot variables + free variables = total variables rank + nullity = columns","detailHtml":"\n          \n          <p>When solving <code>Ax = 0</code>, the <strong>number of free variables = nullity</strong>, and the <strong>number of pivot variables = rank</strong>.</p>\n          <pre>pivot variables + free variables = total variables\n        rank      +    nullity     =    columns</pre>\n        ","question":null},{"id":"la-rank-nullity-027","topicId":"rank-nullity","order":27,"type":"deep-dive","hook":"Pivot variable vs free variable","body":"x₁ + 2x₂ + 3x₃ = 0 x₂ + 4x₃ = 0 pivots: x₁, x₂ → rank = 2 free: x₃ → nullity = 1 variables = 3 → 2 + 1 = 3 ✓","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-20","sourceLabel":"Study in Depth","detail":"x₁ + 2x₂ + 3x₃ = 0 x₂ + 4x₃ = 0 pivots: x₁, x₂ → rank = 2 free: x₃ → nullity = 1 variables = 3 → 2 + 1 = 3 ✓","detailHtml":"\n          \n          <pre>x₁ + 2x₂ + 3x₃ = 0\n      x₂ + 4x₃ = 0\n\npivots: x₁, x₂   → rank = 2\nfree:   x₃       → nullity = 1\nvariables = 3    → 2 + 1 = 3  ✓</pre>\n        ","question":null},{"id":"la-rank-nullity-028","topicId":"rank-nullity","order":28,"type":"deep-dive","hook":"Rank of the transpose","body":"If A is 3×5 with rank 3, then Aᵀ (5×3) also has rank 3.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-21","sourceLabel":"Study in Depth","detail":"rank(A) = rank(Aᵀ) (row rank = column rank) If A is 3×5 with rank 3, then Aᵀ (5×3) also has rank 3.","detailHtml":"\n          \n          <pre>rank(A) = rank(Aᵀ)     (row rank = column rank)</pre>\n          <p>If A is 3×5 with rank 3, then Aᵀ (5×3) also has rank 3.</p>\n        ","question":null},{"id":"la-rank-nullity-029","topicId":"rank-nullity","order":29,"type":"deep-dive","hook":"Rank of a product","body":"🎮 Imagine: if one portal already crushes 3D to a line, a later portal cannot recover the lost information.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-22","sourceLabel":"Study in Depth","detail":"rank(AB) ≤ min(rank(A), rank(B)) 🎮 Imagine: if one portal already crushes 3D to a line, a later portal cannot recover the lost information. rank(A)=2, rank(B)=5 → rank(AB) ≤ 2","detailHtml":"\n          \n          <pre>rank(AB) ≤ min(rank(A), rank(B))</pre>\n          <p><span style=\"color:var(--coral-text)\">🎮 Imagine:</span> if one portal already crushes 3D to a line, a later portal cannot recover the lost information.</p>\n          <pre>rank(A)=2, rank(B)=5 → rank(AB) ≤ 2</pre>\n        ","question":null},{"id":"la-rank-nullity-030","topicId":"rank-nullity","order":30,"type":"deep-dive","hook":"Rank under invertible multiplication","body":"If P and Q are invertible, rank(PAQ) = rank(A) — invertible maps only rotate/relabel, they destroy no information.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-23","sourceLabel":"Study in Depth","detail":"If P and Q are invertible, rank(PAQ) = rank(A) — invertible maps only rotate/relabel, they destroy no information. This is why elementary row operations preserve rank (they are multiplication by invertible elementary matrices).","detailHtml":"\n          \n          <p>If P and Q are invertible, <code>rank(PAQ) = rank(A)</code> — invertible maps only rotate/relabel, they destroy no information.</p>\n          <p>This is why <strong>elementary row operations preserve rank</strong> (they are multiplication by invertible elementary matrices).</p>\n        ","question":null},{"id":"la-rank-nullity-031","topicId":"rank-nullity","order":31,"type":"deep-dive","hook":"rank(AᵀA) = rank(A)","body":"Key in least squares, projections, PCA and the normal equations.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-24","sourceLabel":"Study in Depth","detail":"rank(AᵀA) = rank(AAᵀ) = rank(A) Key in least squares, projections, PCA and the normal equations.","detailHtml":"\n          \n          <pre>rank(AᵀA) = rank(AAᵀ) = rank(A)</pre>\n          <p>Key in least squares, projections, PCA and the normal equations.</p>\n        ","question":null},{"id":"la-rank-nullity-032","topicId":"rank-nullity","order":32,"type":"deep-dive","hook":"The four fundamental subspaces","body":"For an m×n matrix A:","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-25","sourceLabel":"Study in Depth","detail":"For an m×n matrix A: Column space C(A) — span of columns; all outputs Ax ; lives in ℝᵐ; dim = rank. Row space C(Aᵀ) — span of rows; lives in ℝⁿ; dim = rank. Null space N(A) — all x with Ax = 0 ; lives in ℝⁿ; dim = n − rank. Left null space N(Aᵀ) — all y with Aᵀy = 0 ; lives in ℝᵐ; dim = m − rank.","detailHtml":"\n          \n          <p>For an m×n matrix A:</p>\n          <ul class=\"styled\">\n            <li><strong>Column space C(A)</strong> — span of columns; all outputs <code>Ax</code>; lives in ℝᵐ; dim = rank.</li>\n            <li><strong>Row space C(Aᵀ)</strong> — span of rows; lives in ℝⁿ; dim = rank.</li>\n            <li><strong>Null space N(A)</strong> — all x with <code>Ax = 0</code>; lives in ℝⁿ; dim = n − rank.</li>\n            <li><strong>Left null space N(Aᵀ)</strong> — all y with <code>Aᵀy = 0</code>; lives in ℝᵐ; dim = m − rank.</li>\n          </ul>\n        ","question":null},{"id":"la-rank-nullity-033","topicId":"rank-nullity","order":33,"type":"deep-dive","hook":"Four subspaces — table","body":"SubspaceDefinitionLives inDimension Column space C(A)span of columnsℝᵐrank Row space C(Aᵀ)span of rowsℝⁿrank Null space N(A)Ax = 0ℝⁿn − rank Left null space N(Aᵀ)Aᵀy = 0ℝᵐm − rank","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-26","sourceLabel":"Study in Depth","detail":"Subspace Definition Lives in Dimension Column space C(A) span of columns ℝᵐ rank Row space C(Aᵀ) span of rows ℝⁿ rank Null space N(A) Ax = 0 ℝⁿ n − rank Left null space N(Aᵀ) Aᵀy = 0 ℝᵐ m − rank","detailHtml":"\n          \n          <div class=\"tbl-wrap\"><table>\n            <tr><th>Subspace</th><th>Definition</th><th>Lives in</th><th>Dimension</th></tr>\n            <tr><td>Column space C(A)</td><td>span of columns</td><td>ℝᵐ</td><td>rank</td></tr>\n            <tr><td>Row space C(Aᵀ)</td><td>span of rows</td><td>ℝⁿ</td><td>rank</td></tr>\n            <tr><td>Null space N(A)</td><td>Ax = 0</td><td>ℝⁿ</td><td>n − rank</td></tr>\n            <tr><td>Left null space N(Aᵀ)</td><td>Aᵀy = 0</td><td>ℝᵐ</td><td>m − rank</td></tr>\n          </table></div>\n        ","question":null},{"id":"la-rank-nullity-034","topicId":"rank-nullity","order":34,"type":"deep-dive","hook":"Orthogonality of the subspaces","body":"Why? If Ax = 0 then every row · x = 0, so x ⊥ every row ⇒ x ⊥ row space.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-27","sourceLabel":"Study in Depth","detail":"Row space ⊥ Null space (both in ℝⁿ) Column space ⊥ Left null space (both in ℝᵐ) Why? If Ax = 0 then every row · x = 0, so x ⊥ every row ⇒ x ⊥ row space. Trap: do NOT say &quot;column space ⊥ null space&quot; — for m ≠ n they live in different spaces.","detailHtml":"\n          \n          <pre>Row space    ⊥  Null space        (both in ℝⁿ)\nColumn space ⊥  Left null space   (both in ℝᵐ)</pre>\n          <p><span style=\"color:var(--coral-text)\">Why?</span> If <code>Ax = 0</code> then every row · x = 0, so x ⊥ every row ⇒ x ⊥ row space.</p>\n          <p><span style=\"color:var(--coral-text)\">Trap:</span> do NOT say &quot;column space ⊥ null space&quot; — for m ≠ n they live in different spaces.</p>\n        ","question":null},{"id":"la-rank-nullity-035","topicId":"rank-nullity","order":35,"type":"worked-example","hook":"Worked: rank, nullity & null space (2×3)","body":"A = $\\begin{bmatrix}1&2&3\\\\2&4&6\\end{bmatrix}$ (R2 = 2R1) → rank = 1n = 3 columns → nullity = 2x₁ + 2x₂ + 3x₃ = 0 ⇒ x₁ = −2x₂ − 3x₃Null(A) = span{ [−2,1,0], [−3,0,1] } → 2 basis vectorsrank + nullity = 1 + 2 = 3 ✓","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-28","sourceLabel":"Study in Depth","detail":"A = $\\begin{bmatrix}1&amp;2&amp;3\\\\2&amp;4&amp;6\\end{bmatrix}$ (R2 = 2R1) → rank = 1 n = 3 columns → nullity = 2 x₁ + 2x₂ + 3x₃ = 0 ⇒ x₁ = −2x₂ − 3x₃ Null(A) = span{ [−2,1,0], [−3,0,1] } → 2 basis vectors rank + nullity = 1 + 2 = 3 ✓","detailHtml":"\n          \n          <div class=\"math-steps\"><div class=\"ms-line\">A = $\\begin{bmatrix}1&amp;2&amp;3\\\\2&amp;4&amp;6\\end{bmatrix}$   (R2 = 2R1)  → rank = 1</div><div class=\"ms-line\">n = 3 columns → nullity = 2</div><div class=\"ms-line\"></div><div class=\"ms-line\">x₁ + 2x₂ + 3x₃ = 0 ⇒ x₁ = −2x₂ − 3x₃</div><div class=\"ms-line\">Null(A) = span{ [−2,1,0], [−3,0,1] }   → 2 basis vectors</div><div class=\"ms-line\">rank + nullity = 1 + 2 = 3  ✓</div></div>\n        ","question":null},{"id":"la-rank-nullity-036","topicId":"rank-nullity","order":36,"type":"deep-dive","hook":"Rank & nullity for square matrices","body":"So Ax = 0 has a non-trivial solution ⇔ nullity > 0 ⇔ (square) det(A) = 0.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-29","sourceLabel":"Study in Depth","detail":"n×n: rank + nullity = n rank = n → nullity 0, det ≠ 0, invertible, Ax=0 only x=0 rank &lt; n → nullity &gt; 0, det = 0, singular, Ax=0 has non-zero solutions 3×3 with rank 2 → nullity = 1 (one free variable) So Ax = 0 has a non-trivial solution ⇔ nullity &gt; 0 ⇔ (square) det(A) = 0 .","detailHtml":"\n          \n          <pre>n×n:  rank + nullity = n\n\nrank = n → nullity 0, det ≠ 0, invertible, Ax=0 only x=0\nrank &lt; n → nullity &gt; 0, det = 0, singular, Ax=0 has non-zero solutions</pre>\n          <pre>3×3 with rank 2 → nullity = 1 (one free variable)</pre>\n          <p>So <code>Ax = 0</code> has a non-trivial solution ⇔ <code>nullity &gt; 0</code> ⇔ (square) <code>det(A) = 0</code>.</p>\n        ","question":null},{"id":"la-rank-nullity-037","topicId":"rank-nullity","order":37,"type":"deep-dive","hook":"Rank in data & machine learning","body":"For a data matrix (rows = samples, columns = features), rank = number of truly independent features.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-30","sourceLabel":"Study in Depth","detail":"For a data matrix (rows = samples, columns = features), rank = number of truly independent features . features: height, weight, BMI, age BMI depends on height &amp; weight → that column is redundant → dependent columns Low rank ⇒ redundancy / correlated features ⇒ dimensionality can be reduced — this is the basis of PCA, SVD, feature selection .","detailHtml":"\n          \n          <p>For a data matrix (rows = samples, columns = features), rank = <strong>number of truly independent features</strong>.</p>\n          <pre>features: height, weight, BMI, age\nBMI depends on height &amp; weight → that column is redundant → dependent columns</pre>\n          <p>Low rank ⇒ redundancy / correlated features ⇒ dimensionality can be reduced — this is the basis of <strong>PCA, SVD, feature selection</strong>.</p>\n        ","question":null},{"id":"la-rank-nullity-038","topicId":"rank-nullity","order":38,"type":"deep-dive","hook":"Rank in linear regression","body":"If columns of X are dependent, rank(X) < #features → multicollinearity: the parameter solution is non-unique and the model is unstable. Rank tells you whether features are genuinely independent.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-31","sourceLabel":"Study in Depth","detail":"Xβ = y (X = feature matrix) If columns of X are dependent, rank(X) &lt; #features → multicollinearity : the parameter solution is non-unique and the model is unstable. Rank tells you whether features are genuinely independent.","detailHtml":"\n          \n          <pre>Xβ = y   (X = feature matrix)</pre>\n          <p>If columns of X are dependent, <code>rank(X) &lt; #features</code> → <strong>multicollinearity</strong>: the parameter solution is non-unique and the model is unstable. Rank tells you whether features are genuinely independent.</p>\n        ","question":null},{"id":"la-rank-nullity-039","topicId":"rank-nullity","order":39,"type":"deep-dive","hook":"GATE shortcuts","body":"rank = non-zero rows in echelon form = number of pivots. rank ≤ min(m, n); rank(A) = rank(Aᵀ). rank(AB) ≤ min(rank A, rank B). rank + nullity = n (columns). Square: det ≠ 0 ⇔ rank = n ⇔ nullity = 0. Ax=0 has a non-trivial solution ⇔ nullity > 0. Row…","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-32","sourceLabel":"Study in Depth","detail":"rank = non-zero rows in echelon form = number of pivots. rank ≤ min(m, n) ; rank(A) = rank(Aᵀ) . rank(AB) ≤ min(rank A, rank B) . rank + nullity = n (columns). Square: det ≠ 0 ⇔ rank = n ⇔ nullity = 0 . Ax=0 has a non-trivial solution ⇔ nullity &gt; 0. Row space ⊥ null space; column space ⊥ left null space.","detailHtml":"\n          \n          <ul class=\"styled\">\n            <li>rank = non-zero rows in echelon form = number of pivots.</li>\n            <li><code>rank ≤ min(m, n)</code>;   <code>rank(A) = rank(Aᵀ)</code>.</li>\n            <li><code>rank(AB) ≤ min(rank A, rank B)</code>.</li>\n            <li><code>rank + nullity = n</code> (columns).</li>\n            <li>Square: <code>det ≠ 0 ⇔ rank = n ⇔ nullity = 0</code>.</li>\n            <li><code>Ax=0</code> has a non-trivial solution ⇔ nullity &gt; 0.</li>\n            <li>Row space ⊥ null space; column space ⊥ left null space.</li>\n          </ul>\n        ","question":null},{"id":"la-rank-nullity-040","topicId":"rank-nullity","order":40,"type":"deep-dive","hook":"Common GATE traps","body":"rank can exceed the number of rows? No — rank ≤ min(m,n). rank + nullity = number of rows? No — it equals the number of columns. det = 0 ⇒ rank = 0? No — only rank < n (a 3×3 could be rank 1 or 2). rank(AB) = rank(A)·rank(B)? No — it is ≤ min.…","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-33","sourceLabel":"Study in Depth","detail":"rank can exceed the number of rows? No — rank ≤ min(m,n) . rank + nullity = number of rows? No — it equals the number of columns . det = 0 ⇒ rank = 0? No — only rank &lt; n (a 3×3 could be rank 1 or 2). rank(AB) = rank(A)·rank(B)? No — it is ≤ min . nullity = number of zero rows? No — nullity = free variables = columns − rank. column space ⊥ null space (always)? No — row space ⊥ null space.","detailHtml":"\n          \n          <ul class=\"styled\">\n            <li>rank can exceed the number of rows? <strong>No</strong> — <code>rank ≤ min(m,n)</code>.</li>\n            <li>rank + nullity = number of rows? <strong>No</strong> — it equals the number of <em>columns</em>.</li>\n            <li>det = 0 ⇒ rank = 0? <strong>No</strong> — only rank &lt; n (a 3×3 could be rank 1 or 2).</li>\n            <li>rank(AB) = rank(A)·rank(B)? <strong>No</strong> — it is <code>≤ min</code>.</li>\n            <li>nullity = number of zero rows? <strong>No</strong> — nullity = free variables = columns − rank.</li>\n            <li>column space ⊥ null space (always)? <strong>No</strong> — row space ⊥ null space.</li>\n          </ul>\n        ","question":null},{"id":"la-rank-nullity-041","topicId":"rank-nullity","order":41,"type":"deep-dive","hook":"Practice problems","body":"Q1. A = $\\begin{bmatrix}1&2&3\\\\2&4&6\\end{bmatrix}$ — rank & nullity?","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-34","sourceLabel":"Study in Depth","detail":"Q1. A = $\\begin{bmatrix}1&amp;2&amp;3\\\\2&amp;4&amp;6\\end{bmatrix}$ — rank &amp; nullity? R2 = 2R1 → rank 1; columns 3 → nullity 2 Q2. A is 4×7, rank 3 — nullity? nullity = 7 − 3 = 4 Q3. A is 5×3, rank 3 — nullity? nullity = 3 − 3 = 0 (Ax=0 only x=0) Q4. A is 3×3, det ≠ 0 — rank &amp; nullity? rank 3, nullity 0 Q5. A is 6×4 — maximum rank? min(6,4) = 4 Q6. rank 2, 5 columns — nullity? 5 − 2 = 3","detailHtml":"\n          \n          <p class=\"lead\">Q1. A = $\\begin{bmatrix}1&amp;2&amp;3\\\\2&amp;4&amp;6\\end{bmatrix}$ — rank &amp; nullity?</p>\n          <pre>R2 = 2R1 → rank 1; columns 3 → nullity 2</pre>\n          <p class=\"lead\">Q2. A is 4×7, rank 3 — nullity?</p>\n          <pre>nullity = 7 − 3 = 4</pre>\n          <p class=\"lead\">Q3. A is 5×3, rank 3 — nullity?</p>\n          <pre>nullity = 3 − 3 = 0  (Ax=0 only x=0)</pre>\n          <p class=\"lead\">Q4. A is 3×3, det ≠ 0 — rank &amp; nullity?</p>\n          <pre>rank 3, nullity 0</pre>\n          <p class=\"lead\">Q5. A is 6×4 — maximum rank?</p>\n          <pre>min(6,4) = 4</pre>\n          <p class=\"lead\">Q6. rank 2, 5 columns — nullity?</p>\n          <pre>5 − 2 = 3</pre>\n        ","question":null},{"id":"la-rank-nullity-042","topicId":"rank-nullity","order":42,"type":"deep-dive","hook":"Cheatsheet","body":"Rank = independent rows/cols = pivots = dim of column space = dim of row space. Null space = all x with Ax = 0; nullity = its dimension = free variables. rank + nullity = n; rank ≤ min(m,n); rank(A)=rank(Aᵀ). rank(AB) ≤ min(rank A, rank B)…","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-35","sourceLabel":"Study in Depth","detail":"Rank = independent rows/cols = pivots = dim of column space = dim of row space. Null space = all x with Ax = 0; nullity = its dimension = free variables. rank + nullity = n ; rank ≤ min(m,n) ; rank(A)=rank(Aᵀ) . rank(AB) ≤ min(rank A, rank B) ; invertible P,Q ⇒ rank(PAQ)=rank(A) . Square: det ≠ 0 ⇔ rank n ⇔ nullity 0. Row space ⊥ null space; column space ⊥ left null space.","detailHtml":"\n          \n          <ul class=\"styled\">\n            <li>Rank = independent rows/cols = pivots = dim of column space = dim of row space.</li>\n            <li>Null space = all x with Ax = 0; nullity = its dimension = free variables.</li>\n            <li><code>rank + nullity = n</code>;   <code>rank ≤ min(m,n)</code>;   <code>rank(A)=rank(Aᵀ)</code>.</li>\n            <li><code>rank(AB) ≤ min(rank A, rank B)</code>; invertible P,Q ⇒ <code>rank(PAQ)=rank(A)</code>.</li>\n            <li>Square: det ≠ 0 ⇔ rank n ⇔ nullity 0.</li>\n            <li>Row space ⊥ null space; column space ⊥ left null space.</li>\n          </ul>\n        ","question":null},{"id":"la-rank-nullity-043","topicId":"rank-nullity","order":43,"type":"deep-dive","hook":"Best mental model","body":"Input space = all directions before the matrix. Rank = directions that survive; nullity = directions crushed to zero. rank + nullity = total input directions (columns).","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"study-item-36","sourceLabel":"Study in Depth","detail":"Input space = all directions before the matrix. Rank = directions that survive; nullity = directions crushed to zero. rank + nullity = total input directions (columns).","detailHtml":"\n          \n          <ul class=\"styled\">\n            <li><strong>Input space</strong> = all directions before the matrix.</li>\n            <li><strong>Rank</strong> = directions that survive; <strong>nullity</strong> = directions crushed to zero.</li>\n            <li><strong>rank + nullity = total input directions (columns).</strong></li>\n          </ul>\n        ","question":null},{"id":"la-rank-nullity-044","topicId":"rank-nullity","order":44,"type":"cheat-sheet","hook":"$\\operatorname{rank}(A)+\\operatorname{nullity}(A)=n$ (columns).","body":"Memorize this above all.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"cheat-1","sourceLabel":"GATE cheat sheet","detail":"$\\operatorname{rank}(A)+\\operatorname{nullity}(A)=n$ (columns). Memorize this above all.","detailHtml":"<p>$\\operatorname{rank}(A)+\\operatorname{nullity}(A)=n$ (columns). Memorize this above all.</p>","question":null},{"id":"la-rank-nullity-045","topicId":"rank-nullity","order":45,"type":"cheat-sheet","hook":"rank = number of pivots = pivot variables","body":"; nullity = number of free variables.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"cheat-2","sourceLabel":"GATE cheat sheet","detail":"rank = number of pivots = pivot variables ; nullity = number of free variables .","detailHtml":"<p><strong>rank = number of pivots = pivot variables</strong>; <strong>nullity = number of free variables</strong>.</p>","question":null},{"id":"la-rank-nullity-046","topicId":"rank-nullity","order":46,"type":"cheat-sheet","hook":"largest square submatrix with non-zero determinant","body":"are submatrix with non-zero determinant (handy for matrices with parameters).","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"cheat-3","sourceLabel":"GATE cheat sheet","detail":"$\\operatorname{rank}(A)=$ order of the largest square submatrix with non-zero determinant (handy for matrices with parameters).","detailHtml":"<p>$\\operatorname{rank}(A)=$ order of the <strong>largest square submatrix with non-zero determinant</strong> (handy for matrices with parameters).</p>","question":null},{"id":"la-rank-nullity-047","topicId":"rank-nullity","order":47,"type":"cheat-sheet","hook":"$\\operatorname{rank}(A)=\\operatorname{rank}(A^{\\mathsf T})$; rank = number of non-zero eigenvalues only for…","body":"use echelon form.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"cheat-4","sourceLabel":"GATE cheat sheet","detail":"$\\operatorname{rank}(A)=\\operatorname{rank}(A^{\\mathsf T})$; rank = number of non-zero eigenvalues only for diagonalizable cases — safer: use echelon form.","detailHtml":"<p>$\\operatorname{rank}(A)=\\operatorname{rank}(A^{\\mathsf T})$; rank = number of non-zero eigenvalues only for diagonalizable cases — safer: use echelon form.</p>","question":null},{"id":"la-rank-nullity-048","topicId":"rank-nullity","order":48,"type":"cheat-sheet","hook":"$\\operatorname{rank}(AB)\\le\\min(\\operatorname{rank}A,\\operatorname{rank}B)$; multiplying by invertible $P,Q$ keeps…","body":"$\\operatorname{rank}(PAQ)=\\operatorname{rank}(A)$ (row operations preserve rank).","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"cheat-5","sourceLabel":"GATE cheat sheet","detail":"$\\operatorname{rank}(AB)\\le\\min(\\operatorname{rank}A,\\operatorname{rank}B)$; multiplying by invertible $P,Q$ keeps it: $\\operatorname{rank}(PAQ)=\\operatorname{rank}(A)$ (row operations preserve rank).","detailHtml":"<p>$\\operatorname{rank}(AB)\\le\\min(\\operatorname{rank}A,\\operatorname{rank}B)$; multiplying by <em>invertible</em> $P,Q$ keeps it: $\\operatorname{rank}(PAQ)=\\operatorname{rank}(A)$ (row operations preserve rank).</p>","question":null},{"id":"la-rank-nullity-049","topicId":"rank-nullity","order":49,"type":"cheat-sheet","hook":"$\\operatorname{rank}(A^{\\mathsf T}A)=\\operatorname{rank}(AA^{\\mathsf T})=\\operatorname{rank}(A)$ — used in least…","body":"$\\operatorname{rank}(A^{\\mathsf T}A)=\\operatorname{rank}(AA^{\\mathsf T})=\\operatorname{rank}(A)$ — used in least squares, projections, PCA.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"cheat-6","sourceLabel":"GATE cheat sheet","detail":"$\\operatorname{rank}(A^{\\mathsf T}A)=\\operatorname{rank}(AA^{\\mathsf T})=\\operatorname{rank}(A)$ — used in least squares, projections, PCA.","detailHtml":"<p>$\\operatorname{rank}(A^{\\mathsf T}A)=\\operatorname{rank}(AA^{\\mathsf T})=\\operatorname{rank}(A)$ — used in least squares, projections, PCA.</p>","question":null},{"id":"la-rank-nullity-050","topicId":"rank-nullity","order":50,"type":"trap","hook":"columns","body":"Nullity $=m-\\operatorname{rank}$.\" Reality: it's $n-\\operatorname{rank}$ — use the number of columns.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"trap-1","sourceLabel":"Common traps","detail":"Trap: &quot;Nullity $=m-\\operatorname{rank}$.&quot; Reality: it&#x27;s $n-\\operatorname{rank}$ — use the number of columns .","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;Nullity $=m-\\operatorname{rank}$.&quot; <span class=\"right\">Reality:</span> it&#x27;s $n-\\operatorname{rank}$ — use the number of <strong>columns</strong>.</p>","question":null},{"id":"la-rank-nullity-051","topicId":"rank-nullity","order":51,"type":"trap","hook":"Trap","body":"\"Rank can exceed $\\min(m,n)$.\" Reality: never.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"trap-2","sourceLabel":"Common traps","detail":"Trap: &quot;Rank can exceed $\\min(m,n)$.&quot; Reality: never.","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;Rank can exceed $\\min(m,n)$.&quot; <span class=\"right\">Reality:</span> never.</p>","question":null},{"id":"la-rank-nullity-052","topicId":"rank-nullity","order":52,"type":"trap","hook":"Trap","body":"\"$\\det(A)=0$ means $\\operatorname{rank}=0$.\" Reality: it means rank $<n$; a $3\\times3$ singular matrix can have rank 1 or 2.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"trap-3","sourceLabel":"Common traps","detail":"Trap: &quot;$\\det(A)=0$ means $\\operatorname{rank}=0$.&quot; Reality: it means rank $&lt;n$; a $3\\times3$ singular matrix can have rank 1 or 2.","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;$\\det(A)=0$ means $\\operatorname{rank}=0$.&quot; <span class=\"right\">Reality:</span> it means rank $&lt;n$; a $3\\times3$ singular matrix can have rank 1 or 2.</p>","question":null},{"id":"la-rank-nullity-053","topicId":"rank-nullity","order":53,"type":"trap","hook":"Trap","body":"\"$\\operatorname{rank}(AB)=\\operatorname{rank}A\\cdot\\operatorname{rank}B$ or $\\operatorname{rank}(A+B)=\\operatorname{rank}A+\\operatorname{rank}B$.\" Reality: both false — only inequalities hold.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"trap-4","sourceLabel":"Common traps","detail":"Trap: &quot;$\\operatorname{rank}(AB)=\\operatorname{rank}A\\cdot\\operatorname{rank}B$ or $\\operatorname{rank}(A+B)=\\operatorname{rank}A+\\operatorname{rank}B$.&quot; Reality: both false — only inequalities hold.","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;$\\operatorname{rank}(AB)=\\operatorname{rank}A\\cdot\\operatorname{rank}B$ or $\\operatorname{rank}(A+B)=\\operatorname{rank}A+\\operatorname{rank}B$.&quot; <span class=\"right\">Reality:</span> both false — only inequalities hold.</p>","question":null},{"id":"la-rank-nullity-054","topicId":"rank-nullity","order":54,"type":"trap","hook":"Trap","body":"\"Nullity = number of zero rows.\" Reality: nullity = free variables = columns $-$ rank.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"trap-5","sourceLabel":"Common traps","detail":"Trap: &quot;Nullity = number of zero rows.&quot; Reality: nullity = free variables = columns $-$ rank.","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;Nullity = number of zero rows.&quot; <span class=\"right\">Reality:</span> nullity = free variables = columns $-$ rank.</p>","question":null},{"id":"la-rank-nullity-055","topicId":"rank-nullity","order":55,"type":"practice","hook":"Q1. A $5\\times8$ matrix has rank 3. Find its nullity.","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"practice-1","sourceLabel":"Practice problems","detail":"Nullity $=n-\\operatorname{rank}=8-3=5$ ($n$ = columns = 8).","detailHtml":"Nullity $=n-\\operatorname{rank}=8-3=5$ ($n$ = columns = 8).","question":{"type":"REVEAL","prompt":"Q1. A $5\\times8$ matrix has rank 3. Find its nullity.","options":[],"answer":true,"explanation":"Nullity $=n-\\operatorname{rank}=8-3=5$ ($n$ = columns = 8).","explanationHtml":"Nullity $=n-\\operatorname{rank}=8-3=5$ ($n$ = columns = 8)."}},{"id":"la-rank-nullity-056","topicId":"rank-nullity","order":56,"type":"practice","hook":"Q2. A $4\\times4$ matrix has rank 4. Is it invertible? What is its nullity?","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"practice-2","sourceLabel":"Practice problems","detail":"Yes, invertible (full rank); nullity $=0$.","detailHtml":"Yes, invertible (full rank); nullity $=0$.","question":{"type":"REVEAL","prompt":"Q2. A $4\\times4$ matrix has rank 4. Is it invertible? What is its nullity?","options":[],"answer":true,"explanation":"Yes, invertible (full rank); nullity $=0$.","explanationHtml":"Yes, invertible (full rank); nullity $=0$."}},{"id":"la-rank-nullity-057","topicId":"rank-nullity","order":57,"type":"practice","hook":"Q3. What is the maximum possible rank of a $3\\times7$ matrix?","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"practice-3","sourceLabel":"Practice problems","detail":"$\\min(3,7)=3$.","detailHtml":"$\\min(3,7)=3$.","question":{"type":"REVEAL","prompt":"Q3. What is the maximum possible rank of a $3\\times7$ matrix?","options":[],"answer":true,"explanation":"$\\min(3,7)=3$.","explanationHtml":"$\\min(3,7)=3$."}},{"id":"la-rank-nullity-058","topicId":"rank-nullity","order":58,"type":"practice","hook":"Q4. $A$ is $4\\times7$ with rank 3. Find the nullity.","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"practice-4","sourceLabel":"Practice problems","detail":"$7-3=4$ (use columns).","detailHtml":"$7-3=4$ (use columns).","question":{"type":"REVEAL","prompt":"Q4. $A$ is $4\\times7$ with rank 3. Find the nullity.","options":[],"answer":true,"explanation":"$7-3=4$ (use columns).","explanationHtml":"$7-3=4$ (use columns)."}},{"id":"la-rank-nullity-059","topicId":"rank-nullity","order":59,"type":"practice","hook":"Q5. $A$ is $5\\times3$ with rank 3. Find the nullity, and what does it say about $Ax=0$?","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"practice-5","sourceLabel":"Practice problems","detail":"$3-3=0$; so $Ax=0$ has only the trivial solution $x=0$.","detailHtml":"$3-3=0$; so $Ax=0$ has only the trivial solution $x=0$.","question":{"type":"REVEAL","prompt":"Q5. $A$ is $5\\times3$ with rank 3. Find the nullity, and what does it say about $Ax=0$?","options":[],"answer":true,"explanation":"$3-3=0$; so $Ax=0$ has only the trivial solution $x=0$.","explanationHtml":"$3-3=0$; so $Ax=0$ has only the trivial solution $x=0$."}},{"id":"la-rank-nullity-060","topicId":"rank-nullity","order":60,"type":"practice","hook":"Q6. $A$ is $3\\times3$ with $\\det(A)=0$. What can you say (and not say) about its rank?","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"practice-6","sourceLabel":"Practice problems","detail":"Rank $&lt;3$ (singular, dependent columns, $Ax=0$ has non-trivial solutions). You can&#x27;t pin the exact rank — it could be 0, 1, or 2 without more info.","detailHtml":"Rank $&lt;3$ (singular, dependent columns, $Ax=0$ has non-trivial solutions). You can&#x27;t pin the exact rank — it could be 0, 1, or 2 without more info.","question":{"type":"REVEAL","prompt":"Q6. $A$ is $3\\times3$ with $\\det(A)=0$. What can you say (and not say) about its rank?","options":[],"answer":true,"explanation":"Rank $<3$ (singular, dependent columns, $Ax=0$ has non-trivial solutions). You can't pin the exact rank — it could be 0, 1, or 2 without more info.","explanationHtml":"Rank $&lt;3$ (singular, dependent columns, $Ax=0$ has non-trivial solutions). You can&#x27;t pin the exact rank — it could be 0, 1, or 2 without more info."}},{"id":"la-rank-nullity-061","topicId":"rank-nullity","order":61,"type":"practice","hook":"A $5\\times8$ matrix $A$ has rank 3. What is its nullity?","body":"Choose an answer, then check the explanation.","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"04-rank-nullity.html","sourceAnchor":"practice-quiz-1","sourceLabel":"Practice quiz","detail":"✅ Correct — $n-\\operatorname{rank}=8-3=5$.","detailHtml":"✅ Correct — $n-\\operatorname{rank}=8-3=5$.","question":{"type":"MCQ","prompt":"A $5\\times8$ matrix $A$ has rank 3. What is its nullity?","options":["A: 2","B: 3","C: 5","D: 8"],"answer":"C","explanation":"✅ Correct — $n-\\operatorname{rank}=8-3=5$.","explanationHtml":"✅ Correct — $n-\\operatorname{rank}=8-3=5$."}},{"id":"la-linear-equations-001","topicId":"linear-equations","order":1,"type":"basic-definition","hook":"System $Ax=b$","body":"$A$ is the coefficient matrix, $x$ the unknowns, $b$ the right-hand side.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"definition-1","sourceLabel":"Basic definitions","detail":"System $Ax=b$: $A$ is the coefficient matrix, $x$ the unknowns, $b$ the right-hand side.","detailHtml":"<p><strong>System $Ax=b$:</strong> $A$ is the coefficient matrix, $x$ the unknowns, $b$ the right-hand side.</p>","question":null},{"id":"la-linear-equations-002","topicId":"linear-equations","order":2,"type":"basic-definition","hook":"Augmented matrix $[A\\,|\\,b]$","body":"$A$ with the $b$ column attached — what you row-reduce.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"definition-2","sourceLabel":"Basic definitions","detail":"Augmented matrix $[A\\,|\\,b]$: $A$ with the $b$ column attached — what you row-reduce.","detailHtml":"<p><strong>Augmented matrix $[A\\,|\\,b]$:</strong> $A$ with the $b$ column attached — what you row-reduce.</p>","question":null},{"id":"la-linear-equations-003","topicId":"linear-equations","order":3,"type":"basic-definition","hook":"Gaussian elimination","body":"row operations that reduce the system to an easily-solved form.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"definition-3","sourceLabel":"Basic definitions","detail":"Gaussian elimination: row operations that reduce the system to an easily-solved form.","detailHtml":"<p><strong>Gaussian elimination:</strong> row operations that reduce the system to an easily-solved form.</p>","question":null},{"id":"la-linear-equations-004","topicId":"linear-equations","order":4,"type":"basic-definition","hook":"Consistent","body":"at least one solution exists. Inconsistent: none.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"definition-4","sourceLabel":"Basic definitions","detail":"Consistent: at least one solution exists. Inconsistent: none.","detailHtml":"<p><strong>Consistent:</strong> at least one solution exists. <strong>Inconsistent:</strong> none.</p>","question":null},{"id":"la-linear-equations-005","topicId":"linear-equations","order":5,"type":"basic-definition","hook":"Unique vs infinite","body":"exactly one solution, or a whole family (when free variables remain).","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"definition-5","sourceLabel":"Basic definitions","detail":"Unique vs infinite: exactly one solution, or a whole family (when free variables remain).","detailHtml":"<p><strong>Unique vs infinite:</strong> exactly one solution, or a whole family (when free variables remain).</p>","question":null},{"id":"la-linear-equations-006","topicId":"linear-equations","order":6,"type":"basic-definition","hook":"Homogeneous","body":"$b=0$ (i.e. $Ax=0$); always has the trivial solution $x=0$.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"definition-6","sourceLabel":"Basic definitions","detail":"Homogeneous: $b=0$ (i.e. $Ax=0$); always has the trivial solution $x=0$.","detailHtml":"<p><strong>Homogeneous:</strong> $b=0$ (i.e. $Ax=0$); always has the <strong>trivial</strong> solution $x=0$.</p>","question":null},{"id":"la-linear-equations-007","topicId":"linear-equations","order":7,"type":"basic-definition","hook":"Free variable","body":"an unknown not pinned down — each one adds a dimension of solutions.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"definition-7","sourceLabel":"Basic definitions","detail":"Free variable: an unknown not pinned down — each one adds a dimension of solutions.","detailHtml":"<p><strong>Free variable:</strong> an unknown not pinned down — each one adds a dimension of solutions.</p>","question":null},{"id":"la-linear-equations-008","topicId":"linear-equations","order":8,"type":"deep-dive","hook":"What is a system of linear equations?","body":"A system is several linear equations together — and the question is always: does a common solution exist, and how many?","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-1","sourceLabel":"Study in Depth","detail":"A system is several linear equations together — and the question is always: does a common solution exist, and how many? x + 2y = 5 2x + 4y = 10 In 2D each equation is a line, so solving asks: where do the lines meet?","detailHtml":"\n          \n          <p>A <strong>system</strong> is several linear equations together — and the question is always: does a common solution exist, and how many?</p>\n          <pre>x + 2y = 5\n2x + 4y = 10</pre>\n          <p>In 2D each equation is a line, so solving asks: <strong>where do the lines meet?</strong></p>\n        ","question":null},{"id":"la-linear-equations-009","topicId":"linear-equations","order":9,"type":"deep-dive","hook":"Matrix form: Ax = b","body":"Every linear system packs into one equation:","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-2","sourceLabel":"Study in Depth","detail":"Every linear system packs into one equation: x + 2y = 5, 3x + 4y = 6 A = $\\begin{bmatrix}1&amp;2\\\\3&amp;4\\end{bmatrix}$, x = $\\begin{bmatrix}x\\\\y\\end{bmatrix}$, b = $\\begin{bmatrix}5\\\\6\\end{bmatrix}$ $\\begin{bmatrix}1&amp;2\\\\3&amp;4\\end{bmatrix}\\begin{bmatrix}x\\\\y\\end{bmatrix} = \\begin{bmatrix}5\\\\6\\end{bmatrix}$ ⇒ Ax = b A = coefficient matrix, x = unknowns, b = constants.","detailHtml":"\n          \n          <p>Every linear system packs into one equation:</p>\n          <div class=\"math-steps\"><div class=\"ms-line\">x + 2y = 5,   3x + 4y = 6</div><div class=\"ms-line\">A = $\\begin{bmatrix}1&amp;2\\\\3&amp;4\\end{bmatrix}$,   x = $\\begin{bmatrix}x\\\\y\\end{bmatrix}$,   b = $\\begin{bmatrix}5\\\\6\\end{bmatrix}$</div><div class=\"ms-line\"></div><div class=\"ms-line\">$\\begin{bmatrix}1&amp;2\\\\3&amp;4\\end{bmatrix}\\begin{bmatrix}x\\\\y\\end{bmatrix} = \\begin{bmatrix}5\\\\6\\end{bmatrix}$   ⇒   Ax = b</div></div>\n          <p><code>A</code> = coefficient matrix, <code>x</code> = unknowns, <code>b</code> = constants.</p>\n        ","question":null},{"id":"la-linear-equations-010","topicId":"linear-equations","order":10,"type":"deep-dive","hook":"The augmented matrix [A|b]","body":"Attach b to A as an extra column:","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-3","sourceLabel":"Study in Depth","detail":"Attach b to A as an extra column: [A | b] = [1 2 | 5 3 4 | 6] Key names: A = coefficient matrix, [A|b] = augmented matrix. Comparing their ranks decides everything.","detailHtml":"\n          \n          <p>Attach b to A as an extra column:</p>\n          <pre>[A | b] = [1  2 | 5\n           3  4 | 6]</pre>\n          <p><span style=\"color:var(--coral-text)\">Key names:</span> <code>A</code> = coefficient matrix, <code>[A|b]</code> = augmented matrix. Comparing their ranks decides everything.</p>\n        ","question":null},{"id":"la-linear-equations-011","topicId":"linear-equations","order":11,"type":"deep-dive","hook":"Game imagination","body":"Each equation is a rule/wall; the solution is the position satisfying all rules at once.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-4","sourceLabel":"Study in Depth","detail":"Each equation is a rule/wall; the solution is the position satisfying all rules at once. No solution = rules contradict Unique solution = exactly one position fits Infinite solutions = many positions fit","detailHtml":"\n          \n          <p>Each equation is a rule/wall; the solution is the position satisfying <strong>all</strong> rules at once.</p>\n          <pre>No solution       = rules contradict\nUnique solution   = exactly one position fits\nInfinite solutions = many positions fit</pre>\n        ","question":null},{"id":"la-linear-equations-012","topicId":"linear-equations","order":12,"type":"deep-dive","hook":"Geometric meaning in 2D","body":"The second of each pair shows the give-away: same left side with a different (or proportional) right side.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-5","sourceLabel":"Study in Depth","detail":"Unique: lines cross once x+y=3 , x−y=1 No soln: parallel, different x+y=3 , x+y=5 Infinite: same line x+2y=5 , 2x+4y=10 The second of each pair shows the give-away: same left side with a different (or proportional) right side.","detailHtml":"\n          \n          <pre>Unique:   lines cross once     x+y=3 , x−y=1\nNo soln:  parallel, different  x+y=3 , x+y=5\nInfinite: same line            x+2y=5 , 2x+4y=10</pre>\n          <p>The second of each pair shows the give-away: same left side with a different (or proportional) right side.</p>\n        ","question":null},{"id":"la-linear-equations-013","topicId":"linear-equations","order":13,"type":"deep-dive","hook":"Geometric meaning in 3D","body":"With three unknowns each equation is a plane:","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-6","sourceLabel":"Study in Depth","detail":"With three unknowns each equation is a plane : planes meet at a point → unique planes meet on a line → infinite planes share no common point → no solution Solving a system is really geometry.","detailHtml":"\n          \n          <p>With three unknowns each equation is a <strong>plane</strong>:</p>\n          <pre>planes meet at a point  → unique\nplanes meet on a line   → infinite\nplanes share no common point → no solution</pre>\n          <p>Solving a system is really geometry.</p>\n        ","question":null},{"id":"la-linear-equations-014","topicId":"linear-equations","order":14,"type":"deep-dive","hook":"The golden rule (rank test)","body":"This single rule answers every system question in GATE.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-7","sourceLabel":"Study in Depth","detail":"r = rank(A) , r&#x27; = rank([A|b]) , n = number of unknowns r ≠ r&#x27; → No solution r = r&#x27; = n → Unique solution r = r&#x27; &lt; n → Infinitely many solutions This single rule answers every system question in GATE.","detailHtml":"\n          \n          <pre>r  = rank(A) ,  r&#x27; = rank([A|b]) ,  n = number of unknowns\n\nr ≠ r&#x27;        → No solution\nr = r&#x27; = n    → Unique solution\nr = r&#x27; &lt; n    → Infinitely many solutions</pre>\n          <p>This single rule answers every system question in GATE.</p>\n        ","question":null},{"id":"la-linear-equations-015","topicId":"linear-equations","order":15,"type":"deep-dive","hook":"Why rank decides the solutions","body":"Rank = number of independent equations; n = number of variables to pin down.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-8","sourceLabel":"Study in Depth","detail":"Rank = number of independent equations ; n = number of variables to pin down. enough independent equations (r = n) → all variables fixed → unique too few (r &lt; n) → free variables remain → infinite [A|b] gains rank over A → a contradiction row → none","detailHtml":"\n          \n          <p>Rank = number of <strong>independent equations</strong>; n = number of variables to pin down.</p>\n          <pre>enough independent equations (r = n)  → all variables fixed → unique\ntoo few (r &lt; n)                       → free variables remain → infinite\n[A|b] gains rank over A               → a contradiction row    → none</pre>\n        ","question":null},{"id":"la-linear-equations-016","topicId":"linear-equations","order":16,"type":"deep-dive","hook":"What each case looks like","body":"Contradiction (r ≠ r'):","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-9","sourceLabel":"Study in Depth","detail":"Contradiction (r ≠ r&#x27;): [0 0 | 5] → 0 = 5 → impossible → no solution All variables fixed (r = r&#x27; = n): 2 independent equations, 2 unknowns → unique Free variable (r = r&#x27; &lt; n): 2 independent equations, 3 unknowns → free variables = n − r = 1 → infinite","detailHtml":"\n          \n          <p class=\"lead\">Contradiction (r ≠ r&#x27;):</p>\n          <pre>[0 0 | 5]  →  0 = 5  →  impossible  →  no solution</pre>\n          <p class=\"lead\">All variables fixed (r = r&#x27; = n):</p>\n          <pre>2 independent equations, 2 unknowns → unique</pre>\n          <p class=\"lead\">Free variable (r = r&#x27; &lt; n):</p>\n          <pre>2 independent equations, 3 unknowns → free variables = n − r = 1 → infinite</pre>\n        ","question":null},{"id":"la-linear-equations-017","topicId":"linear-equations","order":17,"type":"deep-dive","hook":"Gaussian elimination","body":"The main method: row-reduce [A|b] to echelon form using operations that do not change the solution set:","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-10","sourceLabel":"Study in Depth","detail":"The main method: row-reduce [A|b] to echelon form using operations that do not change the solution set : 1. swap two rows 2. multiply a row by a non-zero scalar 3. add a multiple of one row to another 🎮 Imagine: the same mission rewritten with simpler instructions.","detailHtml":"\n          \n          <p>The main method: row-reduce <code>[A|b]</code> to echelon form using operations that <strong>do not change the solution set</strong>:</p>\n          <pre>1. swap two rows\n2. multiply a row by a non-zero scalar\n3. add a multiple of one row to another</pre>\n          <p><span style=\"color:var(--coral-text)\">🎮 Imagine:</span> the same mission rewritten with simpler instructions.</p>\n        ","question":null},{"id":"la-linear-equations-018","topicId":"linear-equations","order":18,"type":"deep-dive","hook":"Row echelon form & back substitution","body":"Once triangular, solve from the bottom up (back substitution): the last row gives the last variable, then substitute upward.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-11","sourceLabel":"Study in Depth","detail":"[1 2 3 | 4 0 1 5 | 6 0 0 2 | 8] Once triangular, solve from the bottom up ( back substitution ): the last row gives the last variable, then substitute upward.","detailHtml":"\n          \n          <pre>[1  2  3 | 4\n 0  1  5 | 6\n 0  0  2 | 8]</pre>\n          <p>Once triangular, solve from the bottom up (<strong>back substitution</strong>): the last row gives the last variable, then substitute upward.</p>\n        ","question":null},{"id":"la-linear-equations-019","topicId":"linear-equations","order":19,"type":"worked-example","hook":"Worked: unique solution","body":"x + y = 3 , x − y = 1$\\begin{bmatrix}1&1&|&3\\\\1&-1&|&1\\end{bmatrix}$ → R2−R1 → $\\begin{bmatrix}1&1&|&3\\\\0&-2&|&-2\\end{bmatrix}$−2y = −2 → y = 1 ; x + 1 = 3 → x = 2rank(A)=rank([A|b])=2=n → unique: x=2, y=1","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-12","sourceLabel":"Study in Depth","detail":"x + y = 3 , x − y = 1 $\\begin{bmatrix}1&amp;1&amp;|&amp;3\\\\1&amp;-1&amp;|&amp;1\\end{bmatrix}$ → R2−R1 → $\\begin{bmatrix}1&amp;1&amp;|&amp;3\\\\0&amp;-2&amp;|&amp;-2\\end{bmatrix}$ −2y = −2 → y = 1 ; x + 1 = 3 → x = 2 rank(A)=rank([A|b])=2=n → unique: x=2, y=1","detailHtml":"\n          \n          <div class=\"math-steps\"><div class=\"ms-line\">x + y = 3 , x − y = 1</div><div class=\"ms-line\">$\\begin{bmatrix}1&amp;1&amp;|&amp;3\\\\1&amp;-1&amp;|&amp;1\\end{bmatrix}$  →  R2−R1  →  $\\begin{bmatrix}1&amp;1&amp;|&amp;3\\\\0&amp;-2&amp;|&amp;-2\\end{bmatrix}$</div><div class=\"ms-line\"></div><div class=\"ms-line\">−2y = −2 → y = 1 ;  x + 1 = 3 → x = 2</div><div class=\"ms-line\"></div><div class=\"ms-line\">rank(A)=rank([A|b])=2=n  →  unique:  x=2, y=1</div></div>\n        ","question":null},{"id":"la-linear-equations-020","topicId":"linear-equations","order":20,"type":"worked-example","hook":"Worked: infinitely many solutions","body":"x + 2y = 5 , 2x + 4y = 10$\\begin{bmatrix}1&2&|&5\\\\2&4&|&10\\end{bmatrix}$ → R2−2R1 → $\\begin{bmatrix}1&2&|&5\\\\0&0&|&0\\end{bmatrix}$rank = rank' = 1 < 2 → infinitelet y = t: x = 5 − 2t$\\begin{bmatrix}x\\\\y\\end{bmatrix}$ =…","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-13","sourceLabel":"Study in Depth","detail":"x + 2y = 5 , 2x + 4y = 10 $\\begin{bmatrix}1&amp;2&amp;|&amp;5\\\\2&amp;4&amp;|&amp;10\\end{bmatrix}$ → R2−2R1 → $\\begin{bmatrix}1&amp;2&amp;|&amp;5\\\\0&amp;0&amp;|&amp;0\\end{bmatrix}$ rank = rank&#x27; = 1 &lt; 2 → infinite let y = t: x = 5 − 2t $\\begin{bmatrix}x\\\\y\\end{bmatrix}$ = $\\begin{bmatrix}5\\\\0\\end{bmatrix}$ + t·$\\begin{bmatrix}-2\\\\1\\end{bmatrix}$, t ∈ ℝ","detailHtml":"\n          \n          <div class=\"math-steps\"><div class=\"ms-line\">x + 2y = 5 , 2x + 4y = 10</div><div class=\"ms-line\">$\\begin{bmatrix}1&amp;2&amp;|&amp;5\\\\2&amp;4&amp;|&amp;10\\end{bmatrix}$  →  R2−2R1  →  $\\begin{bmatrix}1&amp;2&amp;|&amp;5\\\\0&amp;0&amp;|&amp;0\\end{bmatrix}$</div><div class=\"ms-line\"></div><div class=\"ms-line\">rank = rank&#x27; = 1 &lt; 2  →  infinite</div><div class=\"ms-line\">let y = t:  x = 5 − 2t</div><div class=\"ms-line\"></div><div class=\"ms-line\">$\\begin{bmatrix}x\\\\y\\end{bmatrix}$ = $\\begin{bmatrix}5\\\\0\\end{bmatrix}$ + t·$\\begin{bmatrix}-2\\\\1\\end{bmatrix}$,   t ∈ ℝ</div></div>\n        ","question":null},{"id":"la-linear-equations-021","topicId":"linear-equations","order":21,"type":"worked-example","hook":"Worked: no solution","body":"x + 2y = 5 , 2x + 4y = 11$\\begin{bmatrix}1&2&|&5\\\\2&4&|&11\\end{bmatrix}$ → R2−2R1 → $\\begin{bmatrix}1&2&|&5\\\\0&0&|&1\\end{bmatrix}$last row: 0 = 1 → impossiblerank(A)=1 ≠ rank([A|b])=2 → no solution","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-14","sourceLabel":"Study in Depth","detail":"x + 2y = 5 , 2x + 4y = 11 $\\begin{bmatrix}1&amp;2&amp;|&amp;5\\\\2&amp;4&amp;|&amp;11\\end{bmatrix}$ → R2−2R1 → $\\begin{bmatrix}1&amp;2&amp;|&amp;5\\\\0&amp;0&amp;|&amp;1\\end{bmatrix}$ last row: 0 = 1 → impossible rank(A)=1 ≠ rank([A|b])=2 → no solution","detailHtml":"\n          \n          <div class=\"math-steps\"><div class=\"ms-line\">x + 2y = 5 , 2x + 4y = 11</div><div class=\"ms-line\">$\\begin{bmatrix}1&amp;2&amp;|&amp;5\\\\2&amp;4&amp;|&amp;11\\end{bmatrix}$  →  R2−2R1  →  $\\begin{bmatrix}1&amp;2&amp;|&amp;5\\\\0&amp;0&amp;|&amp;1\\end{bmatrix}$</div><div class=\"ms-line\"></div><div class=\"ms-line\">last row: 0 = 1  →  impossible</div><div class=\"ms-line\">rank(A)=1 ≠ rank([A|b])=2  →  no solution</div></div>\n        ","question":null},{"id":"la-linear-equations-022","topicId":"linear-equations","order":22,"type":"deep-dive","hook":"Homogeneous systems Ax = 0","body":"When the right side is all zeros, Ax = 0 always has the trivial solution x = 0.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-15","sourceLabel":"Study in Depth","detail":"When the right side is all zeros, Ax = 0 always has the trivial solution x = 0. x + 2y = 0 , 3x + 4y = 0 → x = 0, y = 0 always works The real question is whether a non-trivial (non-zero) solution also exists.","detailHtml":"\n          \n          <p>When the right side is all zeros, <code>Ax = 0</code> <strong>always</strong> has the <strong>trivial solution</strong> x = 0.</p>\n          <pre>x + 2y = 0 , 3x + 4y = 0   →   x = 0, y = 0 always works</pre>\n          <p>The real question is whether a <strong>non-trivial</strong> (non-zero) solution also exists.</p>\n        ","question":null},{"id":"la-linear-equations-023","topicId":"linear-equations","order":23,"type":"deep-dive","hook":"Trivial vs non-trivial solution","body":"GATE asks: \"does Ax = 0 have a non-trivial solution?\" = is there a non-zero x with Ax = 0?","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-16","sourceLabel":"Study in Depth","detail":"trivial: x = 0 (all variables zero) non-trivial: at least one variable ≠ 0 (e.g. x=2, y=−1) GATE asks: &quot;does Ax = 0 have a non-trivial solution?&quot; = is there a non-zero x with Ax = 0 ?","detailHtml":"\n          \n          <pre>trivial:     x = 0  (all variables zero)\nnon-trivial: at least one variable ≠ 0  (e.g. x=2, y=−1)</pre>\n          <p>GATE asks: &quot;does <code>Ax = 0</code> have a non-trivial solution?&quot; = is there a non-zero x with <code>Ax = 0</code>?</p>\n        ","question":null},{"id":"la-linear-equations-024","topicId":"linear-equations","order":24,"type":"deep-dive","hook":"Homogeneous golden rule","body":"Because rank + nullity = n: if rank = n then nullity = 0 (no free variable → only x = 0). If rank < n, free variables exist → non-trivial solutions.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-17","sourceLabel":"Study in Depth","detail":"Ax = 0 has ONLY the trivial solution ⟺ rank(A) = n Because rank + nullity = n : if rank = n then nullity = 0 (no free variable → only x = 0). If rank &lt; n , free variables exist → non-trivial solutions.","detailHtml":"\n          \n          <pre>Ax = 0 has ONLY the trivial solution  ⟺  rank(A) = n</pre>\n          <p>Because <code>rank + nullity = n</code>: if rank = n then nullity = 0 (no free variable → only x = 0). If <code>rank &lt; n</code>, free variables exist → non-trivial solutions.</p>\n        ","question":null},{"id":"la-linear-equations-025","topicId":"linear-equations","order":25,"type":"deep-dive","hook":"Homogeneous system for a square matrix","body":"For n×n A, these are all equivalent:","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-18","sourceLabel":"Study in Depth","detail":"For n×n A, these are all equivalent: Ax = 0 only trivial ⟺ rank = n ⟺ det(A) ≠ 0 ⟺ invertible ⟺ columns independent ⟺ nullity 0 And the opposite chain: Ax = 0 has non-trivial ⟺ rank &lt; n ⟺ det(A) = 0 ⟺ singular","detailHtml":"\n          \n          <p>For n×n A, these are all equivalent:</p>\n          <pre>Ax = 0 only trivial  ⟺  rank = n  ⟺  det(A) ≠ 0\n                     ⟺  invertible ⟺ columns independent ⟺ nullity 0</pre>\n          <p>And the opposite chain:</p>\n          <pre>Ax = 0 has non-trivial  ⟺  rank &lt; n  ⟺  det(A) = 0  ⟺  singular</pre>\n        ","question":null},{"id":"la-linear-equations-026","topicId":"linear-equations","order":26,"type":"deep-dive","hook":"Non-homogeneous systems (b ≠ 0)","body":"With b ≠ 0, a solution is not guaranteed — Ax = b may have none, one, or infinitely many solutions (unlike the homogeneous case, which always has at least x = 0).","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-19","sourceLabel":"Study in Depth","detail":"With b ≠ 0 , a solution is not guaranteed — Ax = b may have none, one, or infinitely many solutions (unlike the homogeneous case, which always has at least x = 0).","detailHtml":"\n          \n          <p>With <code>b ≠ 0</code>, a solution is <strong>not</strong> guaranteed — <code>Ax = b</code> may have <strong>none, one, or infinitely many</strong> solutions (unlike the homogeneous case, which always has at least x = 0).</p>\n        ","question":null},{"id":"la-linear-equations-027","topicId":"linear-equations","order":27,"type":"deep-dive","hook":"Solution structure: x = xₚ + xₕ","body":"One real solution, plus every \"invisible\" null-space move that doesn't change the output.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-20","sourceLabel":"Study in Depth","detail":"x = xₚ + xₕ xₚ = one particular solution of Ax = b xₕ = any solution of Ax = 0 (the null space) One real solution, plus every &quot;invisible&quot; null-space move that doesn&#x27;t change the output.","detailHtml":"\n          \n          <pre>x = xₚ + xₕ\nxₚ = one particular solution of Ax = b\nxₕ = any solution of Ax = 0  (the null space)</pre>\n          <p>One real solution, plus every &quot;invisible&quot; null-space move that doesn&#x27;t change the output.</p>\n        ","question":null},{"id":"la-linear-equations-028","topicId":"linear-equations","order":28,"type":"deep-dive","hook":"Why x = xₚ + xₕ works","body":"So once you have one solution, adding any null-space vector keeps you a solution — the full solution set is a shifted null space.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-21","sourceLabel":"Study in Depth","detail":"A xₚ = b , A xₕ = 0 A(xₚ + xₕ) = Axₚ + Axₕ = b + 0 = b ✓ So once you have one solution, adding any null-space vector keeps you a solution — the full solution set is a shifted null space .","detailHtml":"\n          \n          <pre>A xₚ = b ,  A xₕ = 0\nA(xₚ + xₕ) = Axₚ + Axₕ = b + 0 = b  ✓</pre>\n          <p>So once you have one solution, adding any null-space vector keeps you a solution — the full solution set is a <strong>shifted null space</strong>.</p>\n        ","question":null},{"id":"la-linear-equations-029","topicId":"linear-equations","order":29,"type":"worked-example","hook":"Example of the solution structure","body":"general = particular + homogeneous.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-22","sourceLabel":"Study in Depth","detail":"x + 2y = 5 → $\\begin{bmatrix}x\\\\y\\end{bmatrix}$ = $\\begin{bmatrix}5\\\\0\\end{bmatrix}$ + t·$\\begin{bmatrix}-2\\\\1\\end{bmatrix}$ xₚ = $\\begin{bmatrix}5\\\\0\\end{bmatrix}$ (check: 5 + 2·0 = 5 ✓) xₕ = t·$\\begin{bmatrix}-2\\\\1\\end{bmatrix}$ (solves x + 2y = 0) general = particular + homogeneous.","detailHtml":"\n          \n          <div class=\"math-steps\"><div class=\"ms-line\">x + 2y = 5  →  $\\begin{bmatrix}x\\\\y\\end{bmatrix}$ = $\\begin{bmatrix}5\\\\0\\end{bmatrix}$ + t·$\\begin{bmatrix}-2\\\\1\\end{bmatrix}$</div><div class=\"ms-line\"></div><div class=\"ms-line\">xₚ = $\\begin{bmatrix}5\\\\0\\end{bmatrix}$      (check: 5 + 2·0 = 5 ✓)</div><div class=\"ms-line\">xₕ = t·$\\begin{bmatrix}-2\\\\1\\end{bmatrix}$   (solves x + 2y = 0)</div></div>\n          <p>general = particular + homogeneous.</p>\n        ","question":null},{"id":"la-linear-equations-030","topicId":"linear-equations","order":30,"type":"deep-dive","hook":"Free variables and pivot variables","body":"Free variables = n − rank(A); if any exist (and the system is consistent), there are infinitely many solutions.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-23","sourceLabel":"Study in Depth","detail":"x₁ + 2x₂ + 3x₃ = 5 x₂ + 4x₃ = 6 pivot variables: x₁, x₂ → count = rank free variable: x₃ → count = nullity = n − rank Free variables = n − rank(A) ; if any exist (and the system is consistent), there are infinitely many solutions.","detailHtml":"\n          \n          <pre>x₁ + 2x₂ + 3x₃ = 5\n        x₂ + 4x₃ = 6\n\npivot variables: x₁, x₂   → count = rank\nfree variable:   x₃       → count = nullity = n − rank</pre>\n          <p>Free variables = <code>n − rank(A)</code>; if any exist (and the system is consistent), there are infinitely many solutions.</p>\n        ","question":null},{"id":"la-linear-equations-031","topicId":"linear-equations","order":31,"type":"worked-example","hook":"Worked: 3-variable unique solution","body":"x+y+z=6 , 2x+3y+z=11 , x+2y+3z=14R2−2R1, R3−R1 → $\\begin{bmatrix}1&1&1|6\\\\0&1&-1|-1\\\\0&1&2|8\\end{bmatrix}$R3−R2 → $\\begin{bmatrix}1&1&1|6\\\\0&1&-1|-1\\\\0&0&3|9\\end{bmatrix}$3z = 9 → z = 3 ; y − 3 = −1 → y = 2 ; x + 5 = 6 → x = 1rank = rank' = 3 = n →…","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-24","sourceLabel":"Study in Depth","detail":"x+y+z=6 , 2x+3y+z=11 , x+2y+3z=14 R2−2R1, R3−R1 → $\\begin{bmatrix}1&amp;1&amp;1|6\\\\0&amp;1&amp;-1|-1\\\\0&amp;1&amp;2|8\\end{bmatrix}$ R3−R2 → $\\begin{bmatrix}1&amp;1&amp;1|6\\\\0&amp;1&amp;-1|-1\\\\0&amp;0&amp;3|9\\end{bmatrix}$ 3z = 9 → z = 3 ; y − 3 = −1 → y = 2 ; x + 5 = 6 → x = 1 rank = rank&#x27; = 3 = n → unique: (1, 2, 3)","detailHtml":"\n          \n          <div class=\"math-steps\"><div class=\"ms-line\">x+y+z=6 , 2x+3y+z=11 , x+2y+3z=14</div><div class=\"ms-line\">R2−2R1, R3−R1 → $\\begin{bmatrix}1&amp;1&amp;1|6\\\\0&amp;1&amp;-1|-1\\\\0&amp;1&amp;2|8\\end{bmatrix}$</div><div class=\"ms-line\">R3−R2          → $\\begin{bmatrix}1&amp;1&amp;1|6\\\\0&amp;1&amp;-1|-1\\\\0&amp;0&amp;3|9\\end{bmatrix}$</div><div class=\"ms-line\"></div><div class=\"ms-line\">3z = 9 → z = 3 ;  y − 3 = −1 → y = 2 ;  x + 5 = 6 → x = 1</div><div class=\"ms-line\">rank = rank&#x27; = 3 = n → unique:  (1, 2, 3)</div></div>\n        ","question":null},{"id":"la-linear-equations-032","topicId":"linear-equations","order":32,"type":"deep-dive","hook":"Overdetermined & underdetermined systems","body":"Overdetermined: more equations than unknowns (A is 5×2) → often NO exact solution → least squares (regression) Underdetermined: fewer equations than unknowns (A is 2×5) → if consistent, infinitely many solutions (free variables)","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-25","sourceLabel":"Study in Depth","detail":"Overdetermined: more equations than unknowns (A is 5×2) → often NO exact solution → least squares (regression) Underdetermined: fewer equations than unknowns (A is 2×5) → if consistent, infinitely many solutions (free variables)","detailHtml":"\n          \n          <pre>Overdetermined: more equations than unknowns (A is 5×2)\n   → often NO exact solution → least squares (regression)\n\nUnderdetermined: fewer equations than unknowns (A is 2×5)\n   → if consistent, infinitely many solutions (free variables)</pre>\n        ","question":null},{"id":"la-linear-equations-033","topicId":"linear-equations","order":33,"type":"deep-dive","hook":"More unknowns than equations (key result)","body":"For Ax = 0 with n > m (more unknowns than equations):","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-26","sourceLabel":"Study in Depth","detail":"For Ax = 0 with n &gt; m (more unknowns than equations): rank(A) ≤ m &lt; n ⇒ rank &lt; n ⇒ nullity &gt; 0 ⇒ a non-trivial solution ALWAYS exists e.g. 2 equations, 3 unknowns → Ax = 0 has non-zero solutions","detailHtml":"\n          \n          <p>For <code>Ax = 0</code> with <code>n &gt; m</code> (more unknowns than equations):</p>\n          <pre>rank(A) ≤ m &lt; n  ⇒  rank &lt; n  ⇒  nullity &gt; 0\n⇒  a non-trivial solution ALWAYS exists</pre>\n          <pre>e.g. 2 equations, 3 unknowns → Ax = 0 has non-zero solutions</pre>\n        ","question":null},{"id":"la-linear-equations-034","topicId":"linear-equations","order":34,"type":"deep-dive","hook":"Square system Ax = b","body":"A is n×n: det(A) ≠ 0 → unique solution for EVERY b (x = A⁻¹b) det(A) = 0 → not unique: no solution OR infinitely many (depends on b) for Ax = 0 specifically → infinitely many","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-27","sourceLabel":"Study in Depth","detail":"A is n×n: det(A) ≠ 0 → unique solution for EVERY b (x = A⁻¹b) det(A) = 0 → not unique: no solution OR infinitely many (depends on b) for Ax = 0 specifically → infinitely many","detailHtml":"\n          \n          <pre>A is n×n:\ndet(A) ≠ 0 → unique solution for EVERY b  (x = A⁻¹b)\ndet(A) = 0 → not unique: no solution OR infinitely many (depends on b)\n              for Ax = 0 specifically → infinitely many</pre>\n        ","question":null},{"id":"la-linear-equations-035","topicId":"linear-equations","order":35,"type":"deep-dive","hook":"Consistent vs inconsistent & row types","body":"Watch these rows after reduction:","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-28","sourceLabel":"Study in Depth","detail":"consistent ⟺ rank(A) = rank([A|b]) (a solution exists) inconsistent ⟺ rank(A) ≠ rank([A|b]) (no solution) Watch these rows after reduction: [0 0 0 | 5] contradiction → no solution [0 0 0 | 0] no new info → dependency / free variables [0 1 3 | 4] pivot row → useful equation","detailHtml":"\n          \n          <pre>consistent   ⟺ rank(A) = rank([A|b])   (a solution exists)\ninconsistent ⟺ rank(A) ≠ rank([A|b])   (no solution)</pre>\n          <p class=\"lead\">Watch these rows after reduction:</p>\n          <pre>[0 0 0 | 5]  contradiction → no solution\n[0 0 0 | 0]  no new info   → dependency / free variables\n[0 1 3 | 4]  pivot row     → useful equation</pre>\n        ","question":null},{"id":"la-linear-equations-036","topicId":"linear-equations","order":36,"type":"deep-dive","hook":"Reduced row echelon form (RREF)","body":"Gauss–Jordan goes one step further than echelon form, making pivots 1 with zeros above and below:","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-29","sourceLabel":"Study in Depth","detail":"Gauss–Jordan goes one step further than echelon form, making pivots 1 with zeros above and below: [1 0 | 2 0 1 | 1] → reads off directly: x = 2, y = 1","detailHtml":"\n          \n          <p>Gauss–Jordan goes one step further than echelon form, making pivots 1 with zeros above and below:</p>\n          <pre>[1 0 | 2\n 0 1 | 1]   →   reads off directly:  x = 2, y = 1</pre>\n        ","question":null},{"id":"la-linear-equations-037","topicId":"linear-equations","order":37,"type":"deep-dive","hook":"Connection with the column space","body":"Ax is a combination of A's columns: Ax = x₁·col₁ + x₂·col₂ + …. So:","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-30","sourceLabel":"Study in Depth","detail":"Ax is a combination of A&#x27;s columns: Ax = x₁·col₁ + x₂·col₂ + … . So: Ax = b has a solution ⟺ b lies in the column space of A Solving the system = &quot;can b be built from the columns of A?&quot; — the deepest way to see it.","detailHtml":"\n          \n          <p><code>Ax</code> is a combination of A&#x27;s columns: <code>Ax = x₁·col₁ + x₂·col₂ + …</code>. So:</p>\n          <pre>Ax = b has a solution  ⟺  b lies in the column space of A</pre>\n          <p>Solving the system = &quot;can b be built from the columns of A?&quot; — the deepest way to see it.</p>\n        ","question":null},{"id":"la-linear-equations-038","topicId":"linear-equations","order":38,"type":"worked-example","hook":"Column-space example","body":"This matches the rank test exactly.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-31","sourceLabel":"Study in Depth","detail":"A = $\\begin{bmatrix}1&amp;2\\\\2&amp;4\\end{bmatrix}$ (col₂ = 2·col₁ → column space is a line) b = $\\begin{bmatrix}3\\\\6\\end{bmatrix}$ = 3·$\\begin{bmatrix}1\\\\2\\end{bmatrix}$ → in the column space → Ax = b solvable b = $\\begin{bmatrix}3\\\\7\\end{bmatrix}$ → not on that line → no solution This matches the rank test exactly.","detailHtml":"\n          \n          <div class=\"math-steps\"><div class=\"ms-line\">A = $\\begin{bmatrix}1&amp;2\\\\2&amp;4\\end{bmatrix}$   (col₂ = 2·col₁ → column space is a line)</div><div class=\"ms-line\"></div><div class=\"ms-line\">b = $\\begin{bmatrix}3\\\\6\\end{bmatrix}$ = 3·$\\begin{bmatrix}1\\\\2\\end{bmatrix}$  → in the column space → Ax = b solvable</div><div class=\"ms-line\">b = $\\begin{bmatrix}3\\\\7\\end{bmatrix}$            → not on that line   → no solution</div></div>\n          <p>This matches the rank test exactly.</p>\n        ","question":null},{"id":"la-linear-equations-039","topicId":"linear-equations","order":39,"type":"deep-dive","hook":"Connection with the null space","body":"if A xₚ = b, every solution is x = xₚ + z, where A z = 0 (z in Null(A)) nullity 0 → unique solution nullity > 0 → infinitely many (move freely along the null space)","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-32","sourceLabel":"Study in Depth","detail":"if A xₚ = b, every solution is x = xₚ + z, where A z = 0 (z in Null(A)) nullity 0 → unique solution nullity &gt; 0 → infinitely many (move freely along the null space)","detailHtml":"\n          \n          <pre>if A xₚ = b, every solution is  x = xₚ + z,  where A z = 0 (z in Null(A))\n\nnullity 0  → unique solution\nnullity &gt; 0 → infinitely many (move freely along the null space)</pre>\n        ","question":null},{"id":"la-linear-equations-040","topicId":"linear-equations","order":40,"type":"deep-dive","hook":"Number-of-solutions summary","body":"ResultCondition No solutionb ∉ C(A) ; rank(A) ≠ rank([A|b]) Unique solutionb ∈ C(A) ; rank(A) = n ; nullity 0 Infinitely manyb ∈ C(A) ; rank(A) < n ; nullity > 0","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-33","sourceLabel":"Study in Depth","detail":"Result Condition No solution b ∉ C(A) ; rank(A) ≠ rank([A|b]) Unique solution b ∈ C(A) ; rank(A) = n ; nullity 0 Infinitely many b ∈ C(A) ; rank(A) &lt; n ; nullity &gt; 0","detailHtml":"\n          \n          <div class=\"tbl-wrap\"><table>\n            <tr><th>Result</th><th>Condition</th></tr>\n            <tr><td>No solution</td><td>b ∉ C(A) ; rank(A) ≠ rank([A|b])</td></tr>\n            <tr><td>Unique solution</td><td>b ∈ C(A) ; rank(A) = n ; nullity 0</td></tr>\n            <tr><td>Infinitely many</td><td>b ∈ C(A) ; rank(A) &lt; n ; nullity &gt; 0</td></tr>\n          </table></div>\n        ","question":null},{"id":"la-linear-equations-041","topicId":"linear-equations","order":41,"type":"deep-dive","hook":"Where this shows up in GATE DA / ML","body":"Linear regression is a system: Xβ = y (X = data matrix, β = parameters, y = targets). Usually there are far more rows (data points) than columns (parameters), so an exact solution rarely exists.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-34","sourceLabel":"Study in Depth","detail":"Linear regression is a system: Xβ = y (X = data matrix, β = parameters, y = targets). Usually there are far more rows (data points) than columns (parameters), so an exact solution rarely exists. Systems of equations lead directly to least squares, projection, normal equations and optimization .","detailHtml":"\n          \n          <p>Linear regression is a system: <code>Xβ = y</code> (X = data matrix, β = parameters, y = targets). Usually there are far more rows (data points) than columns (parameters), so an exact solution rarely exists.</p>\n          <p>Systems of equations lead directly to <strong>least squares, projection, normal equations and optimization</strong>.</p>\n        ","question":null},{"id":"la-linear-equations-042","topicId":"linear-equations","order":42,"type":"deep-dive","hook":"Least-squares preview","body":"When Ax = b has no exact solution (b outside the column space), find the x that makes Ax closest to b:","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-35","sourceLabel":"Study in Depth","detail":"When Ax = b has no exact solution (b outside the column space), find the x that makes Ax closest to b: minimize || Ax − b ||² ⇔ project b onto the column space of A The full method (projection / normal equations) comes in the Orthogonality and SVD &amp; PCA topics.","detailHtml":"\n          \n          <p>When <code>Ax = b</code> has <strong>no exact solution</strong> (b outside the column space), find the x that makes <code>Ax</code> <em>closest</em> to b:</p>\n          <pre>minimize || Ax − b ||²   ⇔   project b onto the column space of A</pre>\n          <p>The full method (projection / normal equations) comes in the Orthogonality and SVD &amp; PCA topics.</p>\n        ","question":null},{"id":"la-linear-equations-043","topicId":"linear-equations","order":43,"type":"deep-dive","hook":"Common GATE traps","body":"rank(A)=rank([A|b]) ⇒ unique? No — that only guarantees a solution exists; unique also needs rank = n. rank(A) < n ⇒ no solution? No — if consistent it means infinitely many. Homogeneous Ax=0 can have no solution? No — x = 0 always works. Square…","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-36","sourceLabel":"Study in Depth","detail":"rank(A)=rank([A|b]) ⇒ unique? No — that only guarantees a solution exists; unique also needs rank = n . rank(A) &lt; n ⇒ no solution? No — if consistent it means infinitely many. Homogeneous Ax=0 can have no solution? No — x = 0 always works. Square det(A)=0 ⇒ Ax=b has no solution? No — it means not unique (none or infinite). A invertible ⇒ unique solution for every b? True. More unknowns than equations…","detailHtml":"\n          \n          <ul class=\"styled\">\n            <li><code>rank(A)=rank([A|b])</code> ⇒ unique? <strong>No</strong> — that only guarantees a solution exists; unique also needs <code>rank = n</code>.</li>\n            <li><code>rank(A) &lt; n</code> ⇒ no solution? <strong>No</strong> — if consistent it means infinitely many.</li>\n            <li>Homogeneous <code>Ax=0</code> can have no solution? <strong>No</strong> — x = 0 always works.</li>\n            <li>Square <code>det(A)=0</code> ⇒ <code>Ax=b</code> has no solution? <strong>No</strong> — it means <em>not unique</em> (none or infinite).</li>\n            <li>A invertible ⇒ unique solution for every b? <strong>True.</strong></li>\n            <li>More unknowns than equations (homogeneous) ⇒ non-trivial exists? <strong>True.</strong></li>\n          </ul>\n        ","question":null},{"id":"la-linear-equations-044","topicId":"linear-equations","order":44,"type":"deep-dive","hook":"Practice problems","body":"Q1. r=2, r'=3, n=4?","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-37","sourceLabel":"Study in Depth","detail":"Q1. r=2, r&#x27;=3, n=4? r ≠ r&#x27; → no solution Q2. r=3, r&#x27;=3, n=3? r = r&#x27; = n → unique Q3. r=2, r&#x27;=2, n=5? r = r&#x27; &lt; n → infinite; free variables = 5 − 2 = 3 Q4. A is 3×5, Ax = 0 — only trivial? rank ≤ 3 &lt; 5 → nullity &gt; 0 → non-trivial solutions exist Q5. A is 4×4, det ≠ 0? Ax=b: unique for every b ; Ax=0: only trivial Q6. A is 4×4, det = 0? Ax=0: non-trivial solutions ; Ax=b: none or…","detailHtml":"\n          \n          <p class=\"lead\">Q1. r=2, r&#x27;=3, n=4?</p>\n          <pre>r ≠ r&#x27; → no solution</pre>\n          <p class=\"lead\">Q2. r=3, r&#x27;=3, n=3?</p>\n          <pre>r = r&#x27; = n → unique</pre>\n          <p class=\"lead\">Q3. r=2, r&#x27;=2, n=5?</p>\n          <pre>r = r&#x27; &lt; n → infinite; free variables = 5 − 2 = 3</pre>\n          <p class=\"lead\">Q4. A is 3×5, Ax = 0 — only trivial?</p>\n          <pre>rank ≤ 3 &lt; 5 → nullity &gt; 0 → non-trivial solutions exist</pre>\n          <p class=\"lead\">Q5. A is 4×4, det ≠ 0?</p>\n          <pre>Ax=b: unique for every b ; Ax=0: only trivial</pre>\n          <p class=\"lead\">Q6. A is 4×4, det = 0?</p>\n          <pre>Ax=0: non-trivial solutions ; Ax=b: none or infinitely many</pre>\n        ","question":null},{"id":"la-linear-equations-045","topicId":"linear-equations","order":45,"type":"deep-dive","hook":"Cheatsheet","body":"Write it as Ax = b; compare r = rank(A) and r' = rank([A|b]) with n = unknowns. r ≠ r' → none; r = r' = n → unique; r = r' < n → infinite. Free variables = n − rank(A). Ax=0 always has x = 0; only trivial ⟺ rank = n; non-trivial ⟺ rank < n. Square…","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-38","sourceLabel":"Study in Depth","detail":"Write it as Ax = b ; compare r = rank(A) and r&#x27; = rank([A|b]) with n = unknowns. r ≠ r&#x27; → none; r = r&#x27; = n → unique; r = r&#x27; &lt; n → infinite. Free variables = n − rank(A) . Ax=0 always has x = 0; only trivial ⟺ rank = n; non-trivial ⟺ rank &lt; n. Square: rank = n ⟺ det ≠ 0 ⟺ invertible . General solution x = xₚ + xₕ ; solvable ⟺ b ∈ C(A) .","detailHtml":"\n          \n          <ul class=\"styled\">\n            <li>Write it as <code>Ax = b</code>; compare <code>r = rank(A)</code> and <code>r&#x27; = rank([A|b])</code> with n = unknowns.</li>\n            <li><code>r ≠ r&#x27;</code> → none; <code>r = r&#x27; = n</code> → unique; <code>r = r&#x27; &lt; n</code> → infinite.</li>\n            <li>Free variables = <code>n − rank(A)</code>.</li>\n            <li><code>Ax=0</code> always has x = 0; only trivial ⟺ rank = n; non-trivial ⟺ rank &lt; n.</li>\n            <li>Square: <code>rank = n ⟺ det ≠ 0 ⟺ invertible</code>.</li>\n            <li>General solution <code>x = xₚ + xₕ</code>; solvable ⟺ <code>b ∈ C(A)</code>.</li>\n          </ul>\n        ","question":null},{"id":"la-linear-equations-046","topicId":"linear-equations","order":46,"type":"deep-dive","hook":"Best mental model","body":"So x = xₚ + xₕ = one valid input + invisible moves that don't change the output.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"study-item-39","sourceLabel":"Study in Depth","detail":"A = machine , x = input/control , b = target output Ax = b → find the input x that produces target b No solution = target b is unreachable. Unique = exactly one input reaches b. Infinite = many inputs reach the same b (move along the null space). So x = xₚ + xₕ = one valid input + invisible moves that don&#x27;t change the output.","detailHtml":"\n          \n          <pre>A = machine ,  x = input/control ,  b = target output\nAx = b  →  find the input x that produces target b</pre>\n          <ul class=\"styled\">\n            <li><strong>No solution</strong> = target b is unreachable.</li>\n            <li><strong>Unique</strong> = exactly one input reaches b.</li>\n            <li><strong>Infinite</strong> = many inputs reach the same b (move along the null space).</li>\n          </ul>\n          <p>So <code>x = xₚ + xₕ</code> = one valid input + invisible moves that don&#x27;t change the output.</p>\n        ","question":null},{"id":"la-linear-equations-047","topicId":"linear-equations","order":47,"type":"cheat-sheet","hook":"always","body":"neous $Ax=0$ always has the trivial solution $x=0$.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"cheat-1","sourceLabel":"GATE cheat sheet","detail":"Homogeneous $Ax=0$ always has the trivial solution $x=0$.","detailHtml":"<p>Homogeneous $Ax=0$ <strong>always</strong> has the trivial solution $x=0$.</p>","question":null},{"id":"la-linear-equations-048","topicId":"linear-equations","order":48,"type":"cheat-sheet","hook":"$Ax=0$ has non-trivial solutions $\\iff \\operatorname{rank}(A)<n \\iff \\det A=0$ (square).","body":"$Ax=0$ has non-trivial solutions $\\iff \\operatorname{rank}(A)<n \\iff \\det A=0$ (square).","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"cheat-2","sourceLabel":"GATE cheat sheet","detail":"$Ax=0$ has non-trivial solutions $\\iff \\operatorname{rank}(A)&lt;n \\iff \\det A=0$ (square).","detailHtml":"<p>$Ax=0$ has non-trivial solutions $\\iff \\operatorname{rank}(A)&lt;n \\iff \\det A=0$ (square).</p>","question":null},{"id":"la-linear-equations-049","topicId":"linear-equations","order":49,"type":"cheat-sheet","hook":"Square system has a unique solution for every $b$ $\\iff \\det A\\neq0$.","body":"Square system has a unique solution for every $b$ $\\iff \\det A\\neq0$.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"cheat-3","sourceLabel":"GATE cheat sheet","detail":"Square system has a unique solution for every $b$ $\\iff \\det A\\neq0$.","detailHtml":"<p>Square system has a unique solution for every $b$ $\\iff \\det A\\neq0$.</p>","question":null},{"id":"la-linear-equations-050","topicId":"linear-equations","order":50,"type":"cheat-sheet","hook":"General solution $=$ one particular solution $+$ any null-space vector","body":"$x=x_p+x_h$.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"cheat-4","sourceLabel":"GATE cheat sheet","detail":"General solution $=$ one particular solution $+$ any null-space vector: $x=x_p+x_h$.","detailHtml":"<p>General solution $=$ one particular solution $+$ any null-space vector: $x=x_p+x_h$.</p>","question":null},{"id":"la-linear-equations-051","topicId":"linear-equations","order":51,"type":"cheat-sheet","hook":"Cramer's rule","body":"(small square systems, $\\det A\\neq0$): $x_i=\\dfrac{\\det(A_i)}{\\det(A)}$, where $A_i$ is $A$ with column $i$ replaced by $b$. Clean but costly — use Gaussian elimination for big systems.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"cheat-5","sourceLabel":"GATE cheat sheet","detail":"Cramer&#x27;s rule (small square systems, $\\det A\\neq0$): $x_i=\\dfrac{\\det(A_i)}{\\det(A)}$, where $A_i$ is $A$ with column $i$ replaced by $b$. Clean but costly — use Gaussian elimination for big systems.","detailHtml":"<p><strong>Cramer&#x27;s rule</strong> (small square systems, $\\det A\\neq0$): $x_i=\\dfrac{\\det(A_i)}{\\det(A)}$, where $A_i$ is $A$ with column $i$ replaced by $b$. Clean but costly — use Gaussian elimination for big systems.</p>","question":null},{"id":"la-linear-equations-052","topicId":"linear-equations","order":52,"type":"trap","hook":"Trap","body":"\"$\\det A=0$ means no solution.\" Reality: it means not unique — could be none OR infinite; check $r$ vs $r'$.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"trap-1","sourceLabel":"Common traps","detail":"Trap: &quot;$\\det A=0$ means no solution.&quot; Reality: it means not unique — could be none OR infinite; check $r$ vs $r&#x27;$.","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;$\\det A=0$ means no solution.&quot; <span class=\"right\">Reality:</span> it means <em>not unique</em> — could be none OR infinite; check $r$ vs $r&#x27;$.</p>","question":null},{"id":"la-linear-equations-053","topicId":"linear-equations","order":53,"type":"trap","hook":"Trap","body":"\"Homogeneous systems can be inconsistent.\" Reality: never — $x=0$ always works.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"trap-2","sourceLabel":"Common traps","detail":"Trap: &quot;Homogeneous systems can be inconsistent.&quot; Reality: never — $x=0$ always works.","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;Homogeneous systems can be inconsistent.&quot; <span class=\"right\">Reality:</span> never — $x=0$ always works.</p>","question":null},{"id":"la-linear-equations-054","topicId":"linear-equations","order":54,"type":"trap","hook":"Trap","body":"\"More equations ⇒ no solution.\" Reality: only ranks decide, not the count.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"trap-3","sourceLabel":"Common traps","detail":"Trap: &quot;More equations ⇒ no solution.&quot; Reality: only ranks decide, not the count.","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;More equations ⇒ no solution.&quot; <span class=\"right\">Reality:</span> only ranks decide, not the count.</p>","question":null},{"id":"la-linear-equations-055","topicId":"linear-equations","order":55,"type":"practice","hook":"Q1. $r=2$, $r'=3$, $n=3$. How many solutions?","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"practice-1","sourceLabel":"Practice problems","detail":"$r\\neq r&#x27;$ ⇒ no solution (inconsistent).","detailHtml":"$r\\neq r&#x27;$ ⇒ no solution (inconsistent).","question":{"type":"REVEAL","prompt":"Q1. $r=2$, $r'=3$, $n=3$. How many solutions?","options":[],"answer":true,"explanation":"$r\\neq r'$ ⇒ no solution (inconsistent).","explanationHtml":"$r\\neq r&#x27;$ ⇒ no solution (inconsistent)."}},{"id":"la-linear-equations-056","topicId":"linear-equations","order":56,"type":"practice","hook":"Q2. $r=r'=2$, $n=4$. How many solutions?","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"practice-2","sourceLabel":"Practice problems","detail":"$r=r&#x27;&lt;n$ ⇒ infinitely many, with $4-2=2$ free variables.","detailHtml":"$r=r&#x27;&lt;n$ ⇒ infinitely many, with $4-2=2$ free variables.","question":{"type":"REVEAL","prompt":"Q2. $r=r'=2$, $n=4$. How many solutions?","options":[],"answer":true,"explanation":"$r=r'<n$ ⇒ infinitely many, with $4-2=2$ free variables.","explanationHtml":"$r=r&#x27;&lt;n$ ⇒ infinitely many, with $4-2=2$ free variables."}},{"id":"la-linear-equations-057","topicId":"linear-equations","order":57,"type":"practice","hook":"Q3. When does $Ax=0$ (square $A$) have a non-trivial solution?","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"practice-3","sourceLabel":"Practice problems","detail":"When $\\det A=0$ (equivalently $\\operatorname{rank}&lt;n$).","detailHtml":"When $\\det A=0$ (equivalently $\\operatorname{rank}&lt;n$).","question":{"type":"REVEAL","prompt":"Q3. When does $Ax=0$ (square $A$) have a non-trivial solution?","options":[],"answer":true,"explanation":"When $\\det A=0$ (equivalently $\\operatorname{rank}<n$).","explanationHtml":"When $\\det A=0$ (equivalently $\\operatorname{rank}&lt;n$)."}},{"id":"la-linear-equations-058","topicId":"linear-equations","order":58,"type":"practice","hook":"For which $k$ does $x+2y=3,\\ 2x+ky=7$ have no solution?","body":"Choose an answer, then check the explanation.","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"05-linear-equations.html","sourceAnchor":"practice-quiz-1","sourceLabel":"Practice quiz","detail":"✅ Correct — $\\det=k-4=0$ at $k=4$; then $R_2-2R_1$ gives $[0\\,0\\,|\\,1]$, so $r&#x27;\\neq r$ → no solution.","detailHtml":"✅ Correct — $\\det=k-4=0$ at $k=4$; then $R_2-2R_1$ gives $[0\\,0\\,|\\,1]$, so $r&#x27;\\neq r$ → no solution.","question":{"type":"MCQ","prompt":"For which $k$ does $x+2y=3,\\ 2x+ky=7$ have no solution?","options":["A: $k=3$","B: $k=4$","C: $k=5$","D: $k=6$"],"answer":"B","explanation":"✅ Correct — $\\det=k-4=0$ at $k=4$; then $R_2-2R_1$ gives $[0\\,0\\,|\\,1]$, so $r'\\neq r$ → no solution.","explanationHtml":"✅ Correct — $\\det=k-4=0$ at $k=4$; then $R_2-2R_1$ gives $[0\\,0\\,|\\,1]$, so $r&#x27;\\neq r$ → no solution."}},{"id":"la-eigenvalues-001","topicId":"eigenvalues","order":1,"type":"basic-definition","hook":"Eigenvector","body":"a non-zero vector $x$ with $Ax=\\lambda x$ — its direction is unchanged by $A$.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"definition-1","sourceLabel":"Basic definitions","detail":"Eigenvector: a non-zero vector $x$ with $Ax=\\lambda x$ — its direction is unchanged by $A$.","detailHtml":"<p><strong>Eigenvector:</strong> a non-zero vector $x$ with $Ax=\\lambda x$ — its direction is unchanged by $A$.</p>","question":null},{"id":"la-eigenvalues-002","topicId":"eigenvalues","order":2,"type":"basic-definition","hook":"Eigenvalue $\\lambda$","body":"the stretch factor along that eigenvector.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"definition-2","sourceLabel":"Basic definitions","detail":"Eigenvalue $\\lambda$: the stretch factor along that eigenvector.","detailHtml":"<p><strong>Eigenvalue $\\lambda$:</strong> the stretch factor along that eigenvector.</p>","question":null},{"id":"la-eigenvalues-003","topicId":"eigenvalues","order":3,"type":"basic-definition","hook":"Characteristic equation","body":"$\\det(A-\\lambda I)=0$ — its roots are the eigenvalues.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"definition-3","sourceLabel":"Basic definitions","detail":"Characteristic equation: $\\det(A-\\lambda I)=0$ — its roots are the eigenvalues.","detailHtml":"<p><strong>Characteristic equation:</strong> $\\det(A-\\lambda I)=0$ — its roots are the eigenvalues.</p>","question":null},{"id":"la-eigenvalues-004","topicId":"eigenvalues","order":4,"type":"basic-definition","hook":"Characteristic polynomial","body":"the degree-$n$ polynomial $\\det(A-\\lambda I)$ in $\\lambda$.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"definition-4","sourceLabel":"Basic definitions","detail":"Characteristic polynomial: the degree-$n$ polynomial $\\det(A-\\lambda I)$ in $\\lambda$.","detailHtml":"<p><strong>Characteristic polynomial:</strong> the degree-$n$ polynomial $\\det(A-\\lambda I)$ in $\\lambda$.</p>","question":null},{"id":"la-eigenvalues-005","topicId":"eigenvalues","order":5,"type":"basic-definition","hook":"Eigenspace","body":"all eigenvectors for a given $\\lambda$ (plus zero) — a subspace.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"definition-5","sourceLabel":"Basic definitions","detail":"Eigenspace: all eigenvectors for a given $\\lambda$ (plus zero) — a subspace.","detailHtml":"<p><strong>Eigenspace:</strong> all eigenvectors for a given $\\lambda$ (plus zero) — a subspace.</p>","question":null},{"id":"la-eigenvalues-006","topicId":"eigenvalues","order":6,"type":"basic-definition","hook":"Algebraic vs geometric multiplicity","body":"how often $\\lambda$ repeats as a root vs how many independent eigenvectors it has.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"definition-6","sourceLabel":"Basic definitions","detail":"Algebraic vs geometric multiplicity: how often $\\lambda$ repeats as a root vs how many independent eigenvectors it has.","detailHtml":"<p><strong>Algebraic vs geometric multiplicity:</strong> how often $\\lambda$ repeats as a root vs how many independent eigenvectors it has.</p>","question":null},{"id":"la-eigenvalues-007","topicId":"eigenvalues","order":7,"type":"basic-definition","hook":"Spectrum","body":"the full set of eigenvalues; their sum is the trace and product is the determinant.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"definition-7","sourceLabel":"Basic definitions","detail":"Spectrum: the full set of eigenvalues; their sum is the trace and product is the determinant.","detailHtml":"<p><strong>Spectrum:</strong> the full set of eigenvalues; their sum is the trace and product is the determinant.</p>","question":null},{"id":"la-eigenvalues-008","topicId":"eigenvalues","order":8,"type":"deep-dive","hook":"The core idea","body":"A matrix usually changes a vector's direction. But a few special vectors come out on the same line — only their length changes. Those are eigenvectors; the scaling factor is the eigenvalue.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-1","sourceLabel":"Study in Depth","detail":"A matrix usually changes a vector&#x27;s direction. But a few special vectors come out on the same line — only their length changes. Those are eigenvectors ; the scaling factor is the eigenvalue . A x = λ x (A = matrix, x = eigenvector, λ = eigenvalue) Important: x ≠ 0 — the eigenvector is never the zero vector.","detailHtml":"\n          \n          <p>A matrix usually changes a vector&#x27;s direction. But a few <strong>special vectors</strong> come out on the <em>same line</em> — only their length changes. Those are <strong>eigenvectors</strong>; the scaling factor is the <strong>eigenvalue</strong>.</p>\n          <pre>A x = λ x        (A = matrix, x = eigenvector, λ = eigenvalue)</pre>\n          <p><span style=\"color:var(--coral-text)\">Important:</span> <code>x ≠ 0</code> — the eigenvector is never the zero vector.</p>\n        ","question":null},{"id":"la-eigenvalues-009","topicId":"eigenvalues","order":9,"type":"deep-dive","hook":"What is λ?","body":"λ (\"lambda\") is the eigenvalue = the scaling factor along the eigenvector's direction.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-2","sourceLabel":"Study in Depth","detail":"λ (&quot;lambda&quot;) is the eigenvalue = the scaling factor along the eigenvector&#x27;s direction. λ = 2 doubles λ = 1 unchanged λ = 3 triples λ = 0 collapses to zero λ = 0.5 halves λ = -1 flips direction","detailHtml":"\n          \n          <p><code>λ</code> (&quot;lambda&quot;) is the eigenvalue = the scaling factor along the eigenvector&#x27;s direction.</p>\n          <pre>λ = 2    doubles        λ = 1    unchanged\nλ = 3    triples        λ = 0    collapses to zero\nλ = 0.5  halves         λ = -1   flips direction</pre>\n        ","question":null},{"id":"la-eigenvalues-010","topicId":"eigenvalues","order":10,"type":"deep-dive","hook":"Game imagination","body":"A matrix is a transformation portal. Shoot arrows in: most come out turned. But some special arrows come out on the same line (longer, shorter, or reversed).","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-3","sourceLabel":"Study in Depth","detail":"A matrix is a transformation portal. Shoot arrows in: most come out turned. But some special arrows come out on the same line (longer, shorter, or reversed). eigenvector = special direction eigenvalue = power multiplier in that direction","detailHtml":"\n          \n          <p>A matrix is a transformation portal. Shoot arrows in: most come out turned. But some <strong>special arrows come out on the same line</strong> (longer, shorter, or reversed).</p>\n          <pre>eigenvector = special direction\neigenvalue  = power multiplier in that direction</pre>\n        ","question":null},{"id":"la-eigenvalues-011","topicId":"eigenvalues","order":11,"type":"worked-example","hook":"Simple visual example","body":"The x-axis stretches by 2, the y-axis by 3.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-4","sourceLabel":"Study in Depth","detail":"A = $\\begin{bmatrix}2&amp;0\\\\0&amp;3\\end{bmatrix}$ maps $\\begin{bmatrix}x\\\\y\\end{bmatrix} \\to \\begin{bmatrix}2x\\\\3y\\end{bmatrix}$ A$\\begin{bmatrix}1\\\\0\\end{bmatrix} = \\begin{bmatrix}2\\\\0\\end{bmatrix} = 2\\begin{bmatrix}1\\\\0\\end{bmatrix}$ → eigenvector $\\begin{bmatrix}1\\\\0\\end{bmatrix}$, λ = 2 A$\\begin{bmatrix}0\\\\1\\end{bmatrix} = \\begin{bmatrix}0\\\\3\\end{bmatrix} = 3\\begin{bmatrix}0\\\\1\\end{bmatrix}$ → eigenvector…","detailHtml":"\n          \n          <div class=\"math-steps\"><div class=\"ms-line\">A = $\\begin{bmatrix}2&amp;0\\\\0&amp;3\\end{bmatrix}$   maps   $\\begin{bmatrix}x\\\\y\\end{bmatrix} \\to \\begin{bmatrix}2x\\\\3y\\end{bmatrix}$</div><div class=\"ms-line\"></div><div class=\"ms-line\">A$\\begin{bmatrix}1\\\\0\\end{bmatrix} = \\begin{bmatrix}2\\\\0\\end{bmatrix} = 2\\begin{bmatrix}1\\\\0\\end{bmatrix}$   → eigenvector $\\begin{bmatrix}1\\\\0\\end{bmatrix}$, λ = 2</div><div class=\"ms-line\">A$\\begin{bmatrix}0\\\\1\\end{bmatrix} = \\begin{bmatrix}0\\\\3\\end{bmatrix} = 3\\begin{bmatrix}0\\\\1\\end{bmatrix}$   → eigenvector $\\begin{bmatrix}0\\\\1\\end{bmatrix}$, λ = 3</div></div>\n          <p>The x-axis stretches by 2, the y-axis by 3.</p>\n        ","question":null},{"id":"la-eigenvalues-012","topicId":"eigenvalues","order":12,"type":"deep-dive","hook":"Why eigenvectors matter","body":"Eigenvectors reveal a matrix's natural directions — the ones it only stretches/shrinks. They power PCA, dimensionality reduction, covariance analysis, Markov chains, stability analysis, SVD, spectral clustering, and connect to trace, determinant…","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-5","sourceLabel":"Study in Depth","detail":"Eigenvectors reveal a matrix&#x27;s natural directions — the ones it only stretches/shrinks. They power PCA, dimensionality reduction, covariance analysis, Markov chains, stability analysis, SVD, spectral clustering , and connect to trace, determinant, rank, invertibility and diagonalization.","detailHtml":"\n          \n          <p>Eigenvectors reveal a matrix&#x27;s <strong>natural directions</strong> — the ones it only stretches/shrinks. They power <strong>PCA, dimensionality reduction, covariance analysis, Markov chains, stability analysis, SVD, spectral clustering</strong>, and connect to trace, determinant, rank, invertibility and diagonalization.</p>\n        ","question":null},{"id":"la-eigenvalues-013","topicId":"eigenvalues","order":13,"type":"deep-dive","hook":"The eigenvector cannot be zero","body":"Ax = λx technically holds for x = 0 (both sides 0), but the zero vector has no direction.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-6","sourceLabel":"Study in Depth","detail":"Ax = λx technically holds for x = 0 (both sides 0), but the zero vector has no direction. GATE point: an eigenvector must be non-zero (eigenvalue 0 is allowed; eigenvector 0 is not).","detailHtml":"\n          \n          <p><code>Ax = λx</code> technically holds for <code>x = 0</code> (both sides 0), but the zero vector has no direction.</p>\n          <p><span style=\"color:var(--coral-text)\">GATE point:</span> an eigenvector must be <strong>non-zero</strong> (eigenvalue 0 is allowed; eigenvector 0 is not).</p>\n        ","question":null},{"id":"la-eigenvalues-014","topicId":"eigenvalues","order":14,"type":"deep-dive","hook":"How to find eigenvalues","body":"This homogeneous system has a non-zero solution only if the matrix is singular:","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-7","sourceLabel":"Study in Depth","detail":"Ax = λx Ax − λx = 0 → Ax − λIx = 0 (since Ix = x) (A − λI)x = 0 This homogeneous system has a non-zero solution only if the matrix is singular: det(A − λI) = 0 ← the characteristic equation","detailHtml":"\n          \n          <pre>Ax = λx\nAx − λx = 0   →   Ax − λIx = 0   (since Ix = x)\n(A − λI)x = 0</pre>\n          <p>This homogeneous system has a non-zero solution only if the matrix is singular:</p>\n          <pre>det(A − λI) = 0      ← the characteristic equation</pre>\n        ","question":null},{"id":"la-eigenvalues-015","topicId":"eigenvalues","order":15,"type":"deep-dive","hook":"The step-by-step method","body":"Defined only for square matrices.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-8","sourceLabel":"Study in Depth","detail":"Form A − λI . Compute det(A − λI) . Set it to 0 and solve for λ (the eigenvalues). For each λ, solve (A − λI)x = 0 . The non-zero solutions x are the eigenvectors. Defined only for square matrices.","detailHtml":"\n          \n          <ol class=\"steps\">\n            <li>Form <code>A − λI</code>.</li>\n            <li>Compute <code>det(A − λI)</code>.</li>\n            <li>Set it to 0 and solve for λ (the eigenvalues).</li>\n            <li>For each λ, solve <code>(A − λI)x = 0</code>.</li>\n            <li>The non-zero solutions x are the eigenvectors.</li>\n          </ol>\n          <p>Defined only for <strong>square</strong> matrices.</p>\n        ","question":null},{"id":"la-eigenvalues-016","topicId":"eigenvalues","order":16,"type":"worked-example","hook":"Worked example — eigenvalues","body":"A = [4 1 2 3] A − λI = [4−λ 1 2 3−λ] det = (4−λ)(3−λ) − 2 = λ² − 7λ + 10 = 0 (λ − 5)(λ − 2) = 0 → λ = 5, 2","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-9","sourceLabel":"Study in Depth","detail":"A = [4 1 2 3] A − λI = [4−λ 1 2 3−λ] det = (4−λ)(3−λ) − 2 = λ² − 7λ + 10 = 0 (λ − 5)(λ − 2) = 0 → λ = 5, 2","detailHtml":"\n          \n          <pre>A = [4  1\n     2  3]\n\nA − λI = [4−λ   1\n           2   3−λ]\n\ndet = (4−λ)(3−λ) − 2 = λ² − 7λ + 10 = 0\n(λ − 5)(λ − 2) = 0   →   λ = 5, 2</pre>\n        ","question":null},{"id":"la-eigenvalues-017","topicId":"eigenvalues","order":17,"type":"worked-example","hook":"Worked example — eigenvector for λ = 5","body":"Every non-zero multiple ($\\begin{bmatrix}2\\\\2\\end{bmatrix}$, $\\begin{bmatrix}-5\\\\-5\\end{bmatrix}$, …) is the same eigen-direction.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-10","sourceLabel":"Study in Depth","detail":"A − 5I = $\\begin{bmatrix}-1&amp;1\\\\2&amp;-2\\end{bmatrix}$ −x₁ + x₂ = 0 ⇒ x₂ = x₁ x = t$\\begin{bmatrix}1\\\\1\\end{bmatrix}$ → eigenvector $\\begin{bmatrix}1\\\\1\\end{bmatrix}$ Every non-zero multiple ($\\begin{bmatrix}2\\\\2\\end{bmatrix}$, $\\begin{bmatrix}-5\\\\-5\\end{bmatrix}$, …) is the same eigen-direction.","detailHtml":"\n          \n          <div class=\"math-steps\"><div class=\"ms-line\">A − 5I = $\\begin{bmatrix}-1&amp;1\\\\2&amp;-2\\end{bmatrix}$</div><div class=\"ms-line\"></div><div class=\"ms-line\">−x₁ + x₂ = 0  ⇒  x₂ = x₁</div><div class=\"ms-line\">x = t$\\begin{bmatrix}1\\\\1\\end{bmatrix}$   →  eigenvector $\\begin{bmatrix}1\\\\1\\end{bmatrix}$</div></div>\n          <p>Every non-zero multiple ($\\begin{bmatrix}2\\\\2\\end{bmatrix}$, $\\begin{bmatrix}-5\\\\-5\\end{bmatrix}$, …) is the same eigen-direction.</p>\n        ","question":null},{"id":"la-eigenvalues-018","topicId":"eigenvalues","order":18,"type":"worked-example","hook":"Worked example — eigenvector for λ = 2","body":"Result: direction $\\begin{bmatrix}1\\\\1\\end{bmatrix}$ stretches ×5; direction $\\begin{bmatrix}1\\\\-2\\end{bmatrix}$ stretches ×2.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-11","sourceLabel":"Study in Depth","detail":"A − 2I = $\\begin{bmatrix}2&amp;1\\\\2&amp;1\\end{bmatrix}$ 2x₁ + x₂ = 0 ⇒ x₂ = −2x₁ x = t$\\begin{bmatrix}1\\\\-2\\end{bmatrix}$ → eigenvector $\\begin{bmatrix}1\\\\-2\\end{bmatrix}$ Result: direction $\\begin{bmatrix}1\\\\1\\end{bmatrix}$ stretches ×5; direction $\\begin{bmatrix}1\\\\-2\\end{bmatrix}$ stretches ×2.","detailHtml":"\n          \n          <div class=\"math-steps\"><div class=\"ms-line\">A − 2I = $\\begin{bmatrix}2&amp;1\\\\2&amp;1\\end{bmatrix}$</div><div class=\"ms-line\"></div><div class=\"ms-line\">2x₁ + x₂ = 0  ⇒  x₂ = −2x₁</div><div class=\"ms-line\">x = t$\\begin{bmatrix}1\\\\-2\\end{bmatrix}$   →  eigenvector $\\begin{bmatrix}1\\\\-2\\end{bmatrix}$</div></div>\n          <p><strong>Result:</strong> direction $\\begin{bmatrix}1\\\\1\\end{bmatrix}$ stretches ×5; direction $\\begin{bmatrix}1\\\\-2\\end{bmatrix}$ stretches ×2.</p>\n        ","question":null},{"id":"la-eigenvalues-019","topicId":"eigenvalues","order":19,"type":"deep-dive","hook":"Check with trace & determinant","body":"Shortcut: sum of eigenvalues = trace; product = determinant.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-12","sourceLabel":"Study in Depth","detail":"A = $\\begin{bmatrix}4&amp;1\\\\2&amp;3\\end{bmatrix}$: tr = 4+3 = 7, det = 12−2 = 10 eigenvalues 5, 2: 5+2 = 7 ✓ (= trace), 5×2 = 10 ✓ (= det) Shortcut: sum of eigenvalues = trace; product = determinant.","detailHtml":"\n          \n          <div class=\"math-steps\"><div class=\"ms-line\">A = $\\begin{bmatrix}4&amp;1\\\\2&amp;3\\end{bmatrix}$:  tr = 4+3 = 7,  det = 12−2 = 10</div><div class=\"ms-line\">eigenvalues 5, 2:  5+2 = 7 ✓ (= trace),  5×2 = 10 ✓ (= det)</div></div>\n          <p><span style=\"color:var(--coral-text)\">Shortcut:</span> sum of eigenvalues = trace; product = determinant.</p>\n        ","question":null},{"id":"la-eigenvalues-020","topicId":"eigenvalues","order":20,"type":"deep-dive","hook":"The characteristic polynomial (2×2 fast form)","body":"Much faster than expanding the determinant for 2×2 matrices.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-13","sourceLabel":"Study in Depth","detail":"A = $\\begin{bmatrix}a&amp;b\\\\c&amp;d\\end{bmatrix}$ λ² − tr(A)·λ + det(A) = 0 A = $\\begin{bmatrix}4&amp;1\\\\2&amp;3\\end{bmatrix}$: λ² − 7λ + 10 = 0 → λ = 5, 2 Much faster than expanding the determinant for 2×2 matrices.","detailHtml":"\n          \n          <div class=\"math-steps\"><div class=\"ms-line\">A = $\\begin{bmatrix}a&amp;b\\\\c&amp;d\\end{bmatrix}$</div><div class=\"ms-line\">λ² − tr(A)·λ + det(A) = 0</div></div>\n          <div class=\"math-steps\"><div class=\"ms-line\">A = $\\begin{bmatrix}4&amp;1\\\\2&amp;3\\end{bmatrix}$: λ² − 7λ + 10 = 0  →  λ = 5, 2</div></div>\n          <p>Much faster than expanding the determinant for 2×2 matrices.</p>\n        ","question":null},{"id":"la-eigenvalues-021","topicId":"eigenvalues","order":21,"type":"deep-dive","hook":"Triangular / diagonal eigenvalues (shortcut)","body":"For diagonal, upper- or lower-triangular matrices, the eigenvalues are simply the diagonal entries — no work needed.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-14","sourceLabel":"Study in Depth","detail":"For diagonal, upper- or lower-triangular matrices, the eigenvalues are simply the diagonal entries — no work needed. $\\begin{bmatrix}2&amp;5&amp;7\\\\0&amp;3&amp;8\\\\0&amp;0&amp;4\\end{bmatrix}$ → eigenvalues 2, 3, 4 diag(5, −1, 7) → eigenvalues 5, −1, 7","detailHtml":"\n          \n          <p>For diagonal, upper- or lower-triangular matrices, the <strong>eigenvalues are simply the diagonal entries</strong> — no work needed.</p>\n          <div class=\"math-steps\"><div class=\"ms-line\">$\\begin{bmatrix}2&amp;5&amp;7\\\\0&amp;3&amp;8\\\\0&amp;0&amp;4\\end{bmatrix}$  → eigenvalues 2, 3, 4</div><div class=\"ms-line\">diag(5, −1, 7)         → eigenvalues 5, −1, 7</div></div>\n        ","question":null},{"id":"la-eigenvalues-022","topicId":"eigenvalues","order":22,"type":"deep-dive","hook":"Trace / determinant & the missing eigenvalue","body":"Find a missing eigenvalue:","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-15","sourceLabel":"Study in Depth","detail":"tr(A) = λ₁ + λ₂ + … + λₙ ; det(A) = λ₁·λ₂·…·λₙ Find a missing eigenvalue: 3×3, trace 9, eigenvalues 2, 3, λ₃ → 2+3+λ₃ = 9 → λ₃ = 4 3×3, det 24, eigenvalues 2, 4, λ₃ → 2·4·λ₃ = 24 → λ₃ = 3","detailHtml":"\n          \n          <pre>tr(A) = λ₁ + λ₂ + … + λₙ ;   det(A) = λ₁·λ₂·…·λₙ</pre>\n          <p class=\"lead\">Find a missing eigenvalue:</p>\n          <pre>3×3, trace 9, eigenvalues 2, 3, λ₃  →  2+3+λ₃ = 9 → λ₃ = 4\n3×3, det 24,  eigenvalues 2, 4, λ₃  →  2·4·λ₃ = 24 → λ₃ = 3</pre>\n        ","question":null},{"id":"la-eigenvalues-023","topicId":"eigenvalues","order":23,"type":"deep-dive","hook":"Zero eigenvalue ⟺ singular","body":"Because det = product of eigenvalues: one zero eigenvalue forces det 0 → not invertible, rank < n, Ax=0 has non-trivial solutions.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-16","sourceLabel":"Study in Depth","detail":"0 is an eigenvalue of A ⟺ det(A) = 0 ⟺ A is singular Because det = product of eigenvalues : one zero eigenvalue forces det 0 → not invertible, rank &lt; n, Ax=0 has non-trivial solutions.","detailHtml":"\n          \n          <pre>0 is an eigenvalue of A  ⟺  det(A) = 0  ⟺  A is singular</pre>\n          <p>Because <code>det = product of eigenvalues</code>: one zero eigenvalue forces det 0 → not invertible, rank &lt; n, <code>Ax=0</code> has non-trivial solutions.</p>\n        ","question":null},{"id":"la-eigenvalues-024","topicId":"eigenvalues","order":24,"type":"deep-dive","hook":"How eigenvalues transform (key rules)","body":"If Ax = λx, then for the same eigenvector x:","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-17","sourceLabel":"Study in Depth","detail":"If Ax = λx , then for the same eigenvector x: Aᵏ has eigenvalue λᵏ (A² → λ², A³ → λ³). A⁻¹ has eigenvalue 1/λ (if A is invertible, so λ ≠ 0). A + cI has eigenvalue λ + c . cA has eigenvalue cλ . Aᵀ has the same eigenvalues as A (eigenvectors may differ).","detailHtml":"\n          \n          <p>If <code>Ax = λx</code>, then for the same eigenvector x:</p>\n          <ul class=\"styled\">\n            <li><strong>Aᵏ</strong> has eigenvalue <code>λᵏ</code>  (A² → λ², A³ → λ³).</li>\n            <li><strong>A⁻¹</strong> has eigenvalue <code>1/λ</code> (if A is invertible, so λ ≠ 0).</li>\n            <li><strong>A + cI</strong> has eigenvalue <code>λ + c</code>.</li>\n            <li><strong>cA</strong> has eigenvalue <code>cλ</code>.</li>\n            <li><strong>Aᵀ</strong> has the <em>same</em> eigenvalues as A (eigenvectors may differ).</li>\n          </ul>\n        ","question":null},{"id":"la-eigenvalues-025","topicId":"eigenvalues","order":25,"type":"deep-dive","hook":"Eigenvalues of basic special matrices","body":"Identity I → every eigenvalue = 1 Zero O → every eigenvalue = 0 Diagonal → the diagonal entries Triangular → the diagonal entries","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-18","sourceLabel":"Study in Depth","detail":"Identity I → every eigenvalue = 1 Zero O → every eigenvalue = 0 Diagonal → the diagonal entries Triangular → the diagonal entries","detailHtml":"\n          \n          <pre>Identity I   →  every eigenvalue = 1\nZero O       →  every eigenvalue = 0\nDiagonal     →  the diagonal entries\nTriangular   →  the diagonal entries</pre>\n        ","question":null},{"id":"la-eigenvalues-026","topicId":"eigenvalues","order":26,"type":"deep-dive","hook":"Symmetric matrices (very friendly)","body":"If A = Aᵀ (real symmetric):","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-19","sourceLabel":"Study in Depth","detail":"If A = Aᵀ (real symmetric): all eigenvalues are real ; eigenvectors for distinct eigenvalues are orthogonal ; the matrix is always diagonalizable . Covariance matrices are symmetric — this is the foundation of PCA.","detailHtml":"\n          \n          <p>If <code>A = Aᵀ</code> (real symmetric):</p>\n          <ul class=\"styled\">\n            <li>all eigenvalues are <strong>real</strong>;</li>\n            <li>eigenvectors for <strong>distinct</strong> eigenvalues are <strong>orthogonal</strong>;</li>\n            <li>the matrix is always <strong>diagonalizable</strong>.</li>\n          </ul>\n          <p>Covariance matrices are symmetric — this is the foundation of PCA.</p>\n        ","question":null},{"id":"la-eigenvalues-027","topicId":"eigenvalues","order":27,"type":"deep-dive","hook":"Orthogonal matrices: |λ| = 1","body":"If AᵀA = I, length is preserved, so ||Ax|| = ||x||, giving |λ| = 1.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-20","sourceLabel":"Study in Depth","detail":"If AᵀA = I , length is preserved, so ||Ax|| = ||x|| , giving |λ| = 1 . real orthogonal eigenvalues → +1 or −1 (complex ones lie on the unit circle)","detailHtml":"\n          \n          <p>If <code>AᵀA = I</code>, length is preserved, so <code>||Ax|| = ||x||</code>, giving <code>|λ| = 1</code>.</p>\n          <pre>real orthogonal eigenvalues → +1 or −1\n(complex ones lie on the unit circle)</pre>\n        ","question":null},{"id":"la-eigenvalues-028","topicId":"eigenvalues","order":28,"type":"deep-dive","hook":"Complex eigenvalues","body":"A real matrix can have complex eigenvalues. The 90° rotation has no real eigen-direction:","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-21","sourceLabel":"Study in Depth","detail":"A real matrix can have complex eigenvalues. The 90° rotation has no real eigen-direction: R = [0 −1 1 0] → eigenvalues i and −i Complex eigenvalues of real matrices come in conjugate pairs a ± bi .","detailHtml":"\n          \n          <p>A real matrix can have <strong>complex</strong> eigenvalues. The 90° rotation has no real eigen-direction:</p>\n          <pre>R = [0  −1\n     1   0]   →  eigenvalues  i  and  −i</pre>\n          <p>Complex eigenvalues of real matrices come in conjugate pairs <code>a ± bi</code>.</p>\n        ","question":null},{"id":"la-eigenvalues-029","topicId":"eigenvalues","order":29,"type":"deep-dive","hook":"Eigenvalues in PCA (data meaning)","body":"A covariance matrix is symmetric; its eigenvectors = principal directions and eigenvalues = variance along them.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-22","sourceLabel":"Study in Depth","detail":"A covariance matrix is symmetric; its eigenvectors = principal directions and eigenvalues = variance along them. λ₁ = 100, λ₂ = 5 → data spreads far along direction 1, little along 2 PCA keeps the top eigenvectors. (Full treatment in the SVD &amp; PCA topic.)","detailHtml":"\n          \n          <p>A covariance matrix is symmetric; its <strong>eigenvectors = principal directions</strong> and <strong>eigenvalues = variance</strong> along them.</p>\n          <pre>λ₁ = 100, λ₂ = 5  →  data spreads far along direction 1, little along 2</pre>\n          <p>PCA keeps the top eigenvectors. (Full treatment in the SVD &amp; PCA topic.)</p>\n        ","question":null},{"id":"la-eigenvalues-030","topicId":"eigenvalues","order":30,"type":"deep-dive","hook":"Eigenvalues & stability","body":"Repeatedly applying A (x, Ax, A²x, …) — eigenvalues govern long-term behaviour:","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-23","sourceLabel":"Study in Depth","detail":"Repeatedly applying A ( x, Ax, A²x, … ) — eigenvalues govern long-term behaviour: |λ| &lt; 1 → that direction decays |λ| &gt; 1 → it grows λ &lt; 0 → it flips sign each step Used in dynamical systems, Markov chains and iterative algorithms.","detailHtml":"\n          \n          <p>Repeatedly applying A (<code>x, Ax, A²x, …</code>) — eigenvalues govern long-term behaviour:</p>\n          <pre>|λ| &lt; 1  → that direction decays\n|λ| &gt; 1  → it grows\nλ &lt; 0    → it flips sign each step</pre>\n          <p>Used in dynamical systems, Markov chains and iterative algorithms.</p>\n        ","question":null},{"id":"la-eigenvalues-031","topicId":"eigenvalues","order":31,"type":"deep-dive","hook":"Projection matrices","body":"Projection matrices are idempotent (P² = P), so their eigenvalues are 0 or 1.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-24","sourceLabel":"Study in Depth","detail":"Projection matrices are idempotent ( P² = P ), so their eigenvalues are 0 or 1 . P = $\\begin{bmatrix}1&amp;0\\\\0&amp;0\\end{bmatrix}$: P$\\begin{bmatrix}1\\\\0\\end{bmatrix}$=$\\begin{bmatrix}1\\\\0\\end{bmatrix}$ (λ=1, kept), P$\\begin{bmatrix}0\\\\1\\end{bmatrix}$=$\\begin{bmatrix}0\\\\0\\end{bmatrix}$ (λ=0, destroyed)","detailHtml":"\n          \n          <p>Projection matrices are idempotent (<code>P² = P</code>), so their eigenvalues are <strong>0 or 1</strong>.</p>\n          <div class=\"math-steps\"><div class=\"ms-line\">P = $\\begin{bmatrix}1&amp;0\\\\0&amp;0\\end{bmatrix}$:  P$\\begin{bmatrix}1\\\\0\\end{bmatrix}$=$\\begin{bmatrix}1\\\\0\\end{bmatrix}$ (λ=1, kept),  P$\\begin{bmatrix}0\\\\1\\end{bmatrix}$=$\\begin{bmatrix}0\\\\0\\end{bmatrix}$ (λ=0, destroyed)</div></div>\n        ","question":null},{"id":"la-eigenvalues-032","topicId":"eigenvalues","order":32,"type":"deep-dive","hook":"Definiteness (positive/negative definite)","body":"Classify a symmetric matrix A by the sign of xᵀAx — read straight off its eigenvalues:","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-25","sourceLabel":"Study in Depth","detail":"Classify a symmetric matrix A by the sign of xᵀAx — read straight off its eigenvalues: positive definite (PD): xᵀAx &gt; 0 ∀ x≠0 ⟺ all eigenvalues &gt; 0 positive semidefinite (PSD): xᵀAx ≥ 0 ⟺ all eigenvalues ≥ 0 negative definite: xᵀAx &lt; 0 ⟺ all eigenvalues &lt; 0 indefinite: mixed signs ⟺ eigenvalues of both signs Sylvester&#x27;s criterion: A is PD ⟺ every leading principal minor is &gt; 0. Why it matters…","detailHtml":"\n          \n          <p>Classify a symmetric matrix A by the sign of <code>xᵀAx</code> — read straight off its eigenvalues:</p>\n          <pre>positive definite (PD):      xᵀAx &gt; 0 ∀ x≠0   ⟺  all eigenvalues &gt; 0\npositive semidefinite (PSD): xᵀAx ≥ 0          ⟺  all eigenvalues ≥ 0\nnegative definite:           xᵀAx &lt; 0          ⟺  all eigenvalues &lt; 0\nindefinite:                  mixed signs       ⟺  eigenvalues of both signs</pre>\n          <p><span style=\"color:var(--coral-text)\">Sylvester&#x27;s criterion:</span> A is PD ⟺ every <strong>leading principal minor</strong> is &gt; 0.</p>\n          <p>Why it matters: covariance matrices are PSD; the Hessian&#x27;s definiteness decides minima/maxima in optimization.</p>\n        ","question":null},{"id":"la-eigenvalues-033","topicId":"eigenvalues","order":33,"type":"deep-dive","hook":"Common GATE traps","body":"Zero vector is an eigenvector? No — eigenvectors are non-zero. Every real matrix has real eigenvalues? No — only real symmetric ones are guaranteed real. Eigenvalues of A+B = eigenvalues of A + eigenvalues of B? No (true only for A + cI). det(A)=0 ⇒…","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-26","sourceLabel":"Study in Depth","detail":"Zero vector is an eigenvector? No — eigenvectors are non-zero. Every real matrix has real eigenvalues? No — only real symmetric ones are guaranteed real. Eigenvalues of A+B = eigenvalues of A + eigenvalues of B? No (true only for A + cI ). det(A)=0 ⇒ 0 is an eigenvalue? True. Triangular ⇒ eigenvalues are diagonal entries? True. Idempotent ⇒ λ ∈ {0,1}; nilpotent ⇒ all λ = 0; symmetric ⇒ real λ &amp; orthogonal…","detailHtml":"\n          \n          <ul class=\"styled\">\n            <li>Zero vector is an eigenvector? <strong>No</strong> — eigenvectors are non-zero.</li>\n            <li>Every real matrix has real eigenvalues? <strong>No</strong> — only real <em>symmetric</em> ones are guaranteed real.</li>\n            <li>Eigenvalues of <code>A+B</code> = eigenvalues of A + eigenvalues of B? <strong>No</strong> (true only for <code>A + cI</code>).</li>\n            <li><code>det(A)=0</code> ⇒ 0 is an eigenvalue? <strong>True.</strong></li>\n            <li>Triangular ⇒ eigenvalues are diagonal entries? <strong>True.</strong></li>\n            <li>Idempotent ⇒ λ ∈ {0,1}; nilpotent ⇒ all λ = 0; symmetric ⇒ real λ &amp; orthogonal eigenvectors? <strong>All true.</strong></li>\n          </ul>\n        ","question":null},{"id":"la-eigenvalues-034","topicId":"eigenvalues","order":34,"type":"deep-dive","hook":"Practice problems","body":"Q1. Eigenvalues of $\\begin{bmatrix}2&5\\\\0&3\\end{bmatrix}$?","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-27","sourceLabel":"Study in Depth","detail":"Q1. Eigenvalues of $\\begin{bmatrix}2&amp;5\\\\0&amp;3\\end{bmatrix}$? triangular → 2, 3 Q2. 2×2 with trace 7, det 10? λ² − 7λ + 10 = 0 → 5, 2 Q3. Eigenvalues 2,3,4 → det, trace? det = 24, trace = 9 Q4. A has 2,−1,5 → eigenvalues of A²? 4, 1, 25 Q5. A has 2,−1,5 → eigenvalues of 3A and of A+4I? 3A → 6, −3, 15 ; A+4I → 6, 3, 9 Q6. A has 2,4,5 → eigenvalues of A⁻¹? 1/2, 1/4, 1/5 Q7. Idempotent? Nilpotent? Real symmetric?…","detailHtml":"\n          \n          <p class=\"lead\">Q1. Eigenvalues of $\\begin{bmatrix}2&amp;5\\\\0&amp;3\\end{bmatrix}$?</p>\n          <pre>triangular → 2, 3</pre>\n          <p class=\"lead\">Q2. 2×2 with trace 7, det 10?</p>\n          <pre>λ² − 7λ + 10 = 0 → 5, 2</pre>\n          <p class=\"lead\">Q3. Eigenvalues 2,3,4 → det, trace?</p>\n          <pre>det = 24,  trace = 9</pre>\n          <p class=\"lead\">Q4. A has 2,−1,5 → eigenvalues of A²?</p>\n          <pre>4, 1, 25</pre>\n          <p class=\"lead\">Q5. A has 2,−1,5 → eigenvalues of 3A and of A+4I?</p>\n          <pre>3A → 6, −3, 15 ;  A+4I → 6, 3, 9</pre>\n          <p class=\"lead\">Q6. A has 2,4,5 → eigenvalues of A⁻¹?</p>\n          <pre>1/2, 1/4, 1/5</pre>\n          <p class=\"lead\">Q7. Idempotent? Nilpotent? Real symmetric?</p>\n          <pre>{0,1} ;  all 0 ;  real eigenvalues + orthogonal eigenvectors</pre>\n        ","question":null},{"id":"la-eigenvalues-035","topicId":"eigenvalues","order":35,"type":"deep-dive","hook":"Cheatsheet","body":"Ax = λx, x ≠ 0; eigenvalues from det(A − λI) = 0; eigenvectors from (A − λI)x = 0. 2×2: λ² − tr·λ + det = 0; sum λ = trace, product λ = det. Triangular/diagonal → diagonal entries; 0 is an eigenvalue ⟺ det = 0 ⟺ singular. Aᵏ→λᵏ, A⁻¹→1/λ, A+cI→λ+c…","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-28","sourceLabel":"Study in Depth","detail":"Ax = λx , x ≠ 0; eigenvalues from det(A − λI) = 0 ; eigenvectors from (A − λI)x = 0 . 2×2: λ² − tr·λ + det = 0 ; sum λ = trace, product λ = det. Triangular/diagonal → diagonal entries; 0 is an eigenvalue ⟺ det = 0 ⟺ singular. Aᵏ→λᵏ , A⁻¹→1/λ , A+cI→λ+c , cA→cλ , Aᵀ same λ. Symmetric → real λ, orthogonal eigenvectors; orthogonal → |λ|=1; idempotent → 0/1; nilpotent → 0.","detailHtml":"\n          \n          <ul class=\"styled\">\n            <li><code>Ax = λx</code>, x ≠ 0; eigenvalues from <code>det(A − λI) = 0</code>; eigenvectors from <code>(A − λI)x = 0</code>.</li>\n            <li>2×2: <code>λ² − tr·λ + det = 0</code>;   sum λ = trace, product λ = det.</li>\n            <li>Triangular/diagonal → diagonal entries; 0 is an eigenvalue ⟺ det = 0 ⟺ singular.</li>\n            <li><code>Aᵏ→λᵏ</code>, <code>A⁻¹→1/λ</code>, <code>A+cI→λ+c</code>, <code>cA→cλ</code>, <code>Aᵀ</code> same λ.</li>\n            <li>Symmetric → real λ, orthogonal eigenvectors; orthogonal → |λ|=1; idempotent → 0/1; nilpotent → 0.</li>\n          </ul>\n        ","question":null},{"id":"la-eigenvalues-036","topicId":"eigenvalues","order":36,"type":"deep-dive","hook":"Best mental model","body":"And remember: trace = Σλ, determinant = Πλ, and a zero eigenvalue means the matrix is singular.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"study-item-29","sourceLabel":"Study in Depth","detail":"Matrix = transformation machine Eigenvector = special direction that stays on its own line Eigenvalue = the multiplier on that direction λ&gt;1 stretch · 0&lt;λ&lt;1 shrink · λ=1 unchanged · λ=0 collapsed · λ&lt;0 flipped And remember: trace = Σλ, determinant = Πλ, and a zero eigenvalue means the matrix is singular.","detailHtml":"\n          \n          <pre>Matrix = transformation machine\nEigenvector = special direction that stays on its own line\nEigenvalue  = the multiplier on that direction</pre>\n          <pre>λ&gt;1 stretch · 0&lt;λ&lt;1 shrink · λ=1 unchanged · λ=0 collapsed · λ&lt;0 flipped</pre>\n          <p>And remember: trace = Σλ, determinant = Πλ, and a zero eigenvalue means the matrix is singular.</p>\n        ","question":null},{"id":"la-eigenvalues-037","topicId":"eigenvalues","order":37,"type":"cheat-sheet","hook":"$\\sum\\lambda_i=\\operatorname{tr}(A)$ and $\\prod\\lambda_i=\\det(A)$ — fast checks.","body":"$\\sum\\lambda_i=\\operatorname{tr}(A)$ and $\\prod\\lambda_i=\\det(A)$ — fast checks.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"cheat-1","sourceLabel":"GATE cheat sheet","detail":"$\\sum\\lambda_i=\\operatorname{tr}(A)$ and $\\prod\\lambda_i=\\det(A)$ — fast checks.","detailHtml":"<p>$\\sum\\lambda_i=\\operatorname{tr}(A)$ and $\\prod\\lambda_i=\\det(A)$ — fast checks.</p>","question":null},{"id":"la-eigenvalues-038","topicId":"eigenvalues","order":38,"type":"cheat-sheet","hook":"Triangular/diagonal matrix → eigenvalues are the diagonal entries.","body":"Triangular/diagonal matrix → eigenvalues are the diagonal entries.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"cheat-2","sourceLabel":"GATE cheat sheet","detail":"Triangular/diagonal matrix → eigenvalues are the diagonal entries.","detailHtml":"<p>Triangular/diagonal matrix → eigenvalues are the diagonal entries.</p>","question":null},{"id":"la-eigenvalues-039","topicId":"eigenvalues","order":39,"type":"cheat-sheet","hook":"$A^k$ has $\\lambda^k$; $A^{-1}$ has $1/\\lambda$; $A+cI$ has $\\lambda+c$; $A^{\\mathsf T}$ has the same $\\lambda$.","body":"$A^k$ has $\\lambda^k$; $A^{-1}$ has $1/\\lambda$; $A+cI$ has $\\lambda+c$; $A^{\\mathsf T}$ has the same $\\lambda$.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"cheat-3","sourceLabel":"GATE cheat sheet","detail":"$A^k$ has $\\lambda^k$; $A^{-1}$ has $1/\\lambda$; $A+cI$ has $\\lambda+c$; $A^{\\mathsf T}$ has the same $\\lambda$.","detailHtml":"<p>$A^k$ has $\\lambda^k$; $A^{-1}$ has $1/\\lambda$; $A+cI$ has $\\lambda+c$; $A^{\\mathsf T}$ has the same $\\lambda$.</p>","question":null},{"id":"la-eigenvalues-040","topicId":"eigenvalues","order":40,"type":"cheat-sheet","hook":"Symmetric matrix → all real eigenvalues, orthogonal eigenvectors.","body":"Symmetric matrix → all real eigenvalues, orthogonal eigenvectors.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"cheat-4","sourceLabel":"GATE cheat sheet","detail":"Symmetric matrix → all real eigenvalues, orthogonal eigenvectors.","detailHtml":"<p>Symmetric matrix → all real eigenvalues, orthogonal eigenvectors.</p>","question":null},{"id":"la-eigenvalues-041","topicId":"eigenvalues","order":41,"type":"cheat-sheet","hook":"If $0$ is an eigenvalue, $A$ is singular ($\\det=0$).","body":"If $0$ is an eigenvalue, $A$ is singular ($\\det=0$).","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"cheat-5","sourceLabel":"GATE cheat sheet","detail":"If $0$ is an eigenvalue, $A$ is singular ($\\det=0$).","detailHtml":"<p>If $0$ is an eigenvalue, $A$ is singular ($\\det=0$).</p>","question":null},{"id":"la-eigenvalues-042","topicId":"eigenvalues","order":42,"type":"trap","hook":"Trap","body":"\"The zero vector is an eigenvector.\" Reality: eigenvectors must be non-zero ($\\lambda$ can be $0$, but $x$ can't).","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"trap-1","sourceLabel":"Common traps","detail":"Trap: &quot;The zero vector is an eigenvector.&quot; Reality: eigenvectors must be non-zero ($\\lambda$ can be $0$, but $x$ can&#x27;t).","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;The zero vector is an eigenvector.&quot; <span class=\"right\">Reality:</span> eigenvectors must be non-zero ($\\lambda$ can be $0$, but $x$ can&#x27;t).</p>","question":null},{"id":"la-eigenvalues-043","topicId":"eigenvalues","order":43,"type":"trap","hook":"Trap","body":"\"Real matrices have real eigenvalues.\" Reality: they can be complex (e.g. a rotation).","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"trap-2","sourceLabel":"Common traps","detail":"Trap: &quot;Real matrices have real eigenvalues.&quot; Reality: they can be complex (e.g. a rotation).","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;Real matrices have real eigenvalues.&quot; <span class=\"right\">Reality:</span> they can be complex (e.g. a rotation).</p>","question":null},{"id":"la-eigenvalues-044","topicId":"eigenvalues","order":44,"type":"trap","hook":"Trap","body":"\"Eigenvalues of $A+B$ are eigenvalues of $A$ plus those of $B$.\" Reality: false in general.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"trap-3","sourceLabel":"Common traps","detail":"Trap: &quot;Eigenvalues of $A+B$ are eigenvalues of $A$ plus those of $B$.&quot; Reality: false in general.","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;Eigenvalues of $A+B$ are eigenvalues of $A$ plus those of $B$.&quot; <span class=\"right\">Reality:</span> false in general.</p>","question":null},{"id":"la-eigenvalues-045","topicId":"eigenvalues","order":45,"type":"practice","hook":"Q1. Eigenvalues are $2,3,5$. Find the trace and determinant.","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"practice-1","sourceLabel":"Practice problems","detail":"Trace $=2+3+5=10$; determinant $=2\\cdot3\\cdot5=30$.","detailHtml":"Trace $=2+3+5=10$; determinant $=2\\cdot3\\cdot5=30$.","question":{"type":"REVEAL","prompt":"Q1. Eigenvalues are $2,3,5$. Find the trace and determinant.","options":[],"answer":true,"explanation":"Trace $=2+3+5=10$; determinant $=2\\cdot3\\cdot5=30$.","explanationHtml":"Trace $=2+3+5=10$; determinant $=2\\cdot3\\cdot5=30$."}},{"id":"la-eigenvalues-046","topicId":"eigenvalues","order":46,"type":"practice","hook":"Q2. $A$ is triangular with diagonal $1,4,7$. Eigenvalues?","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"practice-2","sourceLabel":"Practice problems","detail":"$1,4,7$ (the diagonal entries).","detailHtml":"$1,4,7$ (the diagonal entries).","question":{"type":"REVEAL","prompt":"Q2. $A$ is triangular with diagonal $1,4,7$. Eigenvalues?","options":[],"answer":true,"explanation":"$1,4,7$ (the diagonal entries).","explanationHtml":"$1,4,7$ (the diagonal entries)."}},{"id":"la-eigenvalues-047","topicId":"eigenvalues","order":47,"type":"practice","hook":"Q3. Eigenvalues of $A$ are $2,3$. Eigenvalues of $A^{-1}$?","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"practice-3","sourceLabel":"Practice problems","detail":"$\\tfrac12,\\tfrac13$ (reciprocals).","detailHtml":"$\\tfrac12,\\tfrac13$ (reciprocals).","question":{"type":"REVEAL","prompt":"Q3. Eigenvalues of $A$ are $2,3$. Eigenvalues of $A^{-1}$?","options":[],"answer":true,"explanation":"$\\tfrac12,\\tfrac13$ (reciprocals).","explanationHtml":"$\\tfrac12,\\tfrac13$ (reciprocals)."}},{"id":"la-eigenvalues-048","topicId":"eigenvalues","order":48,"type":"practice","hook":"If the eigenvalues of $A$ are $2$ and $3$, the eigenvalues of $A^{-1}$ are:","body":"Choose an answer, then check the explanation.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"06-eigenvalues.html","sourceAnchor":"practice-quiz-1","sourceLabel":"Practice quiz","detail":"✅ Correct — $A^{-1}$ has eigenvalues $1/\\lambda$.","detailHtml":"✅ Correct — $A^{-1}$ has eigenvalues $1/\\lambda$.","question":{"type":"MCQ","prompt":"If the eigenvalues of $A$ are $2$ and $3$, the eigenvalues of $A^{-1}$ are:","options":["A: $-2,-3$","B: $\\tfrac12,\\tfrac13$","C: $4,9$","D: $2,3$"],"answer":"B","explanation":"✅ Correct — $A^{-1}$ has eigenvalues $1/\\lambda$.","explanationHtml":"✅ Correct — $A^{-1}$ has eigenvalues $1/\\lambda$."}},{"id":"la-diagonalization-001","topicId":"diagonalization","order":1,"type":"basic-definition","hook":"Diagonalizable","body":"$A$ can be written $A=PDP^{-1}$ with $D$ diagonal.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"definition-1","sourceLabel":"Basic definitions","detail":"Diagonalizable: $A$ can be written $A=PDP^{-1}$ with $D$ diagonal.","detailHtml":"<p><strong>Diagonalizable:</strong> $A$ can be written $A=PDP^{-1}$ with $D$ diagonal.</p>","question":null},{"id":"la-diagonalization-002","topicId":"diagonalization","order":2,"type":"basic-definition","hook":"$P$ and $D$","body":"$P$'s columns are the eigenvectors; $D$'s diagonal holds the matching eigenvalues.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"definition-2","sourceLabel":"Basic definitions","detail":"$P$ and $D$: $P$&#x27;s columns are the eigenvectors; $D$&#x27;s diagonal holds the matching eigenvalues.","detailHtml":"<p><strong>$P$ and $D$:</strong> $P$&#x27;s columns are the eigenvectors; $D$&#x27;s diagonal holds the matching eigenvalues.</p>","question":null},{"id":"la-diagonalization-003","topicId":"diagonalization","order":3,"type":"basic-definition","hook":"Eigenbasis","body":"a full set of $n$ independent eigenvectors — exactly what makes $A$ diagonalizable.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"definition-3","sourceLabel":"Basic definitions","detail":"Eigenbasis: a full set of $n$ independent eigenvectors — exactly what makes $A$ diagonalizable.","detailHtml":"<p><strong>Eigenbasis:</strong> a full set of $n$ independent eigenvectors — exactly what makes $A$ diagonalizable.</p>","question":null},{"id":"la-diagonalization-004","topicId":"diagonalization","order":4,"type":"basic-definition","hook":"Similar matrices","body":"$A$ and $D$ are \"similar\" ($A=PDP^{-1}$); they share eigenvalues, trace and determinant.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"definition-4","sourceLabel":"Basic definitions","detail":"Similar matrices: $A$ and $D$ are &quot;similar&quot; ($A=PDP^{-1}$); they share eigenvalues, trace and determinant.","detailHtml":"<p><strong>Similar matrices:</strong> $A$ and $D$ are &quot;similar&quot; ($A=PDP^{-1}$); they share eigenvalues, trace and determinant.</p>","question":null},{"id":"la-diagonalization-005","topicId":"diagonalization","order":5,"type":"basic-definition","hook":"Defective","body":"a matrix with too few independent eigenvectors — it cannot be diagonalized.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"definition-5","sourceLabel":"Basic definitions","detail":"Defective: a matrix with too few independent eigenvectors — it cannot be diagonalized.","detailHtml":"<p><strong>Defective:</strong> a matrix with too few independent eigenvectors — it cannot be diagonalized.</p>","question":null},{"id":"la-diagonalization-006","topicId":"diagonalization","order":6,"type":"basic-definition","hook":"Algebraic vs geometric multiplicity","body":"repeats of $\\lambda$ vs independent eigenvectors; equal for every $\\lambda$ ⇒ diagonalizable.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"definition-6","sourceLabel":"Basic definitions","detail":"Algebraic vs geometric multiplicity: repeats of $\\lambda$ vs independent eigenvectors; equal for every $\\lambda$ ⇒ diagonalizable.","detailHtml":"<p><strong>Algebraic vs geometric multiplicity:</strong> repeats of $\\lambda$ vs independent eigenvectors; equal for every $\\lambda$ ⇒ diagonalizable.</p>","question":null},{"id":"la-diagonalization-007","topicId":"diagonalization","order":7,"type":"basic-definition","hook":"Orthogonally diagonalizable","body":"symmetric matrices give $A=Q\\Lambda Q^{\\mathsf T}$ with orthonormal eigenvectors (spectral theorem).","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"definition-7","sourceLabel":"Basic definitions","detail":"Orthogonally diagonalizable: symmetric matrices give $A=Q\\Lambda Q^{\\mathsf T}$ with orthonormal eigenvectors (spectral theorem).","detailHtml":"<p><strong>Orthogonally diagonalizable:</strong> symmetric matrices give $A=Q\\Lambda Q^{\\mathsf T}$ with orthonormal eigenvectors (spectral theorem).</p>","question":null},{"id":"la-diagonalization-008","topicId":"diagonalization","order":8,"type":"deep-dive","hook":"What is diagonalization?","body":"A square matrix A is diagonalizable if it can be written","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-1","sourceLabel":"Study in Depth","detail":"A square matrix A is diagonalizable if it can be written A = P D P⁻¹ D = diagonal matrix of eigenvalues P = matrix whose columns are the matching eigenvectors If Av₁=λ₁v₁ , Av₂=λ₂v₂ , … then P = [v₁ v₂ …] and D = diag(λ₁, λ₂, …).","detailHtml":"\n          \n          <p>A square matrix A is <strong>diagonalizable</strong> if it can be written</p>\n          <pre>A = P D P⁻¹\n\nD = diagonal matrix of eigenvalues\nP = matrix whose columns are the matching eigenvectors</pre>\n          <p>If <code>Av₁=λ₁v₁</code>, <code>Av₂=λ₂v₂</code>, … then P = [v₁ v₂ …] and D = diag(λ₁, λ₂, …).</p>\n        ","question":null},{"id":"la-diagonalization-009","topicId":"diagonalization","order":9,"type":"deep-dive","hook":"Why do we need it? (easy powers)","body":"Diagonal matrices are trivial to power:","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-2","sourceLabel":"Study in Depth","detail":"Diagonal matrices are trivial to power: D = $\\begin{bmatrix}2&amp;0\\\\0&amp;3\\end{bmatrix}$ → D¹⁰ = $\\begin{bmatrix}2^{10}&amp;0\\\\0&amp;3^{10}\\end{bmatrix}$ = $\\begin{bmatrix}1024&amp;0\\\\0&amp;59049\\end{bmatrix}$ Diagonalization gives the same ease for any matrix: Aᵏ = P Dᵏ P⁻¹ .","detailHtml":"\n          \n          <p>Diagonal matrices are trivial to power:</p>\n          <div class=\"math-steps\"><div class=\"ms-line\">D = $\\begin{bmatrix}2&amp;0\\\\0&amp;3\\end{bmatrix}$  →  D¹⁰ = $\\begin{bmatrix}2^{10}&amp;0\\\\0&amp;3^{10}\\end{bmatrix}$ = $\\begin{bmatrix}1024&amp;0\\\\0&amp;59049\\end{bmatrix}$</div></div>\n          <p>Diagonalization gives the same ease for any matrix: <code>Aᵏ = P Dᵏ P⁻¹</code>.</p>\n        ","question":null},{"id":"la-diagonalization-010","topicId":"diagonalization","order":10,"type":"deep-dive","hook":"Game imagination","body":"In normal x–y coordinates a matrix looks tangled. Rotate to coordinates aligned with the eigenvectors, and it becomes pure independent stretching:","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-3","sourceLabel":"Study in Depth","detail":"In normal x–y coordinates a matrix looks tangled. Rotate to coordinates aligned with the eigenvectors , and it becomes pure independent stretching: direction 1 stretched by λ₁ direction 2 stretched by λ₂ (no mixing, no twisting) Diagonalization = choosing the coordinate system where A is simplest.","detailHtml":"\n          \n          <p>In normal x–y coordinates a matrix looks tangled. Rotate to coordinates aligned with the <strong>eigenvectors</strong>, and it becomes pure independent stretching:</p>\n          <pre>direction 1 stretched by λ₁\ndirection 2 stretched by λ₂   (no mixing, no twisting)</pre>\n          <p>Diagonalization = choosing the coordinate system where A is simplest.</p>\n        ","question":null},{"id":"la-diagonalization-011","topicId":"diagonalization","order":11,"type":"deep-dive","hook":"Meaning of P, D and P⁻¹","body":"Read right to left: go into the eigenbasis, scale, come back.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-4","sourceLabel":"Study in Depth","detail":"A = P D P⁻¹ P⁻¹ → convert into eigenvector coordinates D → scale each eigen-direction by its eigenvalue P → convert back to normal coordinates Read right to left: go into the eigenbasis, scale, come back.","detailHtml":"\n          \n          <pre>A = P D P⁻¹\n\nP⁻¹ → convert into eigenvector coordinates\nD   → scale each eigen-direction by its eigenvalue\nP   → convert back to normal coordinates</pre>\n          <p>Read right to left: go into the eigenbasis, scale, come back.</p>\n        ","question":null},{"id":"la-diagonalization-012","topicId":"diagonalization","order":12,"type":"deep-dive","hook":"Why D is diagonal (the derivation)","body":"That single line is the whole engine of diagonalization.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-5","sourceLabel":"Study in Depth","detail":"P = [v₁ v₂] AP = [Av₁ Av₂] = [λ₁v₁ λ₂v₂] = P·$\\begin{bmatrix}λ₁&amp;0\\\\0&amp;λ₂\\end{bmatrix}$ = PD so AP = PD ⇒ A = P D P⁻¹ That single line is the whole engine of diagonalization.","detailHtml":"\n          \n          <div class=\"math-steps\"><div class=\"ms-line\">P = [v₁ v₂]</div><div class=\"ms-line\">AP = [Av₁ Av₂] = [λ₁v₁ λ₂v₂] = P·$\\begin{bmatrix}λ₁&amp;0\\\\0&amp;λ₂\\end{bmatrix}$ = PD</div><div class=\"ms-line\"></div><div class=\"ms-line\">so  AP = PD   ⇒   A = P D P⁻¹</div></div>\n          <p>That single line is the whole engine of diagonalization.</p>\n        ","question":null},{"id":"la-diagonalization-013","topicId":"diagonalization","order":13,"type":"deep-dive","hook":"When can a matrix be diagonalized?","body":"Because P must be invertible, and P's columns are the eigenvectors — they must be independent for P⁻¹ to exist.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-6","sourceLabel":"Study in Depth","detail":"A (n×n) is diagonalizable ⟺ A has n linearly independent eigenvectors Because P must be invertible, and P&#x27;s columns are the eigenvectors — they must be independent for P⁻¹ to exist.","detailHtml":"\n          \n          <pre>A (n×n) is diagonalizable  ⟺  A has n linearly independent eigenvectors</pre>\n          <p>Because P must be invertible, and P&#x27;s columns are the eigenvectors — they must be independent for <code>P⁻¹</code> to exist.</p>\n        ","question":null},{"id":"la-diagonalization-014","topicId":"diagonalization","order":14,"type":"deep-dive","hook":"Rule 1: distinct eigenvalues ⇒ diagonalizable","body":"Eigenvectors for distinct eigenvalues are automatically independent, so n distinct eigenvalues give n independent eigenvectors.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-7","sourceLabel":"Study in Depth","detail":"3×3 with eigenvalues 1, 2, 5 → all distinct → diagonalizable Eigenvectors for distinct eigenvalues are automatically independent, so n distinct eigenvalues give n independent eigenvectors.","detailHtml":"\n          \n          <pre>3×3 with eigenvalues 1, 2, 5  → all distinct → diagonalizable</pre>\n          <p>Eigenvectors for distinct eigenvalues are automatically independent, so n distinct eigenvalues give n independent eigenvectors.</p>\n        ","question":null},{"id":"la-diagonalization-015","topicId":"diagonalization","order":15,"type":"deep-dive","hook":"Rule 2: real symmetric ⇒ orthogonally diagonalizable","body":"If A = Aᵀ (real), then A is always diagonalizable, and even orthogonally:","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-8","sourceLabel":"Study in Depth","detail":"If A = Aᵀ (real), then A is always diagonalizable, and even orthogonally: A = Q D Qᵀ (Q orthogonal: Q⁻¹ = Qᵀ) This is the spectral theorem — the backbone of PCA.","detailHtml":"\n          \n          <p>If <code>A = Aᵀ</code> (real), then A is always diagonalizable, and even orthogonally:</p>\n          <pre>A = Q D Qᵀ      (Q orthogonal: Q⁻¹ = Qᵀ)</pre>\n          <p>This is the <strong>spectral theorem</strong> — the backbone of PCA.</p>\n        ","question":null},{"id":"la-diagonalization-016","topicId":"diagonalization","order":16,"type":"deep-dive","hook":"Algebraic multiplicity (AM)","body":"AM = how many times an eigenvalue is a root of the characteristic polynomial.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-9","sourceLabel":"Study in Depth","detail":"AM = how many times an eigenvalue is a root of the characteristic polynomial. p(λ) = (λ − 2)²(λ − 5) → AM(2) = 2, AM(5) = 1","detailHtml":"\n          \n          <p><strong>AM</strong> = how many times an eigenvalue is a root of the characteristic polynomial.</p>\n          <pre>p(λ) = (λ − 2)²(λ − 5)   →   AM(2) = 2,  AM(5) = 1</pre>\n        ","question":null},{"id":"la-diagonalization-017","topicId":"diagonalization","order":17,"type":"deep-dive","hook":"Geometric multiplicity (GM)","body":"GM = number of independent eigenvectors for that eigenvalue = dimension of its eigenspace.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-10","sourceLabel":"Study in Depth","detail":"GM = number of independent eigenvectors for that eigenvalue = dimension of its eigenspace. GM(λ) = dim Null(A − λI) = n − rank(A − λI)","detailHtml":"\n          \n          <p><strong>GM</strong> = number of independent eigenvectors for that eigenvalue = dimension of its eigenspace.</p>\n          <pre>GM(λ) = dim Null(A − λI) = n − rank(A − λI)</pre>\n        ","question":null},{"id":"la-diagonalization-018","topicId":"diagonalization","order":18,"type":"deep-dive","hook":"The AM / GM rule","body":"1 ≤ GM ≤ AM (every eigenvalue) A is diagonalizable ⟺ GM = AM for EVERY eigenvalue ⟺ total independent eigenvectors = n","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-11","sourceLabel":"Study in Depth","detail":"1 ≤ GM ≤ AM (every eigenvalue) A is diagonalizable ⟺ GM = AM for EVERY eigenvalue ⟺ total independent eigenvectors = n","detailHtml":"\n          \n          <pre>1 ≤ GM ≤ AM   (every eigenvalue)\n\nA is diagonalizable  ⟺  GM = AM for EVERY eigenvalue\n                     ⟺  total independent eigenvectors = n</pre>\n        ","question":null},{"id":"la-diagonalization-019","topicId":"diagonalization","order":19,"type":"deep-dive","hook":"Repeated eigenvalue — must check GM","body":"A repeated eigenvalue does not automatically block diagonalization — check GM.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-12","sourceLabel":"Study in Depth","detail":"char poly = (λ − 2)² → λ = 2, AM = 2 GM = 2 → 2 independent eigenvectors → diagonalizable GM = 1 → only 1 eigenvector → NOT diagonalizable A repeated eigenvalue does not automatically block diagonalization — check GM.","detailHtml":"\n          \n          <pre>char poly = (λ − 2)²  →  λ = 2, AM = 2\n\nGM = 2 → 2 independent eigenvectors → diagonalizable\nGM = 1 → only 1 eigenvector        → NOT diagonalizable</pre>\n          <p>A repeated eigenvalue does <em>not</em> automatically block diagonalization — check GM.</p>\n        ","question":null},{"id":"la-diagonalization-020","topicId":"diagonalization","order":20,"type":"worked-example","hook":"Example: identity (repeated but fine)","body":"GM = AM = 2, so the identity is diagonalizable (it already is diagonal).","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-13","sourceLabel":"Study in Depth","detail":"I = $\\begin{bmatrix}1&amp;0\\\\0&amp;1\\end{bmatrix}$ char poly (λ−1)², λ = 1, AM = 2 Ix = x for every x → eigenspace is all of ℝ² → GM = 2 GM = AM = 2, so the identity is diagonalizable (it already is diagonal).","detailHtml":"\n          \n          <div class=\"math-steps\"><div class=\"ms-line\">I = $\\begin{bmatrix}1&amp;0\\\\0&amp;1\\end{bmatrix}$   char poly (λ−1)²,  λ = 1, AM = 2</div><div class=\"ms-line\">Ix = x for every x → eigenspace is all of ℝ² → GM = 2</div></div>\n          <p>GM = AM = 2, so the identity <strong>is</strong> diagonalizable (it already is diagonal).</p>\n        ","question":null},{"id":"la-diagonalization-021","topicId":"diagonalization","order":21,"type":"worked-example","hook":"Example: a defective matrix","body":"GM (1) < AM (2) → not diagonalizable. Such matrices are called defective.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-14","sourceLabel":"Study in Depth","detail":"A = $\\begin{bmatrix}1&amp;1\\\\0&amp;1\\end{bmatrix}$ λ = 1, AM = 2 A − I = $\\begin{bmatrix}0&amp;1\\\\0&amp;0\\end{bmatrix}$ → x₂ = 0 → eigenvectors x₁·$\\begin{bmatrix}1\\\\0\\end{bmatrix}$ only → GM = 1 GM (1) &lt; AM (2) → not diagonalizable . Such matrices are called defective .","detailHtml":"\n          \n          <div class=\"math-steps\"><div class=\"ms-line\">A = $\\begin{bmatrix}1&amp;1\\\\0&amp;1\\end{bmatrix}$   λ = 1, AM = 2</div><div class=\"ms-line\">A − I = $\\begin{bmatrix}0&amp;1\\\\0&amp;0\\end{bmatrix}$  → x₂ = 0 → eigenvectors x₁·$\\begin{bmatrix}1\\\\0\\end{bmatrix}$ only → GM = 1</div></div>\n          <p>GM (1) &lt; AM (2) → <strong>not diagonalizable</strong>. Such matrices are called <em>defective</em>.</p>\n        ","question":null},{"id":"la-diagonalization-022","topicId":"diagonalization","order":22,"type":"worked-example","hook":"Full worked diagonalization","body":"Then A = P D P⁻¹.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-15","sourceLabel":"Study in Depth","detail":"A = $\\begin{bmatrix}4&amp;1\\\\2&amp;3\\end{bmatrix}$ → λ = 5 (v = $\\begin{bmatrix}1\\\\1\\end{bmatrix}$), λ = 2 (v = $\\begin{bmatrix}1\\\\-2\\end{bmatrix}$) P = $\\begin{bmatrix}1&amp;1\\\\1&amp;-2\\end{bmatrix}$, D = $\\begin{bmatrix}5&amp;0\\\\0&amp;2\\end{bmatrix}$ Then A = P D P⁻¹ .","detailHtml":"\n          \n          <div class=\"math-steps\"><div class=\"ms-line\">A = $\\begin{bmatrix}4&amp;1\\\\2&amp;3\\end{bmatrix}$   →   λ = 5 (v = $\\begin{bmatrix}1\\\\1\\end{bmatrix}$),   λ = 2 (v = $\\begin{bmatrix}1\\\\-2\\end{bmatrix}$)</div><div class=\"ms-line\"></div><div class=\"ms-line\">P = $\\begin{bmatrix}1&amp;1\\\\1&amp;-2\\end{bmatrix}$,   D = $\\begin{bmatrix}5&amp;0\\\\0&amp;2\\end{bmatrix}$</div></div>\n          <p>Then <code>A = P D P⁻¹</code>.</p>\n        ","question":null},{"id":"la-diagonalization-023","topicId":"diagonalization","order":23,"type":"deep-dive","hook":"Order-matching warning","body":"The eigenvector order in P must match the eigenvalue order in D — mismatching gives a wrong result.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-16","sourceLabel":"Study in Depth","detail":"P = [v₁ v₂] with v₁↔λ₁, v₂↔λ₂ ⇒ D = $\\begin{bmatrix}λ₁&amp;0\\\\0&amp;λ₂\\end{bmatrix}$ The eigenvector order in P must match the eigenvalue order in D — mismatching gives a wrong result.","detailHtml":"\n          \n          <div class=\"math-steps\"><div class=\"ms-line\">P = [v₁ v₂]  with v₁↔λ₁, v₂↔λ₂   ⇒   D = $\\begin{bmatrix}λ₁&amp;0\\\\0&amp;λ₂\\end{bmatrix}$</div></div>\n          <p>The eigenvector order in P must match the eigenvalue order in D — mismatching gives a wrong result.</p>\n        ","question":null},{"id":"la-diagonalization-024","topicId":"diagonalization","order":24,"type":"deep-dive","hook":"Computing P⁻¹ (2×2)","body":"P = $\\begin{bmatrix}1&1\\\\1&-2\\end{bmatrix}$ det(P) = 1(−2) − 1(1) = −3P⁻¹ = $-\\tfrac13\\begin{bmatrix}-2&-1\\\\-1&1\\end{bmatrix} = \\begin{bmatrix}\\tfrac23&\\tfrac13\\\\[2pt]\\tfrac13&-\\tfrac13\\end{bmatrix}$","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-17","sourceLabel":"Study in Depth","detail":"P = $\\begin{bmatrix}1&amp;1\\\\1&amp;-2\\end{bmatrix}$ det(P) = 1(−2) − 1(1) = −3 P⁻¹ = $-\\tfrac13\\begin{bmatrix}-2&amp;-1\\\\-1&amp;1\\end{bmatrix} = \\begin{bmatrix}\\tfrac23&amp;\\tfrac13\\\\[2pt]\\tfrac13&amp;-\\tfrac13\\end{bmatrix}$","detailHtml":"\n          \n          <div class=\"math-steps\"><div class=\"ms-line\">P = $\\begin{bmatrix}1&amp;1\\\\1&amp;-2\\end{bmatrix}$   det(P) = 1(−2) − 1(1) = −3</div><div class=\"ms-line\"></div><div class=\"ms-line\">P⁻¹ = $-\\tfrac13\\begin{bmatrix}-2&amp;-1\\\\-1&amp;1\\end{bmatrix} = \\begin{bmatrix}\\tfrac23&amp;\\tfrac13\\\\[2pt]\\tfrac13&amp;-\\tfrac13\\end{bmatrix}$</div></div>\n        ","question":null},{"id":"la-diagonalization-025","topicId":"diagonalization","order":25,"type":"deep-dive","hook":"Why diagonalization makes powers easy","body":"The inner P⁻¹P = I collapses everything to a clean diagonal power.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-18","sourceLabel":"Study in Depth","detail":"A² = (PDP⁻¹)(PDP⁻¹) = PD(P⁻¹P)DP⁻¹ = P D² P⁻¹ ⇒ Aᵏ = P Dᵏ P⁻¹ The inner P⁻¹P = I collapses everything to a clean diagonal power.","detailHtml":"\n          \n          <pre>A² = (PDP⁻¹)(PDP⁻¹) = PD(P⁻¹P)DP⁻¹ = P D² P⁻¹\n\n⇒  Aᵏ = P Dᵏ P⁻¹</pre>\n          <p>The inner <code>P⁻¹P = I</code> collapses everything to a clean diagonal power.</p>\n        ","question":null},{"id":"la-diagonalization-026","topicId":"diagonalization","order":26,"type":"deep-dive","hook":"Computing Dᵏ","body":"Just raise each diagonal entry to the power.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-19","sourceLabel":"Study in Depth","detail":"D = diag(λ₁, λ₂, λ₃) → Dᵏ = diag(λ₁ᵏ, λ₂ᵏ, λ₃ᵏ) D = $\\begin{bmatrix}5&amp;0\\\\0&amp;2\\end{bmatrix}$ → D¹⁰ = $\\begin{bmatrix}5^{10}&amp;0\\\\0&amp;2^{10}\\end{bmatrix}$ Just raise each diagonal entry to the power.","detailHtml":"\n          \n          <pre>D = diag(λ₁, λ₂, λ₃)  →  Dᵏ = diag(λ₁ᵏ, λ₂ᵏ, λ₃ᵏ)</pre>\n          <div class=\"math-steps\"><div class=\"ms-line\">D = $\\begin{bmatrix}5&amp;0\\\\0&amp;2\\end{bmatrix}$  →  D¹⁰ = $\\begin{bmatrix}5^{10}&amp;0\\\\0&amp;2^{10}\\end{bmatrix}$</div></div>\n          <p>Just raise each diagonal entry to the power.</p>\n        ","question":null},{"id":"la-diagonalization-027","topicId":"diagonalization","order":27,"type":"deep-dive","hook":"Powers — diagonal vs non-diagonal","body":"GATE loves high powers (A⁵, A¹⁰, A¹⁰⁰) — diagonalization (or Cayley–Hamilton) is how you do them.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-20","sourceLabel":"Study in Depth","detail":"already diagonal: $\\begin{bmatrix}2&amp;0\\\\0&amp;3\\end{bmatrix}$¹⁰ = $\\begin{bmatrix}1024&amp;0\\\\0&amp;59049\\end{bmatrix}$ non-diagonal A = PDP⁻¹: A¹⁰ = P·$\\begin{bmatrix}5^{10}&amp;0\\\\0&amp;2^{10}\\end{bmatrix}$·P⁻¹ GATE loves high powers (A⁵, A¹⁰, A¹⁰⁰) — diagonalization (or Cayley–Hamilton) is how you do them.","detailHtml":"\n          \n          <div class=\"math-steps\"><div class=\"ms-line\">already diagonal:  $\\begin{bmatrix}2&amp;0\\\\0&amp;3\\end{bmatrix}$¹⁰ = $\\begin{bmatrix}1024&amp;0\\\\0&amp;59049\\end{bmatrix}$</div><div class=\"ms-line\"></div><div class=\"ms-line\">non-diagonal A = PDP⁻¹:  A¹⁰ = P·$\\begin{bmatrix}5^{10}&amp;0\\\\0&amp;2^{10}\\end{bmatrix}$·P⁻¹</div></div>\n          <p>GATE loves high powers (A⁵, A¹⁰, A¹⁰⁰) — diagonalization (or Cayley–Hamilton) is how you do them.</p>\n        ","question":null},{"id":"la-diagonalization-028","topicId":"diagonalization","order":28,"type":"deep-dive","hook":"The transformation meaning","body":"So A simply scales each eigen-direction independently — that is the deep meaning of being diagonalizable.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-21","sourceLabel":"Study in Depth","detail":"any x = c₁v₁ + c₂v₂ Ax = c₁·Av₁ + c₂·Av₂ = c₁λ₁v₁ + c₂λ₂v₂ So A simply scales each eigen-direction independently — that is the deep meaning of being diagonalizable.","detailHtml":"\n          \n          <pre>any x = c₁v₁ + c₂v₂\nAx = c₁·Av₁ + c₂·Av₂ = c₁λ₁v₁ + c₂λ₂v₂</pre>\n          <p>So A simply scales each eigen-direction independently — that is the deep meaning of being diagonalizable.</p>\n        ","question":null},{"id":"la-diagonalization-029","topicId":"diagonalization","order":29,"type":"deep-dive","hook":"Symmetric & orthogonal diagonalization","body":"Called orthogonal diagonalization / spectral decomposition; the inverse is free (Q⁻¹ = Qᵀ).","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-22","sourceLabel":"Study in Depth","detail":"real symmetric A = A ᵀ → A = Q D Qᵀ (QᵀQ = I) Q columns = orthonormal eigenvectors, D = eigenvalues Called orthogonal diagonalization / spectral decomposition; the inverse is free ( Q⁻¹ = Qᵀ ).","detailHtml":"\n          \n          <pre>real symmetric A = A ᵀ  →  A = Q D Qᵀ   (QᵀQ = I)\n\nQ columns = orthonormal eigenvectors,  D = eigenvalues</pre>\n          <p>Called <strong>orthogonal diagonalization</strong> / spectral decomposition; the inverse is free (<code>Q⁻¹ = Qᵀ</code>).</p>\n        ","question":null},{"id":"la-diagonalization-030","topicId":"diagonalization","order":30,"type":"deep-dive","hook":"PCA connection","body":"Big eigenvalue = important direction (much spread); small = less important. (Full PCA in the SVD & PCA topic.)","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-23","sourceLabel":"Study in Depth","detail":"covariance matrix Σ (symmetric) → Σ = Q D Qᵀ Q = principal directions , D = variances Big eigenvalue = important direction (much spread); small = less important. (Full PCA in the SVD &amp; PCA topic.)","detailHtml":"\n          \n          <pre>covariance matrix Σ (symmetric)  →  Σ = Q D Qᵀ\nQ = principal directions ,  D = variances</pre>\n          <p>Big eigenvalue = important direction (much spread); small = less important. (Full PCA in the SVD &amp; PCA topic.)</p>\n        ","question":null},{"id":"la-diagonalization-031","topicId":"diagonalization","order":31,"type":"deep-dive","hook":"Diagonalizable ≠ invertible","body":"Diagonalizable = enough independent eigenvectors. Invertible = all eigenvalues non-zero. Different things!","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-24","sourceLabel":"Study in Depth","detail":"A = $\\begin{bmatrix}1&amp;0\\\\0&amp;0\\end{bmatrix}$ diagonal → diagonalizable but det(A) = 0 (eigenvalue 0) → NOT invertible Diagonalizable = enough independent eigenvectors. Invertible = all eigenvalues non-zero. Different things!","detailHtml":"\n          \n          <div class=\"math-steps\"><div class=\"ms-line\">A = $\\begin{bmatrix}1&amp;0\\\\0&amp;0\\end{bmatrix}$   diagonal → diagonalizable</div><div class=\"ms-line\">but det(A) = 0 (eigenvalue 0) → NOT invertible</div></div>\n          <p>Diagonalizable = enough independent eigenvectors. Invertible = all eigenvalues non-zero. Different things!</p>\n        ","question":null},{"id":"la-diagonalization-032","topicId":"diagonalization","order":32,"type":"deep-dive","hook":"Diagonalizable vs distinct eigenvalues","body":"The implication only goes one way.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-25","sourceLabel":"Study in Depth","detail":"distinct eigenvalues ⇒ diagonalizable (TRUE) diagonalizable ⇒ distinct eigenvalues (FALSE — e.g. the identity) The implication only goes one way.","detailHtml":"\n          \n          <pre>distinct eigenvalues  ⇒  diagonalizable     (TRUE)\ndiagonalizable        ⇒  distinct eigenvalues (FALSE — e.g. the identity)</pre>\n          <p>The implication only goes one way.</p>\n        ","question":null},{"id":"la-diagonalization-033","topicId":"diagonalization","order":33,"type":"deep-dive","hook":"trace, det & similar matrices","body":"Similar matrices (B = P⁻¹AP) share eigenvalues, trace, determinant, rank and characteristic polynomial. Diagonalization = A is similar to a diagonal matrix.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-26","sourceLabel":"Study in Depth","detail":"A = PDP⁻¹ ⇒ trace(A) = trace(D) = Σλ , det(A) = det(D) = Πλ Similar matrices ( B = P⁻¹AP ) share eigenvalues, trace, determinant, rank and characteristic polynomial. Diagonalization = A is similar to a diagonal matrix.","detailHtml":"\n          \n          <pre>A = PDP⁻¹  ⇒  trace(A) = trace(D) = Σλ ,  det(A) = det(D) = Πλ</pre>\n          <p><strong>Similar</strong> matrices (<code>B = P⁻¹AP</code>) share eigenvalues, trace, determinant, rank and characteristic polynomial. Diagonalization = A is similar to a diagonal matrix.</p>\n        ","question":null},{"id":"la-diagonalization-034","topicId":"diagonalization","order":34,"type":"deep-dive","hook":"How to check diagonalizability (steps)","body":"Shortcut: real symmetric → diagonalizable automatically.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-27","sourceLabel":"Study in Depth","detail":"Find eigenvalues from det(A − λI) = 0 . All eigenvalues distinct? → diagonalizable, stop. Repeated λ? compute GM = nullity(A − λI) for each. GM = AM for all → diagonalizable; otherwise not. Shortcut: real symmetric → diagonalizable automatically.","detailHtml":"\n          \n          <ol class=\"steps\">\n            <li>Find eigenvalues from <code>det(A − λI) = 0</code>.</li>\n            <li>All eigenvalues distinct? → diagonalizable, stop.</li>\n            <li>Repeated λ? compute <code>GM = nullity(A − λI)</code> for each.</li>\n            <li><code>GM = AM</code> for all → diagonalizable; otherwise not.</li>\n          </ol>\n          <p>Shortcut: real symmetric → diagonalizable automatically.</p>\n        ","question":null},{"id":"la-diagonalization-035","topicId":"diagonalization","order":35,"type":"deep-dive","hook":"Common facts & traps","body":"n distinct eigenvalues ⇒ diagonalizable. True. Diagonalizable ⇒ distinct eigenvalues? False (identity). Real symmetric ⇒ diagonalizable (orthogonally). True. Every matrix is diagonalizable? False (defective ones). Diagonalizable ⇒ invertible? False…","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-28","sourceLabel":"Study in Depth","detail":"n distinct eigenvalues ⇒ diagonalizable. True. Diagonalizable ⇒ distinct eigenvalues? False (identity). Real symmetric ⇒ diagonalizable (orthogonally). True. Every matrix is diagonalizable? False (defective ones). Diagonalizable ⇒ invertible? False (zero eigenvalue allowed). In A = PDP⁻¹ , P holds eigen vectors , D holds eigen values . Cayley–Hamilton: constant term becomes ·I (e.g. A²−5A+4I=0 ).","detailHtml":"\n          \n          <ul class=\"styled\">\n            <li>n distinct eigenvalues ⇒ diagonalizable. <strong>True.</strong></li>\n            <li>Diagonalizable ⇒ distinct eigenvalues? <strong>False</strong> (identity).</li>\n            <li>Real symmetric ⇒ diagonalizable (orthogonally). <strong>True.</strong></li>\n            <li>Every matrix is diagonalizable? <strong>False</strong> (defective ones).</li>\n            <li>Diagonalizable ⇒ invertible? <strong>False</strong> (zero eigenvalue allowed).</li>\n            <li>In <code>A = PDP⁻¹</code>, P holds eigen<strong>vectors</strong>, D holds eigen<strong>values</strong>.</li>\n            <li>Cayley–Hamilton: constant term becomes <code>·I</code> (e.g. <code>A²−5A+4I=0</code>).</li>\n          </ul>\n        ","question":null},{"id":"la-diagonalization-036","topicId":"diagonalization","order":36,"type":"deep-dive","hook":"Practice problems","body":"Q1. 3×3 with eigenvalues 1, 2, 3 — diagonalizable?","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-29","sourceLabel":"Study in Depth","detail":"Q1. 3×3 with eigenvalues 1, 2, 3 — diagonalizable? distinct → yes Q2. 2×2, (λ−4)², GM(4)=1 — diagonalizable? GM 1 &lt; AM 2 → no Q3. Identity I₂ — diagonalizable? GM = AM = 2 → yes Q4. A = PDP⁻¹, D = $\\begin{bmatrix}2&amp;0\\\\0&amp;5\\end{bmatrix}$ — A¹⁰? A¹⁰ = P·$\\begin{bmatrix}2^{10}&amp;0\\\\0&amp;5^{10}\\end{bmatrix}$·P⁻¹ Q5. p(λ)=λ²−7λ+10 — express A²? A² − 7A + 10I = 0 → A² = 7A − 10I Q6. A²−5A+6I=0 — find A⁻¹?…","detailHtml":"\n          \n          <p class=\"lead\">Q1. 3×3 with eigenvalues 1, 2, 3 — diagonalizable?</p>\n          <pre>distinct → yes</pre>\n          <p class=\"lead\">Q2. 2×2, (λ−4)², GM(4)=1 — diagonalizable?</p>\n          <pre>GM 1 &lt; AM 2 → no</pre>\n          <p class=\"lead\">Q3. Identity I₂ — diagonalizable?</p>\n          <pre>GM = AM = 2 → yes</pre>\n          <p class=\"lead\">Q4. A = PDP⁻¹, D = $\\begin{bmatrix}2&amp;0\\\\0&amp;5\\end{bmatrix}$ — A¹⁰?</p>\n          <div class=\"math-steps\"><div class=\"ms-line\">A¹⁰ = P·$\\begin{bmatrix}2^{10}&amp;0\\\\0&amp;5^{10}\\end{bmatrix}$·P⁻¹</div></div>\n          <p class=\"lead\">Q5. p(λ)=λ²−7λ+10 — express A²?</p>\n          <pre>A² − 7A + 10I = 0 → A² = 7A − 10I</pre>\n          <p class=\"lead\">Q6. A²−5A+6I=0 — find A⁻¹?</p>\n          <pre>A(5I−A)=6I → A⁻¹ = (5I − A)/6</pre>\n        ","question":null},{"id":"la-diagonalization-037","topicId":"diagonalization","order":37,"type":"deep-dive","hook":"Cheatsheet","body":"A = PDP⁻¹: P = eigenvectors (order matters!), D = eigenvalues; Aᵏ = PDᵏP⁻¹. Diagonalizable ⟺ n independent eigenvectors ⟺ GM = AM for every λ. n distinct eigenvalues ⇒ diagonalizable; real symmetric ⇒ A = QDQᵀ. Diagonalizable ≠ invertible; trace =…","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-30","sourceLabel":"Study in Depth","detail":"A = PDP⁻¹ : P = eigenvectors (order matters!), D = eigenvalues; Aᵏ = PDᵏP⁻¹ . Diagonalizable ⟺ n independent eigenvectors ⟺ GM = AM for every λ. n distinct eigenvalues ⇒ diagonalizable; real symmetric ⇒ A = QDQᵀ . Diagonalizable ≠ invertible; trace = Σλ , det = Πλ . Cayley–Hamilton: p(A) = 0 (constant → I) → reduce powers &amp; get A⁻¹ .","detailHtml":"\n          \n          <ul class=\"styled\">\n            <li><code>A = PDP⁻¹</code>: P = eigenvectors (order matters!), D = eigenvalues; <code>Aᵏ = PDᵏP⁻¹</code>.</li>\n            <li>Diagonalizable ⟺ n independent eigenvectors ⟺ GM = AM for every λ.</li>\n            <li>n distinct eigenvalues ⇒ diagonalizable; real symmetric ⇒ <code>A = QDQᵀ</code>.</li>\n            <li>Diagonalizable ≠ invertible; <code>trace = Σλ</code>, <code>det = Πλ</code>.</li>\n            <li>Cayley–Hamilton: <code>p(A) = 0</code> (constant → I) → reduce powers &amp; get <code>A⁻¹</code>.</li>\n          </ul>\n        ","question":null},{"id":"la-diagonalization-038","topicId":"diagonalization","order":38,"type":"deep-dive","hook":"Best mental model","body":"A = PDP⁻¹ = go to the eigenbasis, scale, come back; Aᵏ = PDᵏP⁻¹ = a hard power becomes an easy diagonal power.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"study-item-31","sourceLabel":"Study in Depth","detail":"A = complicated machine eigenvectors = its natural directions eigenvalues = stretch factors there diagonalization = switch to those directions, where A = D (simple) A = PDP⁻¹ = go to the eigenbasis, scale, come back; Aᵏ = PDᵏP⁻¹ = a hard power becomes an easy diagonal power.","detailHtml":"\n          \n          <pre>A = complicated machine\neigenvectors = its natural directions\neigenvalues = stretch factors there\ndiagonalization = switch to those directions, where A = D (simple)</pre>\n          <p><code>A = PDP⁻¹</code> = go to the eigenbasis, scale, come back; <code>Aᵏ = PDᵏP⁻¹</code> = a hard power becomes an easy diagonal power.</p>\n        ","question":null},{"id":"la-diagonalization-039","topicId":"diagonalization","order":39,"type":"cheat-sheet","hook":"distinct","body":"inct eigenvalues ⇒ automatically diagonalizable.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"cheat-1","sourceLabel":"GATE cheat sheet","detail":"$n$ distinct eigenvalues ⇒ automatically diagonalizable.","detailHtml":"<p>$n$ <strong>distinct</strong> eigenvalues ⇒ automatically diagonalizable.</p>","question":null},{"id":"la-diagonalization-040","topicId":"diagonalization","order":40,"type":"cheat-sheet","hook":"symmetric","body":"metric matrix is diagonalizable — orthogonally: $A=QDQ^{\\mathsf T}$.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"cheat-2","sourceLabel":"GATE cheat sheet","detail":"Every symmetric matrix is diagonalizable — orthogonally: $A=QDQ^{\\mathsf T}$.","detailHtml":"<p>Every <strong>symmetric</strong> matrix is diagonalizable — orthogonally: $A=QDQ^{\\mathsf T}$.</p>","question":null},{"id":"la-diagonalization-041","topicId":"diagonalization","order":41,"type":"cheat-sheet","hook":"Diagonalizable $\\iff$ $n$ independent eigenvectors (geometric = algebraic multiplicity for each $\\lambda$).","body":"Diagonalizable $\\iff$ $n$ independent eigenvectors (geometric = algebraic multiplicity for each $\\lambda$).","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"cheat-3","sourceLabel":"GATE cheat sheet","detail":"Diagonalizable $\\iff$ $n$ independent eigenvectors (geometric = algebraic multiplicity for each $\\lambda$).","detailHtml":"<p>Diagonalizable $\\iff$ $n$ independent eigenvectors (geometric = algebraic multiplicity for each $\\lambda$).</p>","question":null},{"id":"la-diagonalization-042","topicId":"diagonalization","order":42,"type":"cheat-sheet","hook":"$A^k=PD^kP^{-1}$ — the reason diagonalization is worth it.","body":"$A^k=PD^kP^{-1}$ — the reason diagonalization is worth it.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"cheat-4","sourceLabel":"GATE cheat sheet","detail":"$A^k=PD^kP^{-1}$ — the reason diagonalization is worth it.","detailHtml":"<p>$A^k=PD^kP^{-1}$ — the reason diagonalization is worth it.</p>","question":null},{"id":"la-diagonalization-043","topicId":"diagonalization","order":43,"type":"trap","hook":"Trap","body":"\"Every matrix is diagonalizable.\" Reality: $\\begin{bmatrix}1&1\\\\0&1\\end{bmatrix}$ has $\\lambda=1$ twice but only one eigenvector — defective.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"trap-1","sourceLabel":"Common traps","detail":"Trap: &quot;Every matrix is diagonalizable.&quot; Reality: $\\begin{bmatrix}1&amp;1\\\\0&amp;1\\end{bmatrix}$ has $\\lambda=1$ twice but only one eigenvector — defective.","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;Every matrix is diagonalizable.&quot; <span class=\"right\">Reality:</span> $\\begin{bmatrix}1&amp;1\\\\0&amp;1\\end{bmatrix}$ has $\\lambda=1$ twice but only one eigenvector — defective.</p>","question":null},{"id":"la-diagonalization-044","topicId":"diagonalization","order":44,"type":"trap","hook":"Trap","body":"\"Repeated eigenvalues ⇒ not diagonalizable.\" Reality: fine if enough independent eigenvectors (e.g. $I$).","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"trap-2","sourceLabel":"Common traps","detail":"Trap: &quot;Repeated eigenvalues ⇒ not diagonalizable.&quot; Reality: fine if enough independent eigenvectors (e.g. $I$).","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;Repeated eigenvalues ⇒ not diagonalizable.&quot; <span class=\"right\">Reality:</span> fine if enough independent eigenvectors (e.g. $I$).</p>","question":null},{"id":"la-diagonalization-045","topicId":"diagonalization","order":45,"type":"trap","hook":"Trap","body":"\"$D$ can hold eigenvalues in any order.\" Reality: order of $D$ must match the column order of $P$.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"trap-3","sourceLabel":"Common traps","detail":"Trap: &quot;$D$ can hold eigenvalues in any order.&quot; Reality: order of $D$ must match the column order of $P$.","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;$D$ can hold eigenvalues in any order.&quot; <span class=\"right\">Reality:</span> order of $D$ must match the column order of $P$.</p>","question":null},{"id":"la-diagonalization-046","topicId":"diagonalization","order":46,"type":"practice","hook":"Q1. A $3\\times3$ matrix has eigenvalues $2,4,7$ (all distinct). Diagonalizable?","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"practice-1","sourceLabel":"Practice problems","detail":"Yes — distinct eigenvalues guarantee it.","detailHtml":"Yes — distinct eigenvalues guarantee it.","question":{"type":"REVEAL","prompt":"Q1. A $3\\times3$ matrix has eigenvalues $2,4,7$ (all distinct). Diagonalizable?","options":[],"answer":true,"explanation":"Yes — distinct eigenvalues guarantee it.","explanationHtml":"Yes — distinct eigenvalues guarantee it."}},{"id":"la-diagonalization-047","topicId":"diagonalization","order":47,"type":"practice","hook":"Q2. If $A=PDP^{-1}$ with $D=\\operatorname{diag}(1,2)$, what is $A^5$ in factored form?","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"practice-2","sourceLabel":"Practice problems","detail":"$A^5=P\\operatorname{diag}(1^5,2^5)P^{-1}=P\\operatorname{diag}(1,32)P^{-1}$.","detailHtml":"$A^5=P\\operatorname{diag}(1^5,2^5)P^{-1}=P\\operatorname{diag}(1,32)P^{-1}$.","question":{"type":"REVEAL","prompt":"Q2. If $A=PDP^{-1}$ with $D=\\operatorname{diag}(1,2)$, what is $A^5$ in factored form?","options":[],"answer":true,"explanation":"$A^5=P\\operatorname{diag}(1^5,2^5)P^{-1}=P\\operatorname{diag}(1,32)P^{-1}$.","explanationHtml":"$A^5=P\\operatorname{diag}(1^5,2^5)P^{-1}=P\\operatorname{diag}(1,32)P^{-1}$."}},{"id":"la-diagonalization-048","topicId":"diagonalization","order":48,"type":"practice","hook":"Which matrix is not diagonalizable?","body":"Choose an answer, then check the explanation.","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"07-diagonalization.html","sourceAnchor":"practice-quiz-1","sourceLabel":"Practice quiz","detail":"✅ Correct — repeated $\\lambda=1$ with only one eigenvector (defective).","detailHtml":"✅ Correct — repeated $\\lambda=1$ with only one eigenvector (defective).","question":{"type":"MCQ","prompt":"Which matrix is not diagonalizable?","options":["A: $\\begin{bmatrix}2&0\\\\0&5\\end{bmatrix}$","B: $\\begin{bmatrix}3&1\\\\1&3\\end{bmatrix}$","C: $\\begin{bmatrix}1&1\\\\0&1\\end{bmatrix}$","D: $\\begin{bmatrix}0&-1\\\\1&0\\end{bmatrix}$"],"answer":"C","explanation":"✅ Correct — repeated $\\lambda=1$ with only one eigenvector (defective).","explanationHtml":"✅ Correct — repeated $\\lambda=1$ with only one eigenvector (defective)."}},{"id":"la-orthogonality-001","topicId":"orthogonality","order":1,"type":"basic-definition","hook":"Dot product","body":"$u\\cdot v=u^{\\mathsf T}v=\\sum u_iv_i$; zero means perpendicular.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"definition-1","sourceLabel":"Basic definitions","detail":"Dot product: $u\\cdot v=u^{\\mathsf T}v=\\sum u_iv_i$; zero means perpendicular.","detailHtml":"<p><strong>Dot product:</strong> $u\\cdot v=u^{\\mathsf T}v=\\sum u_iv_i$; zero means perpendicular.</p>","question":null},{"id":"la-orthogonality-002","topicId":"orthogonality","order":2,"type":"basic-definition","hook":"Norm (length)","body":"$\\|v\\|=\\sqrt{v\\cdot v}$. Unit vector: a vector of length 1.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"definition-2","sourceLabel":"Basic definitions","detail":"Norm (length): $\\|v\\|=\\sqrt{v\\cdot v}$. Unit vector: a vector of length 1.","detailHtml":"<p><strong>Norm (length):</strong> $\\|v\\|=\\sqrt{v\\cdot v}$. <strong>Unit vector:</strong> a vector of length 1.</p>","question":null},{"id":"la-orthogonality-003","topicId":"orthogonality","order":3,"type":"basic-definition","hook":"Angle","body":"$\\cos\\theta = \\dfrac{u\\cdot v}{\\|u\\|\\,\\|v\\|}$ between two vectors.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"definition-3","sourceLabel":"Basic definitions","detail":"Angle: $\\cos\\theta = \\dfrac{u\\cdot v}{\\|u\\|\\,\\|v\\|}$ between two vectors.","detailHtml":"<p><strong>Angle:</strong> $\\cos\\theta = \\dfrac{u\\cdot v}{\\|u\\|\\,\\|v\\|}$ between two vectors.</p>","question":null},{"id":"la-orthogonality-004","topicId":"orthogonality","order":4,"type":"basic-definition","hook":"Orthogonal set","body":"every pair is perpendicular. Orthonormal: orthogonal and each of unit length.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"definition-4","sourceLabel":"Basic definitions","detail":"Orthogonal set: every pair is perpendicular. Orthonormal: orthogonal and each of unit length.","detailHtml":"<p><strong>Orthogonal set:</strong> every pair is perpendicular. <strong>Orthonormal:</strong> orthogonal <em>and</em> each of unit length.</p>","question":null},{"id":"la-orthogonality-005","topicId":"orthogonality","order":5,"type":"basic-definition","hook":"Projection","body":"the closest point to $v$ on another vector's line (or onto a subspace).","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"definition-5","sourceLabel":"Basic definitions","detail":"Projection: the closest point to $v$ on another vector&#x27;s line (or onto a subspace).","detailHtml":"<p><strong>Projection:</strong> the closest point to $v$ on another vector&#x27;s line (or onto a subspace).</p>","question":null},{"id":"la-orthogonality-006","topicId":"orthogonality","order":6,"type":"basic-definition","hook":"Orthogonal matrix","body":"square with orthonormal columns ($Q^{\\mathsf T}Q=I$); it preserves lengths and angles.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"definition-6","sourceLabel":"Basic definitions","detail":"Orthogonal matrix: square with orthonormal columns ($Q^{\\mathsf T}Q=I$); it preserves lengths and angles.","detailHtml":"<p><strong>Orthogonal matrix:</strong> square with orthonormal columns ($Q^{\\mathsf T}Q=I$); it preserves lengths and angles.</p>","question":null},{"id":"la-orthogonality-007","topicId":"orthogonality","order":7,"type":"basic-definition","hook":"Gram–Schmidt","body":"a procedure that turns any basis into an orthonormal one.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"definition-7","sourceLabel":"Basic definitions","detail":"Gram–Schmidt: a procedure that turns any basis into an orthonormal one.","detailHtml":"<p><strong>Gram–Schmidt:</strong> a procedure that turns any basis into an orthonormal one.</p>","question":null},{"id":"la-orthogonality-008","topicId":"orthogonality","order":8,"type":"deep-dive","hook":"What is orthogonality?","body":"Orthogonal = perpendicular. The x-axis $\\begin{bmatrix}1\\\\0\\end{bmatrix}$ and y-axis $\\begin{bmatrix}0\\\\1\\end{bmatrix}$ meet at 90°, so they are orthogonal.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-1","sourceLabel":"Study in Depth","detail":"Orthogonal = perpendicular . The x-axis $\\begin{bmatrix}1\\\\0\\end{bmatrix}$ and y-axis $\\begin{bmatrix}0\\\\1\\end{bmatrix}$ meet at 90°, so they are orthogonal. The power of linear algebra: orthogonality works in any dimension (ℝ¹⁰, ℝ¹⁰⁰⁰), not just 2D/3D — which is why it underpins data science. Plain idea: orthogonal directions do not disturb each other.","detailHtml":"\n          \n          <p><strong>Orthogonal = perpendicular</strong>. The x-axis $\\begin{bmatrix}1\\\\0\\end{bmatrix}$ and y-axis $\\begin{bmatrix}0\\\\1\\end{bmatrix}$ meet at 90°, so they are orthogonal.</p>\n          <p>The power of linear algebra: orthogonality works in <strong>any dimension</strong> (ℝ¹⁰, ℝ¹⁰⁰⁰), not just 2D/3D — which is why it underpins data science.</p>\n          <p><span style=\"color:var(--coral-text)\">Plain idea:</span> orthogonal directions do not disturb each other.</p>\n        ","question":null},{"id":"la-orthogonality-009","topicId":"orthogonality","order":9,"type":"deep-dive","hook":"The dot product","body":"For column vectors, uᵀ is a row, so uᵀv multiplies out to the sum of products.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-2","sourceLabel":"Study in Depth","detail":"u·v = u₁v₁ + u₂v₂ + … + uₙvₙ = uᵀv For column vectors, uᵀ is a row, so uᵀv multiplies out to the sum of products.","detailHtml":"\n          \n          <pre>u·v = u₁v₁ + u₂v₂ + … + uₙvₙ = uᵀv</pre>\n          <p>For column vectors, <code>uᵀ</code> is a row, so <code>uᵀv</code> multiplies out to the sum of products.</p>\n        ","question":null},{"id":"la-orthogonality-010","topicId":"orthogonality","order":10,"type":"worked-example","hook":"Dot product example","body":"u = $\\begin{bmatrix}1\\\\2\\end{bmatrix}$ , v = $\\begin{bmatrix}3\\\\4\\end{bmatrix}$u·v = 1×3 + 2×4 = 3 + 8 = 11","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-3","sourceLabel":"Study in Depth","detail":"u = $\\begin{bmatrix}1\\\\2\\end{bmatrix}$ , v = $\\begin{bmatrix}3\\\\4\\end{bmatrix}$ u·v = 1×3 + 2×4 = 3 + 8 = 11","detailHtml":"\n          \n          <div class=\"math-steps\"><div class=\"ms-line\">u = $\\begin{bmatrix}1\\\\2\\end{bmatrix}$ ,  v = $\\begin{bmatrix}3\\\\4\\end{bmatrix}$</div><div class=\"ms-line\">u·v = 1×3 + 2×4 = 3 + 8 = 11</div></div>\n        ","question":null},{"id":"la-orthogonality-011","topicId":"orthogonality","order":11,"type":"deep-dive","hook":"The orthogonality condition","body":"u ⊥ v ⟺ u·v = 0 $\\begin{bmatrix}1\\\\0\\end{bmatrix}$·$\\begin{bmatrix}0\\\\1\\end{bmatrix}$ = 0 → perpendicular","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-4","sourceLabel":"Study in Depth","detail":"u ⊥ v ⟺ u·v = 0 $\\begin{bmatrix}1\\\\0\\end{bmatrix}$·$\\begin{bmatrix}0\\\\1\\end{bmatrix}$ = 0 → perpendicular","detailHtml":"\n          \n          <pre>u ⊥ v  ⟺  u·v = 0</pre>\n          <div class=\"math-steps\"><div class=\"ms-line\">$\\begin{bmatrix}1\\\\0\\end{bmatrix}$·$\\begin{bmatrix}0\\\\1\\end{bmatrix}$ = 0  → perpendicular</div></div>\n        ","question":null},{"id":"la-orthogonality-012","topicId":"orthogonality","order":12,"type":"deep-dive","hook":"Finding a perpendicular vector","body":"In 2D, a vector perpendicular to $\\begin{bmatrix}a\\\\b\\end{bmatrix}$ is $\\begin{bmatrix}b\\\\-a\\end{bmatrix}$ (or $\\begin{bmatrix}-b\\\\a\\end{bmatrix}$) — swap and negate one.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-5","sourceLabel":"Study in Depth","detail":"u = $\\begin{bmatrix}1\\\\2\\end{bmatrix}$ , v = $\\begin{bmatrix}2\\\\-1\\end{bmatrix}$ u·v = 1×2 + 2×(−1) = 0 → orthogonal In 2D, a vector perpendicular to $\\begin{bmatrix}a\\\\b\\end{bmatrix}$ is $\\begin{bmatrix}b\\\\-a\\end{bmatrix}$ (or $\\begin{bmatrix}-b\\\\a\\end{bmatrix}$) — swap and negate one.","detailHtml":"\n          \n          <div class=\"math-steps\"><div class=\"ms-line\">u = $\\begin{bmatrix}1\\\\2\\end{bmatrix}$ ,  v = $\\begin{bmatrix}2\\\\-1\\end{bmatrix}$</div><div class=\"ms-line\">u·v = 1×2 + 2×(−1) = 0  → orthogonal</div></div>\n          <p>In 2D, a vector perpendicular to $\\begin{bmatrix}a\\\\b\\end{bmatrix}$ is $\\begin{bmatrix}b\\\\-a\\end{bmatrix}$ (or $\\begin{bmatrix}-b\\\\a\\end{bmatrix}$) — swap and negate one.</p>\n        ","question":null},{"id":"la-orthogonality-013","topicId":"orthogonality","order":13,"type":"deep-dive","hook":"Dot product & angle","body":"If θ = 90°, then cos 90° = 0, so u·v = 0. That is exactly why a zero dot product means perpendicular.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-6","sourceLabel":"Study in Depth","detail":"u·v = ||u|| ||v|| cos θ If θ = 90°, then cos 90° = 0, so u·v = 0 . That is exactly why a zero dot product means perpendicular.","detailHtml":"\n          \n          <pre>u·v = ||u|| ||v|| cos θ</pre>\n          <p>If θ = 90°, then cos 90° = 0, so <code>u·v = 0</code>. That is exactly why a zero dot product means perpendicular.</p>\n        ","question":null},{"id":"la-orthogonality-014","topicId":"orthogonality","order":14,"type":"deep-dive","hook":"Norm (length) of a vector","body":"It is just Pythagoras in n dimensions.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-7","sourceLabel":"Study in Depth","detail":"||v|| = √(v₁² + v₂² + … + vₙ²) = √(v·v) v = $\\begin{bmatrix}3\\\\4\\end{bmatrix}$ → ||v|| = √(9+16) = √25 = 5 It is just Pythagoras in n dimensions.","detailHtml":"\n          \n          <pre>||v|| = √(v₁² + v₂² + … + vₙ²) = √(v·v)</pre>\n          <div class=\"math-steps\"><div class=\"ms-line\">v = $\\begin{bmatrix}3\\\\4\\end{bmatrix}$ → ||v|| = √(9+16) = √25 = 5</div></div>\n          <p>It is just Pythagoras in n dimensions.</p>\n        ","question":null},{"id":"la-orthogonality-015","topicId":"orthogonality","order":15,"type":"deep-dive","hook":"Unit vector","body":"A unit vector has length 1.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-8","sourceLabel":"Study in Depth","detail":"A unit vector has length 1. $\\begin{bmatrix}1\\\\0\\end{bmatrix}$ and $\\begin{bmatrix}0\\\\1\\end{bmatrix}$ both have norm 1 → unit vectors","detailHtml":"\n          \n          <p>A <strong>unit vector</strong> has length 1.</p>\n          <div class=\"math-steps\"><div class=\"ms-line\">$\\begin{bmatrix}1\\\\0\\end{bmatrix}$ and $\\begin{bmatrix}0\\\\1\\end{bmatrix}$ both have norm 1 → unit vectors</div></div>\n        ","question":null},{"id":"la-orthogonality-016","topicId":"orthogonality","order":16,"type":"deep-dive","hook":"Normalization (make length 1)","body":"Divide a vector by its norm:","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-9","sourceLabel":"Study in Depth","detail":"Divide a vector by its norm: v = $\\begin{bmatrix}3\\\\4\\end{bmatrix}$ , ||v|| = 5 u = v/||v|| = $\\begin{bmatrix}3/5\\\\4/5\\end{bmatrix}$ (check: √(9/25+16/25) = 1) This process is called normalization .","detailHtml":"\n          \n          <p>Divide a vector by its norm:</p>\n          <div class=\"math-steps\"><div class=\"ms-line\">v = $\\begin{bmatrix}3\\\\4\\end{bmatrix}$ ,  ||v|| = 5</div><div class=\"ms-line\">u = v/||v|| = $\\begin{bmatrix}3/5\\\\4/5\\end{bmatrix}$   (check: √(9/25+16/25) = 1)</div></div>\n          <p>This process is called <strong>normalization</strong>.</p>\n        ","question":null},{"id":"la-orthogonality-017","topicId":"orthogonality","order":17,"type":"deep-dive","hook":"Orthogonal vs orthonormal","body":"Memory: orthonormal = orthogonal + normalized.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-10","sourceLabel":"Study in Depth","detail":"orthogonal : u·v = 0 (e.g. $\\begin{bmatrix}2\\\\0\\end{bmatrix}$ &amp; $\\begin{bmatrix}0\\\\5\\end{bmatrix}$) orthonormal: orthogonal AND each length 1 (e.g. $\\begin{bmatrix}1\\\\0\\end{bmatrix}$ &amp; $\\begin{bmatrix}0\\\\1\\end{bmatrix}$) Memory: orthonormal = orthogonal + normalized.","detailHtml":"\n          \n          <div class=\"math-steps\"><div class=\"ms-line\">orthogonal : u·v = 0                 (e.g. $\\begin{bmatrix}2\\\\0\\end{bmatrix}$ &amp; $\\begin{bmatrix}0\\\\5\\end{bmatrix}$)</div><div class=\"ms-line\">orthonormal: orthogonal AND each length 1  (e.g. $\\begin{bmatrix}1\\\\0\\end{bmatrix}$ &amp; $\\begin{bmatrix}0\\\\1\\end{bmatrix}$)</div></div>\n          <p><span style=\"color:var(--coral-text)\">Memory:</span> orthonormal = orthogonal + normalized.</p>\n        ","question":null},{"id":"la-orthogonality-018","topicId":"orthogonality","order":18,"type":"deep-dive","hook":"Orthogonal basis","body":"A basis whose vectors are mutually orthogonal. The cleanest example is the standard basis of ℝ²: $\\begin{bmatrix}1\\\\0\\end{bmatrix}$, $\\begin{bmatrix}0\\\\1\\end{bmatrix}$ (orthonormal).","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-11","sourceLabel":"Study in Depth","detail":"A basis whose vectors are mutually orthogonal. The cleanest example is the standard basis of ℝ²: $\\begin{bmatrix}1\\\\0\\end{bmatrix}$, $\\begin{bmatrix}0\\\\1\\end{bmatrix}$ (orthonormal). 🎮 Game terms: moving right never accidentally moves you up — the directions do not interfere.","detailHtml":"\n          \n          <p>A basis whose vectors are mutually orthogonal. The cleanest example is the standard basis of ℝ²: $\\begin{bmatrix}1\\\\0\\end{bmatrix}$, $\\begin{bmatrix}0\\\\1\\end{bmatrix}$ (orthonormal).</p>\n          <p><span style=\"color:var(--coral-text)\">🎮 Game terms:</span> moving right never accidentally moves you up — the directions do not interfere.</p>\n        ","question":null},{"id":"la-orthogonality-019","topicId":"orthogonality","order":19,"type":"deep-dive","hook":"Orthogonal ⇒ independent","body":"Non-zero, mutually orthogonal vectors are automatically linearly independent.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-12","sourceLabel":"Study in Depth","detail":"Non-zero, mutually orthogonal vectors are automatically linearly independent. v₁·v₂ = v₁·v₃ = v₂·v₃ = 0 (all non-zero) ⇒ independent None can be built from the others when they point in completely separate directions.","detailHtml":"\n          \n          <p><strong>Non-zero, mutually orthogonal vectors are automatically linearly independent.</strong></p>\n          <pre>v₁·v₂ = v₁·v₃ = v₂·v₃ = 0 (all non-zero)  ⇒  independent</pre>\n          <p>None can be built from the others when they point in completely separate directions.</p>\n        ","question":null},{"id":"la-orthogonality-020","topicId":"orthogonality","order":20,"type":"deep-dive","hook":"Inner product","body":"The dot product is the standard inner product: ⟨u,v⟩ = u·v = uᵀv. For GATE DA, treat them as the same thing.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-13","sourceLabel":"Study in Depth","detail":"The dot product is the standard inner product : ⟨u,v⟩ = u·v = uᵀv . For GATE DA, treat them as the same thing.","detailHtml":"\n          \n          <p>The dot product is the standard <strong>inner product</strong>: <code>⟨u,v⟩ = u·v = uᵀv</code>. For GATE DA, treat them as the same thing.</p>\n        ","question":null},{"id":"la-orthogonality-021","topicId":"orthogonality","order":21,"type":"deep-dive","hook":"Projection — the core idea","body":"Projection = the shadow of one vector onto another. With light falling straight down, vector b casts a shadow on vector a:","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-14","sourceLabel":"Study in Depth","detail":"Projection = the shadow of one vector onto another. With light falling straight down, vector b casts a shadow on vector a: proj_a(b) = the part of b lying along a","detailHtml":"\n          \n          <p><strong>Projection</strong> = the shadow of one vector onto another. With light falling straight down, vector b casts a shadow on vector a:</p>\n          <pre>proj_a(b) = the part of b lying along a</pre>\n        ","question":null},{"id":"la-orthogonality-022","topicId":"orthogonality","order":22,"type":"deep-dive","hook":"Projection of b onto a (formula)","body":"The denominator a·a = ||a||² adjusts for the length of a.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-15","sourceLabel":"Study in Depth","detail":"proj_a(b) = (a·b / a·a) a = (a·b / ||a||²) a The denominator a·a = ||a||² adjusts for the length of a.","detailHtml":"\n          \n          <pre>proj_a(b) = (a·b / a·a) a = (a·b / ||a||²) a</pre>\n          <p>The denominator <code>a·a = ||a||²</code> adjusts for the length of a.</p>\n        ","question":null},{"id":"la-orthogonality-023","topicId":"orthogonality","order":23,"type":"worked-example","hook":"Projection example + the error vector","body":"Key idea: b = projection + orthogonal error.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-16","sourceLabel":"Study in Depth","detail":"a = $\\begin{bmatrix}1\\\\0\\end{bmatrix}$ , b = $\\begin{bmatrix}3\\\\4\\end{bmatrix}$ a·b = 3 , a·a = 1 → proj = 3·$\\begin{bmatrix}1\\\\0\\end{bmatrix}$ = $\\begin{bmatrix}3\\\\0\\end{bmatrix}$ error e = b − proj = $\\begin{bmatrix}0\\\\4\\end{bmatrix}$ and e·a = 0 → e ⊥ a Key idea: b = projection + orthogonal error .","detailHtml":"\n          \n          <div class=\"math-steps\"><div class=\"ms-line\">a = $\\begin{bmatrix}1\\\\0\\end{bmatrix}$ ,  b = $\\begin{bmatrix}3\\\\4\\end{bmatrix}$</div><div class=\"ms-line\">a·b = 3 ,  a·a = 1  →  proj = 3·$\\begin{bmatrix}1\\\\0\\end{bmatrix}$ = $\\begin{bmatrix}3\\\\0\\end{bmatrix}$</div><div class=\"ms-line\"></div><div class=\"ms-line\">error e = b − proj = $\\begin{bmatrix}0\\\\4\\end{bmatrix}$   and  e·a = 0  → e ⊥ a</div></div>\n          <p><span style=\"color:var(--coral-text)\">Key idea:</span> <code>b = projection + orthogonal error</code>.</p>\n        ","question":null},{"id":"la-orthogonality-024","topicId":"orthogonality","order":24,"type":"deep-dive","hook":"Projection onto a unit vector","body":"If a is not unit length the denominator handles it; a=$\\begin{bmatrix}2\\\\0\\end{bmatrix}$, b=$\\begin{bmatrix}3\\\\4\\end{bmatrix}$ still gives $\\begin{bmatrix}3\\\\0\\end{bmatrix}$.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-17","sourceLabel":"Study in Depth","detail":"If a is not unit length the denominator handles it; a=$\\begin{bmatrix}2\\\\0\\end{bmatrix}$, b=$\\begin{bmatrix}3\\\\4\\end{bmatrix}$ still gives $\\begin{bmatrix}3\\\\0\\end{bmatrix}$. If u is a unit vector, u·u = 1 , so it simplifies: proj_u(b) = (u·b) u For an orthonormal basis, the coefficient along uᵢ is just b·uᵢ — no denominator. That is why orthonormal bases are so clean.","detailHtml":"\n          \n          <p>If a is not unit length the denominator handles it; a=$\\begin{bmatrix}2\\\\0\\end{bmatrix}$, b=$\\begin{bmatrix}3\\\\4\\end{bmatrix}$ still gives $\\begin{bmatrix}3\\\\0\\end{bmatrix}$.</p>\n          <p>If <code>u</code> is a <strong>unit</strong> vector, <code>u·u = 1</code>, so it simplifies:</p>\n          <pre>proj_u(b) = (u·b) u</pre>\n          <p>For an orthonormal basis, the coefficient along uᵢ is just <code>b·uᵢ</code> — no denominator. That is why orthonormal bases are so clean.</p>\n        ","question":null},{"id":"la-orthogonality-025","topicId":"orthogonality","order":25,"type":"deep-dive","hook":"Projection onto a subspace","body":"To project b onto the column space of A (independent columns):","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-18","sourceLabel":"Study in Depth","detail":"To project b onto the column space of A (independent columns): p = A(AᵀA)⁻¹Aᵀ b projection matrix P = A(AᵀA)⁻¹Aᵀ , p = Pb (AᵀA is invertible when A&#x27;s columns are independent.)","detailHtml":"\n          \n          <p>To project b onto the column space of A (independent columns):</p>\n          <pre>p = A(AᵀA)⁻¹Aᵀ b\nprojection matrix  P = A(AᵀA)⁻¹Aᵀ ,   p = Pb</pre>\n          <p>(AᵀA is invertible when A&#x27;s columns are independent.)</p>\n        ","question":null},{"id":"la-orthogonality-026","topicId":"orthogonality","order":26,"type":"deep-dive","hook":"Projection matrix & its properties","body":"λ = 1 directions are kept (already in the subspace); λ = 0 directions are removed. The error e = b − Pb is orthogonal to the subspace, so Aᵀe = 0 → least squares.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-19","sourceLabel":"Study in Depth","detail":"P² = P (idempotent — projecting twice changes nothing) Pᵀ = P (orthogonal projection is symmetric) eigenvalues of P are 0 or 1 (since λ² = λ) λ = 1 directions are kept (already in the subspace); λ = 0 directions are removed. The error e = b − Pb is orthogonal to the subspace, so Aᵀe = 0 → least squares.","detailHtml":"\n          \n          <pre>P² = P     (idempotent — projecting twice changes nothing)\nPᵀ = P     (orthogonal projection is symmetric)\neigenvalues of P are 0 or 1   (since λ² = λ)</pre>\n          <p>λ = 1 directions are kept (already in the subspace); λ = 0 directions are removed. The error <code>e = b − Pb</code> is orthogonal to the subspace, so <code>Aᵀe = 0</code> → least squares.</p>\n        ","question":null},{"id":"la-orthogonality-027","topicId":"orthogonality","order":27,"type":"deep-dive","hook":"The least-squares problem","body":"When Ax = b has no exact solution (overdetermined: more equations than unknowns), find the best approximation:","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-20","sourceLabel":"Study in Depth","detail":"When Ax = b has no exact solution (overdetermined: more equations than unknowns), find the best approximation: minimize ||Ax − b||² (make the error e = b − Ax as small as possible) This is the heart of fitting models to data.","detailHtml":"\n          \n          <p>When <code>Ax = b</code> has <strong>no exact solution</strong> (overdetermined: more equations than unknowns), find the best approximation:</p>\n          <pre>minimize ||Ax − b||²    (make the error e = b − Ax as small as possible)</pre>\n          <p>This is the heart of fitting models to data.</p>\n        ","question":null},{"id":"la-orthogonality-028","topicId":"orthogonality","order":28,"type":"deep-dive","hook":"Least-squares geometry","body":"Ax always lies in the column space of A, but b may not. The closest point is the projection of b onto C(A):","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-21","sourceLabel":"Study in Depth","detail":"Ax always lies in the column space of A, but b may not. The closest point is the projection of b onto C(A): p = Ax̂ , error e = b − Ax̂ ⊥ C(A) ⇒ Aᵀe = 0 ⇒ Aᵀ(b − Ax̂) = 0","detailHtml":"\n          \n          <p><code>Ax</code> always lies in the column space of A, but b may not. The closest point is the <strong>projection</strong> of b onto C(A):</p>\n          <pre>p = Ax̂ ,  error e = b − Ax̂ ⊥ C(A)  ⇒  Aᵀe = 0  ⇒  Aᵀ(b − Ax̂) = 0</pre>\n        ","question":null},{"id":"la-orthogonality-029","topicId":"orthogonality","order":29,"type":"deep-dive","hook":"The normal equations","body":"This is exactly where the projection matrix P = A(AᵀA)⁻¹Aᵀ comes from.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-22","sourceLabel":"Study in Depth","detail":"AᵀA x̂ = Aᵀb (the normal equations) if AᵀA invertible: x̂ = (AᵀA)⁻¹Aᵀb projection: p = A x̂ = A(AᵀA)⁻¹Aᵀ b This is exactly where the projection matrix P = A(AᵀA)⁻¹Aᵀ comes from.","detailHtml":"\n          \n          <pre>AᵀA x̂ = Aᵀb        (the normal equations)\nif AᵀA invertible:  x̂ = (AᵀA)⁻¹Aᵀb\nprojection:  p = A x̂ = A(AᵀA)⁻¹Aᵀ b</pre>\n          <p>This is exactly where the projection matrix <code>P = A(AᵀA)⁻¹Aᵀ</code> comes from.</p>\n        ","question":null},{"id":"la-orthogonality-030","topicId":"orthogonality","order":30,"type":"deep-dive","hook":"Least squares in linear regression","body":"The residual e = y − Xβ is orthogonal to the column space of X (Xᵀe = 0). This is why orthogonality powers data science.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-23","sourceLabel":"Study in Depth","detail":"Xβ ≈ y (X = features, β = parameters, y = targets) normal equation: XᵀX β = Xᵀy → β = (XᵀX)⁻¹Xᵀy The residual e = y − Xβ is orthogonal to the column space of X ( Xᵀe = 0 ). This is why orthogonality powers data science.","detailHtml":"\n          \n          <pre>Xβ ≈ y   (X = features, β = parameters, y = targets)\nnormal equation:  XᵀX β = Xᵀy   →   β = (XᵀX)⁻¹Xᵀy</pre>\n          <p>The residual <code>e = y − Xβ</code> is orthogonal to the column space of X (<code>Xᵀe = 0</code>). This is why orthogonality powers data science.</p>\n        ","question":null},{"id":"la-orthogonality-031","topicId":"orthogonality","order":31,"type":"deep-dive","hook":"Gram–Schmidt — the idea","body":"Gram–Schmidt turns a set of independent vectors into an orthonormal basis: messy independent directions → clean perpendicular unit vectors.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-24","sourceLabel":"Study in Depth","detail":"Gram–Schmidt turns a set of independent vectors into an orthonormal basis: messy independent directions → clean perpendicular unit vectors. keep v₁&#x27;s direction → remove from v₂ the part along v₁ → normalize the leftover → repeat","detailHtml":"\n          \n          <p>Gram–Schmidt turns a set of independent vectors into an <strong>orthonormal</strong> basis: messy independent directions → clean perpendicular unit vectors.</p>\n          <pre>keep v₁&#x27;s direction → remove from v₂ the part along v₁ → normalize the leftover → repeat</pre>\n        ","question":null},{"id":"la-orthogonality-032","topicId":"orthogonality","order":32,"type":"deep-dive","hook":"Gram–Schmidt — the formula","body":"u₁ = v₁ / ||v₁|| w₂ = v₂ − (v₂·u₁)u₁ , u₂ = w₂ / ||w₂|| w₃ = v₃ − (v₃·u₁)u₁ − (v₃·u₂)u₂ , u₃ = w₃ / ||w₃|| general: wₖ = vₖ − Σ_{i","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-25","sourceLabel":"Study in Depth","detail":"u₁ = v₁ / ||v₁|| w₂ = v₂ − (v₂·u₁)u₁ , u₂ = w₂ / ||w₂|| w₃ = v₃ − (v₃·u₁)u₁ − (v₃·u₂)u₂ , u₃ = w₃ / ||w₃|| general: wₖ = vₖ − Σ_{i","detailHtml":"\n          \n          <pre>u₁ = v₁ / ||v₁||\nw₂ = v₂ − (v₂·u₁)u₁ ,        u₂ = w₂ / ||w₂||\nw₃ = v₃ − (v₃·u₁)u₁ − (v₃·u₂)u₂ , u₃ = w₃ / ||w₃||\n\ngeneral:  wₖ = vₖ − Σ_{i<k}(vₖ·uᵢ)uᵢ ,=\"\" uₖ=\"wₖ\" ||wₖ||<=\"\" pre=\"\">\n        </k}(vₖ·uᵢ)uᵢ></pre>","question":null},{"id":"la-orthogonality-033","topicId":"orthogonality","order":33,"type":"worked-example","hook":"Gram–Schmidt — worked example","body":"Messy vectors became clean x–y axes.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-26","sourceLabel":"Study in Depth","detail":"v₁ = $\\begin{bmatrix}1\\\\0\\end{bmatrix}$ , v₂ = $\\begin{bmatrix}1\\\\1\\end{bmatrix}$ u₁ = $\\begin{bmatrix}1\\\\0\\end{bmatrix}$ v₂·u₁ = 1 → w₂ = $\\begin{bmatrix}1\\\\1\\end{bmatrix}$ − 1·$\\begin{bmatrix}1\\\\0\\end{bmatrix}$ = $\\begin{bmatrix}0\\\\1\\end{bmatrix}$ → u₂ = $\\begin{bmatrix}0\\\\1\\end{bmatrix}$ orthonormal basis: $\\begin{bmatrix}1\\\\0\\end{bmatrix}$, $\\begin{bmatrix}0\\\\1\\end{bmatrix}$ Messy vectors became clean x–y axes.","detailHtml":"\n          \n          <div class=\"math-steps\"><div class=\"ms-line\">v₁ = $\\begin{bmatrix}1\\\\0\\end{bmatrix}$ ,  v₂ = $\\begin{bmatrix}1\\\\1\\end{bmatrix}$</div><div class=\"ms-line\"></div><div class=\"ms-line\">u₁ = $\\begin{bmatrix}1\\\\0\\end{bmatrix}$</div><div class=\"ms-line\">v₂·u₁ = 1 → w₂ = $\\begin{bmatrix}1\\\\1\\end{bmatrix}$ − 1·$\\begin{bmatrix}1\\\\0\\end{bmatrix}$ = $\\begin{bmatrix}0\\\\1\\end{bmatrix}$ → u₂ = $\\begin{bmatrix}0\\\\1\\end{bmatrix}$</div><div class=\"ms-line\"></div><div class=\"ms-line\">orthonormal basis: $\\begin{bmatrix}1\\\\0\\end{bmatrix}$, $\\begin{bmatrix}0\\\\1\\end{bmatrix}$</div></div>\n          <p>Messy vectors became clean x–y axes.</p>\n        ","question":null},{"id":"la-orthogonality-034","topicId":"orthogonality","order":34,"type":"deep-dive","hook":"Orthogonal matrix","body":"A matrix Q is orthogonal when its columns are orthonormal:","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-27","sourceLabel":"Study in Depth","detail":"A matrix Q is orthogonal when its columns are orthonormal: QᵀQ = I ; if Q is square, Q⁻¹ = Qᵀ Q = $\\begin{bmatrix}0&amp;-1\\\\1&amp;0\\end{bmatrix}$ (90° rotation): columns $\\begin{bmatrix}0\\\\1\\end{bmatrix}$, $\\begin{bmatrix}-1\\\\0\\end{bmatrix}$ — unit &amp; perpendicular","detailHtml":"\n          \n          <p>A matrix <code>Q</code> is <strong>orthogonal</strong> when its columns are orthonormal:</p>\n          <pre>QᵀQ = I ;   if Q is square, Q⁻¹ = Qᵀ</pre>\n          <div class=\"math-steps\"><div class=\"ms-line\">Q = $\\begin{bmatrix}0&amp;-1\\\\1&amp;0\\end{bmatrix}$  (90° rotation): columns $\\begin{bmatrix}0\\\\1\\end{bmatrix}$, $\\begin{bmatrix}-1\\\\0\\end{bmatrix}$ — unit &amp; perpendicular</div></div>\n        ","question":null},{"id":"la-orthogonality-035","topicId":"orthogonality","order":35,"type":"deep-dive","hook":"Why QᵀQ = I","body":"The (i, j) entry of QᵀQ is qᵢ·qⱼ. For orthonormal columns: qᵢ·qᵢ = 1 and qᵢ·qⱼ = 0 (i ≠ j) — exactly the identity matrix.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-28","sourceLabel":"Study in Depth","detail":"The (i, j) entry of QᵀQ is qᵢ·qⱼ . For orthonormal columns: qᵢ·qᵢ = 1 and qᵢ·qⱼ = 0 (i ≠ j) — exactly the identity matrix.","detailHtml":"\n          \n          <p>The (i, j) entry of <code>QᵀQ</code> is <code>qᵢ·qⱼ</code>. For orthonormal columns: <code>qᵢ·qᵢ = 1</code> and <code>qᵢ·qⱼ = 0</code> (i ≠ j) — exactly the identity matrix.</p>\n        ","question":null},{"id":"la-orthogonality-036","topicId":"orthogonality","order":36,"type":"deep-dive","hook":"Properties of orthogonal matrices","body":"They represent rotations, reflections, or combinations.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-29","sourceLabel":"Study in Depth","detail":"QᵀQ = QQᵀ = I , Q⁻¹ = Qᵀ (square Q). det(Q) = ±1 . ||Qx|| = ||x|| (lengths preserved). (Qu)·(Qv) = u·v (angles preserved). eigenvalues satisfy |λ| = 1 . They represent rotations, reflections, or combinations.","detailHtml":"\n          \n          <ul class=\"styled\">\n            <li><code>QᵀQ = QQᵀ = I</code>,   <code>Q⁻¹ = Qᵀ</code> (square Q).</li>\n            <li><code>det(Q) = ±1</code>.</li>\n            <li><code>||Qx|| = ||x||</code> (lengths preserved).</li>\n            <li><code>(Qu)·(Qv) = u·v</code> (angles preserved).</li>\n            <li>eigenvalues satisfy <code>|λ| = 1</code>.</li>\n          </ul>\n          <p>They represent rotations, reflections, or combinations.</p>\n        ","question":null},{"id":"la-orthogonality-037","topicId":"orthogonality","order":37,"type":"deep-dive","hook":"Length & angle preservation (proofs)","body":"🎮 Imagine: rotate/flip an object without stretching it.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-30","sourceLabel":"Study in Depth","detail":"||Qx||² = (Qx)ᵀ(Qx) = xᵀQᵀQx = xᵀIx = xᵀx = ||x||² (Qu)·(Qv) = uᵀQᵀQv = uᵀv = u·v 🎮 Imagine: rotate/flip an object without stretching it.","detailHtml":"\n          \n          <pre>||Qx||² = (Qx)ᵀ(Qx) = xᵀQᵀQx = xᵀIx = xᵀx = ||x||²\n(Qu)·(Qv) = uᵀQᵀQv = uᵀv = u·v</pre>\n          <p><span style=\"color:var(--coral-text)\">🎮 Imagine:</span> rotate/flip an object without stretching it.</p>\n        ","question":null},{"id":"la-orthogonality-038","topicId":"orthogonality","order":38,"type":"deep-dive","hook":"Determinant of an orthogonal matrix","body":"+1 = rotation (orientation kept); −1 = reflection (orientation flipped).","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-31","sourceLabel":"Study in Depth","detail":"QᵀQ = I ⇒ det(Qᵀ)det(Q) = 1 ⇒ det(Q)² = 1 ⇒ det(Q) = ±1 +1 = rotation (orientation kept); −1 = reflection (orientation flipped).","detailHtml":"\n          \n          <pre>QᵀQ = I ⇒ det(Qᵀ)det(Q) = 1 ⇒ det(Q)² = 1 ⇒ det(Q) = ±1</pre>\n          <p><code>+1</code> = rotation (orientation kept); <code>−1</code> = reflection (orientation flipped).</p>\n        ","question":null},{"id":"la-orthogonality-039","topicId":"orthogonality","order":39,"type":"deep-dive","hook":"Eigenvalues of an orthogonal matrix","body":"Real eigenvalues can only be ±1; complex ones lie on the unit circle.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-32","sourceLabel":"Study in Depth","detail":"Qx = λx ⇒ ||Qx|| = |λ|·||x||, but ||Qx|| = ||x|| ⇒ |λ| = 1 Real eigenvalues can only be ±1 ; complex ones lie on the unit circle.","detailHtml":"\n          \n          <pre>Qx = λx ⇒ ||Qx|| = |λ|·||x||, but ||Qx|| = ||x|| ⇒ |λ| = 1</pre>\n          <p>Real eigenvalues can only be <code>±1</code>; complex ones lie on the unit circle.</p>\n        ","question":null},{"id":"la-orthogonality-040","topicId":"orthogonality","order":40,"type":"deep-dive","hook":"Orthogonal matrix vs orthogonal vectors","body":"An orthogonal matrix is NOT \"a matrix with dot product zero\" — it is a matrix whose columns are unit perpendicular directions.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-33","sourceLabel":"Study in Depth","detail":"orthogonal vectors: u·v = 0 orthogonal matrix: QᵀQ = I (columns orthonormal) An orthogonal matrix is NOT &quot;a matrix with dot product zero&quot; — it is a matrix whose columns are unit perpendicular directions.","detailHtml":"\n          \n          <pre>orthogonal vectors:  u·v = 0\northogonal matrix:   QᵀQ = I  (columns orthonormal)</pre>\n          <p>An orthogonal matrix is NOT &quot;a matrix with dot product zero&quot; — it is a matrix whose columns are unit perpendicular directions.</p>\n        ","question":null},{"id":"la-orthogonality-041","topicId":"orthogonality","order":41,"type":"deep-dive","hook":"Orthogonal complement (W⊥)","body":"W⊥ (\"W perp\") = all vectors perpendicular to every vector in W.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-34","sourceLabel":"Study in Depth","detail":"W⊥ (&quot;W perp&quot;) = all vectors perpendicular to every vector in W. W = x-axis = span{$\\begin{bmatrix}1\\\\0\\end{bmatrix}$} → W⊥ = y-axis = span{$\\begin{bmatrix}0\\\\1\\end{bmatrix}$} The four-subspace relations ( Row ⊥ Null , Col ⊥ Left-null ) are the big example — see the Rank &amp; Nullity topic.","detailHtml":"\n          \n          <p><code>W⊥</code> (&quot;W perp&quot;) = all vectors perpendicular to every vector in W.</p>\n          <div class=\"math-steps\"><div class=\"ms-line\">W = x-axis = span{$\\begin{bmatrix}1\\\\0\\end{bmatrix}$}   →   W⊥ = y-axis = span{$\\begin{bmatrix}0\\\\1\\end{bmatrix}$}</div></div>\n          <p>The four-subspace relations (<code>Row ⊥ Null</code>, <code>Col ⊥ Left-null</code>) are the big example — see the Rank &amp; Nullity topic.</p>\n        ","question":null},{"id":"la-orthogonality-042","topicId":"orthogonality","order":42,"type":"deep-dive","hook":"Symmetric matrices & orthogonality","body":"For a real symmetric matrix (A = Aᵀ), eigenvectors for distinct eigenvalues are orthogonal, so they can be chosen orthonormal.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-35","sourceLabel":"Study in Depth","detail":"For a real symmetric matrix ( A = Aᵀ ), eigenvectors for distinct eigenvalues are orthogonal , so they can be chosen orthonormal. That gives orthogonal diagonalization A = QDQᵀ (the spectral theorem) — built out fully in the Diagonalization topic.","detailHtml":"\n          \n          <p>For a real symmetric matrix (<code>A = Aᵀ</code>), eigenvectors for <strong>distinct eigenvalues are orthogonal</strong>, so they can be chosen orthonormal.</p>\n          <p>That gives orthogonal diagonalization <code>A = QDQᵀ</code> (the spectral theorem) — built out fully in the Diagonalization topic.</p>\n        ","question":null},{"id":"la-orthogonality-043","topicId":"orthogonality","order":43,"type":"deep-dive","hook":"PCA connection (preview)","body":"A covariance matrix is symmetric, so its eigenvectors are orthonormal — these become the principal components: orthogonal directions of maximum variance (PC1 the most, PC2 ⊥ PC1 the next, …). Full PCA lives in the SVD & PCA topic.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-36","sourceLabel":"Study in Depth","detail":"A covariance matrix is symmetric, so its eigenvectors are orthonormal — these become the principal components : orthogonal directions of maximum variance (PC1 the most, PC2 ⊥ PC1 the next, …). Full PCA lives in the SVD &amp; PCA topic.","detailHtml":"\n          \n          <p>A covariance matrix is symmetric, so its eigenvectors are orthonormal — these become the <strong>principal components</strong>: orthogonal directions of maximum variance (PC1 the most, PC2 ⊥ PC1 the next, …). Full PCA lives in the SVD &amp; PCA topic.</p>\n        ","question":null},{"id":"la-orthogonality-044","topicId":"orthogonality","order":44,"type":"deep-dive","hook":"Cauchy–Schwarz inequality","body":"It follows from u·v = ||u|| ||v|| cos θ and |cos θ| ≤ 1. It guarantees the cosine/correlation between two vectors stays in [−1, 1].","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-37","sourceLabel":"Study in Depth","detail":"|u·v| ≤ ||u|| · ||v|| (equality ⟺ u and v are parallel) It follows from u·v = ||u|| ||v|| cos θ and |cos θ| ≤ 1 . It guarantees the cosine/correlation between two vectors stays in [−1, 1] .","detailHtml":"\n          \n          <pre>|u·v| ≤ ||u|| · ||v||     (equality ⟺ u and v are parallel)</pre>\n          <p>It follows from <code>u·v = ||u|| ||v|| cos θ</code> and <code>|cos θ| ≤ 1</code>. It guarantees the cosine/correlation between two vectors stays in <code>[−1, 1]</code>.</p>\n        ","question":null},{"id":"la-orthogonality-045","topicId":"orthogonality","order":45,"type":"deep-dive","hook":"Common GATE traps","body":"\"Orthogonal means length 1\"? No — orthogonal = dot product 0; length 1 = unit; both = orthonormal. u·v = 0 ⇒ one vector is zero? No ($\\begin{bmatrix}1\\\\0\\end{bmatrix}$·$\\begin{bmatrix}0\\\\1\\end{bmatrix}$=0, both non-zero). Normal equation is Ax = b?…","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-38","sourceLabel":"Study in Depth","detail":"&quot;Orthogonal means length 1&quot;? No — orthogonal = dot product 0; length 1 = unit; both = orthonormal. u·v = 0 ⇒ one vector is zero? No ($\\begin{bmatrix}1\\\\0\\end{bmatrix}$·$\\begin{bmatrix}0\\\\1\\end{bmatrix}$=0, both non-zero). Normal equation is Ax = b ? No — it is AᵀA x = Aᵀb . det(Q) = 1 only? No — ±1 . Non-zero orthogonal vectors can be dependent? No — they are independent. Projection matrix P² = P…","detailHtml":"\n          \n          <ul class=\"styled\">\n            <li>&quot;Orthogonal means length 1&quot;? <strong>No</strong> — orthogonal = dot product 0; length 1 = unit; both = orthonormal.</li>\n            <li><code>u·v = 0</code> ⇒ one vector is zero? <strong>No</strong> ($\\begin{bmatrix}1\\\\0\\end{bmatrix}$·$\\begin{bmatrix}0\\\\1\\end{bmatrix}$=0, both non-zero).</li>\n            <li>Normal equation is <code>Ax = b</code>? <strong>No</strong> — it is <code>AᵀA x = Aᵀb</code>.</li>\n            <li><code>det(Q) = 1</code> only? <strong>No</strong> — <code>±1</code>.</li>\n            <li>Non-zero orthogonal vectors can be dependent? <strong>No</strong> — they are independent.</li>\n            <li>Projection matrix <code>P² = P</code>, orthogonal projection <code>Pᵀ = P</code>, residual ⊥ C(A)? <strong>All true.</strong></li>\n          </ul>\n        ","question":null},{"id":"la-orthogonality-046","topicId":"orthogonality","order":46,"type":"deep-dive","hook":"Practice problems","body":"Q1. $\\begin{bmatrix}1\\\\2\\end{bmatrix}$ and $\\begin{bmatrix}2\\\\-1\\end{bmatrix}$ orthogonal?","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-39","sourceLabel":"Study in Depth","detail":"Q1. $\\begin{bmatrix}1\\\\2\\end{bmatrix}$ and $\\begin{bmatrix}2\\\\-1\\end{bmatrix}$ orthogonal? 1×2 + 2×(−1) = 0 → yes Q2. ||$\\begin{bmatrix}6\\\\8\\end{bmatrix}$||? √(36+64) = 10 Q3. Normalize $\\begin{bmatrix}6\\\\8\\end{bmatrix}$? $\\begin{bmatrix}6/10\\\\8/10\\end{bmatrix}$ = $\\begin{bmatrix}3/5\\\\4/5\\end{bmatrix}$ Q4. Projection of $\\begin{bmatrix}5\\\\7\\end{bmatrix}$ onto $\\begin{bmatrix}1\\\\0\\end{bmatrix}$?…","detailHtml":"\n          \n          <p class=\"lead\">Q1. $\\begin{bmatrix}1\\\\2\\end{bmatrix}$ and $\\begin{bmatrix}2\\\\-1\\end{bmatrix}$ orthogonal?</p>\n          <pre>1×2 + 2×(−1) = 0 → yes</pre>\n          <p class=\"lead\">Q2. ||$\\begin{bmatrix}6\\\\8\\end{bmatrix}$||?</p>\n          <pre>√(36+64) = 10</pre>\n          <p class=\"lead\">Q3. Normalize $\\begin{bmatrix}6\\\\8\\end{bmatrix}$?</p>\n          <div class=\"math-steps\"><div class=\"ms-line\">$\\begin{bmatrix}6/10\\\\8/10\\end{bmatrix}$ = $\\begin{bmatrix}3/5\\\\4/5\\end{bmatrix}$</div></div>\n          <p class=\"lead\">Q4. Projection of $\\begin{bmatrix}5\\\\7\\end{bmatrix}$ onto $\\begin{bmatrix}1\\\\0\\end{bmatrix}$?</p>\n          <div class=\"math-steps\"><div class=\"ms-line\">(5/1)·$\\begin{bmatrix}1\\\\0\\end{bmatrix}$ = $\\begin{bmatrix}5\\\\0\\end{bmatrix}$</div></div>\n          <p class=\"lead\">Q5. Is $\\begin{bmatrix}0&amp;-1\\\\1&amp;0\\end{bmatrix}$ orthogonal?</p>\n          <pre>columns unit &amp; perpendicular → yes</pre>\n          <p class=\"lead\">Q6. Q orthogonal → Q⁻¹? det(Q)? P projection → eigenvalues?</p>\n          <pre>Q⁻¹ = Qᵀ ;  det = ±1 ;  P eigenvalues 0 or 1</pre>\n        ","question":null},{"id":"la-orthogonality-047","topicId":"orthogonality","order":47,"type":"deep-dive","hook":"GATE cheatsheet","body":"u·v = uᵀv; ||v|| = √(v·v); orthogonal ⟺ u·v = 0. Orthonormal = orthogonal + unit; non-zero orthogonal vectors are independent. proj_a(b) = (aᵀb/aᵀa)a; unit a → (aᵀb)a. Projection matrix P = A(AᵀA)⁻¹Aᵀ; P² = P, Pᵀ = P, eigenvalues 0/1. Least squares…","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-40","sourceLabel":"Study in Depth","detail":"u·v = uᵀv ; ||v|| = √(v·v) ; orthogonal ⟺ u·v = 0 . Orthonormal = orthogonal + unit; non-zero orthogonal vectors are independent. proj_a(b) = (aᵀb/aᵀa)a ; unit a → (aᵀb)a . Projection matrix P = A(AᵀA)⁻¹Aᵀ ; P² = P , Pᵀ = P , eigenvalues 0/1. Least squares: minimize ||Ax−b||² → normal equations AᵀAx̂ = Aᵀb ; residual ⊥ C(A). Orthogonal Q: QᵀQ = I , Q⁻¹ = Qᵀ , det = ±1 , |λ| = 1 , preserves length &amp; angle.…","detailHtml":"\n          \n          <ul class=\"styled\">\n            <li><code>u·v = uᵀv</code>;   <code>||v|| = √(v·v)</code>;   orthogonal ⟺ <code>u·v = 0</code>.</li>\n            <li>Orthonormal = orthogonal + unit; non-zero orthogonal vectors are independent.</li>\n            <li><code>proj_a(b) = (aᵀb/aᵀa)a</code>; unit a → <code>(aᵀb)a</code>.</li>\n            <li>Projection matrix <code>P = A(AᵀA)⁻¹Aᵀ</code>; <code>P² = P</code>, <code>Pᵀ = P</code>, eigenvalues 0/1.</li>\n            <li>Least squares: minimize <code>||Ax−b||²</code> → normal equations <code>AᵀAx̂ = Aᵀb</code>; residual ⊥ C(A).</li>\n            <li>Orthogonal Q: <code>QᵀQ = I</code>, <code>Q⁻¹ = Qᵀ</code>, <code>det = ±1</code>, <code>|λ| = 1</code>, preserves length &amp; angle.</li>\n            <li>Gram–Schmidt → orthonormal basis → <code>A = QR</code>; symmetric → <code>A = QDQᵀ</code>.</li>\n          </ul>\n        ","question":null},{"id":"la-orthogonality-048","topicId":"orthogonality","order":48,"type":"deep-dive","hook":"Best mental model","body":"Orthogonality = clean 90° directions that don't interfere. Dot product = interference test (0 = none); norm = length. Orthonormal basis = the perfect coordinate system. Projection = shadow onto a direction/subspace; least squares = closest shadow…","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"study-item-41","sourceLabel":"Study in Depth","detail":"Orthogonality = clean 90° directions that don&#x27;t interfere. Dot product = interference test (0 = none); norm = length. Orthonormal basis = the perfect coordinate system. Projection = shadow onto a direction/subspace; least squares = closest shadow when no exact solution exists. Orthogonal matrix = rotation/reflection that preserves shape.","detailHtml":"\n          \n          <ul class=\"styled\">\n            <li><strong>Orthogonality</strong> = clean 90° directions that don&#x27;t interfere.</li>\n            <li><strong>Dot product</strong> = interference test (0 = none); <strong>norm</strong> = length.</li>\n            <li><strong>Orthonormal basis</strong> = the perfect coordinate system.</li>\n            <li><strong>Projection</strong> = shadow onto a direction/subspace; <strong>least squares</strong> = closest shadow when no exact solution exists.</li>\n            <li><strong>Orthogonal matrix</strong> = rotation/reflection that preserves shape.</li>\n          </ul>\n        ","question":null},{"id":"la-orthogonality-049","topicId":"orthogonality","order":49,"type":"cheat-sheet","hook":"Orthogonal matrix","body":"$Q^{-1}=Q^{\\mathsf T}$ (inverse for free), $\\det=\\pm1$, preserves length.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"cheat-1","sourceLabel":"GATE cheat sheet","detail":"Orthogonal matrix: $Q^{-1}=Q^{\\mathsf T}$ (inverse for free), $\\det=\\pm1$, preserves length.","detailHtml":"<p>Orthogonal matrix: $Q^{-1}=Q^{\\mathsf T}$ (inverse for free), $\\det=\\pm1$, preserves length.</p>","question":null},{"id":"la-orthogonality-050","topicId":"orthogonality","order":50,"type":"cheat-sheet","hook":"Orthogonal sets of non-zero vectors are automatically independent.","body":"Orthogonal sets of non-zero vectors are automatically independent.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"cheat-2","sourceLabel":"GATE cheat sheet","detail":"Orthogonal sets of non-zero vectors are automatically independent.","detailHtml":"<p>Orthogonal sets of non-zero vectors are automatically independent.</p>","question":null},{"id":"la-orthogonality-051","topicId":"orthogonality","order":51,"type":"cheat-sheet","hook":"Symmetric matrices have orthogonal eigenvectors (for distinct $\\lambda$).","body":"Symmetric matrices have orthogonal eigenvectors (for distinct $\\lambda$).","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"cheat-3","sourceLabel":"GATE cheat sheet","detail":"Symmetric matrices have orthogonal eigenvectors (for distinct $\\lambda$).","detailHtml":"<p>Symmetric matrices have orthogonal eigenvectors (for distinct $\\lambda$).</p>","question":null},{"id":"la-orthogonality-052","topicId":"orthogonality","order":52,"type":"cheat-sheet","hook":"Gram–Schmidt gives the $QR$ factorization $A=QR$.","body":"Gram–Schmidt gives the $QR$ factorization $A=QR$.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"cheat-4","sourceLabel":"GATE cheat sheet","detail":"Gram–Schmidt gives the $QR$ factorization $A=QR$.","detailHtml":"<p>Gram–Schmidt gives the $QR$ factorization $A=QR$.</p>","question":null},{"id":"la-orthogonality-053","topicId":"orthogonality","order":53,"type":"trap","hook":"Trap","body":"\"Orthogonal = orthonormal.\" Reality: orthonormal also requires unit length.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"trap-1","sourceLabel":"Common traps","detail":"Trap: &quot;Orthogonal = orthonormal.&quot; Reality: orthonormal also requires unit length.","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;Orthogonal = orthonormal.&quot; <span class=\"right\">Reality:</span> orthonormal also requires unit length.</p>","question":null},{"id":"la-orthogonality-054","topicId":"orthogonality","order":54,"type":"trap","hook":"Trap","body":"\"$Q^{\\mathsf T}Q=I$ means $Q$ is symmetric.\" Reality: it means $Q^{-1}=Q^{\\mathsf T}$, not $Q=Q^{\\mathsf T}$.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"trap-2","sourceLabel":"Common traps","detail":"Trap: &quot;$Q^{\\mathsf T}Q=I$ means $Q$ is symmetric.&quot; Reality: it means $Q^{-1}=Q^{\\mathsf T}$, not $Q=Q^{\\mathsf T}$.","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;$Q^{\\mathsf T}Q=I$ means $Q$ is symmetric.&quot; <span class=\"right\">Reality:</span> it means $Q^{-1}=Q^{\\mathsf T}$, not $Q=Q^{\\mathsf T}$.</p>","question":null},{"id":"la-orthogonality-055","topicId":"orthogonality","order":55,"type":"trap","hook":"Trap","body":"\"Projection changes a vector's length unpredictably.\" Reality: a projection never lengthens; it gives the closest point.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"trap-3","sourceLabel":"Common traps","detail":"Trap: &quot;Projection changes a vector&#x27;s length unpredictably.&quot; Reality: a projection never lengthens; it gives the closest point.","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;Projection changes a vector&#x27;s length unpredictably.&quot; <span class=\"right\">Reality:</span> a projection never lengthens; it gives the closest point.</p>","question":null},{"id":"la-orthogonality-056","topicId":"orthogonality","order":56,"type":"practice","hook":"Q1. Are $(1,2)$ and $(2,-1)$ orthogonal?","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"practice-1","sourceLabel":"Practice problems","detail":"Dot $=1\\cdot2+2\\cdot(-1)=0$ → yes, orthogonal.","detailHtml":"Dot $=1\\cdot2+2\\cdot(-1)=0$ → yes, orthogonal.","question":{"type":"REVEAL","prompt":"Q1. Are $(1,2)$ and $(2,-1)$ orthogonal?","options":[],"answer":true,"explanation":"Dot $=1\\cdot2+2\\cdot(-1)=0$ → yes, orthogonal.","explanationHtml":"Dot $=1\\cdot2+2\\cdot(-1)=0$ → yes, orthogonal."}},{"id":"la-orthogonality-057","topicId":"orthogonality","order":57,"type":"practice","hook":"Q2. For orthogonal $Q$, what is $\\det Q$?","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"practice-2","sourceLabel":"Practice problems","detail":"$\\pm1$.","detailHtml":"$\\pm1$.","question":{"type":"REVEAL","prompt":"Q2. For orthogonal $Q$, what is $\\det Q$?","options":[],"answer":true,"explanation":"$\\pm1$.","explanationHtml":"$\\pm1$."}},{"id":"la-orthogonality-058","topicId":"orthogonality","order":58,"type":"practice","hook":"Q3. Project $(0,5)$ onto $(0,1)$.","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"practice-3","sourceLabel":"Practice problems","detail":"$\\dfrac{5}{1}(0,1)=(0,5)$ — it&#x27;s already on that line.","detailHtml":"$\\dfrac{5}{1}(0,1)=(0,5)$ — it&#x27;s already on that line.","question":{"type":"REVEAL","prompt":"Q3. Project $(0,5)$ onto $(0,1)$.","options":[],"answer":true,"explanation":"$\\dfrac{5}{1}(0,1)=(0,5)$ — it's already on that line.","explanationHtml":"$\\dfrac{5}{1}(0,1)=(0,5)$ — it&#x27;s already on that line."}},{"id":"la-orthogonality-059","topicId":"orthogonality","order":59,"type":"practice","hook":"If $Q$ is orthogonal, what is $Q^{\\mathsf T}Q$?","body":"Choose an answer, then check the explanation.","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"08-orthogonality.html","sourceAnchor":"practice-quiz-1","sourceLabel":"Practice quiz","detail":"✅ Correct — orthonormal columns give $Q^{\\mathsf T}Q=I$, so $Q^{-1}=Q^{\\mathsf T}$.","detailHtml":"✅ Correct — orthonormal columns give $Q^{\\mathsf T}Q=I$, so $Q^{-1}=Q^{\\mathsf T}$.","question":{"type":"MCQ","prompt":"If $Q$ is orthogonal, what is $Q^{\\mathsf T}Q$?","options":["A: $0$","B: $Q$","C: $I$","D: $Q^2$"],"answer":"C","explanation":"✅ Correct — orthonormal columns give $Q^{\\mathsf T}Q=I$, so $Q^{-1}=Q^{\\mathsf T}$.","explanationHtml":"✅ Correct — orthonormal columns give $Q^{\\mathsf T}Q=I$, so $Q^{-1}=Q^{\\mathsf T}$."}},{"id":"la-svd-pca-001","topicId":"svd-pca","order":1,"type":"basic-definition","hook":"SVD","body":"$A=U\\Sigma V^{\\mathsf T}$ — works for any $m\\times n$ matrix.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"definition-1","sourceLabel":"Basic definitions","detail":"SVD: $A=U\\Sigma V^{\\mathsf T}$ — works for any $m\\times n$ matrix.","detailHtml":"<p><strong>SVD:</strong> $A=U\\Sigma V^{\\mathsf T}$ — works for any $m\\times n$ matrix.</p>","question":null},{"id":"la-svd-pca-002","topicId":"svd-pca","order":2,"type":"basic-definition","hook":"$U$ and $V$","body":"orthogonal matrices of left and right singular vectors.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"definition-2","sourceLabel":"Basic definitions","detail":"$U$ and $V$: orthogonal matrices of left and right singular vectors.","detailHtml":"<p><strong>$U$ and $V$:</strong> orthogonal matrices of left and right singular vectors.</p>","question":null},{"id":"la-svd-pca-003","topicId":"svd-pca","order":3,"type":"basic-definition","hook":"Singular values $\\sigma_i$","body":"the non-negative diagonal entries of $\\Sigma$, ordered $\\sigma_1\\ge\\sigma_2\\ge\\dots\\ge0$.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"definition-3","sourceLabel":"Basic definitions","detail":"Singular values $\\sigma_i$: the non-negative diagonal entries of $\\Sigma$, ordered $\\sigma_1\\ge\\sigma_2\\ge\\dots\\ge0$.","detailHtml":"<p><strong>Singular values $\\sigma_i$:</strong> the non-negative diagonal entries of $\\Sigma$, ordered $\\sigma_1\\ge\\sigma_2\\ge\\dots\\ge0$.</p>","question":null},{"id":"la-svd-pca-004","topicId":"svd-pca","order":4,"type":"basic-definition","hook":"Rank-$k$ approximation","body":"keep the top $k$ singular triples for the best low-rank fit (compression).","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"definition-4","sourceLabel":"Basic definitions","detail":"Rank-$k$ approximation: keep the top $k$ singular triples for the best low-rank fit (compression).","detailHtml":"<p><strong>Rank-$k$ approximation:</strong> keep the top $k$ singular triples for the best low-rank fit (compression).</p>","question":null},{"id":"la-svd-pca-005","topicId":"svd-pca","order":5,"type":"basic-definition","hook":"PCA","body":"finds the directions of maximum variance in centered data — the principal components.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"definition-5","sourceLabel":"Basic definitions","detail":"PCA: finds the directions of maximum variance in centered data — the principal components.","detailHtml":"<p><strong>PCA:</strong> finds the directions of maximum variance in centered data — the principal components.</p>","question":null},{"id":"la-svd-pca-006","topicId":"svd-pca","order":6,"type":"basic-definition","hook":"Principal component","body":"an eigenvector of the covariance matrix; the first captures the most variance.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"definition-6","sourceLabel":"Basic definitions","detail":"Principal component: an eigenvector of the covariance matrix; the first captures the most variance.","detailHtml":"<p><strong>Principal component:</strong> an eigenvector of the covariance matrix; the first captures the most variance.</p>","question":null},{"id":"la-svd-pca-007","topicId":"svd-pca","order":7,"type":"basic-definition","hook":"Dimensionality reduction","body":"keep a few top components to compress data while retaining most variance.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"definition-7","sourceLabel":"Basic definitions","detail":"Dimensionality reduction: keep a few top components to compress data while retaining most variance.","detailHtml":"<p><strong>Dimensionality reduction:</strong> keep a few top components to compress data while retaining most variance.</p>","question":null},{"id":"la-svd-pca-008","topicId":"svd-pca","order":8,"type":"deep-dive","hook":"Why SVD is needed","body":"Eigenvalue decomposition works mainly for square matrices. But real data is usually rectangular — e.g. a dataset X = 1000 samples × 20 features (1000×20).","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-1","sourceLabel":"Study in Depth","detail":"Eigenvalue decomposition works mainly for square matrices. But real data is usually rectangular — e.g. a dataset X = 1000 samples × 20 features (1000×20). SVD works for every matrix — square, rectangular, singular, rank-deficient — which is why it is called the crown jewel of linear algebra.","detailHtml":"\n          \n          <p>Eigenvalue decomposition works mainly for <strong>square</strong> matrices. But real data is usually <strong>rectangular</strong> — e.g. a dataset <code>X = 1000 samples × 20 features</code> (1000×20).</p>\n          <p><strong>SVD works for every matrix</strong> — square, rectangular, singular, rank-deficient — which is why it is called the crown jewel of linear algebra.</p>\n        ","question":null},{"id":"la-svd-pca-009","topicId":"svd-pca","order":9,"type":"deep-dive","hook":"The main formula: A = UΣVᵀ","body":"A (m×n) = U Σ Vᵀ U = m×m orthogonal (UᵀU = I, U⁻¹ = Uᵀ) Σ = m×n diagonal-like (singular values) V = n×n orthogonal (VᵀV = I, V⁻¹ = Vᵀ)","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-2","sourceLabel":"Study in Depth","detail":"A (m×n) = U Σ Vᵀ U = m×m orthogonal (UᵀU = I, U⁻¹ = Uᵀ) Σ = m×n diagonal-like (singular values) V = n×n orthogonal (VᵀV = I, V⁻¹ = Vᵀ)","detailHtml":"\n          \n          <pre>A (m×n) = U Σ Vᵀ\n\nU = m×m orthogonal     (UᵀU = I, U⁻¹ = Uᵀ)\nΣ = m×n diagonal-like  (singular values)\nV = n×n orthogonal     (VᵀV = I, V⁻¹ = Vᵀ)</pre>\n        ","question":null},{"id":"la-svd-pca-010","topicId":"svd-pca","order":10,"type":"deep-dive","hook":"Game imagination: rotate → stretch → rotate","body":"Reading Ax = UΣVᵀx right to left, every matrix is just three simple steps:","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-3","sourceLabel":"Study in Depth","detail":"Reading Ax = UΣVᵀx right to left, every matrix is just three simple steps: Vᵀ → rotate/reflect the input into clean axes Σ → stretch each axis by a singular value U → rotate/reflect into the output space SVD = rotate → stretch → rotate. The best mental model.","detailHtml":"\n          \n          <p>Reading <code>Ax = UΣVᵀx</code> right to left, every matrix is just three simple steps:</p>\n          <pre>Vᵀ → rotate/reflect the input into clean axes\nΣ  → stretch each axis by a singular value\nU  → rotate/reflect into the output space</pre>\n          <p><span style=\"color:var(--coral-text)\">SVD = rotate → stretch → rotate.</span> The best mental model.</p>\n        ","question":null},{"id":"la-svd-pca-011","topicId":"svd-pca","order":11,"type":"deep-dive","hook":"Singular values","body":"Σ holds the singular values σ₁ ≥ σ₂ ≥ … ≥ 0 — always non-negative, sorted largest first.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-4","sourceLabel":"Study in Depth","detail":"Σ holds the singular values σ₁ ≥ σ₂ ≥ … ≥ 0 — always non-negative , sorted largest first. σ₁ = strongest stretch direction σ₂ = next strongest, …","detailHtml":"\n          \n          <p>Σ holds the <strong>singular values</strong> <code>σ₁ ≥ σ₂ ≥ … ≥ 0</code> — always <strong>non-negative</strong>, sorted largest first.</p>\n          <pre>σ₁ = strongest stretch direction\nσ₂ = next strongest, …</pre>\n        ","question":null},{"id":"la-svd-pca-012","topicId":"svd-pca","order":12,"type":"deep-dive","hook":"The shape of Σ","body":"Σ has the same shape as A, with singular values on the diagonal positions:","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-5","sourceLabel":"Study in Depth","detail":"Σ has the same shape as A, with singular values on the diagonal positions: A is 3×2: Σ = $\\begin{bmatrix}σ₁&amp;0\\\\0&amp;σ₂\\\\0&amp;0\\end{bmatrix}$ A is 2×3: Σ = $\\begin{bmatrix}σ₁&amp;0&amp;0\\\\0&amp;σ₂&amp;0\\end{bmatrix}$","detailHtml":"\n          \n          <p>Σ has the same shape as A, with singular values on the diagonal positions:</p>\n          <div class=\"math-steps\"><div class=\"ms-line\">A is 3×2:  Σ = $\\begin{bmatrix}σ₁&amp;0\\\\0&amp;σ₂\\\\0&amp;0\\end{bmatrix}$</div><div class=\"ms-line\">A is 2×3:  Σ = $\\begin{bmatrix}σ₁&amp;0&amp;0\\\\0&amp;σ₂&amp;0\\end{bmatrix}$</div></div>\n        ","question":null},{"id":"la-svd-pca-013","topicId":"svd-pca","order":13,"type":"deep-dive","hook":"U and V (singular vectors)","body":"V columns = right singular vectors → live in INPUT space (n-dim), V is n×n U columns = left singular vectors → live in OUTPUT space (m-dim), U is m×m Σ connects them by stretching","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-6","sourceLabel":"Study in Depth","detail":"V columns = right singular vectors → live in INPUT space (n-dim), V is n×n U columns = left singular vectors → live in OUTPUT space (m-dim), U is m×m Σ connects them by stretching","detailHtml":"\n          \n          <pre>V columns = right singular vectors → live in INPUT space (n-dim), V is n×n\nU columns = left  singular vectors → live in OUTPUT space (m-dim), U is m×m\nΣ connects them by stretching</pre>\n        ","question":null},{"id":"la-svd-pca-014","topicId":"svd-pca","order":14,"type":"deep-dive","hook":"The core relationship","body":"Clean input direction vᵢ maps to clean output direction uᵢ, stretched by σᵢ.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-7","sourceLabel":"Study in Depth","detail":"A vᵢ = σᵢ uᵢ (input direction vᵢ → output direction uᵢ, scaled by σᵢ) Aᵀuᵢ = σᵢ vᵢ Clean input direction vᵢ maps to clean output direction uᵢ , stretched by σᵢ .","detailHtml":"\n          \n          <pre>A vᵢ = σᵢ uᵢ        (input direction vᵢ → output direction uᵢ, scaled by σᵢ)\nAᵀuᵢ = σᵢ vᵢ</pre>\n          <p>Clean input direction <code>vᵢ</code> maps to clean output direction <code>uᵢ</code>, stretched by <code>σᵢ</code>.</p>\n        ","question":null},{"id":"la-svd-pca-015","topicId":"svd-pca","order":15,"type":"deep-dive","hook":"Relationship with eigenvalues (key)","body":"Memory: AᵀA gives V and σ²; AAᵀ gives U and σ².","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-8","sourceLabel":"Study in Depth","detail":"singular values: σᵢ = √( eigenvalue of AᵀA ) eigenvalues of AᵀA = σᵢ² V = eigenvectors of AᵀA U = eigenvectors of AAᵀ Memory: AᵀA gives V and σ²; AAᵀ gives U and σ².","detailHtml":"\n          \n          <pre>singular values:  σᵢ = √( eigenvalue of AᵀA )\neigenvalues of AᵀA = σᵢ²\n\nV = eigenvectors of AᵀA\nU = eigenvectors of AAᵀ</pre>\n          <p><span style=\"color:var(--coral-text)\">Memory:</span> AᵀA gives V and σ²; AAᵀ gives U and σ².</p>\n        ","question":null},{"id":"la-svd-pca-016","topicId":"svd-pca","order":16,"type":"deep-dive","hook":"Why AᵀA's eigenvalues are ≥ 0","body":"So AᵀA is positive semidefinite — its eigenvalues are non-negative, which is exactly why singular values are real and ≥ 0.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-9","sourceLabel":"Study in Depth","detail":"xᵀAᵀAx = (Ax)ᵀ(Ax) = ||Ax||² ≥ 0 So AᵀA is positive semidefinite — its eigenvalues are non-negative, which is exactly why singular values are real and ≥ 0.","detailHtml":"\n          \n          <pre>xᵀAᵀAx = (Ax)ᵀ(Ax) = ||Ax||² ≥ 0</pre>\n          <p>So <code>AᵀA</code> is <strong>positive semidefinite</strong> — its eigenvalues are non-negative, which is exactly why singular values are real and ≥ 0.</p>\n        ","question":null},{"id":"la-svd-pca-017","topicId":"svd-pca","order":17,"type":"deep-dive","hook":"Rank & nullity from singular values","body":"Zero singular values mark the directions the matrix destroys.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-10","sourceLabel":"Study in Depth","detail":"rank(A) = number of NON-ZERO singular values nullity(A) = n − rank (zero singular directions = null space) σ = 5, 3, 0, 0 → rank 2 Zero singular values mark the directions the matrix destroys.","detailHtml":"\n          \n          <pre>rank(A) = number of NON-ZERO singular values\nnullity(A) = n − rank   (zero singular directions = null space)</pre>\n          <pre>σ = 5, 3, 0, 0  →  rank 2</pre>\n          <p>Zero singular values mark the directions the matrix destroys.</p>\n        ","question":null},{"id":"la-svd-pca-018","topicId":"svd-pca","order":18,"type":"deep-dive","hook":"SVD examples","body":"Diagonal matrix (already aligned):","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-11","sourceLabel":"Study in Depth","detail":"Diagonal matrix (already aligned): A = $\\begin{bmatrix}3&amp;0\\\\0&amp;2\\end{bmatrix}$ → U = I, Σ = $\\begin{bmatrix}3&amp;0\\\\0&amp;2\\end{bmatrix}$, V = I, σ = 3, 2 Negative diagonal — singular values are still positive: A = $\\begin{bmatrix}-3&amp;0\\\\0&amp;2\\end{bmatrix}$ → eigenvalues −3, 2 but singular values 3, 2 (the flip goes into U or V; Σ only stretches)","detailHtml":"\n          \n          <p class=\"lead\">Diagonal matrix (already aligned):</p>\n          <div class=\"math-steps\"><div class=\"ms-line\">A = $\\begin{bmatrix}3&amp;0\\\\0&amp;2\\end{bmatrix}$  →  U = I, Σ = $\\begin{bmatrix}3&amp;0\\\\0&amp;2\\end{bmatrix}$, V = I,  σ = 3, 2</div></div>\n          <p class=\"lead\">Negative diagonal — singular values are still positive:</p>\n          <div class=\"math-steps\"><div class=\"ms-line\">A = $\\begin{bmatrix}-3&amp;0\\\\0&amp;2\\end{bmatrix}$  →  eigenvalues −3, 2  but  singular values 3, 2</div><div class=\"ms-line\">(the flip goes into U or V; Σ only stretches)</div></div>\n        ","question":null},{"id":"la-svd-pca-019","topicId":"svd-pca","order":19,"type":"deep-dive","hook":"SVD vs eigenvalue decomposition","body":"Eigen-decompositionSVD Works forsquare (mostly)any m×n FormulaA = PDP⁻¹A = UΣVᵀ Valuescan be −/complexσ ≥ 0 real Vectorseigenvectorssingular vectors Stabilityless stablevery stable","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-12","sourceLabel":"Study in Depth","detail":"Eigen-decomposition SVD Works for square (mostly) any m×n Formula A = PDP⁻¹ A = UΣVᵀ Values can be −/complex σ ≥ 0 real Vectors eigenvectors singular vectors Stability less stable very stable","detailHtml":"\n          \n          <div class=\"tbl-wrap\"><table>\n            <tr><th></th><th>Eigen-decomposition</th><th>SVD</th></tr>\n            <tr><td>Works for</td><td>square (mostly)</td><td>any m×n</td></tr>\n            <tr><td>Formula</td><td><code>A = PDP⁻¹</code></td><td><code>A = UΣVᵀ</code></td></tr>\n            <tr><td>Values</td><td>can be −/complex</td><td>σ ≥ 0 real</td></tr>\n            <tr><td>Vectors</td><td>eigenvectors</td><td>singular vectors</td></tr>\n            <tr><td>Stability</td><td>less stable</td><td>very stable</td></tr>\n          </table></div>\n        ","question":null},{"id":"la-svd-pca-020","topicId":"svd-pca","order":20,"type":"deep-dive","hook":"Pseudo-inverse via SVD","body":"The pseudo-inverse works when A is rectangular, singular, or rank-deficient — where a normal inverse does not exist.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-13","sourceLabel":"Study in Depth","detail":"A = UΣVᵀ → A⁺ = V Σ⁺ Uᵀ Σ⁺: replace each non-zero σᵢ with 1/σᵢ, transpose the shape, keep zeros The pseudo-inverse works when A is rectangular, singular, or rank-deficient — where a normal inverse does not exist.","detailHtml":"\n          \n          <pre>A = UΣVᵀ  →  A⁺ = V Σ⁺ Uᵀ\nΣ⁺: replace each non-zero σᵢ with 1/σᵢ, transpose the shape, keep zeros</pre>\n          <p>The pseudo-inverse works when A is rectangular, singular, or rank-deficient — where a normal inverse does not exist.</p>\n        ","question":null},{"id":"la-svd-pca-021","topicId":"svd-pca","order":21,"type":"deep-dive","hook":"What is PCA?","body":"Principal Component Analysis finds the directions where data varies the most — the best new axes for the data. They are orthogonal and ordered by importance:","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-14","sourceLabel":"Study in Depth","detail":"Principal Component Analysis finds the directions where data varies the most — the best new axes for the data. They are orthogonal and ordered by importance : PC1 = max variance ; PC2 = max remaining variance ⊥ PC1 ; …","detailHtml":"\n          \n          <p><strong>Principal Component Analysis</strong> finds the directions where data varies the most — the best new axes for the data. They are <strong>orthogonal</strong> and <strong>ordered by importance</strong>:</p>\n          <pre>PC1 = max variance ;  PC2 = max remaining variance ⊥ PC1 ;  …</pre>\n        ","question":null},{"id":"la-svd-pca-022","topicId":"svd-pca","order":22,"type":"deep-dive","hook":"PCA game imagination","body":"A 2D data cloud stretched diagonally doesn't line up with the x/y axes. PCA rotates the coordinate system to match the data:","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-15","sourceLabel":"Study in Depth","detail":"A 2D data cloud stretched diagonally doesn&#x27;t line up with the x/y axes. PCA rotates the coordinate system to match the data : PC1 = direction of maximum spread PC2 = perpendicular direction of next spread PCA = finding the natural directions of the data.","detailHtml":"\n          \n          <p>A 2D data cloud stretched diagonally doesn&#x27;t line up with the x/y axes. PCA <strong>rotates the coordinate system to match the data</strong>:</p>\n          <pre>PC1 = direction of maximum spread\nPC2 = perpendicular direction of next spread</pre>\n          <p>PCA = finding the natural directions of the data.</p>\n        ","question":null},{"id":"la-svd-pca-023","topicId":"svd-pca","order":23,"type":"deep-dive","hook":"PCA & variance","body":"Variance = spread. PCA keeps high-variance directions and discards low-variance ones, because high variance usually carries the information and low variance is often noise.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-16","sourceLabel":"Study in Depth","detail":"Variance = spread. PCA keeps high-variance directions and discards low-variance ones , because high variance usually carries the information and low variance is often noise.","detailHtml":"\n          \n          <p>Variance = spread. PCA <strong>keeps high-variance directions and discards low-variance ones</strong>, because high variance usually carries the information and low variance is often noise.</p>\n        ","question":null},{"id":"la-svd-pca-024","topicId":"svd-pca","order":24,"type":"deep-dive","hook":"PCA step by step","body":"Data X is n samples × d features.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-17","sourceLabel":"Study in Depth","detail":"Data X is n samples × d features. Center: X̄ = X − mean(X) (each feature mean 0) — PCA needs centered data. Covariance: C = (1/n) X̄ᵀX̄ (a d×d symmetric matrix). Eigendecompose: Cv = λv (real eigenvalues, orthonormal eigenvectors). Sort eigenvalues descending: λ₁ ≥ λ₂ ≥ … ; v₁, v₂, … are the principal components. Project: keep top k → Vₖ , then Z = X̄Vₖ (n×k reduced data).","detailHtml":"\n          \n          <p>Data <code>X</code> is n samples × d features.</p>\n          <ol class=\"steps\">\n            <li><strong>Center:</strong> <code>X̄ = X − mean(X)</code> (each feature mean 0) — PCA needs centered data.</li>\n            <li><strong>Covariance:</strong> <code>C = (1/n) X̄ᵀX̄</code> (a d×d symmetric matrix).</li>\n            <li><strong>Eigendecompose:</strong> <code>Cv = λv</code> (real eigenvalues, orthonormal eigenvectors).</li>\n            <li><strong>Sort</strong> eigenvalues descending: <code>λ₁ ≥ λ₂ ≥ …</code>; v₁, v₂, … are the principal components.</li>\n            <li><strong>Project:</strong> keep top k → <code>Vₖ</code>, then <code>Z = X̄Vₖ</code> (n×k reduced data).</li>\n          </ol>\n        ","question":null},{"id":"la-svd-pca-025","topicId":"svd-pca","order":25,"type":"deep-dive","hook":"PCA & SVD connection","body":"Instead of forming the covariance matrix, apply SVD directly to the centered data:","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-18","sourceLabel":"Study in Depth","detail":"Instead of forming the covariance matrix, apply SVD directly to the centered data: X̄ = UΣVᵀ ⇒ X̄ᵀX̄ = VΣᵀΣVᵀ ⇒ C = (1/n)·VΣᵀΣVᵀ principal components = columns of V covariance eigenvalues = σᵢ²/n (or σᵢ²/(n−1) for sample covariance)","detailHtml":"\n          \n          <p>Instead of forming the covariance matrix, apply SVD directly to the centered data:</p>\n          <pre>X̄ = UΣVᵀ  ⇒  X̄ᵀX̄ = VΣᵀΣVᵀ  ⇒  C = (1/n)·VΣᵀΣVᵀ</pre>\n          <pre>principal components = columns of V\ncovariance eigenvalues = σᵢ²/n   (or σᵢ²/(n−1) for sample covariance)</pre>\n        ","question":null},{"id":"la-svd-pca-026","topicId":"svd-pca","order":26,"type":"deep-dive","hook":"PCA interpretation (explained variance)","body":"Each eigenvalue = variance along its principal component.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-19","sourceLabel":"Study in Depth","detail":"Each eigenvalue = variance along its principal component. explained variance ratio = λᵢ / (λ₁ + λ₂ + … + λd) λ = 50, 10, 1 → PC1 ≈ 81.97%, PC1+PC2 ≈ 98.36% So 2 components can preserve almost all the information.","detailHtml":"\n          \n          <p>Each eigenvalue = variance along its principal component.</p>\n          <pre>explained variance ratio = λᵢ / (λ₁ + λ₂ + … + λd)</pre>\n          <pre>λ = 50, 10, 1 → PC1 ≈ 81.97%,  PC1+PC2 ≈ 98.36%</pre>\n          <p>So 2 components can preserve almost all the information.</p>\n        ","question":null},{"id":"la-svd-pca-027","topicId":"svd-pca","order":27,"type":"deep-dive","hook":"PCA for dimensionality reduction","body":"If 100 features have, say, 10 components explaining 95% variance, reduce 100 → 10 dimensions.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-20","sourceLabel":"Study in Depth","detail":"If 100 features have, say, 10 components explaining 95% variance, reduce 100 → 10 dimensions. benefits: less storage, faster training, less noise, easier visualization, less multicollinearity downside: components are combinations of features → less interpretable","detailHtml":"\n          \n          <p>If 100 features have, say, 10 components explaining 95% variance, reduce <code>100 → 10</code> dimensions.</p>\n          <pre>benefits: less storage, faster training, less noise, easier visualization, less multicollinearity\ndownside: components are combinations of features → less interpretable</pre>\n        ","question":null},{"id":"la-svd-pca-028","topicId":"svd-pca","order":28,"type":"deep-dive","hook":"PCA conditions (centering & scaling)","body":"PCA must be done on centered data. If features have very different scales (income 0–10,00,000 vs age 0–100), the large-scale feature dominates — so standardize first:","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-21","sourceLabel":"Study in Depth","detail":"PCA must be done on centered data. If features have very different scales (income 0–10,00,000 vs age 0–100), the large-scale feature dominates — so standardize first: standardize = subtract mean, divide by standard deviation","detailHtml":"\n          \n          <p>PCA must be done on <strong>centered</strong> data. If features have very different scales (income 0–10,00,000 vs age 0–100), the large-scale feature dominates — so <strong>standardize</strong> first:</p>\n          <pre>standardize = subtract mean, divide by standard deviation</pre>\n        ","question":null},{"id":"la-svd-pca-029","topicId":"svd-pca","order":29,"type":"deep-dive","hook":"Covariance matrix properties","body":"So PCA eigenvalues are variances and can never be negative; eigenvectors can be chosen orthonormal.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-22","sourceLabel":"Study in Depth","detail":"C = (1/n) X̄ᵀX̄ is symmetric and positive semidefinite vᵀCv = (1/n)||X̄v||² ≥ 0 → eigenvalues ≥ 0 So PCA eigenvalues are variances and can never be negative; eigenvectors can be chosen orthonormal.","detailHtml":"\n          \n          <pre>C = (1/n) X̄ᵀX̄  is symmetric and positive semidefinite\nvᵀCv = (1/n)||X̄v||² ≥ 0  →  eigenvalues ≥ 0</pre>\n          <p>So PCA eigenvalues are variances and can never be negative; eigenvectors can be chosen orthonormal.</p>\n        ","question":null},{"id":"la-svd-pca-030","topicId":"svd-pca","order":30,"type":"deep-dive","hook":"SVD & least squares","body":"When Ax = b has no exact solution, the least-squares answer is:","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-23","sourceLabel":"Study in Depth","detail":"When Ax = b has no exact solution, the least-squares answer is: x̂ = A⁺b = VΣ⁺Uᵀ b This works even for rectangular / rank-deficient A. For full column rank it matches the normal-equations answer x̂ = (AᵀA)⁻¹Aᵀb from the Orthogonality topic.","detailHtml":"\n          \n          <p>When <code>Ax = b</code> has no exact solution, the least-squares answer is:</p>\n          <pre>x̂ = A⁺b = VΣ⁺Uᵀ b</pre>\n          <p>This works even for rectangular / rank-deficient A. For full column rank it matches the normal-equations answer <code>x̂ = (AᵀA)⁻¹Aᵀb</code> from the Orthogonality topic.</p>\n        ","question":null},{"id":"la-svd-pca-031","topicId":"svd-pca","order":31,"type":"deep-dive","hook":"SVD vs eigenvalues — careful!","body":"Singular values are non-negative stretch amounts; eigenvalues carry sign/complex behaviour. They align only for symmetric positive-semidefinite matrices (where eigenvalues are ≥ 0).","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-24","sourceLabel":"Study in Depth","detail":"A = [−2]: eigenvalue = −2, singular value = 2 Singular values are non-negative stretch amounts; eigenvalues carry sign/complex behaviour. They align only for symmetric positive-semidefinite matrices (where eigenvalues are ≥ 0).","detailHtml":"\n          \n          <pre>A = [−2]:  eigenvalue = −2,  singular value = 2</pre>\n          <p>Singular values are non-negative stretch amounts; eigenvalues carry sign/complex behaviour. They align only for symmetric positive-semidefinite matrices (where eigenvalues are ≥ 0).</p>\n        ","question":null},{"id":"la-svd-pca-032","topicId":"svd-pca","order":32,"type":"deep-dive","hook":"PCA vs SVD","body":"PCA is an application of SVD / eigendecomposition.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-25","sourceLabel":"Study in Depth","detail":"PCA SVD Goal max-variance directions decompose any matrix Input centered data any matrix Output principal components U, Σ, V Values eigenvalues = variance singular values PCA is an application of SVD / eigendecomposition.","detailHtml":"\n          \n          <div class=\"tbl-wrap\"><table>\n            <tr><th></th><th>PCA</th><th>SVD</th></tr>\n            <tr><td>Goal</td><td>max-variance directions</td><td>decompose any matrix</td></tr>\n            <tr><td>Input</td><td>centered data</td><td>any matrix</td></tr>\n            <tr><td>Output</td><td>principal components</td><td>U, Σ, V</td></tr>\n            <tr><td>Values</td><td>eigenvalues = variance</td><td>singular values</td></tr>\n          </table></div>\n          <p>PCA is an <strong>application</strong> of SVD / eigendecomposition.</p>\n        ","question":null},{"id":"la-svd-pca-033","topicId":"svd-pca","order":33,"type":"deep-dive","hook":"Key formulas","body":"A = UΣVᵀ; σᵢ = √λᵢ(AᵀA); rank = #non-zero σ. ||A||_F² = σ₁² + … + σᵣ²; Aₖ = Σ_{i=1..k} σᵢuᵢvᵢᵀ. energy = (σ₁²+…+σₖ²)/(σ₁²+…+σᵣ²); A⁺ = VΣ⁺Uᵀ; κ = σmax/σmin. PCA: C = (1/n)X̄ᵀX̄, Z = X̄Vₖ, λᵢ = σᵢ²/n (or /(n−1)).","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-26","sourceLabel":"Study in Depth","detail":"A = UΣVᵀ ; σᵢ = √λᵢ(AᵀA) ; rank = #non-zero σ. ||A||_F² = σ₁² + … + σᵣ² ; Aₖ = Σ_{i=1..k} σᵢuᵢvᵢᵀ . energy = (σ₁²+…+σₖ²)/(σ₁²+…+σᵣ²) ; A⁺ = VΣ⁺Uᵀ ; κ = σmax/σmin . PCA: C = (1/n)X̄ᵀX̄ , Z = X̄Vₖ , λᵢ = σᵢ²/n (or /(n−1) ).","detailHtml":"\n          \n          <ul class=\"styled\">\n            <li><code>A = UΣVᵀ</code>;   <code>σᵢ = √λᵢ(AᵀA)</code>;   rank = #non-zero σ.</li>\n            <li><code>||A||_F² = σ₁² + … + σᵣ²</code>;   <code>Aₖ = Σ_{i=1..k} σᵢuᵢvᵢᵀ</code>.</li>\n            <li>energy = <code>(σ₁²+…+σₖ²)/(σ₁²+…+σᵣ²)</code>;   <code>A⁺ = VΣ⁺Uᵀ</code>;   <code>κ = σmax/σmin</code>.</li>\n            <li>PCA: <code>C = (1/n)X̄ᵀX̄</code>, <code>Z = X̄Vₖ</code>, <code>λᵢ = σᵢ²/n</code> (or <code>/(n−1)</code>).</li>\n          </ul>\n        ","question":null},{"id":"la-svd-pca-034","topicId":"svd-pca","order":34,"type":"deep-dive","hook":"Dimensionality reduction — the landscape","body":"Too many features cause the curse of dimensionality: data gets sparse, distances lose meaning, models overfit, and plots are impossible beyond 3-D. Dimensionality reduction keeps the useful information in fewer features.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-27","sourceLabel":"Study in Depth","detail":"Too many features cause the curse of dimensionality : data gets sparse, distances lose meaning, models overfit, and plots are impossible beyond 3-D. Dimensionality reduction keeps the useful information in fewer features. feature selection = keep a subset of original features feature extraction = build new combined features (PCA, autoencoders); LDA uses labels Benefits: faster training, less storage, easier…","detailHtml":"\n          \n          <p>Too many features cause the <strong>curse of dimensionality</strong>: data gets sparse, distances lose meaning, models overfit, and plots are impossible beyond 3-D. <strong>Dimensionality reduction</strong> keeps the useful information in fewer features.</p>\n          <pre>feature selection  = keep a subset of original features\nfeature extraction = build new combined features (PCA, autoencoders); LDA uses labels</pre>\n          <p>Benefits: faster training, less storage, easier visualization, reduced overfitting. (PCA — the main extraction method — is detailed in the cards above.)</p>\n        ","question":null},{"id":"la-svd-pca-035","topicId":"svd-pca","order":35,"type":"deep-dive","hook":"Common GATE traps","body":"SVD works only for square matrices? No — every m×n. Singular values can be negative? No — always ≥ 0. Singular values are eigenvalues of A? No — they are √(eigenvalues of AᵀA). #non-zero σ = determinant? No — it equals the rank. PCA on raw…","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-28","sourceLabel":"Study in Depth","detail":"SVD works only for square matrices? No — every m×n. Singular values can be negative? No — always ≥ 0. Singular values are eigenvalues of A? No — they are √ (eigenvalues of AᵀA). #non-zero σ = determinant? No — it equals the rank . PCA on raw uncentered data? No — center (and often standardize) first. First PC from the smallest eigenvalue? No — the largest. PCs are orthogonal; eigenvalues = variance. (All true.)","detailHtml":"\n          \n          <ul class=\"styled\">\n            <li>SVD works only for square matrices? <strong>No</strong> — every m×n.</li>\n            <li>Singular values can be negative? <strong>No</strong> — always ≥ 0.</li>\n            <li>Singular values are eigenvalues of A? <strong>No</strong> — they are <code>√</code>(eigenvalues of AᵀA).</li>\n            <li>#non-zero σ = determinant? <strong>No</strong> — it equals the <em>rank</em>.</li>\n            <li>PCA on raw uncentered data? <strong>No</strong> — center (and often standardize) first.</li>\n            <li>First PC from the smallest eigenvalue? <strong>No</strong> — the largest. PCs are orthogonal; eigenvalues = variance. (All true.)</li>\n          </ul>\n        ","question":null},{"id":"la-svd-pca-036","topicId":"svd-pca","order":36,"type":"deep-dive","hook":"Practice problems","body":"Q1. Eigenvalues of AᵀA = 25, 9, 0 → singular values & rank?","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-29","sourceLabel":"Study in Depth","detail":"Q1. Eigenvalues of AᵀA = 25, 9, 0 → singular values &amp; rank? σ = 5, 3, 0 ; rank 2 Q2. σ = 10, 4, 0, 0 → rank? 2 Q3. σ = 6, 2, 1 → ||A||_F²? 36 + 4 + 1 = 41 Q4. σ = 10, 5, 1 → energy in top 2? 125/126 ≈ 99.2% Q5. Centered X = UΣVᵀ → principal components? columns of V Q6. Covariance eigenvalues 40, 8, 2 → variance by PC1? top 2? 40/50 = 80% ; 48/50 = 96% Q7. A orthogonal → singular values &amp; κ? all σ = 1 ; κ = 1","detailHtml":"\n          \n          <p class=\"lead\">Q1. Eigenvalues of AᵀA = 25, 9, 0 → singular values &amp; rank?</p>\n          <pre>σ = 5, 3, 0 ;  rank 2</pre>\n          <p class=\"lead\">Q2. σ = 10, 4, 0, 0 → rank?</p>\n          <pre>2</pre>\n          <p class=\"lead\">Q3. σ = 6, 2, 1 → ||A||_F²?</p>\n          <pre>36 + 4 + 1 = 41</pre>\n          <p class=\"lead\">Q4. σ = 10, 5, 1 → energy in top 2?</p>\n          <pre>125/126 ≈ 99.2%</pre>\n          <p class=\"lead\">Q5. Centered X = UΣVᵀ → principal components?</p>\n          <pre>columns of V</pre>\n          <p class=\"lead\">Q6. Covariance eigenvalues 40, 8, 2 → variance by PC1? top 2?</p>\n          <pre>40/50 = 80% ;  48/50 = 96%</pre>\n          <p class=\"lead\">Q7. A orthogonal → singular values &amp; κ?</p>\n          <pre>all σ = 1 ;  κ = 1</pre>\n        ","question":null},{"id":"la-svd-pca-037","topicId":"svd-pca","order":37,"type":"deep-dive","hook":"Cheatsheet","body":"A = UΣVᵀ for ANY matrix; U, V orthogonal; σ ≥ 0 sorted descending. V = eigenvectors of AᵀA; U = of AAᵀ; σ = √λ(AᵀA); rank = #non-zero σ. Best rank-k = top-k σ terms; energy = ratio of σ²; A⁺ = VΣ⁺Uᵀ; κ = σmax/σmin. PCA = SVD/eigendecomposition of…","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-30","sourceLabel":"Study in Depth","detail":"A = UΣVᵀ for ANY matrix; U, V orthogonal; σ ≥ 0 sorted descending. V = eigenvectors of AᵀA; U = of AAᵀ; σ = √λ(AᵀA) ; rank = #non-zero σ. Best rank-k = top-k σ terms; energy = ratio of σ²; A⁺ = VΣ⁺Uᵀ ; κ = σmax/σmin . PCA = SVD/eigendecomposition of centered data; PCs = columns of V; eigenvalues = variance. Center (and standardize) before PCA; covariance is symmetric PSD; largest eigenvalue = PC1.","detailHtml":"\n          \n          <ul class=\"styled\">\n            <li><code>A = UΣVᵀ</code> for ANY matrix; U, V orthogonal; <code>σ ≥ 0</code> sorted descending.</li>\n            <li>V = eigenvectors of AᵀA; U = of AAᵀ; <code>σ = √λ(AᵀA)</code>; rank = #non-zero σ.</li>\n            <li>Best rank-k = top-k σ terms; energy = ratio of σ²; <code>A⁺ = VΣ⁺Uᵀ</code>; <code>κ = σmax/σmin</code>.</li>\n            <li>PCA = SVD/eigendecomposition of centered data; PCs = columns of V; eigenvalues = variance.</li>\n            <li>Center (and standardize) before PCA; covariance is symmetric PSD; largest eigenvalue = PC1.</li>\n          </ul>\n        ","question":null},{"id":"la-svd-pca-038","topicId":"svd-pca","order":38,"type":"deep-dive","hook":"Best mental model","body":"SVD = a universal matrix X-ray. It reveals which input directions matter, how strongly they stretch, which output directions they become, and which are destroyed.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"study-item-31","sourceLabel":"Study in Depth","detail":"SVD = a universal matrix X-ray. It reveals which input directions matter, how strongly they stretch, which output directions they become, and which are destroyed. PCA = SVD applied to data to find the most important directions: which feature-combination has maximum spread, the next, and how few directions still preserve most information. Eigen/eigenvectors → square matrices SVD → ANY matrix PCA → uses…","detailHtml":"\n          \n          <p><strong>SVD = a universal matrix X-ray.</strong> It reveals which input directions matter, how strongly they stretch, which output directions they become, and which are destroyed.</p>\n          <p><strong>PCA = SVD applied to data</strong> to find the most important directions: which feature-combination has maximum spread, the next, and how few directions still preserve most information.</p>\n          <pre>Eigen/eigenvectors → square matrices\nSVD               → ANY matrix\nPCA               → uses SVD/eigenvectors to reduce data</pre>\n        ","question":null},{"id":"la-svd-pca-039","topicId":"svd-pca","order":39,"type":"cheat-sheet","hook":"Singular values are $\\sqrt{\\text{eigenvalues of }A^{\\mathsf T}A}$ — always real and $\\ge0$.","body":"Singular values are $\\sqrt{\\text{eigenvalues of }A^{\\mathsf T}A}$ — always real and $\\ge0$.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"cheat-1","sourceLabel":"GATE cheat sheet","detail":"Singular values are $\\sqrt{\\text{eigenvalues of }A^{\\mathsf T}A}$ — always real and $\\ge0$.","detailHtml":"<p>Singular values are $\\sqrt{\\text{eigenvalues of }A^{\\mathsf T}A}$ — always real and $\\ge0$.</p>","question":null},{"id":"la-svd-pca-040","topicId":"svd-pca","order":40,"type":"cheat-sheet","hook":"Number of non-zero singular values $=\\operatorname{rank}(A)$.","body":"Number of non-zero singular values $=\\operatorname{rank}(A)$.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"cheat-2","sourceLabel":"GATE cheat sheet","detail":"Number of non-zero singular values $=\\operatorname{rank}(A)$.","detailHtml":"<p>Number of non-zero singular values $=\\operatorname{rank}(A)$.</p>","question":null},{"id":"la-svd-pca-041","topicId":"svd-pca","order":41,"type":"cheat-sheet","hook":"$U,V$ are orthogonal; $\\Sigma$ is diagonal.","body":"$U,V$ are orthogonal; $\\Sigma$ is diagonal.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"cheat-3","sourceLabel":"GATE cheat sheet","detail":"$U,V$ are orthogonal; $\\Sigma$ is diagonal.","detailHtml":"<p>$U,V$ are orthogonal; $\\Sigma$ is diagonal.</p>","question":null},{"id":"la-svd-pca-042","topicId":"svd-pca","order":42,"type":"cheat-sheet","hook":"PCA = SVD of the centered data matrix; variance explained $=\\sigma_i^2/(n-1)$.","body":"PCA = SVD of the centered data matrix; variance explained $=\\sigma_i^2/(n-1)$.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"cheat-4","sourceLabel":"GATE cheat sheet","detail":"PCA = SVD of the centered data matrix; variance explained $=\\sigma_i^2/(n-1)$.","detailHtml":"<p>PCA = SVD of the centered data matrix; variance explained $=\\sigma_i^2/(n-1)$.</p>","question":null},{"id":"la-svd-pca-043","topicId":"svd-pca","order":43,"type":"trap","hook":"Trap","body":"\"Singular values = eigenvalues of $A$.\" Reality: only for symmetric PSD matrices; in general $\\sigma_i=\\sqrt{\\lambda_i(A^{\\mathsf T}A)}$.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"trap-1","sourceLabel":"Common traps","detail":"Trap: &quot;Singular values = eigenvalues of $A$.&quot; Reality: only for symmetric PSD matrices; in general $\\sigma_i=\\sqrt{\\lambda_i(A^{\\mathsf T}A)}$.","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;Singular values = eigenvalues of $A$.&quot; <span class=\"right\">Reality:</span> only for symmetric PSD matrices; in general $\\sigma_i=\\sqrt{\\lambda_i(A^{\\mathsf T}A)}$.</p>","question":null},{"id":"la-svd-pca-044","topicId":"svd-pca","order":44,"type":"trap","hook":"Trap","body":"\"Singular values can be negative.\" Reality: never — they are $\\ge0$ by definition.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"trap-2","sourceLabel":"Common traps","detail":"Trap: &quot;Singular values can be negative.&quot; Reality: never — they are $\\ge0$ by definition.","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;Singular values can be negative.&quot; <span class=\"right\">Reality:</span> never — they are $\\ge0$ by definition.</p>","question":null},{"id":"la-svd-pca-045","topicId":"svd-pca","order":45,"type":"trap","hook":"Trap","body":"\"Only square matrices have an SVD.\" Reality: every matrix does.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"trap-3","sourceLabel":"Common traps","detail":"Trap: &quot;Only square matrices have an SVD.&quot; Reality: every matrix does.","detailHtml":"<p><span class=\"wrong\">Trap:</span> &quot;Only square matrices have an SVD.&quot; <span class=\"right\">Reality:</span> every matrix does.</p>","question":null},{"id":"la-svd-pca-046","topicId":"svd-pca","order":46,"type":"practice","hook":"Q1. $A^{\\mathsf T}A$ has eigenvalues $16,9$. Singular values of $A$?","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"practice-1","sourceLabel":"Practice problems","detail":"$\\sqrt{16}=4$ and $\\sqrt{9}=3$.","detailHtml":"$\\sqrt{16}=4$ and $\\sqrt{9}=3$.","question":{"type":"REVEAL","prompt":"Q1. $A^{\\mathsf T}A$ has eigenvalues $16,9$. Singular values of $A$?","options":[],"answer":true,"explanation":"$\\sqrt{16}=4$ and $\\sqrt{9}=3$.","explanationHtml":"$\\sqrt{16}=4$ and $\\sqrt{9}=3$."}},{"id":"la-svd-pca-047","topicId":"svd-pca","order":47,"type":"practice","hook":"Q2. A matrix has singular values $5,2,0,0$. What is its rank?","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"practice-2","sourceLabel":"Practice problems","detail":"2 — the number of non-zero singular values.","detailHtml":"2 — the number of non-zero singular values.","question":{"type":"REVEAL","prompt":"Q2. A matrix has singular values $5,2,0,0$. What is its rank?","options":[],"answer":true,"explanation":"2 — the number of non-zero singular values.","explanationHtml":"2 — the number of non-zero singular values."}},{"id":"la-svd-pca-048","topicId":"svd-pca","order":48,"type":"practice","hook":"Q3. How does PCA relate to SVD?","body":"Solve it before revealing the explanation.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"practice-3","sourceLabel":"Practice problems","detail":"PCA is the SVD of the centered data matrix; principal components are the right singular vectors (eigenvectors of the covariance).","detailHtml":"PCA is the SVD of the centered data matrix; principal components are the right singular vectors (eigenvectors of the covariance).","question":{"type":"REVEAL","prompt":"Q3. How does PCA relate to SVD?","options":[],"answer":true,"explanation":"PCA is the SVD of the centered data matrix; principal components are the right singular vectors (eigenvectors of the covariance).","explanationHtml":"PCA is the SVD of the centered data matrix; principal components are the right singular vectors (eigenvectors of the covariance)."}},{"id":"la-svd-pca-049","topicId":"svd-pca","order":49,"type":"practice","hook":"The singular values of $A$ are the…","body":"Choose an answer, then check the explanation.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"09-svd-pca.html","sourceAnchor":"practice-quiz-1","sourceLabel":"Practice quiz","detail":"✅ Correct — $\\sigma_i=\\sqrt{\\lambda_i(A^{\\mathsf T}A)}$, real and $\\ge0$.","detailHtml":"✅ Correct — $\\sigma_i=\\sqrt{\\lambda_i(A^{\\mathsf T}A)}$, real and $\\ge0$.","question":{"type":"MCQ","prompt":"The singular values of $A$ are the…","options":["A: eigenvalues of $A$","B: square roots of eigenvalues of $A^{\\mathsf T}A$","C: diagonal entries of $A$","D: reciprocals of eigenvalues of $A$"],"answer":"B","explanation":"✅ Correct — $\\sigma_i=\\sqrt{\\lambda_i(A^{\\mathsf T}A)}$, real and $\\ge0$.","explanationHtml":"✅ Correct — $\\sigma_i=\\sqrt{\\lambda_i(A^{\\mathsf T}A)}$, real and $\\ge0$."}},{"id":"la-svd-pca-050","topicId":"svd-pca","order":50,"type":"gate-question","hook":"GATE DA 2026 · Principal components (PCA)","body":"Q11. For a classification problem, PCA is used to reduce the feature-space dimensionality from 100 to 10. What is true about the angle $\\theta$ between the first and the tenth principal components?","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"gate-questions.html","sourceAnchor":"gate-question-1","sourceLabel":"GATE questions","detail":"Principal components are eigenvectors of the symmetric covariance matrix, so any two distinct PCs are mutually orthogonal: $\\theta=90^\\circ$.","detailHtml":"Principal components are eigenvectors of the symmetric covariance matrix, so any two distinct PCs are mutually orthogonal: $\\theta=90^\\circ$.","question":{"type":"MCQ","prompt":"Q11. For a classification problem, PCA is used to reduce the feature-space dimensionality from 100 to 10. What is true about the angle $\\theta$ between the first and the tenth principal components?","options":["A: $\\theta=0^\\circ$","B: $\\theta=90^\\circ$","C: $90^\\circ<\\theta\\le180^\\circ$","D: $0<\\theta<90^\\circ$"],"answer":"B","explanation":"Principal components are eigenvectors of the symmetric covariance matrix, so any two distinct PCs are mutually orthogonal: $\\theta=90^\\circ$.","explanationHtml":"Principal components are eigenvectors of the symmetric covariance matrix, so any two distinct PCs are mutually orthogonal: $\\theta=90^\\circ$."}},{"id":"la-diagonalization-049","topicId":"diagonalization","order":49,"type":"gate-question","hook":"GATE DA 2026 · Matrix powers","body":"Q21. Let $M=\\begin{pmatrix}\\cos\\theta&-\\sin\\theta\\\\\\sin\\theta&\\cos\\theta\\end{pmatrix}$ with $\\theta=\\dfrac{2\\pi}{5}$, and $I_2=\\begin{pmatrix}1&0\\\\0&1\\end{pmatrix}$. Which of the following equals $M^{2026}$?","bodyHtml":"","formula":"","concepts":["diagonalization","matrix-power","eigenvalue","eigenvector","basis"],"difficulty":"Core","source":"gate-questions.html","sourceAnchor":"gate-question-2","sourceLabel":"GATE questions","detail":"$M$ is a rotation by $\\theta=\\tfrac{2\\pi}{5}$, so $M^5=I_2$ (a full $2\\pi$ turn). Since $2026=5(405)+1$, $M^{2026}=M^{1}=M$.","detailHtml":"$M$ is a rotation by $\\theta=\\tfrac{2\\pi}{5}$, so $M^5=I_2$ (a full $2\\pi$ turn). Since $2026=5(405)+1$, $M^{2026}=M^{1}=M$.","question":{"type":"MCQ","prompt":"Q21. Let $M=\\begin{pmatrix}\\cos\\theta&-\\sin\\theta\\\\\\sin\\theta&\\cos\\theta\\end{pmatrix}$ with $\\theta=\\dfrac{2\\pi}{5}$, and $I_2=\\begin{pmatrix}1&0\\\\0&1\\end{pmatrix}$. Which of the following equals $M^{2026}$?","options":["A: $M^2$","B: $M$","C: $M^{-1}$","D: $I_2$"],"answer":"B","explanation":"$M$ is a rotation by $\\theta=\\tfrac{2\\pi}{5}$, so $M^5=I_2$ (a full $2\\pi$ turn). Since $2026=5(405)+1$, $M^{2026}=M^{1}=M$.","explanationHtml":"$M$ is a rotation by $\\theta=\\tfrac{2\\pi}{5}$, so $M^5=I_2$ (a full $2\\pi$ turn). Since $2026=5(405)+1$, $M^{2026}=M^{1}=M$."}},{"id":"la-vectors-053","topicId":"vectors","order":53,"type":"gate-question","hook":"GATE DA 2026 · Subspaces & geometry","body":"Q22. Let $S_1=\\{x=(x_1,x_2,x_3)^{\\mathsf T}\\in\\mathbb{R}^3 : x^{\\mathsf T}x\\le16\\}$ and let $S_2$ be a $2$-dimensional subspace of $\\mathbb{R}^3$. What is the area of $S_1\\cap S_2$?","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"gate-questions.html","sourceAnchor":"gate-question-3","sourceLabel":"GATE questions","detail":"$S_1$ is a ball of radius $4$ ($x^{\\mathsf T}x\\le16$). A $2$-D subspace is a plane through the origin, which cuts the ball in a disk of radius $4$, so the area is $\\pi(4)^2=16\\pi$.","detailHtml":"$S_1$ is a ball of radius $4$ ($x^{\\mathsf T}x\\le16$). A $2$-D subspace is a plane through the origin, which cuts the ball in a disk of radius $4$, so the area is $\\pi(4)^2=16\\pi$.","question":{"type":"MCQ","prompt":"Q22. Let $S_1=\\{x=(x_1,x_2,x_3)^{\\mathsf T}\\in\\mathbb{R}^3 : x^{\\mathsf T}x\\le16\\}$ and let $S_2$ be a $2$-dimensional subspace of $\\mathbb{R}^3$. What is the area of $S_1\\cap S_2$?","options":["A: $16\\pi$","B: $4\\pi$","C: $4\\pi^2$","D: $16\\pi^2$"],"answer":"A","explanation":"$S_1$ is a ball of radius $4$ ($x^{\\mathsf T}x\\le16$). A $2$-D subspace is a plane through the origin, which cuts the ball in a disk of radius $4$, so the area is $\\pi(4)^2=16\\pi$.","explanationHtml":"$S_1$ is a ball of radius $4$ ($x^{\\mathsf T}x\\le16$). A $2$-D subspace is a plane through the origin, which cuts the ball in a disk of radius $4$, so the area is $\\pi(4)^2=16\\pi$."}},{"id":"la-eigenvalues-049","topicId":"eigenvalues","order":49,"type":"gate-question","hook":"GATE DA 2026 · Eigenvalues","body":"Q46. Let $\\gamma_1,\\gamma_2,\\gamma_3$ be the eigenvalues of $\\begin{bmatrix}1&0&0\\\\0&\\cos t&\\sin t\\\\0&-\\sin t&\\cos t\\end{bmatrix}$, where $t\\in[-\\pi,\\pi]$. Which option lists all values of $t$ with $\\gamma_1+\\gamma_2+\\gamma_3=1+\\sqrt2$?","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"gate-questions.html","sourceAnchor":"gate-question-4","sourceLabel":"GATE questions","detail":"The eigenvalues are $1$ and $\\cos t\\pm i\\sin t$, so the sum is $1+2\\cos t$. Setting $1+2\\cos t=1+\\sqrt2$ gives $\\cos t=\\tfrac1{\\sqrt2}$, i.e. $t=\\pm\\tfrac\\pi4$.","detailHtml":"The eigenvalues are $1$ and $\\cos t\\pm i\\sin t$, so the sum is $1+2\\cos t$. Setting $1+2\\cos t=1+\\sqrt2$ gives $\\cos t=\\tfrac1{\\sqrt2}$, i.e. $t=\\pm\\tfrac\\pi4$.","question":{"type":"MCQ","prompt":"Q46. Let $\\gamma_1,\\gamma_2,\\gamma_3$ be the eigenvalues of $\\begin{bmatrix}1&0&0\\\\0&\\cos t&\\sin t\\\\0&-\\sin t&\\cos t\\end{bmatrix}$, where $t\\in[-\\pi,\\pi]$. Which option lists all values of $t$ with $\\gamma_1+\\gamma_2+\\gamma_3=1+\\sqrt2$?","options":["A: $\\{\\tfrac\\pi3,\\,-\\tfrac\\pi4\\}$","B: $\\{\\tfrac\\pi4,\\,-\\tfrac\\pi3\\}$","C: $\\{\\tfrac\\pi4,\\,-\\tfrac\\pi4\\}$","D: $\\{\\tfrac\\pi3,\\,-\\tfrac\\pi3\\}$"],"answer":"C","explanation":"The eigenvalues are $1$ and $\\cos t\\pm i\\sin t$, so the sum is $1+2\\cos t$. Setting $1+2\\cos t=1+\\sqrt2$ gives $\\cos t=\\tfrac1{\\sqrt2}$, i.e. $t=\\pm\\tfrac\\pi4$.","explanationHtml":"The eigenvalues are $1$ and $\\cos t\\pm i\\sin t$, so the sum is $1+2\\cos t$. Setting $1+2\\cos t=1+\\sqrt2$ gives $\\cos t=\\tfrac1{\\sqrt2}$, i.e. $t=\\pm\\tfrac\\pi4$."}},{"id":"la-orthogonality-060","topicId":"orthogonality","order":60,"type":"gate-question","hook":"GATE DA 2026 · Projection matrix","body":"Q52. Let $M=I_n-\\dfrac1n\\mathbf{1}\\mathbf{1}^{\\mathsf T}$, where $\\mathbf{1}=(1,1,\\dots,1)^{\\mathsf T}\\in\\mathbb{R}^n$ and $I_n$ is the identity of order $n$. Which is/are correct?","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"gate-questions.html","sourceAnchor":"gate-question-5","sourceLabel":"GATE questions","detail":"$M$ is the centering matrix: symmetric ($M^{\\mathsf T}=M$, A) and idempotent $M^2=M$, hence a projection (D). Its eigenvalues are $1$ ($n-1$ times) and $0$, so $\\operatorname{Trace}(M)=n-1$ (C false) and $M^2=M\\ne I_n$ (B false).","detailHtml":"$M$ is the centering matrix: symmetric ($M^{\\mathsf T}=M$, A) and idempotent $M^2=M$, hence a projection (D). Its eigenvalues are $1$ ($n-1$ times) and $0$, so $\\operatorname{Trace}(M)=n-1$ (C false) and $M^2=M\\ne I_n$ (B false).","question":{"type":"MSQ","prompt":"Q52. Let $M=I_n-\\dfrac1n\\mathbf{1}\\mathbf{1}^{\\mathsf T}$, where $\\mathbf{1}=(1,1,\\dots,1)^{\\mathsf T}\\in\\mathbb{R}^n$ and $I_n$ is the identity of order $n$. Which is/are correct?","options":["A: $M^{\\mathsf T}=M$","B: $M^2=I_n$","C: $\\operatorname{Trace}(M)=n$","D: $M$ is a projection matrix"],"answer":["A","D"],"explanation":"$M$ is the centering matrix: symmetric ($M^{\\mathsf T}=M$, A) and idempotent $M^2=M$, hence a projection (D). Its eigenvalues are $1$ ($n-1$ times) and $0$, so $\\operatorname{Trace}(M)=n-1$ (C false) and $M^2=M\\ne I_n$ (B false).","explanationHtml":"$M$ is the centering matrix: symmetric ($M^{\\mathsf T}=M$, A) and idempotent $M^2=M$, hence a projection (D). Its eigenvalues are $1$ ($n-1$ times) and $0$, so $\\operatorname{Trace}(M)=n-1$ (C false) and $M^2=M\\ne I_n$ (B false)."}},{"id":"la-eigenvalues-050","topicId":"eigenvalues","order":50,"type":"gate-question","hook":"GATE DA 2026 · Eigenvalues","body":"Q65. Let $M=I_n-\\dfrac1n\\mathbf{1}\\mathbf{1}^{\\mathsf T}$ with $\\mathbf{1}=(1,\\dots,1)^{\\mathsf T}\\in\\mathbb{R}^n$. The value of $\\displaystyle\\max_{x\\in S}\\,x^{\\mathsf T}Mx$, where $S=\\{x\\in\\mathbb{R}^n:x^{\\mathsf T}x=1\\}$, is ______.","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"gate-questions.html","sourceAnchor":"gate-question-6","sourceLabel":"GATE questions","detail":"The centering matrix $M$ has eigenvalues $0$ (eigenvector $\\mathbf{1}$) and $1$ ($n-1$ times). Over unit vectors, $x^{\\mathsf T}Mx$ is maximized by the largest eigenvalue, $1$.","detailHtml":"The centering matrix $M$ has eigenvalues $0$ (eigenvector $\\mathbf{1}$) and $1$ ($n-1$ times). Over unit vectors, $x^{\\mathsf T}Mx$ is maximized by the largest eigenvalue, $1$.","question":{"type":"NAT","prompt":"Q65. Let $M=I_n-\\dfrac1n\\mathbf{1}\\mathbf{1}^{\\mathsf T}$ with $\\mathbf{1}=(1,\\dots,1)^{\\mathsf T}\\in\\mathbb{R}^n$. The value of $\\displaystyle\\max_{x\\in S}\\,x^{\\mathsf T}Mx$, where $S=\\{x\\in\\mathbb{R}^n:x^{\\mathsf T}x=1\\}$, is ______.","options":[],"answer":[1.0,1.0],"explanation":"The centering matrix $M$ has eigenvalues $0$ (eigenvector $\\mathbf{1}$) and $1$ ($n-1$ times). Over unit vectors, $x^{\\mathsf T}Mx$ is maximized by the largest eigenvalue, $1$.","explanationHtml":"The centering matrix $M$ has eigenvalues $0$ (eigenvector $\\mathbf{1}$) and $1$ ($n-1$ times). Over unit vectors, $x^{\\mathsf T}Mx$ is maximized by the largest eigenvalue, $1$."}},{"id":"la-linear-equations-059","topicId":"linear-equations","order":59,"type":"gate-question","hook":"GATE DA 2025 · Solution of equations","body":"Q12. The number of additions and multiplications involved in performing Gaussian elimination on an $n\\times n$ upper-triangular matrix is of the order","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"gate-questions.html","sourceAnchor":"gate-question-7","sourceLabel":"GATE questions","detail":"For an upper-triangular system only back-substitution remains: row $i$ needs about $n-i$ multiply-adds, and $\\sum_i (n-i)=O(n^2)$. (Full Gaussian elimination on a general matrix is $O(n^3)$.)","detailHtml":"For an upper-triangular system only back-substitution remains: row $i$ needs about $n-i$ multiply-adds, and $\\sum_i (n-i)=O(n^2)$. (Full Gaussian elimination on a general matrix is $O(n^3)$.)","question":{"type":"MCQ","prompt":"Q12. The number of additions and multiplications involved in performing Gaussian elimination on an $n\\times n$ upper-triangular matrix is of the order","options":["A: $O(n)$","B: $O(n^2)$","C: $O(n^3)$","D: $O(n^4)$"],"answer":"B","explanation":"For an upper-triangular system only back-substitution remains: row $i$ needs about $n-i$ multiply-adds, and $\\sum_i (n-i)=O(n^2)$. (Full Gaussian elimination on a general matrix is $O(n^3)$.)","explanationHtml":"For an upper-triangular system only back-substitution remains: row $i$ needs about $n-i$ multiply-adds, and $\\sum_i (n-i)=O(n^2)$. (Full Gaussian elimination on a general matrix is $O(n^3)$.)"}},{"id":"la-eigenvalues-051","topicId":"eigenvalues","order":51,"type":"gate-question","hook":"GATE DA 2025 · Eigenvalues","body":"Q13. The sum of the elements in each row of $A\\in\\mathbb{R}^{n\\times n}$ is $1$. If $B=A^3-2A^2+A$, which ONE statement is correct (for $x\\in\\mathbb{R}^n$)?","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"gate-questions.html","sourceAnchor":"gate-question-8","sourceLabel":"GATE questions","detail":"Row sums $1\\Rightarrow A$ has eigenvalue $1$ (eigenvector $\\mathbf{1}$). $B=A(A-I)^2$ has eigenvalue $1\\cdot(1-1)^2=0$, so $B$ is singular and $Bx=0$ has infinitely many solutions.","detailHtml":"Row sums $1\\Rightarrow A$ has eigenvalue $1$ (eigenvector $\\mathbf{1}$). $B=A(A-I)^2$ has eigenvalue $1\\cdot(1-1)^2=0$, so $B$ is singular and $Bx=0$ has infinitely many solutions.","question":{"type":"MCQ","prompt":"Q13. The sum of the elements in each row of $A\\in\\mathbb{R}^{n\\times n}$ is $1$. If $B=A^3-2A^2+A$, which ONE statement is correct (for $x\\in\\mathbb{R}^n$)?","options":["A: $Bx=0$ has no solution","B: $Bx=0$ has exactly two solutions","C: $Bx=0$ has infinitely many solutions","D: $Bx=0$ has a unique solution"],"answer":"C","explanation":"Row sums $1\\Rightarrow A$ has eigenvalue $1$ (eigenvector $\\mathbf{1}$). $B=A(A-I)^2$ has eigenvalue $1\\cdot(1-1)^2=0$, so $B$ is singular and $Bx=0$ has infinitely many solutions.","explanationHtml":"Row sums $1\\Rightarrow A$ has eigenvalue $1$ (eigenvector $\\mathbf{1}$). $B=A(A-I)^2$ has eigenvalue $1\\cdot(1-1)^2=0$, so $B$ is singular and $Bx=0$ has infinitely many solutions."}},{"id":"la-orthogonality-061","topicId":"orthogonality","order":61,"type":"gate-question","hook":"GATE DA 2025 · Orthonormal basis","body":"Q25. Which of the following statements is/are correct?","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"gate-questions.html","sourceAnchor":"gate-question-9","sourceLabel":"GATE questions","detail":"Orthonormal bases are not unique (B). Orthonormal $\\Rightarrow$ linearly independent (D). Independence does not imply orthonormality (C false).","detailHtml":"Orthonormal bases are not unique (B). Orthonormal $\\Rightarrow$ linearly independent (D). Independence does not imply orthonormality (C false).","question":{"type":"MSQ","prompt":"Q25. Which of the following statements is/are correct?","options":["A: $\\mathbb{R}^n$ has a unique set of orthonormal basis vectors","B: $\\mathbb{R}^n$ does not have a unique set of orthonormal basis vectors","C: Linearly independent vectors in $\\mathbb{R}^n$ are orthonormal","D: Orthonormal vectors in $\\mathbb{R}^n$ are linearly independent"],"answer":["B","D"],"explanation":"Orthonormal bases are not unique (B). Orthonormal $\\Rightarrow$ linearly independent (D). Independence does not imply orthonormality (C false).","explanationHtml":"Orthonormal bases are not unique (B). Orthonormal $\\Rightarrow$ linearly independent (D). Independence does not imply orthonormality (C false)."}},{"id":"la-eigenvalues-052","topicId":"eigenvalues","order":52,"type":"gate-question","hook":"GATE DA 2025 · Eigenvalues","body":"Q28. Let $A=I_n+xx^{\\mathsf T}$, where $I_n$ is the identity and $x\\in\\mathbb{R}^n$ with $x^{\\mathsf T}x=1$. Which is/are correct?","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"gate-questions.html","sourceAnchor":"gate-question-10","sourceLabel":"GATE questions","detail":"$xx^{\\mathsf T}$ has eigenvalues $1$ (once) and $0$ ($n-1$ times), so $A$ has eigenvalues $2$ and $1$ — all positive. Hence full rank and invertible (A, B); no zero or negative eigenvalues.","detailHtml":"$xx^{\\mathsf T}$ has eigenvalues $1$ (once) and $0$ ($n-1$ times), so $A$ has eigenvalues $2$ and $1$ — all positive. Hence full rank and invertible (A, B); no zero or negative eigenvalues.","question":{"type":"MSQ","prompt":"Q28. Let $A=I_n+xx^{\\mathsf T}$, where $I_n$ is the identity and $x\\in\\mathbb{R}^n$ with $x^{\\mathsf T}x=1$. Which is/are correct?","options":["A: Rank of $A$ is $n$","B: $A$ is invertible","C: $0$ is an eigenvalue of $A$","D: $A^{-1}$ has a negative eigenvalue"],"answer":["A","B"],"explanation":"$xx^{\\mathsf T}$ has eigenvalues $1$ (once) and $0$ ($n-1$ times), so $A$ has eigenvalues $2$ and $1$ — all positive. Hence full rank and invertible (A, B); no zero or negative eigenvalues.","explanationHtml":"$xx^{\\mathsf T}$ has eigenvalues $1$ (once) and $0$ ($n-1$ times), so $A$ has eigenvalues $2$ and $1$ — all positive. Hence full rank and invertible (A, B); no zero or negative eigenvalues."}},{"id":"la-rank-nullity-062","topicId":"rank-nullity","order":62,"type":"gate-question","hook":"GATE DA 2025 · Rank","body":"Q37. Let $A\\in\\mathbb{R}^{n\\times n}$ satisfy $A^3=A$. Which ONE statement is ALWAYS correct?","bodyHtml":"","formula":"","concepts":["rank","nullity","kernel","column-space","pivot"],"difficulty":"Core","source":"gate-questions.html","sourceAnchor":"gate-question-11","sourceLabel":"GATE questions","detail":"$A^3=A$ makes $A$ diagonalizable with eigenvalues in $\\{-1,0,1\\}$, so $\\operatorname{rank}(A)=\\operatorname{rank}(A^2)$. The others can fail (e.g. $A=I$).","detailHtml":"$A^3=A$ makes $A$ diagonalizable with eigenvalues in $\\{-1,0,1\\}$, so $\\operatorname{rank}(A)=\\operatorname{rank}(A^2)$. The others can fail (e.g. $A=I$).","question":{"type":"MCQ","prompt":"Q37. Let $A\\in\\mathbb{R}^{n\\times n}$ satisfy $A^3=A$. Which ONE statement is ALWAYS correct?","options":["A: $A$ is invertible","B: Determinant of $A$ is $0$","C: The sum of the diagonal elements of $A$ is $1$","D: $A$ and $A^2$ have the same rank"],"answer":"D","explanation":"$A^3=A$ makes $A$ diagonalizable with eigenvalues in $\\{-1,0,1\\}$, so $\\operatorname{rank}(A)=\\operatorname{rank}(A^2)$. The others can fail (e.g. $A=I$).","explanationHtml":"$A^3=A$ makes $A$ diagonalizable with eigenvalues in $\\{-1,0,1\\}$, so $\\operatorname{rank}(A)=\\operatorname{rank}(A^2)$. The others can fail (e.g. $A=I$)."}},{"id":"la-matrices-052","topicId":"matrices","order":52,"type":"gate-question","hook":"GATE DA 2025 · Positive definiteness","body":"Q38. Let $\\{x_1,\\dots,x_n\\}$ be linearly independent in $\\mathbb{R}^n$, and let $A\\in\\mathbb{R}^{n\\times n}$ have $(i,j)$-entry $A_{ij}=x_i^{\\mathsf T}x_j$. Which ONE statement is correct?","bodyHtml":"","formula":"","concepts":["matrix","linear-transformation","identity-matrix","matrix-multiplication","inverse"],"difficulty":"Core","source":"gate-questions.html","sourceAnchor":"gate-question-12","sourceLabel":"GATE questions","detail":"$A$ is the Gram matrix of independent vectors, hence symmetric positive-definite and invertible (A). So no singular value is $0$, $\\det\\neq0$, and $z^{\\mathsf T}Az&gt;0$ for all $z\\neq0$.","detailHtml":"$A$ is the Gram matrix of independent vectors, hence symmetric positive-definite and invertible (A). So no singular value is $0$, $\\det\\neq0$, and $z^{\\mathsf T}Az&gt;0$ for all $z\\neq0$.","question":{"type":"MCQ","prompt":"Q38. Let $\\{x_1,\\dots,x_n\\}$ be linearly independent in $\\mathbb{R}^n$, and let $A\\in\\mathbb{R}^{n\\times n}$ have $(i,j)$-entry $A_{ij}=x_i^{\\mathsf T}x_j$. Which ONE statement is correct?","options":["A: $A$ is invertible","B: $0$ is a singular value of $A$","C: Determinant of $A$ is $0$","D: $z^{\\mathsf T}Az=0$ for some non-zero $z\\in\\mathbb{R}^n$"],"answer":"A","explanation":"$A$ is the Gram matrix of independent vectors, hence symmetric positive-definite and invertible (A). So no singular value is $0$, $\\det\\neq0$, and $z^{\\mathsf T}Az>0$ for all $z\\neq0$.","explanationHtml":"$A$ is the Gram matrix of independent vectors, hence symmetric positive-definite and invertible (A). So no singular value is $0$, $\\det\\neq0$, and $z^{\\mathsf T}Az&gt;0$ for all $z\\neq0$."}},{"id":"la-orthogonality-062","topicId":"orthogonality","order":62,"type":"gate-question","hook":"GATE DA 2025 · Projections","body":"Q50. Let $x_1,\\dots,x_5$ be orthonormal in $\\mathbb{R}^{10}$ and $A=x_1x_1^{\\mathsf T}+\\dots+x_5x_5^{\\mathsf T}$. Which is/are correct?","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"gate-questions.html","sourceAnchor":"gate-question-13","sourceLabel":"GATE questions","detail":"$A$ is the orthogonal projection onto a 5-D subspace: symmetric with eigenvalues $1$ (five times) and $0$ (five times). So singular values $=$ eigenvalues $\\in\\{0,1\\}$ (A, B); having zero eigenvalues, $\\det=0$ and $A$ is not invertible.","detailHtml":"$A$ is the orthogonal projection onto a 5-D subspace: symmetric with eigenvalues $1$ (five times) and $0$ (five times). So singular values $=$ eigenvalues $\\in\\{0,1\\}$ (A, B); having zero eigenvalues, $\\det=0$ and $A$ is not invertible.","question":{"type":"MSQ","prompt":"Q50. Let $x_1,\\dots,x_5$ be orthonormal in $\\mathbb{R}^{10}$ and $A=x_1x_1^{\\mathsf T}+\\dots+x_5x_5^{\\mathsf T}$. Which is/are correct?","options":["A: Singular values of $A$ are also its eigenvalues","B: Singular values of $A$ are either $0$ or $1$","C: Determinant of $A$ is $1$","D: $A$ is invertible"],"answer":["A","B"],"explanation":"$A$ is the orthogonal projection onto a 5-D subspace: symmetric with eigenvalues $1$ (five times) and $0$ (five times). So singular values $=$ eigenvalues $\\in\\{0,1\\}$ (A, B); having zero eigenvalues, $\\det=0$ and $A$ is not invertible.","explanationHtml":"$A$ is the orthogonal projection onto a 5-D subspace: symmetric with eigenvalues $1$ (five times) and $0$ (five times). So singular values $=$ eigenvalues $\\in\\{0,1\\}$ (A, B); having zero eigenvalues, $\\det=0$ and $A$ is not invertible."}},{"id":"la-orthogonality-063","topicId":"orthogonality","order":63,"type":"gate-question","hook":"GATE DA 2025 · Orthogonal matrices","body":"Q52. An $n\\times n$ real matrix $A$ satisfies $\\lVert Ax\\rVert_2=\\lVert x\\rVert_2$ for all $x\\in\\mathbb{R}^n$. Which is/are ALWAYS correct?","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"gate-questions.html","sourceAnchor":"gate-question-14","sourceLabel":"GATE questions","detail":"Norm-preserving $\\Rightarrow A$ is orthogonal (A) and invertible / full rank (D). But orthogonal matrices include rotations, so $A=I$ is not the only one and eigenvalues may be complex on the unit circle.","detailHtml":"Norm-preserving $\\Rightarrow A$ is orthogonal (A) and invertible / full rank (D). But orthogonal matrices include rotations, so $A=I$ is not the only one and eigenvalues may be complex on the unit circle.","question":{"type":"MSQ","prompt":"Q52. An $n\\times n$ real matrix $A$ satisfies $\\lVert Ax\\rVert_2=\\lVert x\\rVert_2$ for all $x\\in\\mathbb{R}^n$. Which is/are ALWAYS correct?","options":["A: $A$ must be orthogonal","B: $A=I$ is the only solution","C: The eigenvalues of $A$ are either $+1$ or $-1$","D: $A$ has full rank"],"answer":["A","D"],"explanation":"Norm-preserving $\\Rightarrow A$ is orthogonal (A) and invertible / full rank (D). But orthogonal matrices include rotations, so $A=I$ is not the only one and eigenvalues may be complex on the unit circle.","explanationHtml":"Norm-preserving $\\Rightarrow A$ is orthogonal (A) and invertible / full rank (D). But orthogonal matrices include rotations, so $A=I$ is not the only one and eigenvalues may be complex on the unit circle."}},{"id":"la-svd-pca-051","topicId":"svd-pca","order":51,"type":"gate-question","hook":"GATE DA 2025 · PCA / covariance","body":"Q60. A dataset $D=\\{x^{(1)},\\dots,x^{(n)}\\}$ with each $x^{(i)}\\in\\mathbb{R}^{100}$ satisfies $\\sum_{i=1}^{n}x^{(i)}=0$. Its covariance matrix has eigenvalues $\\lambda_i=100^{\\,2-i}$, $1\\le i\\le100$. Let $u$ ($u^{\\mathsf T}u=1$) be the direction of…","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"gate-questions.html","sourceAnchor":"gate-question-15","sourceLabel":"GATE questions","detail":"For centered data, $\\frac1n\\sum (u^{\\mathsf T}x^{(i)})^2=u^{\\mathsf T}Cu$, maximized over unit $u$ by the top eigenvector, giving the largest eigenvalue $\\lambda_1=100^{\\,2-1}=100$.","detailHtml":"For centered data, $\\frac1n\\sum (u^{\\mathsf T}x^{(i)})^2=u^{\\mathsf T}Cu$, maximized over unit $u$ by the top eigenvector, giving the largest eigenvalue $\\lambda_1=100^{\\,2-1}=100$.","question":{"type":"NAT","prompt":"Q60. A dataset $D=\\{x^{(1)},\\dots,x^{(n)}\\}$ with each $x^{(i)}\\in\\mathbb{R}^{100}$ satisfies $\\sum_{i=1}^{n}x^{(i)}=0$. Its covariance matrix has eigenvalues $\\lambda_i=100^{\\,2-i}$, $1\\le i\\le100$. Let $u$ ($u^{\\mathsf T}u=1$) be the direction of maximum variance. Then $\\displaystyle\\frac1n\\sum_{i=1}^{n}\\big(u^{\\mathsf T}x^{(i)}\\big)^2$ = ______.","options":[],"answer":[100.0,100.0],"explanation":"For centered data, $\\frac1n\\sum (u^{\\mathsf T}x^{(i)})^2=u^{\\mathsf T}Cu$, maximized over unit $u$ by the top eigenvector, giving the largest eigenvalue $\\lambda_1=100^{\\,2-1}=100$.","explanationHtml":"For centered data, $\\frac1n\\sum (u^{\\mathsf T}x^{(i)})^2=u^{\\mathsf T}Cu$, maximized over unit $u$ by the top eigenvector, giving the largest eigenvalue $\\lambda_1=100^{\\,2-1}=100$."}},{"id":"la-eigenvalues-053","topicId":"eigenvalues","order":53,"type":"gate-question","hook":"GATE DA 2024 · Eigenvalues","body":"Q13. Consider the matrix $A=\\begin{bmatrix}2&-1\\\\3&1\\end{bmatrix}$. Which ONE of the following statements is TRUE?","bodyHtml":"","formula":"","concepts":["eigenvalue","eigenvector","eigenspace","trace","determinant"],"difficulty":"Core","source":"gate-questions.html","sourceAnchor":"gate-question-16","sourceLabel":"GATE questions","detail":"$\\operatorname{tr}(A)=3,\\ \\det(A)=5\\Rightarrow \\lambda^2-3\\lambda+5=0$, discriminant $9-20=-11&lt;0$, so the eigenvalues are a complex conjugate pair.","detailHtml":"$\\operatorname{tr}(A)=3,\\ \\det(A)=5\\Rightarrow \\lambda^2-3\\lambda+5=0$, discriminant $9-20=-11&lt;0$, so the eigenvalues are a complex conjugate pair.","question":{"type":"MCQ","prompt":"Q13. Consider the matrix $A=\\begin{bmatrix}2&-1\\\\3&1\\end{bmatrix}$. Which ONE of the following statements is TRUE?","options":["A: The eigenvalues of $A$ are non-negative and real.","B: The eigenvalues of $A$ are complex conjugate pairs.","C: One eigenvalue of $A$ is positive and real, and another is zero.","D: One eigenvalue is non-negative and real, and another is negative and real."],"answer":"B","explanation":"$\\operatorname{tr}(A)=3,\\ \\det(A)=5\\Rightarrow \\lambda^2-3\\lambda+5=0$, discriminant $9-20=-11<0$, so the eigenvalues are a complex conjugate pair.","explanationHtml":"$\\operatorname{tr}(A)=3,\\ \\det(A)=5\\Rightarrow \\lambda^2-3\\lambda+5=0$, discriminant $9-20=-11&lt;0$, so the eigenvalues are a complex conjugate pair."}},{"id":"la-determinants-059","topicId":"determinants","order":59,"type":"gate-question","hook":"GATE DA 2024 · Determinants","body":"Q35. Consider the matrix $M=\\begin{bmatrix}1&2&3\\\\3&1&3\\\\4&3&6\\end{bmatrix}$. The determinant of $\\big(M^2+12M\\big)$ is ______.","bodyHtml":"","formula":"","concepts":["determinant","singular-matrix","inverse","rank"],"difficulty":"Core","source":"gate-questions.html","sourceAnchor":"gate-question-17","sourceLabel":"GATE questions","detail":"$M^2+12M=M(M+12I)$, so $\\det(M^2+12M)=\\det(M)\\,\\det(M+12I)$. Here $\\det(M)=0$ (the rows are linearly dependent), hence the value is $0$.","detailHtml":"$M^2+12M=M(M+12I)$, so $\\det(M^2+12M)=\\det(M)\\,\\det(M+12I)$. Here $\\det(M)=0$ (the rows are linearly dependent), hence the value is $0$.","question":{"type":"NAT","prompt":"Q35. Consider the matrix $M=\\begin{bmatrix}1&2&3\\\\3&1&3\\\\4&3&6\\end{bmatrix}$. The determinant of $\\big(M^2+12M\\big)$ is ______.","options":[],"answer":[0.0,0.0],"explanation":"$M^2+12M=M(M+12I)$, so $\\det(M^2+12M)=\\det(M)\\,\\det(M+12I)$. Here $\\det(M)=0$ (the rows are linearly dependent), hence the value is $0$.","explanationHtml":"$M^2+12M=M(M+12I)$, so $\\det(M^2+12M)=\\det(M)\\,\\det(M+12I)$. Here $\\det(M)=0$ (the rows are linearly dependent), hence the value is $0$."}},{"id":"la-vectors-054","topicId":"vectors","order":54,"type":"gate-question","hook":"GATE DA 2024 · Subspaces","body":"Q47. Select all choices that are subspaces of $\\mathbb{R}^3$ (with $\\alpha,\\beta\\in\\mathbb{R}$).","bodyHtml":"","formula":"","concepts":["vector","span","linear-independence","basis","dimension","coordinates"],"difficulty":"Core","source":"gate-questions.html","sourceAnchor":"gate-question-18","sourceLabel":"GATE questions","detail":"A is a span (subspace); C is a homogeneous linear system (subspace). B uses $\\alpha^2,\\beta^2\\ge0$ so it is not closed under scaling; D is affine (does not contain $0$).","detailHtml":"A is a span (subspace); C is a homogeneous linear system (subspace). B uses $\\alpha^2,\\beta^2\\ge0$ so it is not closed under scaling; D is affine (does not contain $0$).","question":{"type":"MSQ","prompt":"Q47. Select all choices that are subspaces of $\\mathbb{R}^3$ (with $\\alpha,\\beta\\in\\mathbb{R}$).","options":["A: $\\{\\,x : x=\\alpha\\begin{bmatrix}1\\\\1\\\\0\\end{bmatrix}+\\beta\\begin{bmatrix}1\\\\0\\\\0\\end{bmatrix}\\,\\}$","B: $\\{\\,x : x=\\alpha^2\\begin{bmatrix}1\\\\2\\\\0\\end{bmatrix}+\\beta^2\\begin{bmatrix}1\\\\0\\\\1\\end{bmatrix}\\,\\}$","C: $\\{\\,x : 5x_1+2x_3=0,\\ \\ 4x_1-2x_2+3x_3=0\\,\\}$","D: $\\{\\,x : 5x_1+2x_3+4=0\\,\\}$"],"answer":["A","C"],"explanation":"A is a span (subspace); C is a homogeneous linear system (subspace). B uses $\\alpha^2,\\beta^2\\ge0$ so it is not closed under scaling; D is affine (does not contain $0$).","explanationHtml":"A is a span (subspace); C is a homogeneous linear system (subspace). B uses $\\alpha^2,\\beta^2\\ge0$ so it is not closed under scaling; D is affine (does not contain $0$)."}},{"id":"la-linear-equations-060","topicId":"linear-equations","order":60,"type":"gate-question","hook":"GATE DA 2024 · Solution of equations","body":"Q48. Which of the following statements is/are TRUE? ($b,c$ are vectors of matching size.)","bodyHtml":"","formula":"","concepts":["linear-equations","row-reduction","rank","nullity","column-space"],"difficulty":"Core","source":"gate-questions.html","sourceAnchor":"gate-question-19","sourceLabel":"GATE questions","detail":"A: an invertible $M$ makes $M^{\\mathsf T}$ invertible too (unique, not infinite). C: a $2\\times3$ system is underdetermined, so it can never have a unique solution. B and D are both achievable.","detailHtml":"A: an invertible $M$ makes $M^{\\mathsf T}$ invertible too (unique, not infinite). C: a $2\\times3$ system is underdetermined, so it can never have a unique solution. B and D are both achievable.","question":{"type":"MSQ","prompt":"Q48. Which of the following statements is/are TRUE? ($b,c$ are vectors of matching size.)","options":["A: $\\exists\\,M\\in\\mathbb{R}^{3\\times3}$ such that $Mx=b$ has a unique solution and $M^{\\mathsf T}x=c$ has infinitely many solutions.","B: $\\exists\\,M\\in\\mathbb{R}^{3\\times3}$ such that $Mx=b$ has no solution and $M^{\\mathsf T}x=c$ has infinitely many solutions.","C: $\\exists\\,M\\in\\mathbb{R}^{2\\times3}$ such that $Mx=b$ has a unique solution and $M^{\\mathsf T}x=c$ has infinitely many solutions.","D: $\\exists\\,M\\in\\mathbb{R}^{3\\times2}$ such that $Mx=b$ has a unique solution and $M^{\\mathsf T}x=c$ has infinitely many solutions."],"answer":["B","D"],"explanation":"A: an invertible $M$ makes $M^{\\mathsf T}$ invertible too (unique, not infinite). C: a $2\\times3$ system is underdetermined, so it can never have a unique solution. B and D are both achievable.","explanationHtml":"A: an invertible $M$ makes $M^{\\mathsf T}$ invertible too (unique, not infinite). C: a $2\\times3$ system is underdetermined, so it can never have a unique solution. B and D are both achievable."}},{"id":"la-orthogonality-064","topicId":"orthogonality","order":64,"type":"gate-question","hook":"GATE DA 2024 · Projections","body":"Q49. Let $W$ be a subspace of $\\mathbb{R}^3$ and $P\\in\\mathbb{R}^{3\\times3}$ the matrix of the orthogonal projection onto $W$. Which is/are TRUE?","bodyHtml":"","formula":"","concepts":["orthogonality","orthonormal-basis","projection","orthogonal-matrix","least-squares"],"difficulty":"Core","source":"gate-questions.html","sourceAnchor":"gate-question-20","sourceLabel":"GATE questions","detail":"$\\operatorname{null}(P)=W^\\perp$, so $\\dim=3-\\dim W$: for 1-D $W$ it is 2-D (A false), for 2-D $W$ it is 1-D (B true). A projection is idempotent: $P^2=P$, hence $P^3=P$ (C, D true).","detailHtml":"$\\operatorname{null}(P)=W^\\perp$, so $\\dim=3-\\dim W$: for 1-D $W$ it is 2-D (A false), for 2-D $W$ it is 1-D (B true). A projection is idempotent: $P^2=P$, hence $P^3=P$ (C, D true).","question":{"type":"MSQ","prompt":"Q49. Let $W$ be a subspace of $\\mathbb{R}^3$ and $P\\in\\mathbb{R}^{3\\times3}$ the matrix of the orthogonal projection onto $W$. Which is/are TRUE?","options":["A: If $W$ is 1-dimensional, then the null space of $P$ is 1-dimensional.","B: If $W$ is 2-dimensional, then the null space of $P$ is 1-dimensional.","C: $P^2=P$","D: $P^3=P$"],"answer":["B","C","D"],"explanation":"$\\operatorname{null}(P)=W^\\perp$, so $\\dim=3-\\dim W$: for 1-D $W$ it is 2-D (A false), for 2-D $W$ it is 1-D (B true). A projection is idempotent: $P^2=P$, hence $P^3=P$ (C, D true).","explanationHtml":"$\\operatorname{null}(P)=W^\\perp$, so $\\dim=3-\\dim W$: for 1-D $W$ it is 2-D (A false), for 2-D $W$ it is 1-D (B true). A projection is idempotent: $P^2=P$, hence $P^3=P$ (C, D true)."}},{"id":"la-svd-pca-052","topicId":"svd-pca","order":52,"type":"gate-question","hook":"GATE DA 2024 · Singular values (SVD)","body":"Q61. Let $A=\\begin{bmatrix}1\\\\2\\\\3\\\\4\\\\5\\end{bmatrix}$ and let $\\sigma_1,\\dots,\\sigma_5$ be the singular values of $M=AA^{\\mathsf T}$. The value of $\\displaystyle\\sum_{i=1}^{5}\\sigma_i$ is ______.","bodyHtml":"","formula":"","concepts":["svd","singular-value","pca","covariance","rank"],"difficulty":"Core","source":"gate-questions.html","sourceAnchor":"gate-question-21","sourceLabel":"GATE questions","detail":"$M=AA^{\\mathsf T}$ is rank-1 and symmetric PSD; its only non-zero singular value equals $A^{\\mathsf T}A=1+4+9+16+25=55$, the rest are $0$. Sum $=55$.","detailHtml":"$M=AA^{\\mathsf T}$ is rank-1 and symmetric PSD; its only non-zero singular value equals $A^{\\mathsf T}A=1+4+9+16+25=55$, the rest are $0$. Sum $=55$.","question":{"type":"NAT","prompt":"Q61. Let $A=\\begin{bmatrix}1\\\\2\\\\3\\\\4\\\\5\\end{bmatrix}$ and let $\\sigma_1,\\dots,\\sigma_5$ be the singular values of $M=AA^{\\mathsf T}$. The value of $\\displaystyle\\sum_{i=1}^{5}\\sigma_i$ is ______.","options":[],"answer":[55.0,55.0],"explanation":"$M=AA^{\\mathsf T}$ is rank-1 and symmetric PSD; its only non-zero singular value equals $A^{\\mathsf T}A=1+4+9+16+25=55$, the rest are $0$. Sum $=55$.","explanationHtml":"$M=AA^{\\mathsf T}$ is rank-1 and symmetric PSD; its only non-zero singular value equals $A^{\\mathsf T}A=1+4+9+16+25=55$, the rest are $0$. Sum $=55$."}}]};});
